INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dsca_umbrella$$, $$DSCA$$, $$Defense Security Cooperation Agency$$, $$DSCA$$, $$om_dw_ba04$$, NULL, $$dw_dsca$$, 2026, 9875664000, 2889957000, -175197000, -6.06, 2714760000, 2864252000, $$The Defense Security Cooperation Agency (DSCA), in coordination with the Office of the Under Secretary of Defense for Policy (OUSD(P)), leads the security cooperation enterprise in delivering effective, enduring, and timely solutions that support national security, defense strategic guidance and mutual U.S. and partner interests. The DSCA plans, directs, implements, administers, and provides guidance for the execution of assigned security cooperation programs and activities and facilitates the planning, implementation, monitoring, and evaluation of security cooperation activities funded through the DSCA. The DSCA activities encourage and enable foreign partners to responsibly act in support of U.S. national security objectives. Security cooperation activities are often complex and span the phases of conflict from shaping the environment to enabling civil authority activities. The DSCA collaborates closely with the interagency, geographic combatant commands (GCC), industry, and partner nations to execute security cooperation activities. Moreover, the DSCA seeks to maximize security cooperation program effectiveness. The FY 2026 budget request supports the day-to-day operations of the DSCA headquarters, the Defense Security Cooperation University, the Department of Defense (DoD) Regional Centers for Security Studies, and the Defense Security Cooperation Service (DSCS). Under the provisions of the Title 10 USC Chapter 16, the FY 2026 budget request will continue to support the execution of a Department-wide framework for the assessment, monitoring, and evaluation of security cooperation activities and continue to implement a workforce development program targeting all DoD professionals supporting security cooperation efforts. The DSCA will continue to execute Department of State security sector assistance programs and activities in accordance with the Foreign Assistance Act and the Arms Export and Control Act. Additionally, the DSCA budget request supports program management and administration of the Humanitarian Assistance, Foreign Disaster Relief, and Humanitarian Mine Action programs funded within the Overseas Humanitarian, Disaster and Civic Aid appropriation. ADMINISTRATIVE SUPPORT OPERATIONS DSCA Headquarters The DSCA Headquarters line funds the salaries and operating expenses of the DSCA workforce providing program and financial management support to DoD funded security cooperation programs. Additionally, this account resources operational and information technology system support costs, Defense Finance and Accounting Services costs, and support for enterprise resource systems. DSCA 543 Security Cooperation Data Management The Security Cooperation Data Management program is comprised of the Partner Outreach and Collaboration Support (POCS) and Socium platforms. The POCS provides a common information technology platform (GlobalNET) to improve international partner outreach and collaboration efforts in a federated environment. The POCS enables the DoD institutions and partners to share content and participant data across proprietary community websites, fostering communities of practice and promoting collaboration and resource sharing among the Regional Centers for Security Studies, the Partnership for Peace (PfP), other DoD educational institutions and communities, and international partners. The POCS implements the congressional endorsement for the modernization of Defense capabilities in eligible PfP countries relative to their telecommunications infrastructure and provides allies and partner countries the ability to team in critical cooperative activities that underpin the spirit of the PfP program. GlobalNET currently supports over 85,000 users and facilitates efficiencies and complementarity among a variety of institutional capacity building (ICB) providers in the training and education field. The DSCA oversees execution of the research and development of the GlobalNET effort and its operations and ensures that the program addresses DoD security cooperation requirements in the context of defense, interagency, international information sharing, and collaboration needs. The GlobalNET effort focuses on improving collaboration, supporting outreach efforts, and enabling communication among the Regional Centers for Security Studies, the combatant commands (CCMD), DSCA, the OUSD(P), the North Atlantic Treaty Organization’s (NATO) Military Partnerships Directorate, the PfP Consortium of Defense Academies, PfP partner countries, and other DoD institutions and communities. It provides DoD and international partner security practitioners an unclassified secure platform to share information, communicate and collaborate globally 24/7, and supports administrative activities. It provides the ability to form collaborative communities of interest around security issues. GlobalNET facilitates information sharing and knowledge management concepts in accordance with U.S. policy. Socium is the DoD enterprise-wide technology to facilitate and integrate planning, budgeting, collaboration, design, management, assessment, monitoring, evaluation, and reporting in support of all U.S. security cooperation activities. The DSCA deployed the Socium NIPR application in September 2020 and the SIPR application In June 2021. Socium supported issuance of FY 2025 significant security cooperation initiative (SSCI) guidance from the Office of the Deputy Assistant Secretary of Defense for Global Partnerships. SUPPORT TO OPERATIONS Border Security Section 1226 of the National Defense Authorization Act (NDAA) for FY 2016, as amended, provides support to key allies and partner nations on a reimbursable basis for expenses incurred to increase security and sustain increased security along their borders adjacent to conflict areas. This assistance serves to degrade the free movement of the Islamic State of Iraq and Syria (ISIS) and other violent extremist organizations, illicit weapons, and narcotics as well as other forms of smuggling in an effort to promote greater regional security. DSCA 544 CAPACITY BUILDING Taiwan Security Cooperation Initiative (TSCI) The TSCI is intended to support DoD efforts to strengthen Taiwan’s self-defense capabilities, thereby enhancing deterrence, preserving peace and stability across the Taiwan Strait, and mitigating risk to the U.S. Joint Force. The TSCI complements Taiwan’s defense investments and other U.S. security assistance and security cooperation authorities. The DoD intends to incorporate security cooperation assessment, design, planning, and monitoring best practices in implementing this initiative. Taiwan Drawdown Stock Replacement The Taiwan Drawdown Stock Replacement is intended to support the replacement of defense articles transferred to Taiwan from DoD stocks through the Presidential Drawdown Authority, or the TSCI. Funds bolster Joint Force readiness and enable new procurements to replace equipment provided to Taiwan. This program supports DoD efforts to strengthen Taiwan’s self-defense capabilities, thereby enhancing deterrence, preserving peace and stability across the Taiwan Strait, and mitigating risk to the U.S. Joint Force. International Security Cooperation Programs (ISCP) The ISCP account funds security cooperation programs and activities that build the military capacity of partner forces to address shared national security challenges and to operate in tandem with or in lieu of U.S. forces. In line with the 2025 Interim National Defense Strategic Guidance (INDSG), ISCP activities are focused on deterring Chinese aggression, reducing the flow of illicit goods through the southwest border, buying down risk to forward deployed U.S. warfighters, and shifting the burden for regional security by enabling allies and partners to take on greater responsibility for their own security challenges. These efforts include train-and-equip programs enabling partners to operate across a range of mission areas and ICB to strengthen governance and absorption capacities necessary for full spectrum capability development. ISCP’s initiative-based planning supports the Department’s efforts to conduct assessment, monitoring and evaluation of security cooperation activities to ensure programs yield a return on U.S investments. Authorities funded from amounts appropriated for ISCP include Title 10 U.S.C. Sec. 332, 333 and 335 and the Indo-Pacific Maritime Security Initiative from Sec.1263 of the NDAA for FY 2016. EDUCATION AND TRAINING Regional Defense Fellowship Program (RDFP) The RDFP, authorized in the NDAA for FY 2004 (10 USC 2249c), provides foreign military officers and government security officials with strategic and operational education to enhance partners' capacity to combat terrorism. In the NDAA for FY 2019, Irregular Warfare was added to the authority and the program was redesignated the Regional Defense Combating Terrorism and Irregular Warfare Fellowship Program (10 USC Ch. 16 sec. 345). The RDFP is a key tool for GCCs to foster regional and global cooperation in the war on violent extremism and terrorism. The RDFP enhances the U.S. Government's efforts to provide non-lethal irregular warfare and combatting terrorism assistance. The program supports mobile and resident institutional courses tailored to the specific needs of key regions and countries to advance broader U.S. Government objectives. All personnel are thoroughly vetted consistent with legal requirements regarding human rights issues. Funding for the RDFP: builds and strengthens a global network of experts and practitioners at the operational and strategic levels; builds and reinforces the irregular warfare and combating terrorism capabilities of partner nations through operational and strategic-level education; contributes to irregular warfare and counterterrorism DSCA 545 ideology efforts; and provides the DoD with a flexible and proactive program that can respond to emerging irregular warfare and combatting terrorism requirements. Irregular Warfare Center (IWC) The IWC is a DoD functional center that was authorized in the NDAA for FY 2023. The IWC serves as the central mechanism for developing the irregular warfare knowledge of the DoD and advancing the understanding of irregular warfare concepts and doctrine, in collaboration with key partners and allies to enhance integrated deterrence against hybrid threats below the threshold of conflict. The IWC is the battle lab for operationalizing ideas and validating strategic concepts to enhance readiness. The IWC global network serves as a force multiplier and coordinator of functional IW progress for the Department and beyond. The Center provides cutting-edge research and mobile education tailored to the specific needs of specific organizations and key regions and countries to advance broader U.S. Government objectives. Funding for the IWC: builds and strengthens a domestic and global network of irregular warfare experts and practitioners at the operational and strategic levels; builds and reinforces the irregular warfare capabilities of partner nations through operational and strategic-level education; contributes to irregular warfare efforts; and provides the DoD with an agile and innovative approaches that can respond to emerging irregular warfare challenges. . Irregular Warfare Center of Excellence The IWC Center of Excellence research support contract is intended to conduct academic research on irregular warfare topics to support the IWC in supporting the Department on irregular warfare related knowledge and activities. Regional Centers for Security Studies The Regional Centers conduct academic, research, and outreach activities to promote common perspectives on regional security and promote shared responses to transnational threats. Through these programs and resulting alumni networks, the Regional Centers expand both the will and capability of partners to fulfill roles and take actions that support mutual security and defense goals, consistent with U.S. objectives. The Regional Centers are an executive-level, Title 10 authorized strategic complement to traditional invitational professional military education (I-PME), extending beyond the Ministry of Defense space to influence a broader range of security and defense stakeholders. Participants in Regional Centers programs are generally senior (O-5/GS-14 equivalent and above), multilateral, and inter-ministerial, including security and defense stakeholders from ministries of foreign affairs, justice, law enforcement, and parliamentarians. Section 342 of Title 10 U.S Code authorizes the following Regional Centers: the George C. Marshall European Center for Security Studies (Garmisch-Partenkirchen, Germany); the Daniel K. Inouye Asia-Pacific Center for Security Studies (Honolulu, Hawaii); the William J. Perry Center for Hemispheric Defense Studies (Washington, D.C.); the Africa Center for Strategic Studies (Washington, D.C.); the Near East-South Asia Center for Strategic Studies (Washington, D.C); and the Ted Stevens Center for Arctic Security Studies (Anchorage, Alaska). The DSCA is the designated executive agent for all the Regional Centers. For FY 2026, Regional Centers programming will be aligned to support the 2025 INDSG. These programs will focus on Defending the Homeland, Deterring China in the Indo-Pacific, and increasing burden-sharing with allies and partners. DSCA 546 MANAGEMENT, INFRASTRUCTURE, AND WORKFORCE DEVELOPMENT Assessment Monitoring, and Evaluation (AM&E) The AM&E program is a statutory requirement for the Department to establish an enterprise-wide view of security cooperation and enable strategic decision making. Under the provision and in accordance with DoD policy on AM&E, the Department must execute a comprehensive program to assess, monitor, and evaluate security cooperation programs and activities. The funding requested for this activity provides for Department-wide assessments and monitoring of security cooperation programs and activities as well as the identification of trends, challenges, and lessons learned to improve security cooperation planning and execution. Defense Security Cooperation University (DSCU) Pursuant to Section 384 of Title 10 U.S. Code, the DoD established the DSCU to improve the quality and professionalism of the security cooperation workforce that who directly supports the effectiveness of security cooperation activities necessary to shift burden and strengthen credible coalitions capable of deterring attacks on the U.S. Homeland and in the Indo-Pacific, while simultaneously supporting the U.S. economy and defense industrial base. This request reflects a consolidated DSCU budget activity in accordance with Section 384(h)(2) of Title 10 U.S. Code, composed of previously separate line items that appeared under the headings: “DSCU Operations,” “DSCU – Institute for Security Governance,” “DSCU – Security Cooperation Workforce Development Program,” and “DSCU – Defense Institute of International Legal Studies.” This consolidation of budget activities accomplishes a multi-year plan to align the major program elements of the University into a unified organization. The NDAA for FY 2024 codified the DSCU in statute and further defined its mission to include: education, training, development, and management of the workforce; management of ICB services and international military training and education activities executed by the DoD; as well as advancement of the security cooperation profession through research, data collection, analysis, publication, and learning. Defense Security Cooperation Service (DSCS) The DSCS was established in accordance with the NDAA for FY 2024 (10 U.S.C. § 384) to ensure that the Security Cooperation Organization (SCO) workforce stationed at U.S. embassies is appropriately sized and trained to achieve national and theater security cooperation goals and objectives. Achieving national security objectives requires a dedicated SCO workforce with the right training to advise and assist our allies and partners to develop capabilities that address shared security challenges. The DSCS provides the CCMDs with improved security cooperation workforce capabilities and capacity by: enhancing SCO training; right sizing SCO manpower to align with national security priorities and security cooperation workload at each SCO; improving support for partners and allies’ access to U.S. security cooperation programs and activities; fully meeting DSCA statutory and regulatory responsibilities and roles as the Department’s lead for all security cooperation program execution and administration consistent with 10 USC § 382; and placing an increased emphasis on supporting GCC efforts in achieving national and theater strategic objectives. In FY 2026, existing SCO funding and the associated manpower transfers from the Service budget lines where the GCCs are funded to the DSCA to support the establishment of the DSCS. Strategic Evaluations In accordance with U.S.C. Title 10, Section 383, the OUSD(P) conducts strategic evaluations, funded through the Strategic Evaluation account. Strategic evaluations provide data to inform security cooperation decision making, visibility into security cooperation execution, assess progress towards desired results, and increase security cooperation efficiency and effectiveness. DSCA 547$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 36428000, "fy26": 37524000, "name": "A. ADMINISTRATIVE SUPPORT OPERATIONS:", "fy25_current": 33039000, "fy25_request": 41606000, "fy25_cong_amt": -8564000, "fy25_cong_pct": -20.58}$$::jsonb, $${"fy24": 29031000, "fy26": 30691000, "name": "DSCA Headquarters", "fy25_current": 28492000, "fy25_request": 32695000, "fy25_cong_amt": -4200000, "fy25_cong_pct": -12.85}$$::jsonb, $${"fy24": 4597000, "fy26": 6833000, "name": "Security Cooperation Data Management", "fy25_current": 4547000, "fy25_request": 4894000, "fy25_cong_amt": -347000, "fy25_cong_pct": -7.09}$$::jsonb, $${"fy24": 2800000, "fy26": 0, "name": "Claims Litigations Support", "fy25_current": 0, "fy25_request": 4017000, "fy25_cong_amt": -4017000, "fy25_cong_pct": -100.0}$$::jsonb, $${"fy24": 761920000, "fy26": 192298000, "name": "B. SUPPORT TO OPERATIONS", "fy25_current": 400406000, "fy25_request": 473200000, "fy25_cong_amt": -72794000, "fy25_cong_pct": -15.38}$$::jsonb, $${"fy24": 722261000, "fy26": 192298000, "name": "Border Security", "fy25_current": 350000000, "fy25_request": 400000000, "fy25_cong_amt": -50000000, "fy25_cong_pct": -12.5}$$::jsonb, $${"fy24": 39659000, "fy26": 0, "name": "Coalition Support Funds", "fy25_current": 50406000, "fy25_request": 73200000, "fy25_cong_amt": -22794000, "fy25_cong_pct": -31.14}$$::jsonb, $${"fy24": 8856215000, "fy26": 2383808000, "name": "C. CAPACITY BUILDING", "fy25_current": 2062808000, "fy25_request": 2141174000, "fy25_cong_amt": -78365000, "fy25_cong_pct": -3.66}$$::jsonb, $${"fy24": 7080957000, "fy26": 0, "name": "Ukraine Security Assistance Initiative", "fy25_current": 300000000, "fy25_request": 300000000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 0, "fy26": 1000000000, "name": "Taiwan Security Cooperation Initiative", "fy25_current": 400000000, "fy25_request": 50