INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_caaf_umbrella$$, $$CAAF$$, $$United States Court of Appeals for the Armed Forces$$, $$USCAAF$$, $$om_uscaaf$$, NULL, $$dw_caaf$$, 2026, 16619000, 21035000, 0, 0.0, 21035000, 21243000, $$The United States Court of Appeals for the Armed Forces (USCAAF) funding provides all customary expenses required to operate the activity such as salaries, benefits, travel expenses, rent, communications services, equipment purchases, contractual information technology support, security services, and the expense of printing opinions and decisions of the USCAAF. The requested funds typically support five civilian judges, appointed for 15-year terms, and a staff of 54 civilian personnel. The Court is an Article I Court established by Chapter 47 of Title 10, United States Code (also known as the Uniform Code of Military Justice (UCMJ)), specifically Section 941. The Court exercises appellate jurisdiction over cases arising under the UCMJ on a broad range of legal issues. Decisions by the Court are subject to direct review by the Supreme Court of the United States. CAAF 3 United States Court of Appeals for the Armed Forces$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 16619000, "fy26": 21243000, "name": "U.S. Court of Appeals for the Armed Forces", "fy25_current": 21035000, "fy25_request": 21035000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part_2.pdf$$, 5, 17, FALSE, $${"json_key": "CAAF__umbrella"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 21698000, NULL, NULL, NULL, $$O&M/FY27/DW/Vol1_Part2/CAAF_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
