INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_cmp_umbrella$$, $$CMP$$, $$Civil Military Programs$$, $$CMP$$, $$om_dw_ba04$$, NULL, $$dw_cmp$$, 2026, 280804000, 140375000, 140411000, 100.03, 280786000, 126637000, $$The Department of Defense (DoD) Civil Military Programs (CMP) are managed by the Assistant Secretary of Defense for Manpower and Reserve Affairs (ASD(M&RA)) in the Office of the Under Secretary of Defense for Personnel and Readiness (USD(P&R)), and encompass outreach and service programs identified as follows: • National Guard Youth Challenge Program •   Innovative Readiness Training Program •   DoD STARBASE Program - The Department is not requesting any funding for STARBASE in FY 2026. National Guard Youth Challenge Program (NGYCP) (Title 32 U.S.C. 509, DoDI 1025.08) - The NGYCP is a youth development outreach program managed by ASD(M&RA) and administered by the National Guard Bureau (NGB) through cooperative agreements with the states that provides partnership opportunities to engage with the nation's youth. The goal of the NGYCP is to improve the life skills and employment potential of participants by providing military-based training and supervised work experience. The 18-month program consists of at least a 22 ½ -week residential phase that includes a 2-week pre-challenge phase and a 12-month post-residential phase. The NGYCP has measurably improved the employment and academic outcomes for at-risk youth. Compared to peers, at-risk youth who participate in NGYCP have higher rates of employment and higher earnings and are more likely to earn a GED or college credits. The DoD funds provided may not exceed 75 percent of the costs of operating the NGYCP. The program is currently operating in 37 Youth Challenge and eight Job Challenge program locations (states and territories), to include the District of Columbia (D.C.), and Puerto Rico. The NGYCP core program components are as follows: • Assist participants in attaining a high school diploma or its equivalent; •   Provide leadership development, promoting fellowship and community service; •   Where available, the Additional Job Challenge Phase at certain Youth Challenge Programs provides occupational skills instruction and credentialing; individualized career and academic counseling; leadership development activities that encourage responsibility, employability, and other positive behavior; and employer engagement and job placement. CMP 60 Innovative Readiness Training Program (IRT) (Title 10 U.S.C. 2012, DoDI 1100.24) – The IRT program builds mutually beneficial partnerships between U.S. communities and the DoD to meet training and readiness requirements for Service members and units while simultaneously addressing public and civil society needs. The program generates military readiness for approximately 6,000 joint Service members each year by providing hands-on training for mission-essential tasks in complex interagency, joint, and total force environments that are seldom found outside of a national crisis, and often only simulated during other training events. Projects are in the heart of American communities and typically include conducting horizontal and vertical construction, supporting critical infrastructure, providing mobile health, dental, optometry, and/or veterinary clinics, or performing cyber vulnerability assessments. The IRT program generates both the quality and quantity of training venues required for mission readiness and also develops partnership capabilities that translate into our nation's capacity to form and sustain successful alliances and coalitions. In addition to attracting and retaining talent within the DoD, the program also strengthens the bond between American citizens and the U.S. military, showcasing the robust skillsets and operational excellence of our military members. Examples of IRT projects in FY 2025 include: • Medical Mission – Kodiak Arctic Care: From May 8-22, 2024, the Alaska Air National Guard led a no-cost medical support activity partnered with the Kodiak Area Native Association. The Army Reserve, Marine Corps Reserve, Navy Active Duty, Navy Reserve, Air Force Active Duty, and the Air Force Reserve supported this joint exercise and received real-world medical services training at multiple operational sites, as well as accomplished unit and individual readiness training for military professionals in the areas of general medicine, dentistry, optometry, and veterinary services. During the 15-day mission, 385 Service members performed 7,573 procedures across 1,802 patients in the communities of Akhiok, Larsen Bay, Old Harbor, Ouzinkie, Port Lions, and Kodiak, Alaska. This civil military partnership enhanced deployment readiness and occupational specialties of Service members while providing an estimated $1,381,100 in no-cost healthcare benefits. • Civil Engineering Mission – Operation Appalachian Thunder: From July 9 – August 6, 2024, the Marine Corps Reserve partnered with Stonewall State Park Foundation to remove material from two sites and place it in various low spots creating areas for future expansion. This exercise provided joint training opportunities for a total of 158 Service members across the Marine Corps Active Duty, Marine Corps Reserve, and Air Force Reserve. Participants received training in surveying, general engineering, equipment maintenance, water distribution, and communications while moving more than 16,000 cubic yards of material and installing approximately 2,700 linear feet of environmental controls. As a result, the community received an estimated $1,200,000 in no-cost civil engineering services and is better prepared to improve the park for future generations of visitors. • Cybersecurity Mission – Cyber Nueces: From May 6-15, 2024, the Air Force Reserve partnered with Nueces County in Texas to validate and identify gaps in cybersecurity policies, plans, and procedures, while raising cyber threat awareness for the county. The exercise provided cybersecurity training opportunities for 29 Service members from 15 units, resulting in the completion of 1,295 training requirements. The preparation, execution, and review of this exercise enhanced total force readiness against emerging cyber threats, enabling the units to prepare more diversified response actions. As a result of the 10-day exercise, the community received an estimated $411,000 in no-cost cybersecurity services that will bolster the county’s cyber defense of information systems against potential malicious disclosure, theft, or damage. CMP 61 • Civil Affairs – Qawalangin Needs Assessment: From January 2 – September 30, 2024, the Army Reserve partnered with the Qawalangin Tribe of Unalaska, Alaska to conduct a civil affairs assessment to assist the population of Unalaska. This exercise provided 10 Soldiers with unparalleled training opportunities in core competencies and functions, including civil engagement, civil reconnaissance, and civil information management. This civil military partnership enhanced unit deployment readiness by providing a practical application of their training in a challenging environment while assisting the community with value creation through the identification of future improvement projects. DoD STARBASE Program (Title 10 U.S.C. 2193b, DODI 1025.07) The DoD STARBASE Program is a DoD Youth Outreach Program designed to improve the knowledge and skills of students in mathematics, science, and technology. Each DoD STARBASE is located on or near a military installation, providing exposure to military members and facilities to bridge the civil military divide currently existing in our country. The program works with schools whose students are eligible to receive Title 1 services. The curriculum utilizes hands-on instruction and activities that meet or exceed the National Standards. The Department is not requesting any funding for STARBASE for FY 2026. CMP 62$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 52342000, "fy26": 0, "name": "DoD STARBASE Program", "fy25_current": 53000000, "fy25_request": 0, "fy25_cong_amt": 53000000, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 13284000, "fy26": 16381000, "name": "Innovative Readiness Training (IRT)", "fy25_current": 16197000, "fy25_request": 16197000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 215178000, "fy26": 110256000, "name": "National Guard Youth Challenge Program (NGYCP)", "fy25_current": 211589000, "fy25_request": 124178000, "fy25_cong_amt": 87411000, "fy25_cong_pct": 70.39}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 63, 76, FALSE, $${"json_key": "CMP__umbrella"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 118488000, to_jsonb(ARRAY[$${"fy25": 52.089, "fy27": 0.0, "name": "DoW STARBASE Program", "fy26_current": 53.0, "fy26_request": 0.0, "fy26_cong_amt": 53.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 6.798, "fy27": 16.847, "name": "Innovative Readiness Training Program", "fy26_current": 15.557, "fy26_request": 16.381, "fy26_cong_amt": -0.824, "fy26_cong_pct": -5.03}$$::jsonb, $${"fy25": 210.713, "fy27": 101.641, "name": "National Guard Youth Challenge Program", "fy26_current": 187.727, "fy26_request": 110.256, "fy26_cong_amt": 77.471, "fy26_cong_pct": 70.26}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part1/CMP_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
