INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_cybercom_012d$$, $$012D$$, $$Cyberspace Operations$$, $$CYBERCOM$$, $$om_dw_ba01$$, NULL, $$dw_disa$$, 2026, 1219657000, 1361360000, -46938000, -3.45, 1314422000, 1300384000, $$U. S. Cyber Command (USCYBERCOM) Fiscal Year (FY) 2026 operating budget supports the command’s mission to: direct, synchronize, and coordinate cyberspace operations planning and execution - to defend and advance national interests - in collaboration with domestic and international partners. The USCYBERCOM defends U.S. interests while delivering a warfighting advantage to the DoD, which operates globally. The USCYBERCOM defends the DoDIN and develops options for the full spectrum of cyberspace operations to assist Combatant Commanders (CCMD) and the Joint Force in achieving objectives and countering cyber threat actors and affiliates who seek to harm the U.S, its interests, and its allies. The command defends the nation against dangerous cyber threat actors serving foreign military and intelligence organizations and terrorists. The USCYBERCOM provides options to counter malign actors who exploit cyberspace to support intelligence operations, steal intellectual property, promote violent extremism, impair democratic processes, coerce perceived rivals, and fund transnational illegal activities The USCYBERCOM directs operations through the subordinate commands, including the CNMF Headquarters (CNMF-HQ), DoD Cyber Defense Command (DCDC), Joint Task Forces, and other Joint Force Headquarters elements. The commanders of Army Cyber Command (ARCYBER), Marine Corps Forces Cyberspace Command (MARFORCYBER), Fleet Cyber Command (FLEETCYBER)/Tenth Fleet, Air Force Cyber Command (AFCYBER)/16th Air Force, and Coast Guard Cyber Command also lead their Service cyber components under the USCYBERCOM enterprise. USCYBERCOM Cyber Operations Funded Programs and Organizations: Civilian Pay: USCYBERCOM Cyberspace Operations supports ten Headquarters Directorates and two sub-unified commands, including salaries and benefits for civilian Full-Time Equivalent (FTE). The FY 2026 request for Cyberspace Operations includes 1,431 civilian FTEs. Funds requested enable USCYBERCOM to continue to “Win with People” by providing a pipeline of talented civilian employees and securing and retaining civilian intellectual capital by investing in, building, and cultivating its talent pool with the requisite technical and leadership skills needed to drive results in functional areas, business units, and across the command to gain advantage in cyberspace. CNMF-HQ is a sub-unified command established in response to malicious cyberspace activity (MCA) against the United States' critical infrastructure. The CNMF-HQ defends the Nation in cyberspace and is persistently engaged in cyberspace operations against the world’s most dangerous foreign adversary threats. When ordered, the CNMF-HQ routinely denies or manipulates the most significant foreign cyber threats to Cyber Operations 83 the Nation. The CNMF-HQ is also the Nation’s only organization deploying intel-driven Defend Forward cyber operations teams across the globe to discover and neutralize harmful threats before they reach the United States. DCDC has a mission to exercise command and control of the global security and defense of the DoDIN to synchronize the protection of DoD components' capabilities to enable power projection and freedom of action across all DoD network enclaves and warfighting domains. The full mission scope of the DCDC includes: the critical daily requirement to protect the DoDIN, management of requirements for global engagement, and assessing the DoDIN's readiness against CCMD requirements. DCDC provides unity of command between USCYBERCOM and subordinate headquarters and unity of effort with all other DoD Components. The DCDC ensures the readiness, availability, and security of the DoDIN for Joint Missions, including effects delivered in and through cyberspace. The Cyber Mission Force (CMF) Team is the USCYBERCOM action arm that executes the command's mission to direct, synchronize, coordinate, and execute cyberspace operations to defend U.S. national interests. The CMF is comprised of 147 teams organized into several areas of responsibility, including Cyber Protection Teams, Combat Mission Teams, Combat Support Teams, National Mission Teams, and National Support Teams. Joint Force Headquarters-Cyberspace (JFHQ-C) analyzes, plans, and executes cyberspace operations missions supporting the CCMDs. The JFHQ-C focuses on providing tactical expertise for courses of action and integrating cyberspace operations into the CCDRs’ plans and orders through its subordinate Cyberspace Operations-Integrated Planning Elements (CO-IPEs). Cyberspace Operations-IPE is the USCYBERCOM forward-deployed and integrated planning cells embedded within the staffs of other CCMDs to act as a direct reach-back capability to USCYBERCOM to ensure authorities are in place and synchronization and deconfliction actions have occurred. They provide direct support for planning for DoDIN operations, defensive cyber operations, and offensive cyberspace operations in coordination with their respective JFHQ. Joint Force Trainer (JFT) allows the DoD cyberspace workforce to conduct cyberspace operations training, exercises, mission rehearsals, experimentations, certifications, and the ability to assess and develop cyberspace operations tactics and procedures for missions that cross boundaries and networks. The JFT oversees 2000 to 4000 level training to deliver mission-ready, interoperable forces in support of (ISO) the National Military Strategy (NMS) and INDSG objectives. As a JFT, USCYBERCOM is responsible for managing a "Service-like" training program to ensure that assigned Joint Forces are trained, certified, and interoperable with other forces, and trained to meet joint mission requirements deemed necessary by each of the supported Combatant Commands (CCMDs). USCYBERCOM J7 still intends to offer the Future Operator Readiness Growth and Enrichment (FORGE), Holistic Analytic Mastery and Refinement (HAMR), Computer Network Operations Qualification Course (CNOQC), and other cyber-related training courses for operators, Exploitation Analysts (EAs), and other cyber work roles. The manning, delivery, and development of training content benefits Cyber Mission Force (CMF) teams to achieve and maintain readiness. In FY 2025, the J7 supported two iterations of the Advanced Operations Course (AOC) in the final year of the pilot. The AOC is now undergoing the joint validation process to be federated to the services, and the J7 is planning to support three iterations of AOC in FY 2026 as a cost-effective alternative to FORGE. Cyber Operations 84 Joint Cyber Warfighting Architecture (JCWA) Integration and Innovation is USCYBERCOM’s premier platform that enables the CMF to conduct the full spectrum of cyberspace operations. It provides JCWA foundational software, systems engineering and enterprise architecture, software development, SAP/STO support, test and evaluation, and external integration. It also supports the innovation of capabilities, artificial intelligence, machine learning, and federal labs. The JCWA includes six elements: Cyber Weapons and Tools, Data and Sensors, Robust Infrastructure, Cloud and Unified Platform (UP), Persistent Cyber Training Environment, and Cyber Command and Control. Cyber Weapons and Tools provides dual/multi-use capabilities (i.e., software/hardware) used by the CMF on Joint Assess Platforms to conduct cyberspace operations. The capability delivers platforms and access points that enable the full spectrum of operations and integrates offensive cyber capabilities into combat operations, enhancing lethality through support functions, tool development, and utilization while maximizing innovation to address shifting threats. This includes enablers to support testing, evaluation, validation, and sustainment (e.g., Joint Development, PDP testing, independent testing, signature diversity, and capability repository). Data and Sensors supports the Joint Force, including projects that provide data and information from network security appliances across the network (enterprise, regional, enclave, and endpoint) and on any DoDIN system that identifies indications or confirmation of a compromised cyberspace security capability. Capability provides CNMF-HQ Hunt Forward Kit, Joint Cyber Hunt Kits (JCHK), DoDIN Enhanced Sensing, Analytics, and investment, as well as other sensors used to support the CMF. Portfolio investments support CMF access to commercially available information from mission-relevant cyber threats required to evaluate, analyze, and counter MCA and Malign Influence Activity. Enhanced sensing efforts are components of the larger USINDOPACOM Pacific Deterrence Initiative (PDI) to reduce vulnerabilities, strengthen defenses in key networks in the INDOPACOM AOR, and improve the overall defensive posture in the theater. The near-term focus in FY 2026 is to enhance the defensive posture in Guam to defend critical infrastructure and then expand to other key networks in the Pacific. Robust Infrastructure supports the Joint Force, including armories, platforms, and infrastructures required to launch a cyber capability, payload, or analytic onto its unclassified and classified platform or deliver it to its intended target. This does not include developing or testing the offensive or defensive cyber capability, payload, or analytics. The Joint Common Access Platform (JCAP), the “Best of Breed,” supports USCYBERCOM by providing a protected, managed, orchestrated environment and common firing platform to coordinate and execute in cyberspace against approved targets. This capability enables the CMF to execute operations while managing detection and attribution. As a component of the USINDOPACOM’s overarching PDI, this aspect of this portfolio focuses on integrating existing alternate access tools into the JCWA to enhance the overall effectiveness of the platform, and also includes funding for the Operation in the Information Environment (OIE) Cloud and Unified Platform (UP) provides the Joint Force with interconnected and interoperable infrastructure to conduct integrated planning and execution of cyberspace operations to meet CCDRs’ requirements and provides a persistently owned and maintained environment, providing baseline data storage for the JCWA with full lifecycle support. Cloud services provide shared services enabling fast and responsive ways to adjust to meet processing needs; sharing of information; gains in efficiencies surrounding data collection, cleansing, and storage; scheduling of tasks; and financial efficiencies. The UP is the foundation for the JWCA and is utilized by the USCYBERCOM to curate, connect, and scale the leading cyberspace capabilities of each JCWA component into a federated secure ecosystem. A common UP manages, stores, prepares, and processes Cyber Operations 85 data. The UP provides programming interfaces, standards, and services to share data and analytics internally across tactical, regional, and enterprise echelons and externally to transform data into actionable knowledge. Cyber Training Environment provides replicates of friendly, neutral, and adversary terrain in cyberspace and enables warfighters to train, test, and rehearse for missions and develop standardized tactics, techniques, and procedures (TTP). Cyber Command and Control (C2) supports the Joint Force by providing USCYBERCOM near real-time, cyber-related information tracking, processing, and disseminating capabilities that facilitate cross-domain collaboration with DoD, coalition, and interagency partners. This capability provides a tailorable visualization of cyberspace operation (CO) information to improve the commander's ability to collaborate, plan, direct, monitor, assess, force employment, mission management and other command and control functions to include Nuclear Command, Control and Communication (NC3) from the strategic to the tactical level. MDDE provides advanced non-kinetic capabilities that directly support USCYBERCOM operational directives tied to the INDSG, the Department of Defense Cyber Strategy, and other formal requirements documents outlining needed capabilities against identified threats. Further details are held at a higher classification level and can be found in the Information Technology Cyberspace Congressional Justification Book. Cyber Operations 86$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 1219657000, "fy26": 1300384000, "name": "Cyberspace Operations", "fy25_current": 1314422000, "fy25_request": 1361360000, "fy25_cong_amt": -46938000, "fy25_cong_pct": -3.45}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 87, 104, FALSE, $${"json_key": "CYBERCOM__012D"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 1880381000, NULL, NULL, NULL, $$O&M/FY27/DW/Vol1_Part1/USCYBERCOM_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_cybercom_015e$$, $$015E$$, $$CYBERCOM Headquarters$$, $$CYBERCOM$$, $$om_dw_ba01$$, NULL, $$dw_cybercom$$, 2026, 285718000, 344376000, -29280000, -8.5, 315096000, 314284000, $$U. S. Cyber Command (USCYBERCOM) Fiscal Year (FY) 2026 operating budget supports the command’s mission to direct, synchronize, and coordinate cyberspace operations planning and execution, and to defend and advance national interests in collaboration with domestic and international partners. The USCYBERCOM defends U.S. interests while delivering a warfighting advantage to the Department of Defense (DoD), which operates globally. USCYBERCOM defends the DoD Information Network (DoDIN) and develops options for the full spectrum of cyberspace operations to assist Combatant Commanders (CCMD) and the Joint Force in achieving objectives and countering cyber threat actors and affiliates who seek to harm the U.S, its interests, and its allies. The command defends the nation against dangerous cyber threat actors serving foreign military and intelligence organizations and terrorists. The USCYBERCOM provides options to counter malign actors who exploit cyberspace to support intelligence operations, steal intellectual property, promote violent extremism, impair democratic processes, coerce perceived rivals, and fund transnational illegal activities. In FY 2026, the USCYBERCOM's Headquarters Cyberspace funding supports global strategic challenges, enhances the command's posture in cyberspace, and enables USCYBERCOM to develop improved cyberspace access and support planning and operations. The USCYBERCOM strategy is driven by people, partnerships, and delivering a decisive advantage to “Own the Domain" by (1) sharpening our world-class force through readiness, resilience, and mission improvement; (2) strengthening warfighting advantage throughout competition, crisis, and conflict; and (3) executing our authorities to build and sustain decisive advantage for national security. USCYBERCOM Headquarters Operational Funded Programs: Civilian Pay: The USCYBERCOM's Headquarters (HQ) civilian personnel workforce focuses on four main activities: (1) defending the DoDIN, (2) providing support to CCMDs for execution of missions around the world, (3) strengthening our nation's ability to withstand and respond to Malicious Cyber Actors (MCA), and (4) increasing DoD Cyber effectiveness through combined efforts with allies and partners. The workforce supports the Commander in unifying the direction of cyberspace operations, strengthens DoD cyberspace capabilities, and integrates and bolsters DoD’s cyber expertise. CYBERCOM Headquarters 101 The workforce also assists USCYBERCOM enterprise work to improve DoD's capabilities to operate resilient, reliable information and communication networks, counter cyberspace threats, and assure access to cyberspace. The civilian workforce collaborates in designing the CMF, training requirements, and certification standards to enable the Services to build the cyber mission force (CMF) required to execute our assigned missions. The USCYBERCOM HQ civilian workforce is assigned among the ten directorates. The FY 2026 request includes 407 civilian FTE. • USCYBERCOM is working closely with the Army Civilian Human Resources Agency (CHRA) Cyber HR Team to implement deliberate recruiting and retention strategies. To reduce the time required to bring an employee on-board, the command reviews each position‘s security requirements. An unclassified workspace is being created to allow quicker onboarding for employees who only require unclassified clearances (HR, FM, etc.). For employees requiring higher security clearances, the command is increasing the number of individuals conducting security reviews to reduce hiring timelines. Travel: Resources fund TDY cost for personnel traveling for operation and mission requirements, certification trainings, and planning events; funds also cover travel and transportation of equipment for mission requirements. Defense Industrial Base (DIB): Resources fund USCYBERCOM activities to assist the DIB Cybersecurity (CS) program in protecting intellectual property and safeguarding the DoD content residing on or transitioning its networks. This effort provides DoD situational awareness of programs, technologies, or science and technology advantages affected by Malicious Cyber Actors (MCA) on DIB unclassified infrastructures. Facilities and Security: Resources fund the full logistical and security support for USCYBERCOM’s cyberspace operations by preparing effective operational plans, delivering war-fighting forces and equipment, sustaining efficient logistics flows, and providing mission-ready facilities. These funds support the management of all sustainment, renovation, facility operations, maintenance, and security requirements for USCYBERCOM. Headquarters Information Technology (IT): The C4 Systems Directorate and Chief Information Officer deliver C4 systems, cybersecurity, and IT services while sustaining mission-ready capabilities to enable USCYBERCOM and its subordinates and to cultivate Mission Partners’ interoperability to execute cyber operations. In support of the FY 2025 Interim-National Defense Strategic Guidance (INDSG) and DoD CIO 2019- 2023 Digital Modernization Strategy, USCYBERCOM’s strategy is to oversee, govern, and operate a commercial cloud environment for USCYBERCOM’s enterprise, and integrate cybersecurity and standard IT services with cyberspace operations planning and execution. The funding covers cloud hosting, engineering to establish a shared environment across the networks, and migrating new and existing mission and business systems/applications into the multi-cloud environment. •   In FY 2025, efforts continue to enhance cyber capabilities through targeted investments in technical, scientific, and engineering support. The funding continues cloud technology with the security and reliability requirements across classification levels and supports evolving DoDIN Area of Operation and component requirements for more effective engagement with adversaries via advanced defensive and offensive cyber operations. Key initiatives included the integration of special program capabilities, the development of new operating concepts to counter emerging threats, and the refinement of systems engineering processes. These efforts collectively improved the CYBERCOM Headquarters 102 command’s ability to protect national interests by equipping Cyber Forces with the necessary tools and strategies to defend against and respond to cyber threats. •   In FY 2026, the funding continues to support critical engineering and architecture tasks that further refine and enhance USCYBERCOM’s cyberspace operations. The focus is on advancing systems integration strategies, improving mission readiness, and developing innovative solutions to emerging threats. Specific priorities include the continued support of Joint Cyber Warfighting Architecture (JCWA), CNMF in executing Hunt Forward Operations, and analyzing Malicious Cyber Actor (MCA) target systems. Additionally, USCYBERCOM continues to evolve its operating concepts and refine the processes needed to operationalize new capabilities. This includes advancing the development of a joint architecture for Defensive Cyber Operations (DCO) and ensuring a seamless transition of innovations into the mission to maintain and enhance its cybersecurity posture. These ongoing efforts ensure that the command remains at the forefront of cyber defense, effectively safeguarding national security in an increasingly complex cyber environment. Official representation funds (ORF): Resources fund official receptions, dinners, and similar events or otherwise extend official courtesies to U.S. and DoD guests to maintain U.S. and DoD standing and prestige. Support Staff: The USCYBERCOM utilizes various subject matter experts to support activities across four focus areas: (1) defending the DoDIN, (2) supporting CCMDs in execution of missions around the world, (3) strengthening our nation's ability to withstand and respond to MCA, and (4) advancing DoD missions in cyberspace through collaboration with allies and partners. Support includes, but is not limited to, supply chain risk management, continuity of operations preparedness activities, wargaming, and Department of State services. CYBERCOM Headquarters 103$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 285718000, "fy26": 314284000, "name": "USCYBERCOM Headquarters", "fy25_current": 315096000, "fy25_request": 344376000, "fy25_cong_amt": -29280000, "fy25_cong_pct": -8.5}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 105, 118, FALSE, $${"json_key": "CYBERCOM__015E"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 303726000, NULL, NULL, NULL, $$O&M/FY27/DW/Vol1_Part1/USCYBERCOM_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_cybercom_umbrella$$, $$CYBERCOM$$, $$United States Cyber Command$$, $$CYBERCOM$$, $$om_dw_ba01$$, NULL, $$dw_disa$$, 2026, 1505375000, 1705736000, -76218000, -4.47, 1629518000, 1614668000, $$Consistent with congressional direction enacted in the FY 2022 National Defense Authorization Act (NDAA), Section 1507 (Public Law 117-81, December 27, 2021), this action transferred the responsibility for planning, programming, budgeting, and execution to USCYBERCOM, under the authority, direction, and control of the Office of the Principal Cyber Advisor. Following, the FY 2024 Appropriation realigned Cyber Mission Force (CMF) resources from the Military Departments and the Defense Information Services Agency (DISA) to U.S. Cyber Command (USCYBERCOM) in the Defense-wide appropriations. USCYBERCOM FY 2026 President’s Budget request is $1,614,668 thousand, which is $14,850 thousand less than the FY 2025 Enacted and supports the USCYBERCOM mission to direct, synchronize, and coordinate cyberspace planning and operations to defend and advance national interests in collaboration with domestic and international partners. The FY 2026 request includes 1,838 budgeted civilian Full Time Equivalents (FTE). The request will enhance USCYBERCOM’s capabilities by focusing on: (1) Sharpening our world-class force through readiness, resilience, and mission improvement; (2) Strengthening warfighting advantage throughout competition, crisis, and conflict; and (3) Executing our authorities to build and sustain decisive advantage for national security. The request enables USCYBERCOM’s four missions: (1) Defend the DoD Information Network (DoDIN); (2) Defend the homeland; (3) Support the Joint Force; and (4) Build and strengthen partners. Funding is used for civilian pay, contractor support, travel, and operations; provides cyberspace intelligence surveillance, and reconnaissance; and provides cyber support to Combatant Commands. Further, these activities attain freedom of action in cyberspace while denying the same to adversaries, and when directed, conduct full-spectrum cyberspace operations to deter or defeat threats to United States (U.S.) interests and infrastructure. These activities also support DoD mission assurance by achieving joint force commander objectives. These funds are critical in protecting and defending the homeland and international partners and deterring foreign adversaries by executing operational instructions and command and control of the Cyber Mission Force (CMF) consistent with the National Security Strategy and National Military Strategy of the U.S. All O&M-funded activities align with the DoD Cyber Strategy and enable USCYBERCOM to continuously upgrade and strengthen cyberspace for the United States and its allies. CYBERCOM 74$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 1505375000, "fy26": 1614668000, "name": "1. Operating Forces", "fy25_current": 1629518000, "fy25_request": 1705736000, "fy25_cong_amt": -76218000, "fy25_cong_pct": -4.47}$$::jsonb, $${"fy24": 1219657000, "fy26": 1300384000, "name": "Cyberspace Operations", "fy25_current": 1314422000, "fy25_request": 1361360000, "fy25_cong_amt": -46938000, "fy25_cong_pct": -3.45}$$::jsonb, $${"fy24": 285718000, "fy26": 314284000, "name": "USCYBERCOM Headquarters", "fy25_current": 315096000, "fy25_request": 344376000, "fy25_cong_amt": -29280000, "fy25_cong_pct": -8.5}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 77, 86, FALSE, $${"json_key": "CYBERCOM__Cyber"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 2184107000, NULL, NULL, NULL, $$O&M/FY27/DW/Vol1_Part1/USCYBERCOM_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_disa_cyber$$, $$DISA - Cyber$$, $$Defense Information Systems Agency Cyber$$, $$DISA$$, $$om_dw_ba04$$, NULL, $$dw_disa$$, 2026, 515093000, 504896000, -13548000, -2.68, 491348000, 559426000, $$The Defense Information Systems Agency (DISA) is a combat support agency that provides, operates, and assures command and control, information sharing capabilities, and a globally accessible enterprise information infrastructure in direct support to the joint warfighters, National- level leaders, and other missions and coalition partners across the full spectrum of operations. The DISA Next Strategy is designed to drive the combat support priorities and initiatives that enable the delivery of capacity and capability for the warfighting information system. The DISA plans, engineers, acquires, tests, fields, operates, and assures information-sharing capabilities, command and control solutions, and a global enterprise infrastructure to support the DoD and National-level leadership. The DISA drives innovation and collaboration to match capabilities with evolving threats and is integral to achieving the SECDEF’s priorities to rebuild the military and reestablish deterrence by defending the homeland. By embodying the core principles of readiness, campaigning, continuous modernization, and establishing lethality, the DISA ensures the military is agile and adaptable, capable of quickly incorporating new technologies and tactics to respond to evolving threats. The DISA serves the needs of the President, Vice President, Secretary of Defense, Joint Chiefs of Staff, Combatant Commands (CCMD), and other DoD Components providing networks, computing infrastructure, and enterprise services to support information sharing and decision making for the warfighters and those who support them in the defense of the nation. The DISA is committed to advancing new technologies to strengthen the security and resilience of networks and systems that contribute to current and future U.S. military advantages over potential adversaries. Cyber, National Leadership Command Capability (NLCC), and the White House support are priority areas. Four strategic imperatives guide the DISA’s efforts: Strategic Imperative #1: Operate and Secure the DISA Portion of the DOD Information Network (DoDIN) This strategic imperative involves fortifying infrastructure, innovating processes, and dedicating critical resources, and includes providing relevant, modern enterprise and business tools, over 200 of which are already in place. A resilient and redundant Defense Information Systems Network (DISN) backbone is crucial for data transport security. DISA - Cyber 410 Strategic Imperative #2: Support Strategic Command, Control, and Communications (C3) Developing, provisioning, and operating C3 solutions that enable secure communications is a critical function for the DISA. Operationalizing the cloud, building an accessible hybrid cloud environment, and strengthening standards for data management are key operational goals. These innovations will allow warfighters to access data at the scope and scale needed for modern combat operations and maintain the agility and adaptability to respond to emerging threats. Strategic Imperative #3: Optimize the Network Optimizing the DoDIN is a responsibility that involves both security and adaptability. Innovating while providing the infrastructure necessary to maintain confidence in the network resilience guides the DISA strategy in this area. The user experience must be seamless, and technical debt must be minimized. Goals around an unconstrained DoDIN, consolidated Defense Agencies and Field Activities (DAFA), and CCMDs will help steer this priority imperative. Strategic Imperative #4: Operationalize Data Leveraging data to make decisions that help the warfighter gain a strategic advantage over adversaries is critical to a continued competitive advantage. Culture, conduct, and capabilities must be aligned to innovate in the operationalization of data. Modernizing the coordination capabilities of the NLCC and joint warfighting tools will enhance the collaborative process of operationalizing data. The DISA aligns its program resource structure across seven mission areas. These mission areas reflect the DoD national defense priorities and represent DISA’s focus on executing its lines of operations: Transition to Net Centric Environment: Create and strengthen the network environment to facilitate DoD information sharing by making data continuously available in a trusted environment. Cultivate emerging technologies to rapidly integrate them into the military’s arsenal to maintain a technological edge over adversaries. Eliminate Bandwidth Constraints: Build and sustain the DoDIN transport infrastructure that eliminates bandwidth constraints and rapidly surges to meet demands, whenever and wherever needed. DoDIN Network Operations and Defense: Operate, protect, defend, and sustain the enterprise infrastructure and information sharing services and enable Command and Control. Supports the CCMDs by providing cybersecurity and network operations to the edge of conflict. Exploit the DoDIN for Improved Decision Making: Build the DoD enterprise-wide capabilities for communities of interest, such as command and control, and combat support that exploit the DoDIN for improved decision-making. Enables collaboration, joint military exercises, intelligence sharing, and strategic planning for strategic deterrence. Deliver Capabilities Effectively/Efficiently: Deliver capabilities, based on established requirements, more effectively, economically, and efficiently than the DISA does today. Special Mission Area: Execute special missions to provide communications support required by the President, including day-to-day management, fielding, operation, and maintenance of communications and information technology. DISA - Cyber 411 Cyberspace Operations (described in this Cyber OP-5): Defend DoD networks against cyber-attacks, proactively identify threats, and promote Zero Trust implementation throughout the Department. Ensures robust defense mechanisms are in place to protect the homeland from threats, both on the ground and in the air. The DISA continues to use the Cost Allocation Model (CAM) to assign shared services costs to products and services. The CAM identifies the total cost of a program and avoids unintended subsidies to the Defense Working Capital Fund (DWCF), provides visibility into the cost and consumption of shared services, and identifies efficiencies. Mission Area: Cyberspace Activities - (FY 2026: $559,426 thousand) 1. Information Systems Security Program (ISSP)/ Joint Information Environment (JIE) (FY 2026: $559,426 thousand): The ISSP, Public Key Infrastructure (PKI), and JIE mission provide enterprise-wide cybersecurity solutions for all DoD components, ensuring critical mission execution in contested cyber environments. The PKI modernization will enable post-quantum cryptography (PQC), increase automation, and implement emerging industry standards. The ISSP data security enhancements will improve the Department’s ability to detect and prevent malicious traffic and threats across the DoDIN by implementing or expanding break-and-inspect functionality and refining data discovery, tagging, labeling, classification, and protection measures. Other zero-trust enhancements include deterrence of zero-day attacks, phishing, and other cyber threats while streamlining cyber defense tools. These capabilities are critical to maintaining a secure and resilient cyber footprint for the DoD. The program provides solutions to harden the network by: •   Reducing the exposed attack surface and gaps that allow adversaries to exploit and disrupt communications. Critical efforts include deploying and operating defenses at the perimeter that sit at the border between the DoD and the internet. Perimeter Defenses protect over five million users with state-of-the-art measures by mitigating malicious activities such as viruses, exfiltration, and emergent cyber threats. •   Deploying a secure protocol, decryption, and re-encryption mechanism to protect communications through the Internet Access Points (IAPs). This is an advanced technological capability integrated network-wide. •   Providing vital situational awareness to senior decision-makers and network defenders that enables attack detection and diagnosis. Real- time situational awareness is crucial for deterring emerging threats. •   Supporting safe information sharing with allies and mission partners by expanding enterprise services that enable secure access and data transfer between networks of differing classification levels. By utilizing cyber identity credentials and expanding this capability on Secret Internet Protocol Router Network (SIPRNet), the DISA is driving anonymity out of the networks. DISA - Cyber 412 •   Enabling authentication of the user and device, end-to-end encryption, micro-segmentation of traffic, and dynamic networking, while providing enhanced cyber situational awareness solutions with end-to-end visibility, monitoring, and automation. •   Providing a joint DoD Routing-Only (RO solution) and Transport Infrastructure (TI) for the remaining Joint Regional Security Stacks (JRSS) Customers. •   Providing oversight of Information Assurance (IA) programs, projects, and initiatives from requirements management through implementation and sustainment. •   Providing advanced technological capabilities training to DoD civilians by continuing to generate information assurance and NetOps training used throughout the Department using web-enabled tools. •   Federating all ICAM solutions across the Department and sustaining federated capabilities. Application Program Interface (API) Gateways improve security and access control and support Zero Trust user and device pillars by enabling publishing, maintaining, monitoring, securing, and operating APIs, thus reducing vulnerabilities in one of the largest cybersecurity vectors. •   Ensuring only authorized users have access to authorized data sources, that those authorizations are automatically updated based on multiple user attributes, and that only authorized credentials are accepted to authenticate those authorized users. The ICAM solution leverages a Fed Hub, which bridges and enables the interoperability of the various DoD ICAMs. The use of the ICAM federation hub on the Non-classified Internet Protocol Router Network (NIPRNet) and SIPRNet, where all DoD can rely on a single ICAM capability, supports coordination of Joint Operations by enabling members of one Component to access applications in other Components with a single identity. •   Implementing requirements for Internal Controls over Financial Reporting (ICOFR) applications to leverage centralized ICAM solutions with automated account provisioning in support of “passing a financial audit”. ICAM supports the SECDEF’s priority to Rebuild the Military by enhancing the Department’s audit posture. •   Providing DISA’s initial implementation of a Zero Trust Architecture (ZTA) (under the concept of least privileged access) as part of the Thunderdome Capability. Zero Trust is a data-centric security model that eliminates the idea of trusted or untrusted networks, devices, personas, or processes and shifts to multi-attribute-based confidence levels that enable authentication and authorization policies under the concept of least privileged access. The Zero Trust approach to security helps the warfighter remain ahead of constantly evolving threats and adversaries. DISA - Cyber 413 •   Providing Continuous Compliance Monitoring (CCM) for all DoD mission partners’ containerized applications, which cover all the DevSecOps pillars via DevSecOps Operational Container Scanning (DOCS). The DOCS process provides CCM for all DoD mission partners’ containerized applications. DOCS provides Security Technical Implementation Guide (STIG) automation via Compliance as Code files. The STIG capabilities include automated STIG compliance monitoring for popular software technologies, a comprehensive user dashboard for continuous monitoring, and the ability for users to send data to Enterprise Mission Assurance Support Service (eMASS) for increased system status visibility. •   Publishing cybersecurity guidelines and assessing compliance. The DISA is changing the STIGs to enable better automation of the DoD’s configuration and supply chain risk management requirements and reporting processes. Maintaining a robust risk management strategy increases transparency and confidence in the warfighter support network. •   Supporting the Cleared Defense Contractor Gateway (CDCG) is critical to the cybersecurity architecture deployed to protect the SIPRNet. The CDCG is designed to secure communications between defense contractor facilities (i.e., Defense Industrial Base (DIB) mission partners) and the DoD SIPRNet. The focus is on cybersecurity enhancements and supporting operations and sustainment for a lab and two production sites. DISA - Cyber 414$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 5360000, "fy26": 0, "name": "Defense Industrial Base (DIB) - Cyberspace Operations", "fy25_current": 718000, "fy25_request": 5886000, "fy25_cong_amt": -5168000, "fy25_cong_pct": -87.8}$$::jsonb, $${"fy24": 509733000, "fy26": 559426000, "name": "Information Assurance (IA) - Cyberspace Operations", "fy25_current": 490630000, "fy25_request": 499010000, "fy25_cong_amt": -8380000, "fy25_cong_pct": -1.68}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 413, 436, FALSE, $${"json_key": "DISA__Cyber"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 602017000, to_jsonb(ARRAY[$${"fy25": 0.305, "fy27": 0.0, "name": "Defense Industrial Base (DIB) - Cyberspace Operations", "fy26_current": 0.0, "fy26_request": 0.0, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 486.409, "fy27": 602.017, "name": "Cyberspace Operations", "fy26_current": 539.413, "fy26_request": 559.426, "fy26_cong_amt": -20.013, "fy26_cong_pct": -3.58}$$::jsonb, $${"fy25": 3.2, "fy27": 0.0, "name": "JFHQ", "fy26_current": 0.0, "fy26_request": 0.0, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part1/DISA_Cyber_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dau_umbrella$$, $$DAU$$, $$Defense Acquisition University$$, $$DAU$$, $$om_dw_ba03$$, NULL, $$dw_dau$$, 2026, 182769000, 184963000, -2545000, -1.38, 182418000, 173265000, $$The Defense Acquisition University (DAU) (http://www.dau.edu) is the Congressionally mandated acquisition professional development, training, and policy research and analysis organization of the DoD, under the oversight of the Office of the Under Secretary of Defense for Acquisition and Sustainment (OUSD(A&S)). The DAU mission is to develop a high-performing Defense Acquisition Workforce (DAW) through talent management, acquisition training, online resources, and organization support to deliver effective, affordable warfighting capabilities. The DAU vision is to produce an accomplished and innovative DAW, empowered by DAU’s modern learning platform to provide the warfighter the decisive edge. The DAU provides talent development and continuous professional learning for approximately 166,000 DAW members, other DoD professionals, federal civilian agencies, and industry partners to develop, field, and sustain warfighting capability. The DAU products and services target workplace performance, leadership and professionalism, while promoting organizational mission effectiveness. Additionally, DAU performs research, develops professional publications, offers symposia and frequent topical webinars, and consults in subjects related to the acquisition functional areas. The FY 2026 request includes funding 535 civilian FTEs, and operational support to 43 military faculty assigned to DAU. The DAU main campus is located at Fort Belvoir, Virginia. The DAU structure supports innovative learning solution development and responsive delivery through regional campuses and specialized colleges with five regional campuses strategically located in areas with a high concentration of DoD acquisition workforce members. The five regional campuses are: •     Capital and Northeast – Fort Belvoir, Virginia (serves a workforce of 39,804) •     Mid-Atlantic – California, Maryland (serves a workforce of 28,221) •     Midwest – Kettering, Ohio (serves a workforce of 25,419) •     South – Huntsville, Alabama (serves a workforce of 41,195) •     West – San Diego, California (serves a workforce of 32,262) DAU 116 The DAU also has two colleges: •     Defense Systems Management College (DSMC) – Fort Belvoir, Virginia. The DSMC is tasked with offering the global DoD acquisition workforce a range of executive-level training and educational programs to include program management, international acquisition management, requirements determination, mission assistance, leadership, and research. •     College of Contract Management (CCM) – Fort Gregg-Adams, Virginia. Co-located with the Defense Contract Management Agency (DCMA) headquarters, the CCM is tasked to provide the professional, accredited courses necessary to enhance the DCMA’s workforce leadership skills, and competencies related to post-award contract management. DAU Core Functions The DAU provides high quality, low-cost training, online resources, and direct support at the point of need to enable the acquisition, requirements determination, and contingency missions of the DoD (and elements of the Federal Government). The DAU’s core functions are defined as: 1. Teaching: Meeting the challenges of the current and forecasted threat environment requires a workforce that is competent and confident enough to innovate quickly and at scale. The DAU instructor-led courses build upon certification training with continuous learning and job support resources on the DAU platform for developing critical job competencies, innovative thinking, and analytical skills across essential acquisition functional and leadership roles. 2. Learning Asset Development and Curation: The DAU designs, develops, and deploys an expansive portfolio of on-line and instructor-led courses designed to develop workforce knowledge base and skills to solve complex acquisition problems, manage portfolios, and lead cross- functional teams to deliver the warfighter a decisive edge. The DAU catalog of self-paced, online learning, including credentials and topical modules—helps the workforce meet DAWIA certification requirements and pursue opportunities for career growth. The DAU learning asset development capability ensures the workforce has the modern content needed to address foundational skills and emerging concepts with a process that incorporates real-world acquisition lessons learned and uses representative DoD scenarios to hone critical acquisition skills and confidence to decide and act. Asset development and maintenance are mission critical; moreover, learning content must be continuously refreshed to foster rapid technology adaptation, at the speed of relevance. In addition, DAU’s category management of licenses with vendors such as Coursera, Linked-in Learning, and Percipio, provide workforce members with economical access to commercial learning assets relevant to non-DoD specific aspects of acquisition, technology, logistics, and leadership. 3. On-Demand Learning: The DAU Platform hosts a wide-range of DAU-developed or curated learning assets such as eLearning, “how to” videos, performance support tools, and web events. The DAU platform offers convenient access for workforce members to maintain currency, excel at job-related activities and explore emerging concepts. Through webinars and more formal in-person events, such as TEDxDAU, DAU helps the workforce stay up to date on the latest concepts in DoD acquisition and leadership. DAU’s portfolio of online tools—including its online library, Ask A Professor, ACQuipedia, and job-support-resources—help the workforce complete critical tasks. The DAU media library also provides a compendium of on-demand assets. DAU 117 4. Field Training Teams and Mission Assistance: The DAU’s faculty members use their subject matter expertise to help acquisition program teams and other customers achieve specific outcomes and improve business results. Examples of these offerings include consulting on specific acquisition challenges, workshops tailored to program needs, functional simulations, and executive coaching. 5. Faculty Rotation Support/Research/Other Mandates: The DAU executes activities in support of acquisition innovation and continuous improvement. These include Acquisition Workforce Educational Partnerships (AWEP) Initiatives, such as the Faculty Rotation Program for enhancing faculty currency, Peer Mentoring and Advising, Training to Meet Operational Challenges, Flexible Acquisition Practices, and Expert Lecturers. The DAU is also required to conduct research and analysis of defense acquisition policy issues from an academic perspective. This includes support for DAW, Human Capital, and continually expanding the USD (A&S) body of knowledge through legislatively mandated research on issues and concerns identified by the workforce. DAU Major Programs/Efforts In support of the President’s priorities, the DoD is taking significant action to reform, right-size, and train the acquisition workforce. These efforts include DAU being tasked to implement Field Training Teams (FTT), restructuring performance evaluations metrics, analyzing the acquisition workforce staffing levels, and rapidly providing the workforce with the acquisition reform training and tools required to succeed. Section 832 of the National Defense Authorization Act (NDAA) for FY 2025 requires DAU to establish a training program to support cross- functional personnel and contractors of the DoD involved in any phase of the acquisition and sustainment lifecycle. These teams are directed to deliver on-site, mission-specific acquisition training, tailored to the needs of operational units across the DoD, to assist with making important decisions with respect to acquisition or sustainment, requirements validation, the development of an acquisition strategy, awarding contracts, and ongoing management of performance and governance. In addition, Executive Order 14265, titled “Modernizing Defense Acquisitions and Spurring Innovation in the Defense Industrial Base”, signed in April 2025, mandates the Under Secretary of Defense for Acquisition and Sustainment to establish FTTs led by senior acquisition executives or managers with expertise in innovative acquisition authorities and commercial solutions. To comply with the law, DAU must allocate 25 percent of its faculty capacity for a minimum of 50 percent of their time each year in support of the training program. This equates to an effect of 12.5 percent of available capacity. The Defense Acquisition Workforce Improvement Act (DAWIA) training and the Faculty Rotation Program consume an additional 10 percent of the faculty capacity each year. There is also a requirement for each FTT to include at least one individual from the private sector or academia with experience in commercial transitions. The inclusion, accomplished via contract each year, will foster a culture of innovation and continuous improvement in acquisition and sustainment processes The DAU also continues to provide the global learning environment required to empower the acquisition workforce to meet emerging threats and provide the warfighter a decisive edge. These acquisition experts are responsible for providing and maintaining efficient and cost-effective warfighting capabilities for the DoD. Through certification courses, job-specific training courses and credentials, and workshops, DAU provides the tools necessary for the acquisition workforce to meet their training needs and competently serve as stewards of taxpayer dollars. DAU 118 In addition to the courses and credentials, DAU also provides workshops, tailored training, and rapid deployment training events. These resources allow the acquisition workforce to quickly learn subject-specific information and produce actionable products tailored to their specific needs. The DAU continues to provide the best certification training content to workforce members by determining the information they need and harnessing innovative technologies to deliver it as efficiently as possible. The DAU continues its aggressive transformation of the DAWIA for the DAW and continues to modernize its learning assets, completing more maintenance and new development than it ever has, while also continuing to modernize and improve its learning platform to facilitate continuous, lifelong learning and delivery of knowledge and solutions at scale for the Department. DAU continues to collaborate with the Under Secretary of Defense for Acquisition and Sustainment, the Services, and Components to incorporate advanced technologies like the use of artificial intelligence to enhance the learning experiences and approaches to tailored training and professional development. The DAU continues to leverage its transformation from a schoolhouse into a modern learning platform of exponentially greater value to our customers by connecting all members of the DAW with the information and resources they need to adapt to the rapidly evolving acquisition environment and support our Warfighters. This transformation provides an environment that encourages continuous learning by focusing on three key areas: •    Frictionless Learning - Ensuring that learning opportunities are easily accessible and personalized to meet the immediate needs of the workforce. •    World-Class Content - Committing to high-quality, relevant, and timely learning content that builds critical thinking and decision- making skills. •    Dynamic Network - Leveraging DAU's extensive network to connect individuals with knowledge and expertise, facilitating collaboration and knowledge sharing at scale for the Department. Prominent features of our operating environment are change and ambiguity. To thrive in this environment, the DAW must be flexible and adaptable as well as knowledgeable and well-prepared. The new modernized training program will give the workforce the tools it needs to continue providing our warfighters with the capabilities they need to succeed. Strategic investments in DAU will continue to drive embedded field and traditional training toward tailorable engagements and courses, supplemented with informal online learning, and job/role-specific credentials. These changes will support acquisition reforms by quickly upskilling the workforce in new areas and supporting individual and organizational needs with hyper-relevant content and solutions. The DAU accomplished the following through May 28, 2025: •    Delivered 3.66 million hours of training •    Adaptive Acquisition Framework (AAF) had 459,880 page views •    Provided a total of 81 credentials, which attracted over 15,260 new enrollments •    Provided 2,681 course offerings with 356,822 completions •    Hosted 980 consulting engagements and 784 workshops DAU 119 •    Held 66 executive coaching events •    Registered 7,059 virtual and 430 in person attendees for TEDxDAU 2025 •    Streamed 311 webcasts to 101,086 attendees, many of which were recorded and placed on DAU media servers, further expanding the reach to more than 21,359 views •    Maintained 53 online Communities of Practice outlining acquisition best practices with a total of 523,000 views DAU Strategic Goals The Strategic Plan presents a high-level view of DAU's goals, laying out the organization's mission and vision for the future, along with codifying DAU's brand promise. The document includes an analysis of why DAU must become more customer focused and the path DAU will take to achieve its overall strategic goals and objectives. The strategic plan document outlines four primary goals: Goal 1 – Shape the future through continuous acquisition improvement. This goal aims to identify and suggest improvements for identified acquisition friction points into FY 2026. It involves scanning the acquisition environment and key stakeholders for opportunities, implementing processes for evaluating and acting on enterprise ideas, and pursuing strategic initiatives to enhance acquisition outcomes. Goal 2 – Empower the Acquisition Workforce to meet emerging needs; build and retain a workforce of varied acquisition experience. This goal focuses on achieving certification targets for the Defense Acquisition Workforce, satisfying teaching capacity requirements, and supporting professional development by encouraging diversification of different types of acquisition workforce experience. It also includes achieving AcqDemo permanence by December 2026 and developing policies for cross-functional Knowledge Areas. Goal 3 – Improve our learning assets and how we create them. This goal is centered on enhancing the quality and sourcing of learning assets to provide relevant and current experiences informed by experts. Goal 4 – Grow and support a world-class DAU. This goal aims to maximize faculty rotations, maintain cost-effective operations, ensure a high faculty direct to indirect ratio, and demonstrate the value of DAU training through external assessment. It also includes strategically communicating acquisition initiatives and building awareness of DAU products and services. These goals collectively guide DAU to improve acquisition processes, develop the workforce, enhance learning assets, and support the growth of DAU to maintain a decisive edge for the Warfighter. At DAU, our brand promise is to inspire understanding, solve problems, and foster connections. This commitment is reflected in our strategic initiatives, where we prioritize empowerment through innovation and the development of a high-performing DAW. Our focus on continuous acquisition improvement, workforce empowerment, and alignment with national defense priorities ensures that we provide the Warfighter with a decisive edge. By embracing technological integration and tailored learning, we adapt to changing workforce needs and maintain a customer- focused approach. The DAU brand promise is not just a statement; it reflects our values and our dedication to excellence in serving the Warfighter's evolving needs. DAU 120 Mission Success DAU continues to prove it’s not just a training institution; it is a force multiplier that delivers tangible mission outcomes. By embedding within programs, driving innovation, and aligning workforce practices with policy, DAU directly supports the Department's acquisition reform initiatives. Some examples are: 1. FTTs and Embedded Program Support • PMA-209 NGEN Radio: Assisted with acquisition strategy and document updates through bi-weekly engagements. • Sentinel Program Office: Supported re-baselining post-Nunn-McCurdy breach, guiding strategy and transition workshops. • NAVWAR Overmatch Portfolio: Planning to execute Base Camp FTT with Agile Center of Excellence and PEO C4I leadership. • F-35 & Defense POW/MIA Accounting Agency: Conducted Workshops to improve work statements for contracting effectiveness. • AFICC 764 ESS: Conducted multi-phase services acquisition workshop for a $974 million base ops support recompete. 2. Tailored Acquisition and Workforce Development Training • DLA PEO EA: Delivered Software Acquisition Pathway (SWP) training to 300+ personnel for business systems. • Army DEVCOM Aviation: Delivered AI training supporting wargame applications; demonstrated Army's CamoGPT. • Office of Principal Cyber Advisor: Provided SWP training aligned with SECDEF March 2025 memo on software modernization. • DAU/HCI Workforce Management Group: Facilitated cross-functional competency alignment discussions. 3. Cybersecurity, Software, and Agile Enablement • JLTV/ARV Programs: Conducted Cyber T&E workshops and cyber resilience engineering using the National Cyber Range. • Army Ground Vehicle Systems Center: Provided Agile software management workshop covering SCRUM and AAF integration. • SysML Workshop for PEO C3N: Delivered digital engineering training aligned with USD(R&E) workforce priorities. • Innovation Teaching Factory with NSWC: Developed innovation skills using real-world decoy scenario. • DAU-JLTV “Survivable Weapon Systems” Workshops: Enabled SCRE and mission-based cyber risk assessments. 4. Strategic Policy, Executive Support, and Acquisition Reform • EO on Modernizing Defense Acquisitions: DAU leads workforce reform section and supports SAEs and OUSD(A&S). • DHA Director and PEO OMS: Provided executive overview workshop focused on reacclimating to Middle-Tier Acquisition. • USD(A&S) ADA Violation Training: Provided enhanced compliance literacy through detailed, policy-aligned instruction. • DASA DEC (Army): Facilitated industrial base strategy discussions to support export and cooperation strategy. 5. Contracting, Cost Estimation, and Sustainment Optimization • Marine Corps Food Services SAW: Provided custom strategy workshop for $2.4 billion contract to improve operational sustainment. • USAF VC-25B IBR Training: Supported baseline and schedule evaluation with contractor; identified cost/schedule risks. • Earned Value Management Workshops: Delivered program-specific insights to strengthen PMO financial oversight. DAU 121$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 51008000, "fy26": 48356000, "name": "1. Teaching", "fy25_current": 50909000, "fy25_request": 66520000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 58242000, "fy26": 55213000, "name": "2. Learning Asset Development", "fy25_current": 58130000, "fy25_request": 54649000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 34053000, "fy26": 32283000, "name": "3 Field Training Teams/Mission Assistance", "fy25_current": 33988000, "fy25_request": 37237000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 20497000, "fy26": 19431000, "name": "4. On-Demand Learning", "fy25_current": 20458000, "fy25_request": 13847000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 18969000, "fy26": 17982000, "name": "5. Legislative Mandates/Research/Others", "fy25_current": 18933000, "fy25_request": 12710000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 0, "fy26": 0, "name": "contracts", "fy25_current": 0, "fy25_request": 0, "fy25_cong_amt": -48000, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 0, "fy26": 0, "name": "and assistance services", "fy25_current": 0, "fy25_request": 0, "fy25_cong_amt": -509000, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 0, "fy26": 0, "name": "8. OSD Requested Reduction", "fy25_current": 0, "fy25_request": 0, "fy25_cong_amt": -1988000, "fy25_cong_pct": 0.0}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 119, 137, FALSE, $${"json_key": "DAU__umbrella", "fy27_v192_bucket_a_dw": {"session": "2026-05-09_v41", "source_pdf": "O&M/FY27/DW/Vol1_Part1/DAU_OP-5.pdf", "content_hash": "95223ebfbc3fd8ef8922879dca68bdbae7f1d36698d71a81b041d71d55d1b04d", "source_page_amount": 8, "source_page_description": 2}}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 193017000, to_jsonb(ARRAY[$${"fy25": 38.316, "fy27": 37.451, "name": "1. Teaching", "fy26_current": 33.339, "fy26_request": 48.355, "fy26_cong_amt": -1.44, "fy26_cong_pct": -2.98}$$::jsonb, $${"fy25": 69.015, "fy27": 71.386, "name": "2. Learning Asset Development", "fy26_current": 63.549, "fy26_request": 55.212, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 46.398, "fy27": 45.531, "name": "3. Field Training Services", "fy26_current": 40.533, "fy26_request": 32.283, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 14.802, "fy27": 20.626, "name": "4. On-Demand Learning", "fy26_current": 18.362, "fy26_request": 19.432, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 15.58, "fy27": 18.023, "name": "5. Faculty Rotation Support/Research/Other Mandates", "fy26_current": 16.042, "fy26_request": 17.983, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/FY2027_o1.txt$$, 15084000) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dawdf_umbrella$$, $$DAWDF$$, $$Department of Defense Acquisition Workforce Development Fund$$, $$DAWDF$$, $$om_dawdf$$, NULL, $$dw$$, 2026, 0, 0, 0, NULL, 0, 0, NULL, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/FY2027_o1.txt$$, NULL, NULL, FALSE, $${"fy27_v192_bucket_a_dw": {"session": "2026-05-09_v41", "source_pdf": "O&M/FY27/DW/Vol1_Part2/DAWDA_OP-5.pdf", "content_hash": "7b5d4f66e444f42e589fcdcfeefa6bad78bf76761c225f2141d89572bd6f62df", "source_page_amount": 3, "source_page_description": 1}, "fy26_v192_special_fund_fy26_zero_synth": {"session": "2026-05-09_v41", "source_pdf": "O&M/FY27/FY2027_o1.pdf", "synth_type": "special_fund_fy26_zero_synth", "content_hash": "d6d633635442f4d9894f8e3f85133172e8cc82a0e4f0b83f698db228b46e9d6a"}}$$::jsonb, $$2026-05-08T03:39:53.660777+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 37478000, NULL, NULL, NULL, $$O&M/FY27/FY2027_o1.txt$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dcaa_cyber$$, $$DCAA - Cyber$$, $$Defense Contract Audit Agency Cyber$$, $$DCAA$$, $$om_dw_ba04$$, NULL, $$dw_dcaa$$, 2026, 4012000, 4961000, -57000, -1.15, 4904000, 3844000, $$The Defense Contract Audit Agency (DCAA) cybersecurity operations mission and major functions are to secure, configure, operate, maintain, and sustain DCAA cyberspace operations to preserve the confidentiality, availability, and integrity of DCAA's segment of the DoD Information Network (DoDIN). The DCAA's Cyberspace Activities budget protects, secures, and defends the information and information technology (IT) systems under its purview by ensuring functional owners and operators have confidence in the confidentiality, integrity, and availability of the DCAA information needed to make decisions. Some of the key security principles include providing isolation; containment; redundancy; layers of defense; least privilege; situational awareness; and physical or logical segmentation of networks, services, and applications. This budget request supports these endeavors by providing government and contract support to prevent unauthorized access into the network by protecting all information systems, enclaves, and computing environments from external and internal threats. DCAA - Cyber 157$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 4012000, "fy26": 3844000, "name": "Cyberspace Activities", "fy25_current": 4904000, "fy25_request": 4961000, "fy25_cong_amt": -57000, "fy25_cong_pct": -1.15}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 160, 171, FALSE, $${"json_key": "DCAA__Cyber"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 3825000, to_jsonb(ARRAY[$${"fy25": 4.858, "fy27": 3.825, "name": "Cyberspace Activities", "fy26_current": 3.844, "fy26_request": 3.844, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part1/DCAA_Cyber_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dcaa_umbrella$$, $$DCAA$$, $$Defense Contract Audit Agency$$, $$DCAA$$, $$om_dw_ba04$$, NULL, $$dw_dcaa$$, 2026, 654427000, 673621000, -15292000, -2.27, 658329000, 632959000, $$Defense Contract Audit Agency’s mission is to conduct contract audits and provide accounting and financial advisory services regarding contracts and subcontracts to all DoD Components responsible for procurement and contract administration. DCAA may also provide contract audit services to other federal agencies, as appropriate. DCAA only audits and provides financial information and advice on proposed or existing contracts and contractors. DCAA’s role in the financial oversight of government contracts is critical to ensure DoD gets the best value for every dollar spent on defense contracting. DCAA operates under the authority, direction, and control of the Under Secretary of Defense (Comptroller)/Chief Financial Officer. DCAA’s work supports the President’s clear mission to achieve Peace through Strength and the Secretary of Defense’s priorities to revive the warrior ethos, rebuild the military, and reestablish deterrence. DCAA’s audits and financial advisory services enable contracting officials to make necessary investments to ensure the US military remains the strongest and most lethal force in the world. DCAA’s outreach to defense contractors of all sizes helps to revive the industrial base and field emerging technology by enhancing contractors’ understanding of contract requirements. Through industry outreach, we strive to learn contractor’s challenges and, when possible, ease the burden of defense contracting. The Agency's primary function is to conduct contract audits and related financial advisory services. Contract audits are independent, professional examinations of financial representations made by defense contractors. Specifically, DCAA helps determine whether contract costs are allowable, allocable, and reasonable. The DCAA conducts audits in accordance with Generally Accepted Government Auditing Standards (GAGAS), a set of standards that ensures audit conclusions are well supported by evidence. The type and extent of the DCAA's audit work varies based on the type of contract awarded, but its audit services are generally limited to acquisitions under Federal Acquisition Regulation (FAR), Part 15 (Contracting by Negotiation). The DCAA audits only contractors and it has no internal audit responsibilities within DoD. DCAA auditors examine contractor accounts, records, and business systems to evaluate whether contractor business practices and procedures are in compliance with the FAR, the Defense Federal Acquisition Regulation Supplement (DFARS), Cost Accounting Standards (CAS), and other applicable government laws and regulations. DCAA has no direct role in determining which companies are awarded defense contracts; rather, it provides recommendations to government officials on contractor cost assertions regarding specific products and services. With these recommendations, contracting officers are better able to negotiate prices and settle contracts for major weapons systems, services, and supplies. Out of a population of approximately 7,000 active contractors, the DCAA engages with over 4,400 contractors in a typical year, examining more than $599 billion in contract costs, and issuing 2,465 audit reports and 7,629 memos. DCAA 135 In FY2026, the DCAA will be executing its entire portfolio of audit work including Incurred Cost, Forward Pricing, Terminations and Claims, Business Systems, Cost Accounting Standards (CAS), and Truth in Negotiation (TiN) compliance audits. In addition, the DCAA will use Contractor Information Surveys to collect information, primarily from select smaller contractors, to inform the audit effort. Focusing on the entire portfolio of audit work enables DCAA to fulfill its role in the financial oversight of government contracts and is critical to ensuring the DoD gets the best value for every dollar spent on defense contracting. DCAA will continue efforts to review incurred cost proposals within 12 months of the receipt of an adequate submission in order to: (1) assist in achieving auditable financial statements, a Secretary of Defense priority; (2) assist the Department in closing completed contracts; and (3) prevent undue delays in payments of fees to contractors (a portion of fees to contractors is delayed until the contract is closed). The DCAA’s FY 2024 Financial Statements received an unmodified opinion from independent public auditors. DCAA has continuously maintained an unmodified audit opinion since FY 2000. DCAA is required to pass an external peer review every three years. In FY 2022, DCAA received a rating of pass on its external peer review, which determines whether DCAA’s internal quality control review system is in place and operating effectively. The external peer review team is currently active reviewing DCAA’s audits for the FY2025 peer review. The DCAA continues to return savings to the Government that far exceed the cost of its operations. In FY2024, the Agency audited approximately $599 billion in contract costs, issuing 530 incurred costs audit reports and 3,058 memos examining $256 billion, and issuing 649 forward pricing proposal audit reports and 94 memos examining $125 billion in proposed contract costs. As a result of reported audit findings, the DCAA recognized $5.1 billion in net savings. The return on taxpayers’ investment is approximately $7.2 for every dollar invested in the Agency ($709.3 million in FY 2024, including reimbursable funding). The DCAA’s workload and associated staffing levels follow the DoD procurement funding levels; however, there is a time lag for the DoD audit workload to decrease because of contract execution and closeout. DCAA contract audit workload is divided into the major functional categories described below: 1. Forward Pricing Effort. Per the FAR and Public Law 100-679, the Cost Accounting Standards (CAS) require the DoD procurement officials to comply with various administrative procedures before entering into contracts. These procedures include obtaining pertinent accounting and financial advice before making decisions related to prospective contract prices. The ultimate goal of the forward pricing audit effort is to assist contracting officers in determining and negotiating fair and reasonable prices for goods and services. DCAA furnishes pre-award services to contracting officers including: a. Price Proposal Audits. These examinations determine the reasonableness of contractors’ price proposals submitted in anticipation of negotiating Government contracts. Contracting officers request these audits, which must be accomplished within a short period of time to avoid delaying the procurement process. DCAA has no control over the number or timing of price proposal audits and must respond to each audit request as a top priority. DCAA 136 b. Forward Pricing Rate Proposal Audits. These examinations determine the reasonableness of projected labor, overhead, and other indirect expense rates submitted by a contractor prior to submission of price proposals. Normally, a contracting officer negotiates these rates separately - the contractor then uses the rates in subsequent price proposals. c. Responses to Requests for Specific Cost Information. This effort includes providing specific cost information to procurement officials on labor rates, overhead rates, and similar factors when information is readily available within the DCAA’s files. 2. Incurred Cost Effort. The FAR requires DCAA to perform audits of claimed costs incurred and submitted by contractors for reimbursement under cost reimbursable, fixed price incentive, and other types of flexibly priced contracts to determine if the costs are acceptable in accordance with contract terms, FAR, and CAS rules and regulations, if applicable. These audits must be accomplished for the government to close contracts and make final payment to the contractor. This effort includes examinations of direct labor and material costs and indirect expenses and provides insight on the function of contractor business systems and related internal controls. Although the primary purpose of incurred cost audits is to express an opinion on the acceptability of costs claimed under Government contracts, the knowledge of contractors’ accounting and other business systems gained during these audits is helpful in evaluating contractors’ price proposals. In FY2025, DCAA will complete incurred costs audits within 12 months of receiving an adequate submission in order to (1) assist in achieving auditable financial statements, a Secretary of Defense priority; (2) assist the Department in closing completed contracts; and (3) prevent undue delays in payments of fees to contractors (a portion of fees to contractors is delayed until the contract is closed),pursuant to 10 U.S.C. §3842. 3. Claims and Terminations. The contracting officer normally requests audits that include examinations of termination claims, progress payment requests, and equitable adjustment claims that must be accomplished within a short period to avoid adverse effects such as additional claims for interest on amounts due. Claims and Terminations also include accounting system audits the DCAA performs for procurement contracting offices prior to contract award or during contract performance, and other efforts requested by the contracting officers. DCAA has little control over the number or timing of these audits and must respond to all such requests as a priority. 4. Business Systems, Cost Accounting Standards, & Truth in Negotiations. These audits are primarily performed after contract award and can be requested by a contracting officer or initiated by DCAA. The Agency typically initiates these types of audits when there is potential for a high risk of misallocation or mischarging costs: a. Truth in Negotiations Audits (TiN). These audits require contracting officers to obtain certified cost or pricing data from contractors before awarding a contract unless an exception applies (10 USC §2306a). Under TiN, the Government has the right to examine records to ensure that certified cost or pricing data is accurate, current, and complete. DCAA is responsible for performing these audits, which assist in determining whether a contract or subcontract price was unduly increased because the contractor failed to furnish accurate, complete, or current certified cost or pricing information when negotiating a contract. DCAA 137 b. Business System Audits. These audits evaluate contractor systems to assess whether the systems comply with DFARS business systems requirements and generate accurate and reliable data for contracting officers to use in determining fair and reasonable prices. DCAA performs audits of the contactors’ accounting system, material management and accounting system (MMAS), and estimating system. c. Cost Accounting Standards (CAS). Contracts and subcontracts that do not qualify for an exemption are subject to CAS coverage as a condition of Government contracting. The FAR assigns DCAA responsibility for examining contractors’ implementation and compliance with CAS rules and regulations. CAS related audit effort includes assessing adequacy and compliance of the CAS Disclosure Statement, compliance with CAS, and assessment of contractor Cost Impact Statements for noncompliance. 5. Other Direct Audit Efforts. Other audit-related activities include providing on-site assistance to procurement and contract administration offices, corporate audit directorate programs, and negotiation support. This activity includes efforts related to Congressional, Government Accountability Office (GAO), DoD Inspector General (DoDIG), and other external requests, surveys, and reports. The major functions are: a. Financial Liaison. DCAA maintains financial liaison advisors, as appropriate, at major procurement and contract administration offices. Their primary functions are to: facilitate effective communication and coordination between procurement officers and auditors; provide DCAA management with information regarding specific awards, trends in type and volume of awards, and other data impacting immediate or long range DCAA responsibilities; and provide DCAA management with information on the adequacy, responsiveness and timeliness of audit services rendered to procurement and contract administration offices. b. Corporate Audit Directorate. DCAA extended the success of its Contract Audit Coordinator (CAC) program into a Corporate Audit Directorate (CAD) structure and now has six of the largest contractors organized into four CADs. The contractors’ accounting functions, operations, and contract performance may occur at multiple locations under the audit cognizance of multiple DCAA field offices, but the contract audit activities and reporting associated with each contractor are under the direction of one DCAA management hierarchy. c. Negotiation Conferences. A fundamental requirement of DCAA’s mission is to provide high quality contract audit services to ensure the Government is paying fair prices. Audit results often involve complex accounting issues and quantitative analyses that dispute contractors’ cost estimates or representations. On these occasions, the best interests of the Government are served by having auditors present at negotiations to further explain the audit position, perform analyses of additional contractor data presented at the negotiation table, and provide any other accounting and financial assistance the contracting officer may require during the negotiation process. d. External Audit Interface. DCAA develops information and comments on reports from the GAO, DoD IG, and other government Inspector General offices. This activity also includes efforts related to discussions and conferences, and any interface involving other government audit organizations. DCAA 138 e. Suspected Irregular Conduct (SIC). This activity represents effort expended related to SIC referrals and responses to requests from investigative agencies or the Department of Justice regarding fraud or other irregular practices. The DCAA also develops evidence for the U.S. attorney, grand jury, and for use at trial. f. Audit Support and Planning. DCAA field offices prepare annual audit program plans for the upcoming year and work on projects and studies requested by the Regions, CADs or Headquarters. Projects normally relate to new and innovative ways of performing DCAA’s audit mission and add to the body of knowledge needed to enhance Agency mission accomplishment through the development and application of improved audit management technology and audit techniques. 6. Field Support. This includes support personnel assigned to four regional offices, four CADs, the Defense Contract Audit Institute, the Office of Information Technology, and Technical Audit Services Division. a. Regional Offices and CADs. These offices provide technical audit management and supervision to field office personnel. b. Defense Contract Audit Institute (DCAI). The DCAI develops and delivers training for over 4,000 contract auditors and is an affiliated member of the Defense Acquisition University; directs and controls the development and delivery of classroom courses, seminars, computer- based self-study courses, and internet-based, instructor-led courses; has program management responsibility for the DCAA training and career development including ensuring the workforce obtains DoD Acquisition and Financial Management certification requirements; assures that programs of instruction, courses, and training materials meet DoD, GAGAS, and National Association of State Boards of Accountancy (NASBA) standards; provides training and education policy guidance, monitoring and evaluation of Agency training not conducted by the Institute; ensures training materials are up-to-date; and develops new courses when required by the changing audit environment. Programs provided by DCAI include audit, leadership, and supervisory training. c. Office of Information Technology (OIT). The OIT is responsible for the design, development, and maintenance of Agency-specific automated information systems (AIS), web applications, and audit software; it is also responsible for operating the Agency-wide communications infrastructure, monitoring network performance, managing the DCAA’s information assurance program, and establishing and implementing policy and standards for information technology (IT) systems and services. The OIT employs a computer hardware acquisition strategy/plan to satisfy AIS and personal computing requirements. d. Technical Audit Services Division (OTS). The OTS conducts research and distributes information to the field on quantitative audit techniques, computer-assisted audit techniques, and other auditing topics that have Agency-wide application. The OTS also provides technical assistance to auditors in planning reviews of contractor’s electronic data processing systems and supports field offices in the implementation of DoD electronic commerce initiatives. DCAA 139 e. Chief Digital and Artificial Intelligence Office (CDAO). The CDAO prioritizes DCAA's ability to leverage automation and deliver data analytics/AI applications. The CDAO is also responsible for capability exploration, digital optimization, governance, and enterprise platforms to include CaseWare and ServiceNow. f. Field Professional Support Staff. These personnel provide clerical, administrative, and resource management services. 7. Headquarters. DCAA Headquarters performs the work associated with the central office of a professional public organization. Headquarters develops policy and promulgates instructions and operating directives needed to perform the Agency’s mission; performs oversight reviews of regional and field office operations and audit quality; provides Regions and CADs with resource management services including human capital, administration, and financial management; and includes the General Counsel which provides legal advice regarding contracts, ethics, and personnel issues. Headquarters personnel interface with other DoD components, other Government agencies, and Congressional committees. DCAA 140$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 654427000, "fy26": 632959000, "name": "1. Audit Operations", "fy25_current": 658329000, "fy25_request": 673621000, "fy25_cong_amt": -15292000, "fy25_cong_pct": -2.27}$$::jsonb, $${"fy24": 8185000, "fy26": 1410000, "name": "DCAA Communications", "fy25_current": 9694000, "fy25_request": 9694000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 45547000, "fy26": 46730000, "name": "DCAA Major Headquarters", "fy25_current": 50436000, "fy25_request": 50436000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 600695000, "fy26": 584819000, "name": "DCAA Operations", "fy25_current": 598199000, "fy25_request": 613491000, "fy25_cong_amt": -15292000, "fy25_cong_pct": -2.49}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 138, 159, FALSE, $${"json_key": "DCAA__umbrella"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 611600000, to_jsonb(ARRAY[$${"fy25": 654.554, "fy27": 611.6, "name": "1. Audit Operations", "fy26_current": 630.538, "fy26_request": 632.959, "fy26_cong_amt": -2.421, "fy26_cong_pct": -0.38}$$::jsonb, $${"fy25": 8.944, "fy27": 0.581, "name": "DCAA Communications", "fy26_current": 1.41, "fy26_request": 1.41, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 43.141, "fy27": 51.898, "name": "DCAA Major Headquarters", "fy26_current": 46.73, "fy26_request": 46.73, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 602.469, "fy27": 559.121, "name": "DCAA Operations", "fy26_current": 582.398, "fy26_request": 584.819, "fy26_cong_amt": -2.421, "fy26_cong_pct": -0.41}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part1/DCAA_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dcma_cyber$$, $$DCMA - Cyber$$, $$Defense Contract Management Agency Cyber$$, $$DCMA$$, $$om_dw_ba04$$, NULL, $$dw_dcma$$, 2026, 29203000, 42541000, -472000, -1.11, 42069000, 43434000, $$The Defense Contract Management Agency (DCMA) Cybersecurity Program mission is to execute the Department of Defense (DoD) Cyber Strategy while achieving the cyberspace objectives to protect the warfighter. To protect, secure, and defend the DCMA information and Information Technology (IT) systems, the DCMA IT must maintain a vigilant presence to detect and deter threats and vulnerabilities in cyberspace, expand alliances and partnerships, improve infrastructures and firewalls, and cultivate and sustain a cyber-readiness environment and workforce. The DCMA DIB Cyber Assessment Center, is DoD's sole entity for DIB-wide cyber assessments, conducting over 700 assessments on $2.8 trillion in contracts, proactively identifying and mitigating vulnerabilities within the defense industrial base. The DCMA Cyber budget protects, secures, and defends information and IT systems under its purview to ensure functional owners and operators have confidence in the confidentiality, integrity, availability, and non-repudiation of the DCMA information needed to make informed decisions. Some key security principles include isolation; containment; redundancy; layers of defense; least privilege; situational awareness; and physical or logical segmentation of networks, services, and applications. This budget supports these activities by providing government and contractor support to prevent unauthorized network access by protecting all information systems, enclaves, and computing environments from external and internal threats of interception, modification, fabrication, and interruption. In FY 2026, the DCMA plans to continue to make incremental improvements to the cybersecurity operational environment by enhancing core processes and investments towards the defense of the DCMA and DoD enterprise. In addition to reaffirming the Agency's current security posture through validation and verification of security controls, DCMA will continue to work towards implementing of the Zero Trust Reference Architecture (ZTRA), supporting the strategic outcomes of ZTRA outlined in the current DoD ZT Strategy. The DCMA will continue to leverage DISA Cybersecurity Service Provider (Tier II/III) services to increase visibility and Area of Operations (AO), streamlining the Cybersecurity Service Provider (CSSP) efforts within the DCMA, while simultaneously strengthening the capability to perform and execute required mission partner CSSP capabilities at the Tier III level. The DCMA anticipates these efforts will support the protection and defense of information and information systems facilitating a transformative evolution into a more agile, mobile, and cloud-supported workforce. The DCMA Cybersecurity Center requires a specialized highly skilled, qualified cybersecurity workforce, including civilians and contractors, to perform defensive cyberspace operations (DCO). This function directly supports improving of cybersecurity operations, supporting effective damage containment, mitigation, and remediation activities when a device, network, user, or credential becomes compromised. DCMA - Cyber 224 The DCMA Cybersecurity Center plans to recruit, train, and retain a skilled and lethal workforce qualified under the new DoD 8140.01 Cyber Workforce Management program to meet requirements associated with the DoD ZT Strategy. Additionally, DCMA will obtain skilled labor support through service contract vehicles to provide for critical capabilities required to meet and sustain the intent of the ZT strategy. The DCMA continues to support 4th Estate Consolidation efforts by reviewing network designs, decommission efforts, and secure policy deployments during the transition to DoDNet. This DoD modernized network infrastructure will improve the DoD IT systems' efficiency, security, and overall user experience. The Defense Industrial Base Cybersecurity Assessment Center (DIBCAC) is the sole entity entrusted with the Department’s mission of conducting cybersecurity assessments of defense contractor information systems that process, transmit, or store Controlled Unclassified Information (CUI) in accordance with DFARS 252.204-7012 and DFARS 252.204-7020. The Defense Industrial Base (DIB) supply chain includes over 220,000 defense contractors and suppliers and is increasingly targeted by capable adversaries to undermine U.S. national interests. The DIBCAC directly supports the DoD DIB Cybersecurity Strategy mission and vision to “ensure the generation, reliability, and preservation of U.S. warfighting capabilities by protecting sensitive information, operational capabilities, and product integrity...[through] a secure, resilient, and technologically superior Defense Industrial Base.” Furthermore, the DIBCAC assists in Goal 2 of the strategy to “enhance the cybersecurity posture of the DIB” by achieving Objective 2.1, “evaluate DIB compliance with DoD’s cybersecurity requirements” as the office of primary responsibility (OPR) for current DoD cybersecurity assessments and as the office of coordinating responsibility (OCR) for DoD’s Cybersecurity Maturity Model Certification (CMMC) program. The DIBCAC prioritizes assessments based upon the DoD Sector Risk Management Agency’s (SRMA) list of systemically important entities as required by the National Security Memorandum (NSM) 22 and other critical priorities. The DIBCAC is committed to collaborating with foreign partners to protect CUI worldwide. The complex multinational supply chain and rapidly evolving technology landscape transcends national borders and territories, making ongoing international cooperation essential. In support of DoD Chief Information Officer (CIO) and OUSD Acquisition & Sustainment (A&S) initiatives, the DIBCAC and foreign partners work closely to establish a mutually accepted reciprocal cybersecurity assessment framework to be included in the existing Defense Procurement Agreement (DPA) Government Quality Assurance (GQA) annexes. DIBCAC engagements with foreign partners include assessor training of the partner’s personnel and joint cybersecurity assessments performed in the U.S. and the partner nation. The DIBCAC spearheads a multilateral international initiative to develop future assessment standards and training material, including implementation of National Institute of Standards and Technology Special Publication (NIST SP) 800-171r3, NIST SP 800-172, and CMMC Level 3. A crucial player in the Department of Justice Civil Cyber Fraud Initiative, DIBCAC works closely with investigative entities within DoD, such as the Naval Criminal Investigative Service (NCIS). As the only organic DoD entity focused on unclassified cybersecurity assessments throughout the global DIB supply chain, DIBCAC's expertise and insights remain invaluable in supporting potential DIB cybersecurity fraud investigations. DCMA - Cyber 225$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 29203000, "fy26": 43434000, "name": "Cyberspace Activities", "fy25_current": 42069000, "fy25_request": 42541000, "fy25_cong_amt": -472000, "fy25_cong_pct": -1.11}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 227, 239, FALSE, $${"json_key": "DCMA__Cyber"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 42367000, to_jsonb(ARRAY[$${"fy25": 41.411, "fy27": 42.367, "name": "Cyberspace Activities", "fy26_current": 42.858, "fy26_request": 43.434, "fy26_cong_amt": -0.576, "fy26_cong_pct": -1.33}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part1/DCMA_Cyber_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dpaa_umbrella$$, $$DPAA$$, $$Defense POW/MIA Accounting Agency$$, $$DPAA$$, $$om_dw_ba04$$, NULL, $$dw_dpaa$$, 2026, 185159000, 188022000, -2165000, -1.15, 185857000, 171339000, $$The Defense Prisoners of War/Missing in Action (POW/MIA) Accounting Agency (DPAA) is a Defense Agency that provides families and the Nation with the fullest possible accounting for missing personnel from past conflicts. The DPAA leads the national effort to develop and implement the Department of Defense (DoD) policy on all matters relating to personnel accounting from past conflicts, conduct global search, recovery, and laboratory operations to identify personnel from past conflicts, ensure timely and accurate information is provided to the families of missing personnel, share their stories, and when possible, bring home their remains. This includes those who are unaccounted for from World War II, the Korean War, Cold War, Indochina (Vietnam) War, Persian Gulf War, the Iraq Theater of Operations, and other conflicts or incidents as the Secretary of Defense directs. The DPAA provides analytical support to official U.S. delegations and engages in technical discussions with host nation officials. Additionally, the DPAA is continuing to implement the transformation of the DoD’s personnel accounting for past conflicts that involve enhanced strategic partnerships to account for missing personnel more effectively and to ensure their families receive accurate information. Research and Analysis Line of Effort (LOE): This is the foundation to all activities and tasks in DPAA. This includes developing background for an individual case file, preparing to communicate with a family at a Family Member Update, identifying locations for an onsite investigation or recovery effort, identifying remains in the lab or at the Armed Forces Medical Examiner System, or preparing the products that will go to a family in the form of an accounting packet. By harnessing the capabilities inherent in our Case Management System (CMS), sharing the most effective practices across our research staff, and leveraging the capabilities of partners, DPAA will set the conditions necessary to increase the effectiveness of the Research and Analysis activities so that the DPAA can increase the efficiency of all other accounting and communicating activities. The goal associated with the Research and Analysis LOE is for DPAA to increase the pace and scope of accurate research, investigations, and analysis to enhance the accounting and communications processes and sustain the capability and capacity to account for 200+ personnel on an annual basis. DPAA 528 Accounting LOE: A key aspect of DPAA’s mission is to “lead the national effort to account for unaccounted-for DoD personnel and designated civilians from designated past conflicts.” The DPAA has set ambitious objectives to progressively increase the number of individuals accounted for each year and the conditions required to achieve Fullest Possible Accounting for Vietnam War losses, our current main effort. Along with these objectives, DPAA will focus on harnessing the capabilities of the CMS to synchronize our accounting efforts and the capabilities of our partners to both augment our field and laboratory activities, to increase our personnel resources, and to increase our efficiency. This LOE is critical to the DPAA’s efforts to, investigate, disinter, recover, and identify those that served the nation. The culmination of this effort is to increase the number of personnel accounted for annually while providing the results of all our accounting efforts to the families of the missing, even when it does not result in an individual identification. The DPAA conducts investigation, excavation, and recovery operations to recover the remains of missing personnel. The DPAA personnel manage the command and control, logistics, and in-country support during supported missions. The DPAA is the lead DoD agency for coordinating with other U.S. Government (USG) agencies, foreign governments through the Department of State, and non-governmental organizations on all matters related to the personnel accounting mission, including conducting international negotiations to achieve access to loss sites and/or information that leads to the recovery of artifacts or the remains of personnel missing from past conflicts. In addition, the DPAA supports the USG side of the U.S.-Russia Joint Commission on POW/MIAs. The DPAA operates two laboratories that perform forensic and anthropological analysis of remains, as well as material analysis of artifacts and other items related to crash sites and personnel losses. The analysis performed at the laboratories is critical for accurate and scientific identification of remains. The identification laboratories coordinate with the Armed Forces Deoxyribonucleic Acid (DNA) Identification Laboratory (AFDIL) and Service Casualty Offices to collect and identify DNA samples. Additionally, the DPAA also supports operations by conducting research in U.S. and international archives, analyzing data, creating, and maintaining comprehensive records (including the official list of unaccounted-for by conflict), interviewing witnesses, and investigating losses. Key projects in this area include: 1. Developing an information technology solution to establish accounting community-accessible personnel files for each missing person that contain all available information regarding the disappearance, whereabouts, and status of missing persons, and are available to families upon request (to comply with 10 U.S.C. § 1509). 2. Completing the digitization of the Individual Deceased Personnel Files of U.S. Service members missing since World War II. DPAA 529 Communications and Engagement LOE: The second key aspect of DPAA’s mission is to communicate all available information concerning unaccounted-for DoD personnel and designated civilians to family members. To provide this information to families we must not only keep open channels of communication with our families we must also use engagements to set the conditions for our accounting efforts. Whether it is communicating with families and veteran service organizations, engaging with foreign governments to gain and maintain access to loss sites, or engaging with Congress and our partner agencies within the US government to enable resourcing of our accounting mission, DPAA continues to leverage our ability to communicate effectively to set the conditions for accomplishing our mission. The DPAA’s ability to effectively communicate to families and external stakeholders is vital to providing the fullest possible accounting for missing personnel. While the Outreach and Communications Directorate is primarily responsible for many of the tasks within this LOE, the entire agency has important supporting and supported responsibilities as well. Pursuant to 10 U.S.C. § 1501, the Department is responsible for informing the families, Congress, veteran’s service organizations, military service organizations, family support groups, and the general public about missing personnel and ongoing efforts to recover and identify missing personnel. The DPAA conducts communications and outreach programs, including four family member update meetings and two annual government briefings each year to provide case updates, collect DNA family reference samples, and share information on DoD personnel accounting and recovery activities with families of missing persons. The four family member updates are held in-person in major cities across the U.S. to inform and build trust with approximately 1,800 family members per year. Two annual government briefings in Washington, D.C. update family members of the missing from the Vietnam War and Korean/Cold War. During these briefings, USG-officials brief on government procedures, processes, and efforts to account for missing personnel. The DPAA is very actively engaged in responding to requests for information from families of the missing, veterans, the public, and members of Congress, the declassification of DPAA and legacy agency documents, and the transfer of information to the Library of Congress and the National Archives for public access and maintaining a website detailing POW/MIA information and accounting efforts. Business Enterprise LOE: The goal is to shape the resources, processes, capabilities, and culture to enable efficient, effective, informed, and collaborative outcomes. To operate at a high level of efficiency and effectiveness, the DPAA must continue to invest in the workforce, refine processes and procedures, and geographically distribute the right workforce to enable our mission. To this end, the DPAA will continuously refine decision-making processes, including establishing or dissolving working groups, boards, and councils where needed, explore options for adjusting facilities footprints to support operational requirements, implement training programs to enhance the workforce’s skills, harness innovation, and enhance all capabilities by fully leveraging the CMS and our partners. DPAA 530$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 185159000, "fy26": 171339000, "name": "4. Administration and Servicewide Activities", "fy25_current": 185857000, "fy25_request": 188022000, "fy25_cong_amt": -2165000, "fy25_cong_pct": -1.15}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 531, 545, FALSE, $${"json_key": "DPAA__umbrella"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 160358000, to_jsonb(ARRAY[$${"fy25": 184.278, "fy27": 160.358, "name": "4. Administration and Servicewide Activities", "fy26_current": 167.068, "fy26_request": 171.339, "fy26_cong_amt": -4.271, "fy26_cong_pct": -2.49}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part1/DPAA_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_mc_active_3c3f$$, $$3C3F$$, $$Junior ROTC$$, $$Marine Corps$$, $$om_mc_active_ba03$$, $$BA-03: Training and Recruiting$$, $$mc$$, 2026, 29381000, 29631000, 0, NULL, 29631000, 30808000, NULL, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY26/Navy/OMMC_Book.pdf$$, NULL, NULL, FALSE, $${"k": "mc_active__3C3F", "_v191_note": "FY26 backfill via v189-style footer-anchored extractor (F-NEW-V39-2).", "_v191_session": "2026-05-09", "fy26_v191_kind": "extracted_op5", "fy26_v191_source_file": "O&M/FY26/Navy/OMMC_Book.pdf", "fy26_v191_source_page_amt": null, "fy26_v191_source_page_desc": 154}$$::jsonb, $$2026-04-29T00:56:40.835426+00:00$$, FALSE, 29579000, NULL, NULL, NULL, 30808000, 33292000, NULL, NULL, NULL, $$O&M/FY27/Navy/OMMC_Book.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dcma_umbrella$$, $$DCMA$$, $$Defense Contract Management Agency$$, $$DCMA$$, $$om_dw_ba04$$, NULL, $$dw_dcma$$, 2026, 1556832000, 1543134000, -22473000, -1.46, 1520661000, 1441456000, $$The Defense Contract Management Agency (DCMA) ensures entrusted taxpayer resources are used to rebuild our military and supports the pre- contract award for delivering weapons systems to the Warfighters. The DCMA operates under the authority of the Under Secretary of Defense for Acquisition and Sustainment (USD(A&S)) as the Principal Staff Assistant. Per DoD 5105.64 and FAR Part 42.302, the DCMA mission is to perform Contract Administration Services (CAS) and Contingency Contract Administration Services (CCAS) for Department of Defense (DoD), other Federal Agencies, foreign governments, international organizations, and others as authorized, to ensure the taxpayer gets what they pay for, and enable DoD to meet the National Defense Authorization Act (NDAA) for FY 2024 requirement to achieve an unqualified opinion on the financial statements of the Department by not later than December 31, 2028. The DCMA is the centralized force multiplier for standardized inspection and acceptance of combat weapon systems and payments to the Defense Industrial Base (DIB). The Department’s uniquely situated DIB sensor network, acquisition and support professionals are the critical link between the Department and the DIB at 880 DCMA sites in 14 countries; surveilling 17,414 global contractor facilities in 42 countries; administering approximately 303,000 active contracts totaling $7.81 trillion; delivering unparalleled insight to ensure timely delivery of warfighting equipment, safeguarding taxpayer dollars, supporting a healthy industrial base; and ultimately contribute to the strength and readiness of our armed forces. The CAS and CCAS workload performed by the workforce enables services to increase the on-time delivery and procurement of critical warfighting equipment at a fair and equitable cost. The DoD weapon system and materiel investments are key factors that drive DCMA workload during the procurement, operations, and sustainment phases of CAS and CCAS. The DCMA consistently generates a positive annual return on investment (ROI) for the DoD and taxpayer significantly, greater than the DCMA’s annual budget. For every dollar invested in DCMA for FY 2024, DCMA efforts resulted in a ratio of approximately 5.83:1. The DCMA activities such as litigation, cost and pricing actions, cost rate settlements, workers’ compensation claims, and Equal Employment Opportunity (EEO) settlements returned $9.24 billion to the Department in refunds, recovered costs, forward (future) pricing rates, and negotiated price reductions. The DCMA has consistently produced a positive ROI for the past nine years, averaging a return of $3.20 for every $1 invested. DCMA 206 Alignment with the Department of Defense priorities The DCMA directly supports the DoD priorities to enable DoD to remain the world’s preeminent fighting force. The DCMA mission and responsibilities align with Defense priorities to revive the warrior ethos; rebuild our military; reestablish deterrence; and improve efficiency and reform. The DCMA workforce performs acquisition life-cycle management activities from pre-award through contract closeout, which include: • Controlling contractor indirect costs by establishing forward and final rates, resolving claims and disputes, and making final determinations on cost accounting standard audits • Providing negotiation intelligence by ensuring business system compliance for contract accounting, property management, material management, earned value and purchasing systems • Influencing contract negotiations by making commercial item determinations and providing insight into contract cost and pricing, approximately 85% of the DCMA workforce are acquisition professionals including production, quality assurance, manufacturing, contracting, and engineering personnel performing the mission globally. • Administering DoD awarded contracts through the execution of contract modifications; cost monitoring; managing ground and flight operations, delivery schedules, and government property; providing transportation authorizations for in-plant material; accepting and authorizing payments for contracted goods and services; recovering expiring and cancelling funds; and contract close-out. The DCMA is at the forefront of executing the DoD Security Cooperation (SC) mission to build and sustain Allied security interests and industrial capabilities collaboratively. Within the SC community, the DCMA provides support to Foreign Military Sales delegated by the Service buying commands, Foreign Direct Commercial Sales contracts, and international agreements, which the DCMA directly aligns personnel to support Allies in critical locations in the U.S. and overseas. FY 2026 Budget Priorities The FY 2026 DCMA budget priorities are to implement DoD directives to optimize the value-added support to Service customers and the DoD; streamline processes to gain mission efficiencies; invest strategically in non-labor projects to maximize potential returns on investment; modernize legacy Information Technology (IT) systems; and leverage advanced IT for greater efficiencies. Approximately 84% ($1,216.8 million) of the FY 2026 non-cyber budget request supports Agency personnel compensation for the direct funded full-time equivalent employees. The remaining 16% ($224.8 million) supports the DCMA workforce for critical requirements as: IT network and modernization, commercial tools, tech refresh and equipment sustainment; facility project renovations, sustainment, and leases; intragovernmental support for human resource and accounting services; mission travel; Ability One contract closeout and contractor support; equipment; permanent change of station (household goods storage); and supplies. The DoD continues to invest in new emerging programs and weapon systems DCMA continues to leverage automation to effectively align its workforce with its workload and support current and future DoD investment growth most efficiently. DCMA 207 Personnel Compensation The DCMA workforce is the most valuable asset for mission accomplishment. The DCMA will continue to assess the workforce and workload requirements to better align with the Interim National Defense Strategic Guidance (INDSG) while ensuring continued recruitment and retention of a high-caliber acquisition workforce. The DCMA has invested in an innovative initiative to model Operational Unit (OU) functional workload and utilize model output to inform OU workforce requirements and data-informed resourcing decisions. This developing and evolving approach continues to be instrumental in improving the DCMA allocation and alignment of the workforce with mission workload. Information Technology The DCMA acquisition workforce relies on automation to enable and enhance communication capabilities with the commercial industry, the DoD acquisition community, and its customers. The DCMA executes an annual non-labor IT budget of approximately $81 million to maintain mission systems and resources, excluding cyber. In accordance with DoD guidance, the DCMA continues to integrate several major reform initiatives to prioritize IT efforts and improve its network environment for managing and optimizing business operations and the mission support infrastructure required to support the Warfighter. In FY 2026 and beyond, the DCMA expects to be fully transitioned to the DISA DoDNet offering for common use networks. The DCMA continues to fund most hardware, software, and other IT efforts within its baseline budget to sustain lifecycle replacements as required. The DCMA-funded IT non-labor costs are anticipated to increase beginning in FY 2025 due to implementing the Fourth Estate Network Optimization (4ENO) reform initiative and the associated transformation cost from legacy to modernized business applications. The DCMA modernization strategy supports the DoD IT Reform and Modernization initiatives to retire legacy software applications. The DCMA continues to buy down accumulated technical debt. Facilities The DCMA facility rent/lease/agreement and government vehicles programs have a standard annual estimated cost of approximately $42 million for mission-critical requirements, with no trade-space for major course corrections. In FY 2026, the DCMA needs to build two major secure spaces on DoD military installations (Camp Pendleton, CA and Hanscom AFB, MA) to support programs associated with integrated deterrence efforts. The DCMA mission is to execute a new strategic enterprise space plan in response to the "Return to In-Person Work" (RIPW) Presidential Memorandum and the NDAA for FY 2025 direction to reduce commercial leased space. The DCMA space efficiency action plan will close and increase seating capacities at enduring sites to accommodate displaced employees (and reduce RIPW exemptions) in a progressive and targeted approach. As such, the FY 2026 space efficiency effort will focus on internal furniture reconfigurations, to the extent service providers (such as Military Hosts, GSA and UNICOR) can support, to increase seating capacities in several offices (for example, Garden City, NY; Fort Eustis, VA; and Fort Sam Houston, TX). Finally, the DCMA continues to explore collaborations and partnerships with other DoD Agencies to improve space efficiency further and accommodate greater in-person work. DCMA 208$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 1556832000, "fy26": 1441456000, "name": "4. Administration and Servicewide Activities", "fy25_current": 1520661000, "fy25_request": 1543134000, "fy25_cong_amt": -22473000, "fy25_cong_pct": -1.46}$$::jsonb, $${"fy24": 1556832000, "fy26": 1441456000, "name": "Contract Management", "fy25_current": 1520661000, "fy25_request": 1543134000, "fy25_cong_amt": -22473000, "fy25_cong_pct": -1.46}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 209, 226, FALSE, $${"json_key": "DCMA__umbrella", "fy27_v192_bucket_a_dw": {"session": "2026-05-09_v41", "source_pdf": "O&M/FY27/DW/Vol1_Part1/DCMA_OP-5.pdf", "content_hash": "ea8615e3d56ffa81eb84d3e2a33a0a33c8894ee14c1839b57cc1a5f729d4b5f9", "source_page_amount": 5, "source_page_description": 2}}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 1462988000, to_jsonb(ARRAY[$${"fy25": 1522.859, "fy27": 1462.988, "name": "4. Administration and Servicewide Activities", "fy26_current": 1431.929, "fy26_request": 1441.456, "fy26_cong_amt": -9.527, "fy26_cong_pct": -0.66}$$::jsonb, $${"fy25": 1522.859, "fy27": 1462.988, "name": "Contract Management", "fy26_current": 1431.929, "fy26_request": 1441.456, "fy26_cong_amt": -9.527, "fy26_cong_pct": -0.66}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/FY2027_o1.txt$$, 152720000) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dcsa_cyber$$, $$DCSA - Cyber$$, $$Defense Counterintelligence and Security Agency Cyber$$, $$DCSA$$, $$om_dw_ba04$$, NULL, $$dw_dcsa$$, 2026, 9835000, 9794000, -523000, -5.34, 9271000, 11120000, $$DoD Cyberspace Activities The Defense Counterintelligence and Security Agency (DCSA) Cyberspace activities are defined as an enterprise cybersecurity strategy to promote, maintain, and deliver services to safeguard the agency’s information assets, security posture, and the national industrial security oversight, compliance, security education, and personnel vetting missions. These activities are accomplished while protecting and sustaining critical information and data, remaining DoD compliant, being audit ready, and successfully providing assurance to our stakeholders that we are defending DoD information systems, enclaves, and mission. These efforts ensure Confidentiality, Integrity, and Availability security measures are adhered to in an efficient and effective manner to reduce internal and external attack vectors while managing risk. The incorporation and implementation of Zero Trust (ZT) and Identity, Credential, and Access Management (ICAM) requirements on the JWICS domain addresses cybersecurity requirements ensuring access by trusted users. The strategy encompasses security in both traditional and cloud environments for all impact level/classifications. DCSA - Cyber 194$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 9835000, "fy26": 11120000, "name": "Cyberspace Activities", "fy25_current": 9271000, "fy25_request": 9794000, "fy25_cong_amt": -523000, "fy25_cong_pct": -5.34}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 197, 208, FALSE, $${"json_key": "DCSA__Cyber"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 16885000, to_jsonb(ARRAY[$${"fy25": 9.271, "fy27": 16.885, "name": "Cyberspace Activities", "fy26_current": 10.558, "fy26_request": 11.12, "fy26_cong_amt": -0.562, "fy26_cong_pct": -5.05}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part1/DCSA_Cyber_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dcsa_umbrella$$, $$DCSA$$, $$Defense Counterintelligence and Security Agency$$, $$DCSA$$, $$om_dw_ba04$$, NULL, $$dw_dcsa$$, 2026, 990915000, 952464000, -47932000, -5.03, 904532000, 1168366000, $$On behalf of the Secretary of Defense, the Defense Counterintelligence and Security Agency (DCSA) serves as the primary Federal entity for personnel vetting to ensure an effective, efficient, and trusted workforce for the Federal Government as directed in the Executive Order (EO) 13869, as well as the continuation of the National Industrial Security Program (NISP) mission. The DCSA was formed over the course of 2019 to 2021 and is dedicated to building the best possible security enterprise to defend the United States. from extant and future adversaries attempting to gain a national security advantage through the workforce, technologies, and supply chain. Since its formal establishment, DCSA restructured its organization to realign personnel previously assigned to the disestablished Defense Vetting Directorate (DVD) to better support and align with the Interim National Defense Strategic Guidance by ensuring a trusted federal, industrial, and affiliated workforce through continuous vetting and insider threat programs. These programs enable government and industry to deliver uncompromised capabilities to the warfighter by utilizing artificial intelligence, machine learning, and cutting-edge technologies and innovation. The blending of the operational missions of Industrial Security, Personnel Security, Counterintelligence, Insider Threat, and professional education and certification provides DCSA with the unique advantage in preserving the nation’s strategic edge. The DCSA ensures that sensitive and classified U.S. and foreign government information, technologies, and material entrusted to cleared industry are securely protected. The DCSA, headquartered in Quantico, Virginia, with 172 field offices located across the United States, executes NISP oversight for the Department of Defense (DoD) and 35 other Federal executive branch agencies, determines security eligibility for all non-Intelligence DoD personnel and conducts personnel vetting for more than 100 federal agencies. As the primary Industrial Security functional manager for the DoD, DCSA provides security education, training, certification, and professional development for DoD and other U.S. Government contractor employees, and U.S. foreign government partners. The DCSA conducts required NISP assessments to deter, detect, and identify loss or compromise of classified information and ensure corrective actions are taken to prevent recurrence. DCSA 169 A. Industrial Security (IS) Directorate: The IS Directorate contributes to national security by serving as the primary interface between the DoD and cleared industry under DoD cognizance. Pursuant to DoD Instruction 5220.32, Vol.1, and EO 12829, DCSA administers and implements the defense portion of the NISP on behalf of the DoD and 35 other federal executive branch agencies. The IS Directorate vets and provides oversight, direction, and assistance to cleared contractors, their security programs, and associated classified information systems, and the analysis and mitigation of foreign ownership, control, or influence (FOCI) at over 10,000 cleared companies with 12,500 contractor facilities and 5,600 classified computer systems. The IS Directorate plays a key role providing guidance and direction for the mitigating of potential insider threats and intrusions by adversaries attempting to gain access to classified information. While maintaining its primary role as the Cognizant Security Office for DoD within the NISP, the IS Directorate maintains four congruent missions in addition to its traditional NISP mission execution. The IS Directorate: 1. Congruent with the assessment and authorization of cleared contractor information systems, established the Cyber Operational Readiness Assessment (CORA) program, formerly known as the Command Cyber Readiness Inspection (CCRI) program. Mandated by the Chairman of the Joint Chiefs of Staff (CJCS) Instruction 6211.02D, CJCS Instruction 6510.01F, DoD Instruction (DoDI) 8010.01, and DoDI 8500.01, the formal program allows DCSA the ability to evaluate the protection posture of NISP contractors with Secret Internet Protocol Router Network (SIPRNet) nodes. This program increases accountability and improves the overall security posture of the DoD Information Network (DODIN). During FY 2025, DCSA is on track to perform 60 CORAs growing to 75 CORAs in FY 2026. 2. Pursuant to DoD Manual 5100.76, assesses security measures for the physical security of sensitive conventional Arms, Ammunition and Explosives (AA&E) at contractor facilities. DCSA’s contribution to DoD’s AA&E program includes conducting pre-award security surveys (PASS) and annually recurring physical security AA&E inspections of U.S. contractor-owned, contractor-operated (COCO) facilities that manufacture, test, store, and transport DoD's sensitive (identified as Security Risk Category (SRC) I, II, III or IV) conventional AA&E. DCSA is responsible for 164 facilities within the AA&E program--most of these AA&E facilities (83) are uncleared while the rest (81) are cleared contractors with Facility Clearances. DCSA conducted 122 PASS and 70 annual AA&E inspections in 2024. DCSA currently has 164 facilities in its AA&E portfolio. 3. Expanded its entity vetting mission to now include provisions for Section 847 of the Fiscal Year (FY) 2020 National Defense Authorization Act (NDAA) to conduct FOCI analysis and recommend mitigation and management of beneficial ownerships for certain DoD contracts over $5 million in support of DoD acquisition programs. The mission supports the Office of the Under Secretary of Defense, Intelligence and Security (OUSD(I&S)), Office of the Under Secretary of Defense, Acquisition & Sustainment (OUSD(A&S)), and the Office of the Under Secretary of Defense, Research and Engineering (OUSD(R&E)) in enabling the protection of DoD supply chains to further reduce Defense Industrial Base FOCI risks. DCSA 170 4. Provides operational and administrative support to field operations in the form of guidance and policy interpretation regarding safeguarding and disseminating controlled unclassified information (CUI) that reside within classified contracts. This activity is responsive to requirements outlined in DoDI 5200.48. B. DoD Insider Threat Management and Analysis Center (DITMAC): The DITMAC provides an enterprise level, integrated capability to collect and analyze information to support insider threat detection and mitigation. The program gathers, integrates, reviews, assesses, and responds to information derived from DoD Insider Threat hubs, Counterintelligence (CI), security, cybersecurity, civilian and military personnel management, workplace violence, anti-terrorism risk management, law enforcement, and other sources as necessary and appropriate to identify, coordinate mitigation, and counter insider threats to DoD personnel, assets and information. The DITMAC further supports the 43 DoD component insider threat hubs by providing enterprise services, which include a Behavioral Threat Analysis Center (BTAC) composed of a wide range of subject matter experts, installation-level insider threat integration management, assessments and professionalization of insider threat personnel and programs, management of requirements for integrated systems, and operation of an insider threat reporting portal to the DoD workforce. C. Training Directorate: 1. Security Training (ST) The ST directorate delivers security education, training, and certification products and services to the DoD, other federal agencies, and industry under the NISP. The ST directorate utilizes an agile delivery platform to maximize accessibility from in-person, instructor-led courses, online courses, webinars, video presentations, toolkits, and job aids. The ST directorate develops and manages the Security Professional Education Development Certification Program, which provides a series of National Commission for Certifying Agencies accredited professional certifications across multiple security disciplines designed to professionalize the security workforce via a common set of competencies that promote interoperability and facilitate professional development and training. With the enhancement of curricula for DCSA Industrial Security Professionals, the ST directorate is expanding capacity to offer training and education for security professionals across the Defense Security Enterprise and Industry. 2. National Center for Credibility Assessment (NCCA) The NCCA is the sole provider of credibility assessment education and training and audits of agencies' quality assurance programs against federal standards; that also provides oversight and recommendations for research, development, testing and evaluation of credibility assessment equipment and protocols within the federal government. The NCCA provides services to 30 federal partner agencies, conducting three 12-week initial polygraph examiner training courses per year and multiple continuing education courses, to include required countermeasures training. The NCCA has the oversight responsibility to ensure federal programs consisting of approximately 1,100 polygraph examiners conduct their examinations in accordance with federal and agency policies and requirements. These federally trained examiners conduct more than 110,000 screening, operational, and criminal specific examinations per year. DCSA 171 D. Counterintelligence (CI) Analysis: DCSA CI Analysis identifies, assesses, and disrupts foreign intelligence entity threats to DCSA, the trusted workforce and the cleared national industrial base, including its critical technologies, supply chains, and personnel. The CI Special Agents work extensively with companies and other U.S. Government agencies to identify, share, and refer actionable threat information quickly and efficiently in coordination with the IS Directorate. The CI Analysis Division conducts all-source analysis assessing FOCI related to contractors / sub-contractors pursuing classified contracts as well as certain DoD contracts exceeding $5 million in accordance with Section 847 of the FY 2020 NDAA. CI Analysis assessments inform the development of DCSA’s comprehensive FOCI mitigation strategy countering identified foreign threats related to the prospective contractor. The CI Analysis Cyber Mission Center (CMC) employs cyber tools and analytical processes to address cyber-based threats to cleared contractors. The CI Analysis CMC proficiencies in cyber, CI, and analysis create a work center capable of implementing innovative solutions to identify, assess, and neutralize the CI related cyber threat from foreign adversaries. 1. Critical Technology Protection Integration Cell (CTPIC) The CTPIC is a whole-of-government engagement effort to deter, detect, and disrupt the unauthorized technology transfer activities of our adversaries. The CTPIC serves as the DoD focal point for assessments, coordination, integration, and operational information sharing related to critical technology protection across all phases of research, development, and sustainment. The CTPIC also encompasses Blue Advantage, which provides assessments on DoD and interagency efforts to safeguard critical and emerging technology with defense and defense intelligence applications. 2. Applied Research Laboratory for Intelligence and Security (ARLIS) The ARLIS program management office oversees the University Affiliated Research Center (UARC) located at the University of Maryland on behalf of the Defense Intelligence and Security Enterprises to provide strategic research and development to solve intelligence and security problems. The ARLIS overlays human behavior, social science, and culture and language expertise with proficiency, research, and development in emerging and advanced technologies to solve increasingly technical, but human-centered intelligence and security challenges. E. Personnel Security: 1. Personnel Security Investigations for Industry (PSI-I) The centrally managed PSI-I budget is used to execute requests for initial background investigations and continuous vetting (CV) for all contractor personnel security clearances in support of DoD components and 35 other federal agencies participating in the NISP. Budgetary requirements are based on anticipated industry investigations by case type, and CV related products in accordance with the DCSA Working Capital Fund published rates and adjusted to include costs on a case-by-case basis for Triggered Enhanced Subject Interviews and Reimbursable Security Investigations. The PSI-I budget requirements are increased by changes in security policy (e.g., Trusted Workforce 2.0 requirements for initial vetting and CV), increases to investigation pricing, and higher demand for research, development, and acquisition programs supporting DoD components and Federal agencies participating in the NISP. DCSA 172 Personnel Security Industry Operations Provides personnel security support and oversight of NISP contractor personnel by PSI-I mission, granting interim determinations for national security clearances. Provides personnel security oversight of industry personnel having access to U.S. and foreign classified information. Manages approximately 1 million cleared contractors during the lifecycle of their time having access to classified information. 2. Security Review Proceedings (SRP) Reforms This program executes the mandated Security Review Proceedings (SRP) Reforms that requires 100% legal sufficiency reviews (LSRs) of all proposed letters of intent and statements of reasons (LOI/SOR) and affords an opportunity for personal appearances before denial or revocation of security clearance eligibility. DCSA is responsible for this program, as identified in the memorandum signed on April 6, 2023, by the USD(I&S). This program applies to eligibility determinations for civilian personnel, military members, and contractor personnel requiring sensitive compartmented information (SCI) eligibility. These efforts will transform the Department’s process for determining eligibility for access to classified information or to occupy a national security position. All applicants will be afforded an opportunity for a personal appearance before a decision is made to issue a final letter of denial or letter of revocation (LOD/LOR). The program implements LSRs of all proposed LOIs/SORs and all LODs/LORs before a decision is made to issue any such documents. 3. International Military Student (IMS) Screening The IMS provides centralized screening and vetting of IMS training in the U.S. because of the December 2019 Pensacola Naval Air Station Shooting. The DoD procedures for IMS vetting were established in accordance with Section 1090 of the FY 2021 NDAA. Budgetary requirements are based on the anticipated number of initial and continuing or periodic reviews. The IMS population is vetted through the Expedited Screen Protocol products and services offered by the DCSA Working Capital Fund. This capability optimizes intelligence data sources, other classified and unclassified U.S. Government data systems and human analytics to provide multi-point identity detection of potential foreign risks and high risk, which includes association with international terrorism, foreign intelligence entities, and international crime. Operational Support Activities A. Management Headquarters: DCSA Headquarters enables mission execution through centralized management of strategic enterprise priorities to provide direct service support to field operations. These functions provide critical common services support devoted to the daily operations by enabling industry’s delivery of uncompromised capabilities and leveraging advanced technologies and innovation. The support consists of financial management, contract procurement operations, human capital management, legal advice and assistance through the general counsel and inspector general, strategic communications, security, maintenance of facilities, strategic management, logistical, property management, and equal employment opportunity. DCSA 173 1. Facilities and Physical Security DCSA acquires, modifies, and sustains physical space as well as provides comprehensive, compliant, and responsive solutions for the protection of DCSA’s assets (personnel, facilities and information) in performance of the DCSA mission. This support includes protection of information and assets while also fostering an agency-wide culture of security and accountability awareness. This capability is supported by the Logistics Management Office (LMO) that conducts facility acquisition, maintenance, property management, and logistical management and the Security Programs Office (SPO) that provides security management, access control, insider threat, emergency management, and antiterrorism/force protection support for approximately 172 DCSA CONUS/OCONUS (Alaska/Hawaii/Puerto Rico/Guam) field offices. DCSA led LMO and SPO programs ensure proper planning to address the dynamic physical space requirements associated with mission expansion and transfers. The requirements include additional SCIFs, maintenance and security improvements to existing physical spaces, leasing government vehicles, and the implementation of a regional field structure to optimize efficiencies and mission accomplishment. 2. Office of the Chief Information Officer (OCIO) The OCIO is responsible for the operations and oversight of all IT infrastructure, platforms, tools, systems and investments. The OCIO provides enterprise IT services to DCSA’s workforce of nearly 15,000 staff in 172 locations that enables DCSA to carry out its personnel security, industrial security, counterintelligence, and security training mission areas. The OCIO provides customer support, desktop computing, mobile computing, collaboration, telecommunications, secure network communications, and infrastructure and platform hosting capabilities across three networks: Non-classified Internet Protocol (IP) Router Network (NIPRNet), Secret Internet Protocol Router Network (SIPRNet), and Joint Worldwide Intelligence Communications System (JWICS). The OCIO provides DCSA’s Program Executive Office (PEO) with secure networks, infrastructure, platforms, and tools that enable the PEO to provide a portfolio of applications that supports the DCSA mission. The OCIO is tasked to provide the best secure IT services available in a cost-effective manner to meet DCSA's business operations and customer needs. The OCIO provides wide-ranging network protection and security of the DCSA network and information systems. The OCIO is responsible for developing, maintaining, and facilitating the implementation and integration of the DCSA IT architecture and services and responding to a wide range of agency requirements to optimize mission and enterprise performance with the enterprise goal to develop a secure digital eco- system. This mission is accomplished by continuously implementing enterprise capabilities, while decommissioning legacy, inadequate infrastructure, platforms, tools and systems, to strengthen and optimize the enterprise IT foundation for the DCSA mission success across all goals. The OCIO is responsible for implementation, execution, and oversight of all IT directives and mandates from EOs, Secretary of Defense, DoD Chief Information Officer, Office of Management and Budget (OMB), National Institutes of Standards and Technology (NIST), Defense Information Systems Agency (DISA), National Security Agency (NSA), Committee on National Security Systems (CNSS), Office of the Director of National Intelligence (ODNI), and Joint Forces Headquarters DODIN. The DCSA IT strategy and budget submission aligns to the DoD’s Capability Planning Guidance (CPG). DCSA 174 B. Program Executive Office (PEO): The PEO provides a portfolio of enterprise-wide IT system programs that employ best practice methodologies for the delivery of innovative IT solutions, advancing DCSA’s broad-spectrum National Security capabilities to better serve the DoD, the U.S. Government, and cleared industry. Essential programs within the PEO include: 1. Defense Security Analysis and Threat System (DSATS) (Formerly Titled DITMAC System of Systems (DSoS)) In FY 2026 DCSA will support the sustainment of the DSATS Increment I on the SIPRNet and JWICS networks for reporting and tracking insider threat cases; and will sustain DSATS Increment II on the NIPRNet network as it transitions from the Interim Solution for unclassified and installation- level reporting. Sustainment of these systems includes licenses, security patching, defect resolution, user management, training, operations, and help desk support to multiple DoD and Intelligence Community entities. Additionally, sustainment of the underlying system architecture, hosting platform, and data layer are planned to ensure a safe and secure system and data integration. 2. National Industrial Security System (NISS) The NISS provides industrial security capabilities that include serving as the system of record for facilities clearance information and industrial security oversight, improved risk assessment and mitigation related to contractors under FOCI, and identification of clearances requirements for contracting companies. Funding supports software sustainment activities to include system updates to meet emerging DoD and DCSA policy (e.g., migration to new cloud environments, data sharing with DoD stakeholders, etc.), cybersecurity updates to remain compliant with emerging accreditation requirements (e.g., Security Technical Implementation Guides, application and platform configurations, etc.), and continuous monitoring along with annual security reviews for NIPRNet and SIPRNet, software licenses and system vulnerability assessments, and mitigation plans. Current NISS legacy system capabilities and workflows will be integrated into a single Increment II modernized IT system. The expectation is that the new Increment II system will meet current performance characteristics and incorporate emerging technologies & capabilities to automate and support the NISS mission. 3. Security Education & Training Systems (SETS) The SETS provide end-to-end learning services enabling accessibility of security education training and content for DCSA's mission systems and whole of government workforce. Serving the DCSA learning community throughout government, industry, and public workforces, SETS supports unity of effort for the entire DCSA enterprise. Funding ensures SETS will sustain current operations while planning for the transition to fully operational data centric training platform services that enable learners, educators and administrators to interact with independently developed content. The program’s end state will be a comprehensive platform that supports the end-to- end education, training, and learning management missions. The FY 2026 request enables the identification and transition to a secure security education & training ecosystem that aligns to agency strategy, technology, data and knowledge management principles by leveraging Scaled Agile Framework (SAFe) methodology throughout the solution driving agency transformation. DCSA 175 4. National Background Investigations Services (NBIS) The NBIS is being developed as an enterprise Information System architecture and data strategy for migrating and modernizing the Office of Personnel Management (OPM) legacy IT systems supporting background investigations (BI). NBIS utilizes web and cloud- based capabilities with robust cybersecurity to provide a more secure infrastructure and investigative support system for initial and continuous vetting of DoD and Federal Agencies’ personnel. NBIS leverages DoD’s cybersecurity technologies, processes, and capabilities to protect personal data and investigative information for government civilians, military personnel, and contractors. It supports the distributed adjudication processes with built-in security, active governance structure, and a new national security culture based on process improvements, artificial intelligence (AI), machine learning and change management. For FY 2025, NBIS was funded out of the DCSA Working Capital Fund (WCF) but due to delays in fielding was moved to appropriated funding (Operation and Maintenance and Research, Development, Test, and Evaluation) in FY 2026 and until development is complete to not effect DCSA WCF product pricing. 5. Integrated Security Data Services (ISDS) The ISDS build on NBIS data layer efforts to implement Federal and DoD Data Strategies and DCSA’s modernization and efficiency objectives. The ISDS will integrate disparate data sources into a cloud-based capability enabling AI to improve identification and mitigation of risks while ensuring compliance with data governance, privacy, and security regulations. As a unified data ecosystem, ISDS is designed to consolidate and leverage data from various sources across DCSA. By eliminating critical capability gaps that prevent maximizing the value of these data, ISDS will bolster national security by empowering data-driven decision-making and providing robust support for key programs such as DSATS, NBIS, and NISS. This initiative will facilitate a more proactive and informed security posture by enabling the agency to meet any mission or business need through enhanced access to and analysis of its data holdings. DCSA 176$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 60877000, "fy26": 78762000, "name": "Counterintelligence (CI) Analysis", "fy25_current": 78635000, "fy25_request": 78635000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 37471000, "fy26": 28783000, "name": "Facilities and Physical Security", "fy25_current": 26910000, "fy25_request": 26910000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 82136000, "fy26": 182214000, "name": "Industrial Security", "fy25_current": 162805000, "fy25_request": 176437000, "fy25_cong_amt": -13632000, "fy25_cong_pct": -7.73}$$::jsonb, $${"fy24": 40240000, "fy26": 30390000, "name": "(DITMAC)", "fy25_current": 58529000, "fy25_request": 88529000, "fy25_cong_amt": -30000000, "fy25_cong_pct": -33.89}$$::jsonb, $${"fy24": 138470000, "fy26": 33093000, "name": "Management Headquarters", "fy25_current": 35101000, "fy25_request": 35101000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 0, "fy26": 178120000, "name": "National Background Investigations Services (NBIS)", "fy25_current": 0, "fy25_request": 0, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 0, "fy26": 17339000, "name": "National Industrial Security System (NISS)", "fy25_current": 18460000, "fy25_request": 18460000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 61612000, "fy26": 54555000, "name": "Office of Chief Information Officer", "fy25_current": 36119000, "fy25_request": 36119000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 117259000, "fy26": 38198000, "name": "Personnel Security", "fy25_current": 24300000, "fy25_request": 24300000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 323760000, "fy26": 461629000, "name": "Personnel Security Investigations for Industry (PSI-I)", "fy25_current": 387822000, "fy25_request": 387822000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 88849000, "fy26": 24331000, "name": "Program Executive Office (PEO)", "fy25_current": 35442000, "fy25_request": 38442000, "fy25_cong_amt": -3000000, "fy25_cong_pct": -7.8}$$::jsonb, $${"fy24": 40241000, "fy26": 40952000, "name": "Training Directorate", "fy25_current": 40409000, "fy25_request": 41709000, "fy25_cong_amt": -1300000, "fy25_cong_pct": -3.12}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 172, 196, FALSE, $${"json_key": "DCSA__umbrella"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 1035974000, to_jsonb(ARRAY[$${"fy25": 70.35, "fy27": 90.438, "name": "Counterintelligence (CI) Analysis", "fy26_current": 78.762, "fy26_request": 78.762, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 107.524, "fy27": 48.83, "name": "Enterprise Operations (ATH)", "fy26_current": 54.555, "fy26_request": 54.555, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 18.862, "fy27": 22.82, "name": "Facilities and Physical Security", "fy26_current": 28.783, "fy26_request": 28.783, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 67.051, "fy27": 191.724, "name": "Industrial Security (IS)", "fy26_current": 174.387, "fy26_request": 182.214, "fy26_cong_amt": -7.827, "fy26_cong_pct": -4.3}$$::jsonb, $${"fy25": 30.43, "fy27": 17.466, "name": "(DITMAC)", "fy26_current": 30.39, "fy26_request": 30.39, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 116.841, "fy27": 25.079, "name": "Management Headquarters", "fy26_current": 33.093, "fy26_request": 33.093, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 2.914, "fy27": 157.135, "name": "National Background Investigations Services (NBIS)", "fy26_current": 178.12, "fy26_request": 178.12, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 20.075, "fy27": 28.997, "name": "National Industrial Security System (NISS)", "fy26_current": 17.339, "fy26_request": 17.339, "fy26_cong_amt": 5.0, "fy26_cong_pct": 28.84}$$::jsonb, $${"fy25": 0.0, "fy27": 0.923, "name": "Personal Security Investigations (PSI)", "fy26_current": 0.0, "fy26_request": 0.0, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 372.352, "fy27": 344.312, "name": "Personnel Security Investigations for Industry (PSI-I)", "fy26_current": 409.145, "fy26_request": 461.629, "fy26_cong_amt": -52.484, "fy26_cong_pct": -11.37}$$::jsonb, $${"fy25": 13.149, "fy27": 37.02, "name": "(PSMOI)", "fy26_current": 38.198, "fy26_request": 38.198, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 41.181, "fy27": 26.546, "name": "Program Acquisition Executive (PAE)", "fy26_current": 29.331, "fy26_request": 24.331, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 41.143, "fy27": 44.684, "name": "Training Directorate", "fy26_current": 40.952, "fy26_request": 40.952, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part1/DCSA_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dhra_cyber$$, $$DHRA - Cyber$$, $$Defense Human Resources Activity Cyber$$, $$DHRA$$, $$om_dw_ba04$$, NULL, $$dw_dhra$$, 2026, 37384000, 39781000, -777000, -1.95, 39004000, 46621000, $$The Defense Human Resources Activity (DHRA) is a Field Activity of the Under Secretary of Defense (Personnel & Readiness), (USD (P&R)) that consists of multiple direct reporting units. The DHRA by design gives USD (P&R) greater capability and flexibility in managing the work of a diverse set of activities supporting the DoD Human Resources (HR) mission. Each Center/Office organization within DHRA has a unique, but complementary mission set. The DHRA Mission Support serves as an intermediary between the centers/offices and provides planning, programming, and budgeting for all activities within the DHRA enterprise, to include executing, coordinating, and providing direct oversight to the work of each center/office. The DHRA ensures that the Department’s warfighters present and past along with their families and civilian members of the Department receive the care and support they deserve, fairly, and in a timely fashion, through benefits administration, program execution and policy enforcement. The DHRA cybersecurity budget is used to support the secure operation of the information systems that enable DHRA to successfully execute its mission to: • Organize, direct, and manage all assigned resources, to include the programs described herein; • Maintain a central repository of the DoD HR information, both current and historic; approximately 45.3 million records currently in repository; • Provide rapid data-driven analytic solutions to support the decision-making needs to effectively maintain the readiness of the All-Volunteer Force; • Administer the sexual assault prevention and response policies and programs for DoD; • Administer transition assistance programs for approximately 200,000 eligible Service members who separate, retire, or are released from active duty each year; • Serve as the single focal point for commercial travel within the DoD for approximately 2.9 million DoD Service members and civilian personnel and centrally manage all commercial travel programs; • Administer the program that distributes DoD identification cards to members of the Military, DoD civilians, contractors, and other eligible personnel, approximately 425,000 cards issued monthly; • Serve as the authoritative source of identification and authentication of DoD-affiliated personnel for credentialing, identity protection, security, entitlements, and benefits verification; DHRA - Cyber 323 •   Administer the federal responsibilities of the Uniformed and Overseas Citizens Absentee Voting Act of 1986, as most recently amended by the Military Overseas Voter Empowerment Act, to approximately 2.8 million overseas citizens who are eligible to vote; •   Provide assistive technology to approximately 292,000 potential DoD civilian employees and Service members to allow DoD and federal employees with disabilities to access electronic and information technology; •   Provide assistance to approximately 650,000 Service members and Veterans to pursue their educational goals and earn degrees or certifications during and after their service. In particular, the DHRA Cybersecurity budget is used to deliver and enhance a cybersecurity program that safeguards DHRA information infrastructure and data assets from unauthorized use, disclosure, modification, damage or loss by implementing standardized security practices in planning, implementation, management, and operations that foster a secure operating environment by: • Defending, mitigating and securing current and future systems, networks and infrastructure against cyber threats; • Operating continuous monitoring and assessment tools, such as network and host vulnerability scanners, compliance scanners, and intrusion detection systems; • Strengthening technical measures to maintain an agile and resilient network and infrastructure; • Provide incident response for identified cybersecurity incidents; • Developing and enforcing policy to support this mission and educating DHRA associates about security requirements; • Regularly assessing systems using Risk Management Framework (RMF) methodologies; • Providing security architecture consulting to DHRA programs requiring additional guidance. Narrative Explanation of Changes: The FY 2026 DHRA Cyber budget represents a net programmatic increase of $6.832 million with a price growth of $0.785 million. Cyber Funding: (Dollars in Thousands) FY 2024               FY 2025                   FY 2026 37,384                39,004                    46,621 Defense Suicide Prevention Office (DSPO): (Dollars in Thousands) FY 2024               FY 2025                   FY 2026 83                    106                       85 DHRA - Cyber 324 This is for DSPO Military Mortality Database (MMDB) to fund ongoing cyber services, to include contracts and procurements to establish policy, procedures, process controls, compliance with orders and directives, incident response, system protections and tools. This includes capabilities to detect, monitor, analyze, respond to, report on, and prevent cybersecurity incidents. Defense Manpower Data Center (DMDC) manages five DHRA programs: • Defense Enrollment Eligibility Reporting System (DEERS) • Enterprise Data Service (EDS) • Enterprise Human Resource Information System (EHRIS) • Identity Credential Management (ICM) • Personnel Support Program (PSP) Cybersecurity funding supports the sustainment of DMDC cyber toolsets, enterprise security engineering, auditing, continuous monitoring, incident response, and compliance reporting. These costs and services are shared across all of DMDC programs to provide efficiencies of scale and allow the specialization of the cybersecurity professionals that provide the support. Cybersecurity funding is also used to acquire DoD-mandated Cyber Security Service Provider (CSSP) support for each program’s systems. DMDC – Defense Enrollment Eligibility Reporting System (DEERS): (Dollars in Thousands) FY 2024               FY 2025                  FY 2026 15,013                12,393                   12,866 Cybersecurity funding provides the DEERS portfolio with access to DMDC’s continuous monitoring program, cybersecurity tools, audits, incident response, risk management support, and security engineering services. DMDC – Enterprise Data Service (EDS): (Dollars in Thousands) FY 2024               FY 2025                  FY 2026 5,922                  8,855                   9,128 Cybersecurity funding provides the EDS portfolio with access to DMDC’s continuous monitoring program, cybersecurity tools, audits, incident response, risk management support, and security engineering services. DHRA - Cyber 325 DMDC – Enterprise Human Resource Information System (EHRIS): (Dollars in Thousands) FY 2024               FY 2025                  FY 2026 2,116                  2,185                   2,244 Cybersecurity funding provides the EHRIS portfolio with access to DMDC’s continuous monitoring program, cybersecurity tools, audits, incident response, risk management support, and security engineering services. DMDC – Identity Credential Management (ICM): (Dollars in Thousands) FY 2024               FY 2025                  FY 2026 9,355                  9,797                   15,646 Cybersecurity funding provides the ICM portfolio with access to DMDC’s continuous monitoring program, cybersecurity tools, audits, incident response, risk management support, and security engineering services and ensures the Identity solutions DMDC provides to the Department are secure. DMDC – Personnel Support Program (PSP): (Dollars in Thousands) FY 2024               FY 2025                  FY 2026 2,289                  2,358                   2,406 Cybersecurity funding provides the PSP portfolio with access to DMDC’s continuous monitoring program, cybersecurity tools, audits, incident response, risk management support, and security engineering services. Defense Personnel Analytics Center (DPAC) manages two DHRA programs: • DoD Office of the Actuary (OACT) • Office of People Analytics (OPA) The Office of the Actuary does not have any specific cyber requirements. DHRA - Cyber 326 DPAC – Office of People Analytics (OPA): (Dollars in Thousands) FY 2024              FY 2025                  FY 2026 394                  519                      835 Cyber funding is used by OPA for necessary annual audits under the RMF and for CSSP support for our testing and recruiting related applications. Defense Support Service Center (DSSC) manages the following DHRA programs: • Computer/Electronic Accommodations Program (CAP) • Defense Activity for Non-Traditional Education Support (DANTES) • Defense Language and National Security Education Office (DLNSEO) • Defense Travel Management Office (DTMO) • Employer Support of the Guard and Reserves (ESGR) • Federal Voting Assistance Program (FVAP) • Military-Civilian Transition Office (MCTO) DSSC – Computer/Electronic Accommodations Program (CAP): (Dollars in Thousands) FY 2024              FY 2025                  FY 2026 460                  117                      120 The CAP is recognized by the U.S. Office of Personnel Management as a model program to increase DoD Federal employment opportunity for individuals with targeted and significant disabilities. The program has provided over 246,000 accommodations to more than 98,000 DoD civilian employees and Service members since its inception and is widely recognized as the principal source on providing disability employment subject matter expertise, assistive technology solutions, and employment support services. These functions would not be possible without the use of CAP’s Defense Business System (DBS), CAPX which is comprised of CAP’s website and secure portal, Activity and Reporting Management System (ARMS). The CAPX is hosted by the DMDC, who as the hosting provider, includes network and cybersecurity support and to assist CAP with managing/supporting CAPX’s Authority to Operate (ATO). In FY 2026 CAP anticipates continued collaboration with the Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center to ensure the new CAP system is ready to go live. DHRA - Cyber 327 DSSC – Defense Activity for Non-Traditional Education Support (DANTES): (Dollars in Thousands) FY 2024                FY 2025                   FY 2026 355                     337                      407 The DANTES cyber activities support two IT investments: DoD Voluntary Education Partnership Memorandum of Understanding (MOU) and the Modernized Military Transcript (MMT). The DoD policy requires educational institutions that wish to participate in the DoD Tuition Assistance (TA) Program to sign the MOU conveying the commitments and agreements between the educational institution and the DoD prior to an educational institution receiving funds from a Service's TA program. The MMT is an official academic record that provides colleges and universities with documented evidence of professional military education, training, prior learning, and occupation experiences achieved by Service members and veterans. Cyber security activities to support these two IT investments include contractor support to complete DoD RMF accreditation requirements (e.g. CSSP and ATO validations). DSSC – Defense Language and National Security Education Office (DLNSEO): (Dollars in Thousands) FY 2024                FY 2025                  FY 2026 225                    274                      280 Supports the cybersecurity requirements for DLNSEO's information technology systems. Funding is used to ensure compliance with RMF responsibilities and activities for DLNSEO's information technology systems, and to obtain cybersecurity services including continuous monitoring, incident response and compliance reporting for DLNSEO's information technology systems and users. DSSC – Defense Travel Management Office (DTMO): (Dollars in Thousands) FY 2024                FY 2025                   FY 2026 247                     379                      388 The DTMO’s cyber activities support two DTMO IT investments: DTMO Passport and Oracle Service Cloud. The DTMO hosts the DTMO Passport boundary within the Oracle Cloud infrastructure. This boundary is divided into three environments: lower, middle, and higher regions, and it encompasses a total of 60 servers. To support the DTMO's infrastructure needs, the DMDC procures Infrastructure as a Service (IaaS) from Oracle Cloud Infrastructure (OCI). In turn, DMDC provides DTMO with Platform as a Service (PaaS) service support for a fee. This PaaS support encompasses enterprise services, CSSP, cybersecurity management, infrastructure support, networking, server management, and database DHRA - Cyber 328 support for DTMO applications. DTMO Passport consists of DTMO’s travel data repository, Commercial Travel Information Management database, and over 30 applications that support the travel enterprise. Oracle Service Cloud, commonly known as the Ticket Management System, is a Software as a Service product used by the Travel Assistance Center to manage travel help desk ticket submitted by the DoD travel community. Cyber security activities to support these two IT investments, include: CSSP support, Cyber Scanning Tools licenses (Passport only), and Security Control Assessment – Validation. DSSC – Employer Support of the Guard and Reserve (ESGR): (Dollars in Thousands) FY 2024               FY 2025                    FY 2026 285                    119                       363 Cybersecurity functions supporting ESGR include prevention of, damage to, protection of, and restoration of ESGR’s web applications to ensure its availability, integrity, authentication, confidentiality, and nonrepudiation. Additionally, cybersecurity functions include specialized contractor support for DoD RMF accreditation requirements. The ESGR’s systems are hosted at the Defense Information Systems Agency (DISA), which provides comprehensive services for monitoring and analysis of network traffic entering and exiting network boundaries. ESGR also shares in the costs for EventPLUS and Exhibit Arts Fulfillment System through CSSP, is covered by the C5ISR Center. DSSC – Federal Voting Assistance Program (FVAP): (Dollars in Thousands) FY 2024               FY 2025                    FY 2026 114                    101                       104 The FVAP cyber needs are integrated into our entire core mission of being able to provide information and assistance to those in the military, their spouses, and overseas citizens to make sure they have the tools and knowledge to be able to vote anywhere in the world. Our website is an integrated content management system. The online assistant, also called R3, directly assists voters with completing two FVAP-prescribed forms, the Federal Post Card Application and the Federal Write-In Absentee Ballot. The FVAP Portal also consists of a database back end to support reporting of voting assistance metrics from voting assistance officers all over the world on U.S. military bases. With all of our functions we make updates and enhancements as needed to better the functionality and security of the system. Our enhancements are covered by IT Coalition and our security, through CSSP, is covered by the C5ISR Center. DHRA - Cyber 329 DSSC – Military-Civilian Transition Office (MCTO): The MCTO mission is to provide full-spectrum program management that continuously improves design, content, and delivery of timely, relevant, and meaningful information, support, services, and resources to transitioning and reintegrating Service members and their families worldwide. (Dollars in Thousands) FY 2024                FY 2025                    FY 2026 233                    1,171                     1,450 •   Transition Assistance Program (TAP) •   Yellow Ribbon Reintegration Program (YRRP) •   Department of Defense (DoD) SkillBridge The MCTO provides TAP, YRRP, and SkillBridge program management including research, strategy, policy development, program design, budget and contract management, grant management, curriculum development, program evaluation, program assessment, program compliance, IT, public affairs, strategic communications, and outreach. The MCTO ensures a common level of support, across all Military Departments and Components, to respective program eligible Service members and their families at over 200 locations around the globe. The MCTO manages formal DoD and Federal interagency governance of transition and reintegration services and support while coordinating and collaborating with diverse stakeholders including the Department of Veterans Affairs/DoD Joint Executive Committee, TAP Interagency, DoD Manpower & Reserve Affairs (M&RA), Joint Staff, National Guard Bureau, Military Departments, employers, institutions of higher learning, entrepreneurial activities, and other governmental and non-governmental entities. The MCTO resource consolidation provides streamlined program management and supports planned development of a single source, authoritative Enterprise Transition & Reintegration IT System enabling seamless management of transition and reintegration requirements across the Services and supporting federal agencies while ensuring full statutory and policy compliance. In FY 2026 MCTO anticipates continued collaboration with the C5ISR Center to ensure the new IT system is ready to go live. DSSC – MCTO / Enterprise Transition & Reintegration IT System: In FY 2024, MCTO initiated development of a single source, authoritative Transition & Reintegration IT Enterprise System that will host a secure Client Tracking System which: (1) captures reported data as defined in the new statue, (2) enables seamless management of Service member transition across all Military Services and installations; (3) provides Installation and Unit Commanders performance reports and (4) introduces a streamlined way to provide person-based "data as a service" and "analytics as a service" to all of DoD Military Services and other Federal Agencies; and (5) provides a Learning Management System for Active Duty and Reserve Component Service members with relevant curricula tailored to their individual transition and/or reintegration requirements. Lastly, these enhancements fulfill requirements within Section 1144(f) of Title 10, U.S. Code and applicable Congressional mandates requiring updating, modifying, and developing new curriculum to account for new statutorily required topics and framework for delivery. DHRA - Cyber 330 DSSC – MCTO / Transition Assistance Program (TAP): The TAP is codified in Sections 1142 and 1144 of Title 10, U.S. Code, and DoD Instruction 1332.35. The MCTO absorbed SkillBridge and other programs midyear which drove increases across the programmatic portfolio with the highest increases in IT enhancements, curriculum development, training, contract support, and manpower requirements. The TAP provides streamlined and effective transition assistance that effectively supports individualized transition preparation for approximately 200,000 eligible Service members who separate, retire, or are released from active duty each year. The TAP-IT suite is the DoD-wide source for capturing transitioning Service members’ TAP course attendance and documenting transition progress on an electronic DoD (DD) Form 2648 across the Services. The MCTO and the Military Services are currently executing FY 2019 – FY 2022 National Defense Authorization Act (NDAA) mandated changes and the 2018 Government Accountability Office (GAO) report number 18-23 recommended improvements and subsequent major changes that have resulted in a DoD policy to modify the Career Readiness Standards (CRS). The DoD requires Service members to meet with a TAP Counselor for their initial counseling prior to their pre-separation counseling and transition from Service if they have served on active duty for 180 continuous days. The mandated NDAA changes as well as the DoD and GAO recommendations require modification to both the electronic and portable document format DD Form 2648 “Pre-separation Counseling Checklist for Active Component (AC), Active Guard Reserve (AGR), Active Reserve (AR), Full Time Support (FTS), and Reserve Program Administrator (RPA) Service Members”, to increase reporting requirements, and necessitate new development for adding a client management capability to the TAP-IT suite. These functions would not be possible without the use of TAP-IT, which is hosted by the DMDC, who in their role as host, includes cyber security support for the network and system applications. Additionally, there are cyber security efforts to safeguard personally identifiable information. DSSC – MCTO / Yellow Ribbon Reintegration Program (YRRP): The YRRP is codified in Public Law 110-181, Section 582 and DoD Instruction 1342.28 and is a DoD-wide effort to promote the well-being of National Guard and Reserve Component Service members, their families, and communities, by connecting them with resources throughout and beyond the deployment cycle. Cybersecurity functions include prevention of, damage to, protection of, and restoration of EventPLUS to ensure its availability, integrity, authentication, confidentiality, and nonrepudiation, including contractor support for DoD Risk Management Framework accreditation requirements. The EventPLUS is hosted through Amazon Web Services (government) and actively monitored by the Combat Capabilities Development Command (CCDC) C5ISR Center, which provides comprehensive services for monitoring and analysis of network traffic entering and exiting network boundaries. Specifically, CCDC C5ISR services are external vulnerability scans, web vulnerability scanning, malware notification protection, and attack sensing & warning. DHRA - Cyber 331 DSSC – MCTO / SkillBridge: SkillBridge is codified in 10 U.S. Code, Chapter 58, § 1143, and DoD Instruction 1322.29. SkillBridge provides eligible transitioning Service members with job training and employment skills training, including apprenticeship programs, to help prepare them for employment in the civilian sector. Participating Service members gain valuable civilian work experience through specific industry training, apprenticeships, or internships during the last 180 days of service. The MCTO prioritized elimination of backlogged potential employer MOU requests. The MOU serves as an agreement between the employer and the DoD stipulating the services the employer offers to the separating Service members to facilitate readiness for employment in the civilian sector. The MCTO also conducted an internal programmatic review to develop a baseline understanding of “as is” cyber requirements and capabilities. That internal assessment identified significant cyber vulnerabilities with the current IT platform with no cost-effective mitigation under the current contract. A cyber vulnerabilities corrective action plan was implemented in FY 2024. Sexual Assault Prevention and Response Office (SAPRO): (Dollars in Thousands) FY 2024                FY 2025                    FY 2026 253                     293                       299 The Department, under the guidance of the Sexual Assault Prevention and Response Office (SAPRO), has worked to improve its programs to provide military sexual assault survivors with a full range of best-in-class support services. Funding for the Defense Sexual Assault Incident Database (DSAID) greatly assists the military Service sexual assault prevention and response (SAPR) program management and DoD SAPRO oversight activities. The DSAID serves as the DoD’s SAPR source for internal and external requests for statistical data on sexual assault in accordance with Section 563 of the NDAA for FY 2009. The DoD Safe Helpline is codified in Public Law 113-291, Section 545 and DoD Instruction 6495.02 and is the Department’s sole 24/7, anonymous, confidential hotline for members of the DoD community affected by sexual assault. The Safe Helpline offers specialized services including crisis intervention support and resource referrals to survivors, their families, and other DoD Stakeholders. DHRA - Cyber 332$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 40000, "fy26": 0, "name": "Defense Civilian Personnel Advisory Service (DCPAS)", "fy25_current": 0, "fy25_request": 0, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 83000, "fy26": 85000, "name": "Defense Suicide Prevention Office (DSPO)", "fy25_current": 106000, "fy25_request": 106000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 15013000, "fy26": 12866000, "name": "System (DEERS)", "fy25_current": 12393000, "fy25_request": 12393000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 5922000, "fy26": 9128000, "name": "DMDC - Enterprise Data Services (EDS)", "fy25_current": 8855000, "fy25_request": 8855000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 2116000, "fy26": 2244000, "name": "System (EHRIS)", "fy25_current": 2185000, "fy25_request": 2185000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 9355000, "fy26": 15646000, "name": "DMDC - Identity Credential Management (ICM)", "fy25_current": 9797000, "fy25_request": 9797000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 2289000, "fy26": 2406000, "name": "DMDC - Personnel Support Programs (PSP)", "fy25_current": 2358000, "fy25_request": 2358000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 394000, "fy26": 835000, "name": "DPAC - Office of People Analytics (OPA)", "fy25_current": 519000, "fy25_request": 819000, "fy25_cong_amt": -300000, "fy25_cong_pct": -36.63}$$::jsonb, $${"fy24": 460000, "fy26": 120000, "name": "(CAP)", "fy25_current": 117000, "fy25_request": 117000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 355000, "fy26": 407000, "name": "Support (DANTES)", "fy25_current": 337000, "fy25_request": 337000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 225000, "fy26": 280000, "name": "Education Office (DLNSEO)", "fy25_current": 274000, "fy25_request": 274000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 247000, "fy26": 388000, "name": "DSSC - Defense Travel Management Office (DTMO)", "fy25_current": 379000, "fy25_request": 379000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 285000, "fy26": 363000, "name": "(ESGR)", "fy25_current": 119000, "fy25_request": 356000, "fy25_cong_amt": -237000, "fy25_cong_pct": -66.57}$$::jsonb, $${"fy24": 114000, "fy26": 104000, "name": "DSSC - Federal Voting Assistance Program (FVAP)", "fy25_current": 101000, "fy25_request": 101000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 233000, "fy26": 1450000, "name": "DSSC - Military-Civilian Transition Office (MCTO)", "fy25_current": 1171000, "fy25_request": 1411000, "fy25_cong_amt": -240000, "fy25_cong_pct": -17.01}$$::jsonb, $${"fy24": 253000, "fy26": 299000, "name": "(SAPRO)", "fy25_current": 293000, "fy25_request": 293000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 326, 359, FALSE, $${"json_key": "DHRA__Cyber"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 49611000, to_jsonb(ARRAY[$${"fy25": 0.087, "fy27": 0.0, "name": "Defense Civilian Personnel Advisory Service (DCPAS)", "fy26_current": 0.0, "fy26_request": 0.0, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 0.0, "fy27": 0.0, "name": "Defense Suicide Prevention Office (DSPO)", "fy26_current": 0.085, "fy26_request": 0.085, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 12.361, "fy27": 13.248, "name": "System (DEERS)", "fy26_current": 12.457, "fy26_request": 12.866, "fy26_cong_amt": -0.409, "fy26_cong_pct": -3.18}$$::jsonb, $${"fy25": 10.754, "fy27": 9.44, "name": "DMDC - Enterprise Data Services (EDS)", "fy26_current": 9.128, "fy26_request": 9.128, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 2.185, "fy27": 2.312, "name": "System (EHRIS)", "fy26_current": 2.244, "fy26_request": 2.244, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 9.798, "fy27": 17.826, "name": "DMDC - Identity Credential Management (ICM)", "fy26_current": 15.646, "fy26_request": 15.646, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 2.358, "fy27": 2.48, "name": "DMDC - Personnel Support Programs (PSP)", "fy26_current": 2.406, "fy26_request": 2.406, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 0.306, "fy27": 0.859, "name": "DPAC - Office of People Analytics (OPA)", "fy26_current": 0.835, "fy26_request": 0.835, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 0.005, "fy27": 0.123, "name": "(CAP)", "fy26_current": 0.12, "fy26_request": 0.12, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 0.109, "fy27": 0.35, "name": "Support (DANTES)", "fy26_current": 0.407, "fy26_request": 0.407, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 0.218, "fy27": 0.288, "name": "Education Office (DLNSEO)", "fy26_current": 0.28, "fy26_request": 0.28, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 0.255, "fy27": 0.4, "name": "DSSC - Defense Travel Management Office (DTMO)", "fy26_current": 0.388, "fy26_request": 0.388, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 0.243, "fy27": 0.375, "name": "(ESGR)", "fy26_current": 0.363, "fy26_request": 0.363, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 0.116, "fy27": 0.107, "name": "DSSC - Federal Voting Assistance Program (FVAP)", "fy26_current": 0.104, "fy26_request": 0.104, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 0.1, "fy27": 1.494, "name": "DSSC - Military-Civilian Transition Office (MCTO)", "fy26_current": 1.45, "fy26_request": 1.45, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 0.109, "fy27": 0.309, "name": "(SAPRO)", "fy26_current": 0.299, "fy26_request": 0.299, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part1/DHRA_Cyber_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dhra_umbrella$$, $$DHRA$$, $$Defense Human Resources Activity$$, $$DHRA$$, $$om_dw_ba04$$, NULL, $$dw_dhra$$, 2026, 1060194000, 1104152000, -61542000, -5.57, 1042610000, 932144000, $$The Defense Human Resources Activity (DHRA) is a Field Activity of the Under Secretary of Defense for Personnel & Readiness (USD(P&R)) that consists of multiple direct reporting units. The DHRA gives USD(P&R) greater capability and flexibility in managing the work of a diverse set of activities supporting the Department of Defense (DoD) Human Resources (HR) mission. Each Center/Office organization within DHRA has a unique but complementary mission set. The DHRA Mission Support serves as an intermediary between the Centers/Offices and provides planning, programming, and budgeting for all activities within the DHRA enterprise, to include executing, coordinating, and providing direct oversight to the work of each Center/Office. The DHRA ensures that the Department’s warfighters present and past, along with their families and civilian members of the Department, receive the care and support they deserve, fairly, and in a timely fashion, through benefits administration, program execution, and policy enforcement. The DHRA budget funds execution of the Field Activity’s mission to: • Organize, direct, and manage all assigned resources, to include the programs described herein. • Design and manage DHRA programs and activities to improve standards of performance, economy, and efficiency. • Maintain a central repository of DoD HR information, both current and historic; approximately 45.3 million records currently in repository. • Provide program and policy support and associated information management and administrative services to the DoD Components on civilian HR matters. • Provide DoD-wide guidance on civilian personnel policy implementation and professional development programs (except with regard to Defense Civilian Intelligence Personnel System, where guidance is developed by the Under Secretary of Defense for Intelligence in conjunction with the USD(P&R)). • Provide rapid data-driven analytic solutions to support the decision-making needs to effectively maintain the readiness of the All-Volunteer Force. • Support the development of policy and administer the sexual assault prevention and response policies and programs for DoD. • Support the development of policy and administer the suicide prevention policies and programs for the DoD. • Support the development of policy and administer transition assistance programs for approximately 200,000 eligible Service members who separate, retire, or are released from active duty each year. • Develop policy and administer the combating trafficking in persons’ policies and programs for the DoD. DHRA 237 •   Support the development DoD civilian personnel policies while providing consulting/advisory services, programs, and solutions that strengthen the mission readiness and morale of DoD HR professionals and directly impact the more than 900,000 civilian employees that make up the DoD civilian workforce. •   Assist in the establishment and administration of policy regarding the development, maintenance, and utilization of language capabilities; monitor trends in the promotion, accession, and retention of individuals with critical skills; and explore innovative concepts to expand language capabilities. •   Serve as the single focal point for commercial travel within the DoD for approximately 2.9 million DoD Service members and civilian personnel; assist in establishing strategic direction and in establishing and administering travel policy; centrally manage all commercial travel programs. •   Develop policy for DoD identification cards distributed to members of the Military, DoD civilians, contractors, and other eligible personnel and execute associated programs and capabilities, approximately 425,000 cards issued monthly. •   Serve as the authoritative source of identification and authentication of DoD-affiliated personnel for credentialing, identity protection, security, entitlements, and benefits verification. •   Administer the federal responsibilities of the Uniformed and Overseas Citizens Absentee Voting Act of 1986 (UOCAVA), as most recently amended by the Military Overseas Voter Empowerment Act (MOVE Act) to approximately 2.8 million overseas citizens who are eligible to vote. •   Provide assistive technology to approximately 292,000 potential DoD civilian employees and Service members to allow DoD and federal employees with disabilities to access electronic and information technology. •   Assist approximately 650,000 Service members and Veterans to pursue their educational goals and earn degrees or certifications during and after their service. •   Perform the technical research support needed to assess the impact and effectiveness of many P&R programs and policies which provides both evidence for DoD Leadership to base decisions on, and researched findings that identify opportunities to strengthen the All- Volunteer Force. •   Provide a Center of Excellence for training, education, research, and consultation in matters related to military and civilian equal opportunity; and the prevention and response to sexual harassment, harassment, hazing and bullying across the Total Force. The Field Activity is comprised of operational programs that support the OUSD(P&R) in its mission to develop policies, plans, and programs that will ensure the readiness of the Total Force and the well-being of military families. The Field Activity supports the USD(P&R) vision of creating an organization dedicated and committed to the readiness of the Department’s Service men and women, their families, and civilian employees. DHRA 238 Narrative Explanation of Changes: The FY 2026 DHRA budget represents a net programmatic decrease of approximately $126.8 million with a price growth of $16.4 million. Defense Civilian Personnel Advisory Service (DCPAS): (Dollars in Thousands) FY 2024                FY 2025                   FY 2026 39,936                 35,071                    32,333 The DoD civilian workforce represents more than a third of the Total Force. These employees provide direct and indirect support to the warfighter across numerous disciplines, such as engineering, supply management, information technology, cybersecurity, intelligence and financial management. Established in 1993, DCPAS provides enterprise leadership in HR management. The DCPAS directly supports the development and administration of innovative and fiscally responsible DoD civilian personnel policies, plans, and programs that directly support the HR lifecycle for the more than 900,000 DoD civilian employees worldwide. The DCPAS organization is structured under seven major functional areas: Planning and Accountability (strategic planning, skill and competency gap analysis, workforce data analytics, and accountability); Employment and Compensation (recruitment, staffing, compensation and workforce shaping); Benefits, Wage, and Non-appropriated Fund (NAF) Policy (benefits, work-life, injury and unemployment compensation, NAF policy and program, and Wage Surveys); Talent Development (training, education, and professional development); Labor and Employee Relations (local labor-management engagement, union pre-decisional involvement, employee performance management); Executive Resource Management (policies, programs, and procedures to support lifecycle management of all DoD Senior Executives); and Enterprise Solutions and Integration (functional oversight for the Defense Civilian Human Resources Management Systems Portfolio Development, Modernization and Sustainment, USA Staffing, electronic Official Personnel Folder (eOPF), Human Resources Line of Business (HRLoB)). Each functional area has a policy, training, advisory and operational role in support of the Services and Components. The DCPAS’s goals and objectives continue to support the military departments and defense agencies as the enterprise leader in developing and delivering human resources solutions that strengthen the nation’s mission readiness. For additional information, please visit https://www.dcpas.osd.mil. DHRA 239 Defense Suicide Prevention Office (DSPO): (Dollars in Thousands) FY 2024                FY 2025                    FY 2026 34,614                 35,248                     38,197 The DSPO was established in 2012 and is part of the DoD Office of the USD(P&R). The creation of DSPO was the result of a recommendation by the congressionally-established Task Force on the Prevention of Suicide by Members of the Armed Forces. The DSPO oversees all strategic development, implementation, centralization, standardization, communication and evaluation of DoD suicide and risk reduction programs, policies, and surveillance activities. The DSPO develops and publishes DoD’s Annual Report on Suicide in the Military as well as the Quarterly Suicide Report. To reduce the impact of suicide on Service members and their families, DSPO uses a range of approaches related to policy, research, communications, and law, working and responding to policy-makers and leaders in the suicide prevention field. The DSPO works to empower those organizations that are directly responsible for suicide prevention by investing in systems that have quality, validated data and fomenting the translation of quality research into actionable results. The DSPO’s data surveillance activities help with the proactive identification of at-risk populations and facilitate the development and dissemination of content that informs analysis, decision-making, training, and awareness. Grounded in a collaborative approach, DSPO works with the Military Services and other agencies to support our military community and foster a climate that reduces stigma and encourages help-seeking behaviors. The DSPO provides oversight over suicide prevention efforts across DoD, to include overseeing the implementation of the Suicide Prevention and Response Independent Review Committee (SPRIRC) recommendations. It also works to implement the actions from the SPRIRC that are intended to improve Service member well-being and to review the suicide prevention and response programs and other factors that may contribute to the incidence or prevention of suicide across the Total Force. For additional information, please visit https://www.dspo.mil. Defense Equal Opportunity Management Institute (DEOMI): (Dollars in Thousands) FY 2024                FY 2025                    FY 2026 5,928                   6,522                     5,194 The DEOMI is sole provider in the Department charged to educate, train, and sustain the Military Equal Opportunity (MEO) professional workforces for all active duty, Reserve, National Guard, and Coast Guard. In addition, DEOMI develops and distributes online training on key topics for approximately 30,000 students annually. The DEOMI’s mission is to foster cultures of excellence through learning, research, and integrated knowledge management to optimize Total Force readiness. The program provides education and training, develops field products, conducts research, evaluates programs, and provides clearinghouse on organizational culture per DoD Instruction (DoDI) 1350.02 (DoD Military DHRA 240 Equal Opportunity (MEO) Program), DoDI 1020.03 (Harassment Prevention and Response in the Armed Forces), and DoDI 1020.04 (Harassment Prevention and Responses for DoD Civilian Employees). For additional information, please visit https://www.deomi.mil. Defense Manpower Data Center (DMDC) manages the following programs: • Defense Enrollment Eligibility Reporting System (DEERS) • Enterprise Data Service (EDS) • Enterprise Human Resource Information System (EHRIS) • Identity Credential Management (ICM) • Personnel Support Programs (PSP), formerly known as Personnel Accountability and Security (PAS) For additional information, please visit https://dwp.dmdc.osd.mil. DMDC - Defense Enrollment Eligibility Reporting System (DEERS): (Dollars in Thousands) FY 2024                FY 2025                    FY 2026 70,880                 76,554                     81,921 The DEERS is DoD’s authoritative eligibility and enrollment repository for manpower, personnel identity, and affiliation data on military, civilians, retirees, family members, and other populations. The DEERS includes identity and personnel data for roughly 80 million persons, including current, retired, and former members of the eight Uniformed Services and their family members. In addition, DEERS maintains records for Veterans and their caregivers. The DEERS derives DoD benefits for members of all components of the Uniformed Services, including Active Duty, Reserve, National Guard, and retired personnel and their family members. Data is received from DoD and other personnel and finance systems, as well as through adds/updates made at Real-time Automated Personnel Identification System (RAPIDS) stations worldwide. In addition, DEERS supports access to DoD benefits such as commissary, exchange, and morale-welfare services for a growing number of current and former DoD populations, including disabled Veterans and their caregivers and Medal of Honor and Purple Heart recipients. The DEERS program is comprised of subprograms centered on support for the Affordable Care Act (ACA), Benefits and Entitlements, and Electronic Health Record and the Virtual Lifetime Electronic Record (EHRM/VLER). All DEERS programs are conducted in accordance with DoD cybersecurity standards and Personally Identifiable Information (PII) directives. - The ACA provides data services supporting the Centers for Medicare and Medicaid Services Health Insurance Marketplace maintaining and providing DoD medical coverage information as required under the ACA. The DEERS also provides DoD health care coverage information to the DHRA 241 Uniformed Services pay centers to generate required Minimum Essential Coverage reports, individual 1095 tax forms, and employer Internal Revenue Service (IRS) reporting. - Benefits and Entitlements provides real-time determination of eligibility for DoD entitlements (including medical, dental, life insurance, education, and commissary programs) and Morale, Welfare and Recreation activities (such as Exchange privileges and recreational activities) for 10 million Service members, retirees, and their families. Since 2020, DEERS has supported expanded commissary and exchange privileges for disabled Veterans and their caregivers as well as Medal of Honor and Purple Heart recipients in coordination with the Department of Veterans Affairs (VA) and has been integral in identifying and supporting VA benefits processes under the Honoring our Promise to Address Comprehensive Toxics (PACT) Act. The DEERS manages all TRICARE enrollments for the Military Health System. It provides enrollment and eligibility verification data on a real-time basis to thousands of DoD locations worldwide, ensuring DoD provides consistent entitlements and benefits across time and location. The DEERS also provides personalized responses to individual inquiries about specific benefits and entitlements, through self-service offerings and the DMDC Support Center. - The EHRM/VLER programs provide support for evolving efforts to modernize medical records that can be used across the Federal enclave to support care in facilities managed by DoD, the VA, and other Federal partners. The DEERS administers medical and other benefits seamlessly as individuals move through a “virtual lifetime” in the Uniformed Services and VA. The DEERS provides authoritative patient identity for the shared record, supporting correlation of patient records between legacy DoD and VA systems and identification and correction of potential duplicate records in the Person Data Repository (PDR), the authoritative personnel repository for DoD. The DEERS supports the joint exchange of DoD and VA medical record data with commercial and other partners as part of the nationwide Health Information Exchange. Further, the EHRM/VLER programs provide authoritative and certified records for all periods of military duty to support DoD reporting. Active Duty and Reserve/Guard records are shared with the VA to support eligibility determination for VA benefits, including disability payments, provision of health care, education benefits, home loans, and cemetery programs. The VLER programs provide critical data to support VA programs to implement the PACT Act. The DEERS provides entitlement information to support the extension of Exchange and Morale, Welfare and Recreation privileges to more than 30 million veterans, their families, and caregivers. Finally, DEERS runs programs to identify improper medical claims payments based on loss of eligibility comparisons, sharing these with the Defense Health Agency to fuel significant cost recovery and deter fraud. DMDC - Enterprise Data Service (EDS): (Dollars in Thousands) FY 2024                FY 2025                    FY 2026 125,171                 132,924                   108,230 The EDS governs the collection, storage, and distribution of DMDC data assets safeguarded by the security mechanisms which ensure compliance with DoD cybersecurity standards and the PII directives. The EDS program is comprised of Data Governance and Data Operations and Enterprise Information Technology (IT) Business Services subprograms. DHRA 242 - Data Governance and Data Operations oversees the collection, custodial storage, and use of DMDC Enterprise Data assets. This subprogram applies data governance practices to the maintenance of the Personnel Data Repository and maintains the Automated Data Repository, the data- mart that maintains the current snapshot of every person in the PDR. This subprogram supports DMDC Enterprise Data efforts, including: •   Identity Web Services provides core DoD benefit, affiliation, personnel, and identity data to hundreds of provisioned DoD organizations and other Federal agencies through real-time and batch services. •   The DoD Person Search application enables authorized users to search DoD personnel and obtain limited data about those personnel and their dependents. •   Data Acquisition collects and maintains personnel records on each member of the Active and Reserve Components as well as retired and civilian DoD communities, for research, actuarial analysis, interagency reporting, and evaluation of DoD programs and policies. •   Uniformed Services Human Resources Information System (USHRIS) reduces or eliminates redundant military personnel, pay, and manpower databases under a new single, modernized, Total Force military human resources information system for DoD. The USHRIS ensures data quality for all managed data feeds and makes data available to most other DMDC missions that aligns to existing DoD policy requirements. •   Information Delivery and Decision Support fulfills over 4,000 data requests per year for information used to make critical data-driven decisions and provide information for speeches, Congressional testimony, policy support, DoD and Federal decision support, research, law enforcement, FOIA, legislative affairs, public affairs, military personnel and policy, readiness, health affairs, reserve affairs, suicide prevention, personnel security, and transition assistance. And supports a variety of self-service reports and the DoD occupational crosswalk known as the Occupational Database. •   The PDR is the central repository of all DoD personnel (uniformed and civilian DoD personnel, DoD beneficiaries, DoD contractors, and personnel with access to DoD facilities and systems), DoD benefits and identity data. Includes satellite databases such as the Medical Data Repository (MDR), VA Satellite, and RAPIDS database. •   Data Governance operations, including metadata management, master data management, data lineage, and other data governance activities of all DMDC data stores. •   Beacon is the DHRA enclave of the OUSD(C) ADVANA environment. Beacon is a single application that serves as the central repository for all DHRA reporting data and all reporting and analytical functionality and services. Several products are scheduled to move into the Beacon enclave, including the Recruit Market Information System (RMIS), Civilian Personnel Data Warehouse, Military Performance Metrics (MPM) and the Military Morbidity Database (MMDB). Beacon will also provide an Analytics Environment for use by DHRA research customers. This program also manages the transfer of large portions of DMDC HR data holdings to Advana for Department-wide use. DHRA 243 •   Shared Core Services supports application data security provisioning and enforcement, DoD enterprise access control web services, common update framework and data access layer, quality analysis data copy services, common upload/download services, and system event scheduling. Enterprise IT Business Services supports the delivery of effective IT business services to DHRA stakeholders, maximizing the availability, performance, and compliance of IT solutions. Enables data driven IT Investment decisions through Portfolio Management and Enterprise Architecture. Delivers IT business tools and leverages technology and innovation to provide modern hosting environments and work environments that utilize IT tools effectively. •   Data Delivery Services (DDS) provides an automated, real time, streamlined direct access to DMDC databases for authorized customers using web services and application programming interfaces (API). DDS will make more efficient DMDC internal data sharing and processes and improve data sharing with customers. This supports specific customer requirements, aligns DMDC data sharing with the DoD Data Strategy, supports the DoD Identity Credential Access Management (ICAM) and Zero Trust Strategies, leverages modern cloud native technologies and will rationalize and replace outdated legacy technologies. - Enterprise IT Business Services supports the delivery of effective IT business services to DHRA stakeholders, maximizing the availability, performance, and compliance of IT solutions; enables data driven IT Investment decisions through Portfolio Management and Enterprise Architecture; delivers IT business tools; and leverages technology and innovation to provide modern hosting environments and work environments that utilize IT tools effectively. This is comprised of: •   Cloud Center of Excellence (CoE) for sustainment and operations of the DHRA approved cloud hosting enterprise information environments: Fit-for-purpose Cloud (FitCloud), and General-purpose Cloud (GenCloud) cloud infrastructure. As part of the Cloud Strategy, December 2018, the DoD Chief Information Officer (CIO) has directed migration of DoD-managed on-premises facilities to the cloud to accelerate speed to capability, provide assured cybersecurity, and rapidly changing mission needs. •   DHRA ServiceNow (SNOW) supports the definition, implementation, and sustainment of the enterprise service management framework that integrates DHRA business processes, IT service operations, and operational dashboards. SNOW supports the Consolidated Customer Center (CCC) helpdesk ticketing system, as well as the DMDC Defense Information Systems Agency (DISA) IT Service Management helpdesk ticketing system supporting IT system operations and user IT. DMDC - Enterprise Human Resource Information System (EHRIS): (Dollars in Thousands) FY 2024               FY 2025                  FY 2026 64,882                59,108                   36,027 The EHRIS program is responsible for developing and maintaining the systems that support Civilian HR Management (CHRM) processes across DoD and is comprised of the legacy Defense Civilian Personnel Data System (DCPDS) and Civilian HR IT Program Planning and Management subprograms. DHRA 244 - Civilian Human Resources (HR) Information Technology (IT) Enterprise Services is responsible for the development, operations, and sustainment of all enterprise civilian HR IT capabilities not provided by DCPDS. These systems support DoD-wide business functions, to include unemployment and injury compensation management; equal employment opportunity (EEO) complaint investigations; labor and employee relations case management; senior executive performance and talent management; strategic human capital management (HCM) analysis and planning; and the priority placement program. - Civilian HR IT Program Planning and Management centralizes civilian HR IT planning and strategy activities within DMDC to create an integrated plan that both aligns with higher level guidance and takes into account requirements and priorities across the Department for automation of civilian HR IT processes. This program works with functional sponsors and users to produce validated functional requirements, as well as technical requirements that apply to all DoD HR IT systems and provides oversight of CHRM IT systems across the Department to ensure capabilities are not duplicated and to enforce enterprise level CHRM IT systems. DMDC - Identity Credential Management (ICM): (Dollars in Thousands) FY 2024               FY 2025                   FY 2026 92,181                94,945                   112,483 The ICM program supports identity data updates and the issuance of identification cards to Service members, civilian employees, contractors, retirees and other Federal partners. The program sustains the RAPIDS/Common Access Card (CAC), and Identity Services. - RAPIDS/CAC provides the global system of software and hardware that issues official DoD ID cards to eligible personnel. RAPIDS/CAC provides the worldwide infrastructure to securely produce the CAC and associated public key infrastructure (PKI) certificates. The CAC facilitates access to DoD bases and installations, DoD networks and computers, and DoD benefits and entitlements. RAPIDS is the authoritative means to register new family members with the DoD so they can receive benefits and entitlements. RAPIDS also securely produces the Uniformed Service Identification (USID) card used by uniformed service retirees, family members, Inactive Ready Reserve, Medal of Honor recipients, 100 percent Disabled American Veterans, and other personnel categories to facilitate access to DoD bases and installations, and benefits and entitlements. - Identity Services consists of systems that DMDC developed to credential and authenticate non-CAC eligible beneficiaries and individuals with a need for access to a DoD owned resource. Identity Services include the DoD Self-Service Logon, a secure, self-service credential providing access to personally identifiable information and personal health information across many applications within the DoD and Department of Veteran Affairs and Identity, Credential, and Access Management (ICAM) services such as the Mission Partner Registry, Multi-Factor Authentication (MFA) Credential Registry and Backend Attribute Exchange to facilitate the registration and sponsorship of DoD Mission Partner’s and their externally issued credentials and the associated attribute exchange service to facilitate logical access for Mission Partners to DoD Assets. The NIPRNet Enterprise Alternate Token Management System (NEATS)/Alternate Token Issuance and Management System (ATIMS) is a centralized token DHRA 245 management system for medium assurance DoD PKI certificates on NEATS tokens, also known as Alternate Logon Tokens (ALT), for use cases to include administrators, groups, roles, code signing, and individuals not authorized to receive a CAC. NEATS is an Acquisition Category I Program. DMDC - Personnel Support Programs (PSP): (Dollars in Thousands) FY 2024               FY 2025                  FY 2026 31,770                30,885                   45,992 The PSP enhances the effectiveness & readiness of the department by providing comprehensive and efficient IT Program services while remaining committed to ensuring the safety, well-being, and support of all DoD personnel by delivering accurate and timely information and services. The PSP sub-programs include: - The Defense Personnel Accountability Systems support a collection of applications and web services which gather, analyze, and share information on the physical location of DoD members and affiliated personnel, including, Personnel Accountability Reporting System (PARS), Personnel Location Exchange Suite (PLX), and Joint Personnel Accounting Reconciliation and Reporting System (JPARR). - The Defense Travel System (DTS) provides an automated, end-to-end travel management system that enables DoD travelers to create authorizations and travel orders, prepare reservations, receive approvals, generate travel vouchers, and receive reimbursement. Supports the development, and deployment of modernized travel management services. - The NEO Tracking System (NTS) and Emergency Tracking Accountability System (ETAS) are an integrated hardware/software platform used during Large Scale Evacuations Non-Combatant Evacuation Operations (NEO) and/or Mass Casualty Events to account for, and sustain visibility of, noncombatant evacuees during a NEO and/or during continental U.S. (CONUS) events. These systems provide accountability for evacuees by creating a database of evacuees and tracking their movement throughout the evacuation process. - Personnel Data Reporting Systems include applications that use the personnel data received by DMDC from DoD authoritative sources to provide effective information management services for DoD Agencies, Services, DoD Field Activities, Joint Staff, Combatant Commands (CCMD), Joint Staff, Service members, and veterans such as.: •   Defense Personnel Records Information Retrieval System (DPRIS) provides a single secure source to electronically request and retrieve Official Military Personnel File (OMPF) data for DoD, VA, Department of Labor (DoL) benefits, to include the DD Form 214 in near real time. DHRA 246 •   Defense Sexual Assault Incident Database (DSAID) is the Department’s authoritative, centralized case-level database used to collect and maintain information on sexual assaults involving members of the Armed Forces, including tracking and reporting on sexual assault-related retaliation data. DoD SAPRO operates DSAID and works collaboratively with the Services to implement and sustain the system, conduct oversight, inform DoD planning and analysis, and report as required in law to Congress. DSAID needs modernization of its Case Synopsis Module which tracks Subject case outcomes required to meet section 563 of the National Defense Authorization Act (NDAA) for FY 2009, and an interface between DSAID and ADVANA (Advanced Analytics). •   Financial Readiness Systems (FRS) includes the Servicemembers Civil Relief Act (SCRA) and Military Lending Act (MLA) applications. SCRA allows users to verify the military status of active duty, reserve, and National Guard members on specific date(s) for the purpose of postponing or suspending certain civil, legal and financial obligations. MLA allows users to determine whether an individual is entitled to MLA protections, including interest rate caps and fee limitations. •   General and Flag Officer (GO/FO) serves as the authoritative DoD enterprise system that tracks nominations, appointments, and other actions of GO/FO, O6 and below promotion nominations and original appointments. •   Joint Duty Assignment Management Information System (JDAMIS) centralizes the ability to view and manage both the Joint Duty billets and officers assigned to them and manage officer promotions and joint qualifications. •   Military Recruiter Information System (MRIS) provides reenlistment eligibility, prior service military selection, recruiter access to high schools, and recruit market analysis. - The Synchronized Predeployment and Operational Tracker – Enterprise Suite (SPOT‐ES) is the joint enterprise suite of products that serve as the central repository of information on operational contract support for contingency, humanitarian, and peacekeeping missions Outside Continental U.S. (OCONUS) worldwide. SPOT is the federally mandated authoritative database for operational contract support required by Public Law 110-181, 48 Code of Federal Regulations (CFR) subpart 225.3, and 32 CFR Part 158. It is deployed over both classified and unclassified networks, allowing access to individual contractor identity, movement data, contractor-owned equipment, and associated contract-related information. SPOT includes a workflow process that generates digitally signed Letters of Authorization (LOAs) that identify authorized government services as part of the deployment process for overseas contractors. Defense Personnel Analytics Center (DPAC) manages the following programs: • DoD Office of the Actuary (OACT) • Office of People Analytics (OPA) DHRA 247 DPAC - Office of the Actuary (OACT): (Dollars in Thousands) FY 2024                FY 2025                   FY 2026 2,091                   2,505                    2,702 The DoD OACT program consists of two functional areas - OACT and the DoD Station and Housing Allowances. DoD OACT participates in financial statement audit committees for the Military Retirement Fund (MRF) and the Medicare-Eligible Retiree Health Care Fund (MERHCF). The DoD Inspector General audits the MRF and MERHCF financial statements. The MRF statements have consistently received an unqualified audit opinion. OACT computes DoD and Treasury Fund contributions for inclusion in annual budgets and estimates the MRF and MERHCF liabilities for DoD and government-wide annual financial statements. OACT also makes calculations for the Education Benefits Fund (EBF) and the Voluntary Separation Incentive Fund (VSIF). OACT calculates DoD’s and Treasury’s required annual contributions into and the liabilities of each of the EBF and VSIF using methods and assumptions approved by the DoD Board of Actuaries and the DoD Medicare- Eligible Retiree Health Care Board of Actuaries. DoD OACT produces cost estimates for legislative proposals involving military benefits (such as Combat-Related Special Compensation, Concurrent Receipt Disability Pay, and the Blended Retirement System) and adapts retirement, education benefits, and retiree health care system valuation models to legislated changes. In addition, OACT participates in various groups and commissions studying military benefits, such as the Quadrennial Review of Military Compensation, the Military Compensation and Retirement Modernization Commission, and the Blended Retirement System Working Group. For additional information, please visit https://www.actuary.defense.gov. The DoD Station and Housing Allowances program governs the Department’s annual $30 billion station and housing allowances portfolio for the OUSD(P&R) Military Compensation Policy Directorate. This is accomplished by acquiring and analyzing housing and cost-of-living data to determine military compensation through the Basic Allowance for Housing (BAH), Overseas Housing Allowance (OHA), OCONUS Cost of Living Allowance (OCONUS COLA), and CONUS COLA for members of the eight Uniformed Services. The program is also responsible for managing the policy and regulations governing these allowances, as well as the Temporary Lodging Allowance, though the DoD Financial Management Regulations. For additional information, please visit https://www.travel.dod.mil/Allowances/. DHRA 248 DPAC - Office of People Analytics (OPA): (Dollars in Thousands) FY 2024               FY 2025                   FY 2026 130,202                120,788                  112,960 The OPA provides high-quality, timely research and analytic insights, products and tools that drive OUSD(P&R) program and policy decision-making. The OPA is comprised of four functional areas: Recruitment and Outreach Research, Testing and Assessment, Health and Resilience, and Retention and Readiness, with cross-cutting support from the Statistics, Data Science, and Analytics team and the Research Strategy, Policy and Dissemination team. OPA continues to leverage synergies, coordinate missions, and provide DoD Leadership with evidence-based research recommendations to improve programs and policies that strengthen the All-Volunteer Force. -Recruitment and Outreach Research - Joint Advertising, Market Research and Studies (JAMRS) enables DoD Leadership and the Armed Services to make informed research-based recruiting decisions, eliminating unnecessary redundancies across the recruiting communities, and conduct focused outreach efforts that are distinct from—yet integral to—those of the Armed Services to preserve and enhance the All- Volunteer Force, in support of Accession Policy within OUSD(P&R). Within the DoD, JAMRS has the sole responsibility for monitoring the youth market and providing timely, accurate, and actionable information regarding youths’ interest in and reasons for joining, as well as influencers’ attitudes toward, military service. In essence, JAMRS ensures shared information needs required for military recruiting are met and duplication of efforts are minimized. Further, JAMRS has sole responsibility for compiling, processing, storing, and distributing prospect lists that are the foundation of the Armed Services’ recruiting outreach efforts. JAMRS also executes targeted outreach efforts designed to elevate perceptions as well as consideration of military careers among young adults and their influencers during the career decision making process. These outreach efforts increase awareness and advocacy of the military and create a more fertile and cost- effective recruiting environment for the Armed Services. -Testing and Assessment, also known as the Defense Testing and Assessment Center (DTAC), develops, administers, deploys and continuously evaluates DoD selection and classification tools including the Armed Services Vocational Aptitude Battery (ASVAB) test and the Tailored Adaptive Personality Assessment System (TAPAS), in support of Accession Policy within OUSD(P&R). The ASVAB testing program enables the Armed Services to recruit and select highly qualified military recruits based on cognitive factors. It is administered annually to approximately 360,000 applicants for Military Service as part of the DoD Enlistment Testing program, and the ASVAB is administered to over 700,000 students in more than 13,000 high schools and post-secondary schools via the ASVAB career Exploration Program. The DoD uses a single test, the ASVAB, to determine eligibility of military applicants and to report recruit quality data to Congress. Through the ASVAB Career Exploration Program (CEP), DTAC administers the ASVAB to high school students as a career counseling tool and as a source of qualified prospects for the Military Services. The TAPAS testing program enables the Armed Services to recruit and select highly qualified military recruits based on non-cognitive factors. Finally, DTAC supports the development and DHRA 249 maintenance of the Nation’s foreign language testing capabilities in support of the Defense Language and National Security Education Office (DLNSEO). -Health and Resilience conducts high-quality, timely research and analysis in support of the Office of Force Resiliency enterprise within OUSD(P&R) regarding the behavioral health and wellbeing of the entire DoD community, with a focus on sexual assault, harassment, discrimination, suicide, and command climate. This research includes the administration and reporting of multiple large-scale, congressionally mandated scientific surveys, including the Workplace Experiences Survey and the Service Academy Experiences Survey, and the Defense Organizational Climate Survey (DEOCS), as well as various qualitative and advanced data analytic research techniques. -Retention and Readiness conducts high-quality, timely research and analysis in support of the Manpower & Reserve Affairs enterprise within OUSD(P&R) regarding the retention and quality of life of the DoD community, including retention intentions, satisfaction with military life, housing, financial readiness, access to food, spouse unemployment, and the impacts of Permanent Change of Station (PCS) moves. This research includes the administration and reporting of multiple long-standing scientific surveys, including the Status of Forces Survey (Active and Reserve) and the Spouse Survey (Active and Reserve), as well as qualitative and advanced data analytic research techniques. -Statistics, Data Science, and Analytics supports the four functional areas in OPA by providing enterprise-wide data science, statistical methods, analytics, and survey operations expertise. Statistics, Data Science, and Analytics leverages a collaborative analytic environment to conduct state-of-the-art analytic work including data architecture development, data acquisition and preparation, predictive analysis, small area estimation techniques, natural language processing, survey sampling, weighting for survey nonresponse, assessment of missing data and nonresponse bias, estimating the precision of survey estimates, and survey dataset creation and documentation. Statistics, Data Science, and Analytics creates analytic products and tools that increase efficiency and accelerate analytic capabilities across OPA’s four functional areas. Statistics, Data Science, and Analytics also provides enterprise ad-hoc analytic support capability across OPA’s four functional areas. -Research Strategy, Policy, and Dissemination supports the four functional areas in OPA by providing cross-cutting nontechnical support. The division provides OPA research strategy, DoD-wide survey strategy and policy, OPA research dissemination and product improvement, and OPA communication and stakeholder outreach support. Examples include maintaining compliant and effective procedures for OPA data sharing; overseeing OPA research project ingest and prioritization; external strategic communications; data visualizations and interpretation; science communication expertise; and oversight and execution of the requirements of the DoDI 1100.13 “DoD Surveys”. For additional information, please visit https://www.opa.mil. DHRA 250 Defense Support Service Center (DSSC) manages the following programs: • Computer/Electronic Accommodations Program (CAP) • Defense Activity for Non-Traditional Education Support (DANTES) • Defense Language and National Security Education Office (DLNSEO) • Equal Employment Opportunity (EEO), formerly Diversity Management Operations (DMO) • Defense Travel Management Office (DTMO) • Employer Support of the Guard and Reserves (ESGR) • Federal Voting Assistance Program (FVAP) • Military-Civilian Transition Office (MCTO) DSSC - Computer/Electronic Accommodations Program (CAP): (Dollars in Thousands) FY 2024               FY 2025                    FY 2026 7,532                  5,920                     3,733 The CAP is recognized by the U.S. Office of Personnel Management as a model program to increase DoD Federal employment opportunity for individuals with targeted and significant disabilities. Since 1990, the program has provided over 246,000 accommodations to more than 98,000 DoD civilian employees and Service members. CAP is widely recognized as the principal source on providing disability employment subject matter expertise, assistive technology (AT) solutions, and employment support services. This program eliminates barriers and advances employment for DoD civilians with disabilities. In 2015, CAP’s scope was expanded under the DoD Instruction, AT for Wounded, Ill and Injured Service Members (DoDI 6025.22) which established DoD wide policy for programs in the Military Health System and the Recovery Coordination Program. Approximately 2.8 million customers (DoD employees, wounded, ill and injured Service members, active-duty Service members, and reserve military personnel) are potentially eligible for CAP AT products and services at no cost to the customer or their DoD agency. For additional information, please visit https://www.cap.mil. DHRA 251 DSSC - Defense Activity for Non-Traditional Education Support (DANTES): (Dollars in Thousands) FY 2024                FY 2025                    FY 2026 13,585                 11,046                     9,923 The DANTES Mission Programs deliver the Department’s portfolio of voluntary educational opportunities that supports approximately 650,000 Service members in reaching their educational and civilian transition goals. DANTES Mission Programs support the Office of the Assistant Secretary of Defense (OASD), Military Personnel Policy (Officer and Enlisted Personnel Management), Voluntary Education (VolEd) mission, by managing a portfolio of programs and partnerships that enable access to quality postsecondary educational opportunities, empower informed Service member decision-making, shape meaningful personal and professional pathways, and drive military student success in higher education. The consolidated management of programs prevents duplication of effort among the Services. Through its activities, DANTES supports DoD recruitment, retention, readiness and transition efforts. The DANTES Mission Programs include the following sub-programs: -College and Career Readiness programs help Service members develop individual education and career pathways, prepare for online learning experiences, and search and compare academic institutions that have been vetted for quality and value. -Defense Education Partnership programs maximize postsecondary educational opportunities for Service members by facilitating educational institution compliance with Defense Tuition Assistance policies and managing academic institutional partnerships that provide student protections and access to basic skills through graduate level education, academic testing, and language training including in forward deployed areas. -Credit for Prior Learning programs enable Service members to earn college credit recommendations through prior learning (credit by examination) and military training and occupational experience (American Council on Education course evaluation). These college credit recommendations help Service members and veterans succeed by reducing the number of courses needed to satisfy degree requirements, saving time and avoiding tuition assistance costs. -Voluntary Education Enterprise Support programs provide tailored VolEd workforce professional development activities and resources, coupled with key information technology infrastructure and analytic capabilities, for the VolEd enterprise that support each Service’s delivery of academic counseling, test administration, and tuition assistance services to active duty and reserve Service members. For additional information, please visit https://www.dantes.mil. DHRA 252 DSSC - Defense Language and National Security Education Office (DLNSEO): (Dollars in Thousands) FY 2024               FY 2025             FY 2026 63,471                52,410              25,268 Funding in the above table includes the following the Language Training Centers and Language Flagship Program funding profiles: (Dollars in Thousands) Program                                                    FY 2024              FY 2025      FY 2026 Language Training Centers – baseline                          0                     0           0 Language Training Centers – congressional add               15,000                  0           0 Language Flagship Program - baseline                        23,800               24,500       16,000 Language Flagship Program – congressional add                 0                   4,000         0 The DLNSEO provides strategic direction, supports policy development, and provides programmatic oversight to the Military Departments, Defense Agencies, and the CCMDs on present and future requirements related to language, regional expertise, and culture; and manages a portfolio of programs that provide language support to the Department. DLNSEO, through policy and programs, builds and sustains a combination of language, regional, and cultural capabilities to meet current, projected, and surge needs, and creates a workforce pipeline that supports U.S. national security needs for the future. The DLNSEO supports the DoD mission of building partner capacity through innovative concepts designed to expand Defense foreign language, regional, and cultural skills, and capabilities, and through English language training to support heritage recruiting. The office’s vital investment in strategic partnerships with the U.S. education community ensures a flow of highly qualified, language proficient candidates into the federal sector. Language Training Center (LTC): DLNSEO provides OSD-level guidance in the areas of language and culture training, testing, and curriculum development. It develops, recommends, and monitors policies for language, regional, and culture capabilities related to the accession, management, and utilization of members of the Armed Forces and DoD civilian employees. Language Flagship Program: DLNSEO efforts support language studies among U.S. undergraduate and graduate students who are committed to federal service in national security through nationally recognized Boren Scholarships and Fellowships, and also expand opportunities to achieve professional level proficiency in critical languages through the Language Flagship Program. For additional information, please visit https://www.dlnseo.org. DHRA 253 DSSC - Equal Employment Opportunity (EEO), formerly Diversity Management Operations (DMO): (Dollars in Thousands) FY 2024                FY 2025                    FY 2026 3,803                   2,053                     1,751 - Investigations and Resolutions Directorate (IRD): Investigates and mediates EEO discrimination complaints across the Department, including the Military Departments and Defense agencies/activities. Investigates and mediates, internal to the Department, approximately 2,500 EEO cases annually. DSSC - Defense Travel Management Office (DTMO): (Dollars in Thousands) FY 2024                FY 2025                    FY 2026 15,275                 12,166                     10,610 The DTMO serves as the focal point for commercial travel within DoD, serving approximately 2.9 million DoD Service members and civilian personnel, providing central oversight for Commercial Travel Management, Travel Policy and Implementation, Travel Card Program Management, Customer Support and Training, and Functional Oversight of DoD TDY Travel Systems. By centralizing travel functions management under one organization, the DoD standardized management practices, leveraged economies of scale, reduced administrative costs, and works towards a common set of goals. DTMO is focused on travel reform and modernization that simplifies travel policy and drives compliance, expands strategic sourcing opportunities, improves programs/processes, leverages current technologies, and reduces the overall cost of travel without impairing DoD’s mission. For additional information, please visit https://www.travel.dod.mil. DSSC - Employer Support of the Guard and Reserve (ESGR): (Dollars in Thousands) FY 2024                FY 2025                    FY 2026 9,397                   9,489                     8,302 The ESGR program fosters a culture in which all employers support and value the employment of members of the National Guard and Reserve Components (RC) in the U.S. and Territories, thereby increasing the readiness of the RCs. ESGR develops and promotes supportive work environments for Service members in the RCs through outreach, recognition, and educational opportunities that increase awareness of applicable DHRA 254 laws and resolves employer conflicts between the Service members and their employers. ESGR operates in every state, territory, and the District of Columbia through a network of 2,300 volunteers and approximately 54 support staff members to increase the readiness of the RCs. The ESGR's national engagement program increases employer and Service member awareness of their rights and responsibilities under the Uniformed Services Employment and Reemployment Rights Act (USERRA) and emphasizes employers' critical contributions to the defense of the Nation through support of their National Guard and reserve employees. ESGR provides authoritative advice and counsel to the Reserve Component staffs, National Guard and Reserve Component Chiefs, and DoD civilian leadership through the development of instructions, policies, and legislation concerning employer relations. For additional information, please visit https://www.esgr.mil. DSSC - Federal Voting Assistance Program (FVAP): (Dollars in Thousands) FY 2024               FY 2025                    FY 2026 4,005                  5,061                     4,974 The FVAP administers many of the federal responsibilities of the Uniformed and Overseas Citizens Absentee Voting Act (UOCAVA) of 1986 and other federal military voter registration and assistance laws to over 2.8 million overseas citizens eligible to vote. FVAP works to ensure Service members, their eligible family members and overseas citizens are aware of their right to vote and have the tools and resources to successfully do so – from anywhere in the world. FVAP achieves this mission through direct assistance to UOCAVA voters and works with state and local election officials. FVAP reaches out to members of the military and overseas citizens by executing a comprehensive communication and media engagement plan with a special emphasis on younger, first-time voters. These efforts include sending emails and mail pieces to all members of the Uniformed Services, conducting interactive social media activities, developing and disseminating public service announcements, and placing online advertisements in military-interest publications and on websites frequented by UOCAVA citizens. Additionally, FVAP works directly with the Military Services to provide training, information, and tools for their Voting Assistance Officers and Installation Voter Assistance Offices charged with providing in-person assistance to UOCAVA voters at command, installation, and unit levels. For additional information, please visit https://www.fvap.gov. DHRA 255 DSSC - Military-Civilian Transition Office (MCTO): The MCTO’s mission is to provide full-spectrum program management that continuously improves design, content, and delivery of timely, relevant, and meaningful information, support, services, and resources to transitioning and reintegrating Service members and their families worldwide. (Dollars in Thousands) FY 2024               FY 2025                  FY 2026 35,586                11,013                   9,236 •   Transition Assistance Program (TAP) •   Yellow Ribbon Reintegration Program (YRRP) •   Department of Defense (DoD) SkillBridge The MCTO provides TAP, YRRP, and SkillBridge program management including research, strategy, policy development, program design, budget and contract management, grant management, curriculum development, program evaluation, program assessment, program compliance, information technology (IT), public affairs, strategic communications, and outreach. MCTO ensures a common level of support, across all Military Departments and components, to respective program eligible Service members and their families at over 200 locations around the globe. MCTO manages formal DoD and federal interagency governance of transition and reintegration services and support while coordinating and collaborating with diverse stakeholders including the Department of Veterans Affairs/DoD Joint Executive Committee, TAP Interagency, DoD Manpower & Reserve Affairs (M&RA), Joint Staff, National Guard Bureau, Military Departments, employers, institutions of higher learning, entrepreneurial activities, and other governmental and non-governmental entities. MCTO resource consolidation provides streamlined program management and supports planned development of a single source, authoritative Enterprise Transition & Reintegration IT System enabling seamless management of transition and reintegration requirements across the Services and supporting federal agencies while ensuring full statutory and policy compliance. DSSC - MCTO / Transition Assistance Program (TAP): The TAP is codified in Title 10, U.S. Code, Sections 1142 and 1144, and DoD Instruction 1332.35. MCTO need to absorb SkillBridge and other programs at midyear drove increases across the programmatic portfolio with the highest increases in IT enhancements, curriculum development, training, contract support, and manpower requirements. TAP provides streamlined and effective transition assistance that effectively supports individualized transition preparation for approximately 200,000 eligible Service members who separate, retire, or are released from active duty each year. DHRA 256 The TAP design and delivery is a federal interagency collaboration led by DoD with MCTO serving as the lead agent for governance, coordination, and collaboration. The TAP Interagency is governed through a multi-agency Memorandum of Understanding (MOU) with its federal partners -- the Departments of Labor, Education, Veterans Affairs, Homeland Security as well as the Small Business Administration and the Office of Personnel Management. The MOU codifies the federal government's long-term commitment to govern, design, staff, resource, and deliver TAP at over 200 locations around the globe. The TAP is a statutory requirement for all Service members separating after 180 days of continuous active duty under Title 10. MCTO is leading a change to the Department's culture from an end-of-service transition planning commitment to a career-long approach, with individualized career readiness planning emphasized throughout a Service Member’s Military Life Cycle. Through annual curriculum refreshes, MCTO along with our federal partners, ensures career readiness and transition assistance curricula are adaptive, agile, and forward-looking to meet the needs of our Service members. MCTO oversees the Military Departments’ implementation of TAP to ensure program delivery in accordance with law, policy, and leadership intent. MCTO’s additional collaboration with other governmental and non-governmental entities fosters national support and increased opportunities to enhance Service member career readiness. The MCTO’s interagency TAP Evaluation Strategy and the planned single source, authoritative Transition & Reintegration IT Enterprise System provide a pathway for the development and implementation of enhanced program evaluation, assessment, and compliance to ensure execution of statutory and policy requirements while providing continuous improvement in TAP effectiveness. For additional information, please visit https://www.dodtap.mil. DSSC - MCTO Yellow Ribbon Reintegration Program (YRRP): The YRRP is codified in Public Law 110-181, section 582 and DoD Instruction 1342.28. The YRRP is a DoD-wide effort to promote the well-being of National Guard and Reserve Component Service members, their families, and communities, by connecting them with resources be throughout and beyond the deployment cycle. The YRRP events held around the world provide support before, during, and after activation, mobilization, or deployment for all eligible Reserve Component (RC) Service members, their families, or designated representatives. YRRP provides access to programs, services, resources, and referrals to minimize stress and maximize resiliency during all phases of the deployment cycle. YRRP events also offer information on benefits such as health care, education, and financial and legal counseling. The YRRP proactively develops and maintains collaborative efforts with federal, state, and local organizations nationwide to streamline the delivery of military information and resources. These actions ensure relevant and timely resources are accessible at YRRP events and via local community-based networks. YRRP coordinates and collaborates with numerous key organizations, including Employer Support of the National Guard and Reserve Components, Small Business Administration, and the Departments of Labor and Veterans Affairs. DHRA 257 The YRRP continuously improves the consistency and standardization of YRRP program delivery across the RCs. In addition, YRRP develops in- person and/or online curriculum to ensure flexible and agile support meeting the changing needs of RC Service members and their families. The centerpiece of this effort is YRRP’s prioritization on improving data gathering, analysis, evaluation, and assessment to determine program efficiencies, maintain cost control, and develop program enhancements to enhance the readiness, resilience, and retention of RC Service members. For additional information, please visit https://www.yellowribbon.mil. DSSC - MCTO SkillBridge Program: SkillBridge is codified in Title 10, U.S. Code, Chapter 58, Section 1143, and DoD Instruction 1322.29. SkillBridge provides eligible transitioning Service members with job training and employment skills training, including apprenticeship programs, to help prepare them for employment in the civilian sector. Participating Service members gain valuable civilian work experience through specific industry training, apprenticeships, or internships during the last 180 days of service. For Service members, SkillBridge provides an invaluable chance to develop civilian work force competencies prior to separation from active duty. For employers, SkillBridge is an opportunity to access the world's most highly trained and motivated workforce. Service members participating in SkillBridge programs continue receiving their military compensation and benefits, while industry partners provide the civilian training and work experience. Commanders can grant Service members up to 180 days of permissive duty to focus solely on civilian training full-time with industry partners. These employers offer real-world training and in-demand work experience while having the opportunity to evaluate the Service member's suitability for future employment. SkillBridge bridges the gap between a Service members' end of service and the beginning of their civilian career. Over 6,000 employers have signed MOUs with DoD SkillBridge. These partnerships resulted in over 22,000 Service members participating in SkillBridge in 2024. Those SkillBridge training opportunities resulted in an over 85 percent job offer rate, far exceeding comparative industry standards. exceeding comparative industry standards. For additional information, please visit https://skillbridge.osd.mil. DHRA 258 Mission Support: (Dollars in Thousands) FY 2024                FY 2025                    FY 2026 33,012                 31,925                     33,669 The DHRA Mission Support provides enterprise strategic direction for and oversees the implementation of strategic services focused on force management, development, and support. Mission Support accomplishes its governance role through the Office of the Director, EEO Office, Comptroller, Facilities and Security, and Human Resources. Additionally, it is responsible for the management of contracting, facilities, training, and security, along with National Capital Region transportation subsidies, Defense Finance and Accounting Services support, and Defense Logistics Agency Human Resources support. For additional information, please visit https://www.dhra.mil. Civilian Pay/Labor: (Dollars in Thousands) FY 2024                FY 2025                    FY 2026 237,406                 251,362                   222,342 The DHRA Civilian Pay/Labor program line funds civilian pay and benefits for 1,205 civilian Full Time Equivalents (FTEs) for FY 2026. Sexual Assault Prevention and Response Office (SAPRO): (Dollars in Thousands) FY 2024             FY 2025                   FY 2026 38,078              54,090                    26,297 * In FY 2025, SAPRO was the recipient of a Congressional program increase for Special Victims' Counsel. This funding is vetted by SAPRO and then reprogrammed to the Services for execution. The SAPRO represents the Secretary of Defense and serves as the single point of authority, accountability, and oversight for the sexual assault prevention and response program, in accordance with Section 1611 of the NDAA FY 2011. SAPRO promotes military readiness by reducing incidents of sexual assault through prevention, advocacy, execution of program policy, planning, and oversight across the DoD Community. DHRA 259 In addition, SAPRO: - Oversees implementation of Sexual Assault Prevention and Response (SAPR) program to prevent the crime of sexual assault and encourage military personnel, adult military dependents, and others covered by the SAPR policy, who are victims of sexual assault to report and seek victim services. - Oversees and evaluates Department-wide SAPR program effectiveness via a core set of standardized metrics measured through a standardized methodology. - Assesses the capability of the Department to respond to the needs of adult sexual assault victims in the SAPR Program. - Oversee implementation of the comprehensive policy for the DoD SAPR Program and provides oversight to ensure that the military departments are in compliance with the SAPR Policy. - Collects data through onsite visits, monitors/analyzes reports of sexual assault, and monitors/analyzes DoD surveys and other data sources to determine the efficacy of SAPR policies/programs. - Prepares annual reports to Congress on progress in eliminating and responding to sexual assault in the U.S. military writ large, as well as SAPRO’s assessment of programs to address sexual harassment and violence at the military service academies. - Oversees policy and programmatic requirements for the Defense Sexual Assault Information Database (DSAID), including DSAID user training. - Administers the DoD Sexual Assault Advocate Certification Program. - Through the Office of Force Resiliency, acts as the Functional Community Manager for the Sexual Assault Response Workforce. - Manages the DoD Safe Helpline, the 24/7 phone and on-line resource for those members of the DoD community impacted by sexual assault. - Provides on-demand primary prevention customized support, provision of job-aid products, and job-focused professional development for on-the- job prevention challenges related to planning, implementation, and evaluation of prevention activities. - Operates the Sexual Assault Prevention and Response Training and Education Center (SAPRTEC) to develop, deliver, and evaluate Integrated Primary Prevention (IPP) and SAPR education and training requirements, as well as promote excellence and standardization in the military population and IPP and Sexual Assault Response workforces. - Implements the Independent Review Commission (IRC) recommendations to reform Department approaches to address sexual assault, to include fielding a full-time prevention workforce; providing victim advocates with enhanced skill and independence to promote victim recovery, reforming military justice, and improving the Department’s research base. For additional information, please visit https://www.sapr.mil. DHRA 260$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 237406000, "fy26": 222342000, "name": "Civilian Pay/Labor", "fy25_current": 251362000, "fy25_request": 252317000, "fy25_cong_amt": -955000, "fy25_cong_pct": -0.38}$$::jsonb, $${"fy24": 39936000, "fy26": 32333000, "name": "Defense Civilian Personnel Advisory Service (DCPAS)", "fy25_current": 35071000, "fy25_request": 35834000, "fy25_cong_amt": -763000, "fy25_cong_pct": -2.13}$$::jsonb, $${"fy24": 5928000, "fy26": 5194000, "name": "(DEOMI)", "fy25_current": 6522000, "fy25_request": 8599000, "fy25_cong_amt": -2077000, "fy25_cong_pct": -24.15}$$::jsonb, $${"fy24": 34614000, "fy26": 38197000, "name": "Defense Suicide Prevention Office (DSPO)", "fy25_current": 35248000, "fy25_request": 45113000, "fy25_cong_amt": -9865000, "fy25_cong_pct": -21.87}$$::jsonb, $${"fy24": 70880000, "fy26": 81921000, "name": "System (DEERS)", "fy25_current": 76554000, "fy25_request": 76609000, "fy25_cong_amt": -55000, "fy25_cong_pct": -0.07}$$::jsonb, $${"fy24": 125171000, "fy26": 108230000, "name": "DMDC - Enterprise Data Services (EDS)", "fy25_current": 132924000, "fy25_request": 149568000, "fy25_cong_amt": -16644000, "fy25_cong_pct": -11.13}$$::jsonb, $${"fy24": 64882000, "fy26": 36027000, "name": "System (EHRIS)", "fy25_current": 59108000, "fy25_request": 91561000, "fy25_cong_amt": -32453000, "fy25_cong_pct": -35.44}$$::jsonb, $${"fy24": 92181000, "fy26": 112483000, "name": "DMDC - Identity Credential Management (ICM)", "fy25_current": 94945000, "fy25_request": 97773000, "fy25_cong_amt": -2828000, "fy25_cong_pct": -2.89}$$::jsonb, $${"fy24": 31770000, "fy26": 45992000, "name": "DMDC - Personnel Support Programs (PSP)", "fy25_current": 30885000, "fy25_request": 27396000, "fy25_cong_amt": 3489000, "fy25_cong_pct": 12.74}$$::jsonb, $${"fy24": 130202000, "fy26": 112960000, "name": "DPAC - Office of People Analytics (OPA)", "fy25_current": 120788000, "fy25_request": 133432000, "fy25_cong_amt": -12644000, "fy25_cong_pct": -9.48}$$::jsonb, $${"fy24": 2091000, "fy26": 2702000, "name": "DPAC - Office of the Actuary (OACT)", "fy25_current": 2505000, "fy25_request": 2505000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 38000, "fy26": 0, "name": "DSSC - Advance Distributed Learning (ADL)", "fy25_current": 0, "fy25_request": 0, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 7532000, "fy26": 3733000, "name": "Program (CAP)", "fy25_current": 5920000, "fy25_request": 6920000, "fy25_cong_amt": -1000000, "fy25_cong_pct": -14.45}$$::jsonb, $${"fy24": 13585000, "fy26": 9923000, "name": "(DANTES)", "fy25_current": 11046000, "fy25_request": 11658000, "fy25_cong_amt": -612000, "fy25_cong_pct": -5.25}$$::jsonb, $${"fy24": 63471000, "fy26": 25268000, "name": "Education Office (DLNSEO)", "fy25_current": 52410000, "fy25_request": 49179000, "fy25_cong_amt": 3231000, "fy25_cong_pct": 6.57}$$::jsonb, $${"fy24": 15275000, "fy26": 10610000, "name": "DSSC - Defense Travel Management Office (DTMO)", "fy25_current": 12166000, "fy25_request": 13437000, "fy25_cong_amt": -1271000, "fy25_cong_pct": -9.46}$$::jsonb, $${"fy24": 9397000, "fy26": 8302000, "name": "(ESGR)", "fy25_current": 9489000, "fy25_request": 9738000, "fy25_cong_amt": -249000, "fy25_cong_pct": -2.56}$$::jsonb, $${"fy24": 3803000, "fy26": 1751000, "name": "DSSC - Equal Employment Opportunity (EEO)", "fy25_current": 2053000, "fy25_request": 2561000, "fy25_cong_amt": -508000, "fy25_cong_pct": -19.84}$$::jsonb, $${"fy24": 1351000, "fy26": 0, "name": "(EEO)/Workforce Recruitment Program (WRP)", "fy25_current": 1525000, "fy25_request": 2113000, "fy25_cong_amt": -588000, "fy25_cong_pct": -27.83}$$::jsonb, $${"fy24": 4005000, "fy26": 4974000, "name": "DSSC - Federal Voting Assistance Program (FVAP)", "fy25_current": 5061000, "fy25_request": 5380000, "fy25_cong_amt": -319000, "fy25_cong_pct": -5.93}$$::jsonb, $${"fy24": 35586000, "fy26": 9236000, "name": "DSSC - Military-Civilian Transition Office (MCTO)", "fy25_current": 11013000, "fy25_request": 11341000, "fy25_cong_amt": -328000, "fy25_cong_pct": -2.89}$$::jsonb, $${"fy24": 33012000, "fy26": 33669000, "name": "Mission Support", "fy25_current": 31925000, "fy25_request": 35183000, "fy25_cong_amt": -3258000, "fy25_cong_pct": -9.26}$$::jsonb, $${"fy24": 38078000, "fy26": 26297000, "name": "(SAPRO)", "fy25_current": 54090000, "fy25_request": 35935000, "fy25_cong_amt": 18155000, "fy25_cong_pct": 50.52}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 240, 325, FALSE, $${"json_key": "DHRA__umbrella"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 1505352000, to_jsonb(ARRAY[$${"fy25": 252.69, "fy27": 423.757, "name": "Civilian Pay/Labor", "fy26_current": 219.945, "fy26_request": 222.342, "fy26_cong_amt": -2.397, "fy26_cong_pct": -1.08}$$::jsonb, $${"fy25": 34.482, "fy27": 28.505, "name": "Defense Civilian Personnel Advisory Service", "fy26_current": 32.333, "fy26_request": 32.333, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 5.538, "fy27": 4.639, "name": "Defense Equal Opportunity Management Institute", "fy26_current": 5.194, "fy26_request": 5.194, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 34.382, "fy27": 0.0, "name": "Defense Suicide Prevention Office", "fy26_current": 34.395, "fy26_request": 38.197, "fy26_cong_amt": -3.802, "fy26_cong_pct": -9.95}$$::jsonb, $${"fy25": 74.814, "fy27": 76.088, "name": "System", "fy26_current": 76.771, "fy26_request": 81.921, "fy26_cong_amt": -5.15, "fy26_cong_pct": -6.29}$$::jsonb, $${"fy25": 122.045, "fy27": 92.809, "name": "DMDC - Enterprise Data Services", "fy26_current": 102.63, "fy26_request": 108.23, "fy26_cong_amt": -5.6, "fy26_cong_pct": -5.17}$$::jsonb, $${"fy25": 66.687, "fy27": 278.06, "name": "System", "fy26_current": 36.027, "fy26_request": 36.027, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 89.901, "fy27": 109.636, "name": "DMDC - Identity Credential Management", "fy26_current": 104.82, "fy26_request": 112.483, "fy26_co