sonb, $${"fy25": 12.069, "fy27": 9.205, "name": "DSSC - Military-Civilian Transition Office", "fy26_current": 21.236, "fy26_request": 9.236, "fy26_cong_amt": 12.0, "fy26_cong_pct": 129.93}$$::jsonb, $${"fy25": 30.668, "fy27": 30.371, "name": "Mission Support", "fy26_current": 32.788, "fy26_request": 33.669, "fy26_cong_amt": -0.881, "fy26_cong_pct": -2.62}$$::jsonb, $${"fy25": 29.779, "fy27": 34.343, "name": "Sexual Assault Prevention and Response Office", "fy26_current": 73.297, "fy26_request": 26.297, "fy26_cong_amt": 47.0, "fy26_cong_pct": 178.73}$$::jsonb, $${"fy25": 0.0, "fy27": 241.955, "name": "U.S. Military Entrance Processing Command", "fy26_current": 0.0, "fy26_request": 0.0, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part1/DHRA_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_disa_umbrella$$, $$DISA$$, $$Defense Information Systems Agency$$, $$DISA$$, $$om_dw_ba04$$, NULL, $$dw_disa$$, 2026, 2627907000, 2614041000, -66263000, -2.53, 2547778000, 3042559000, $$The Defense Information Systems Agency (DISA) is a combat support agency that provides, operates, and assures command and control, information sharing capabilities, and a globally accessible enterprise information infrastructure in direct support to the joint warfighters, National- level leaders, and other missions and coalition partners across the full spectrum of operations. The DISA Next Strategy is designed to drive the combat support priorities and initiatives that enable the delivery of capacity and capability for the warfighting information system. The DISA plans, engineers, acquires, tests, fields, operates, and assures information-sharing capabilities, command and control solutions, and a global enterprise infrastructure to support the DoD and National-level leadership. The DISA drives innovation and collaboration to match capabilities with evolving threats and is integral to achieving the SECDEF’s priorities to rebuild the military and reestablish deterrence by defending the homeland. By embodying the core principles of readiness, campaigning, continuous modernization, and establishing lethality, the DISA ensures the military is agile and adaptable, capable of quickly incorporating new technologies and tactics to respond to evolving threats. The DISA serves the needs of the President, Vice President, Secretary of Defense, Joint Chiefs of Staff, Combatant Commands (CCMD), and other DoD Components provides networks, computing infrastructure, and enterprise services to support information sharing and decision making for the Nation’s warfighters and those who support them in the defense of the nation. The DISA is committed to advancing new technologies to strengthen the security and resilience of networks and systems that contribute to current and future U.S. military advantages over potential adversaries. Cyber, National Leadership Command Capability (NLCC), and the White House support are priority areas. Four strategic imperatives guide the DISA’s efforts: Strategic Imperative #1: Operate and Secure the DISA Portion of the DOD Information Network (DoDIN) This involves fortifying infrastructure, innovating on process, dedicating critical resources, and providing relevant, modern enterprise and business tools – over 200 of which are already in place. A resilient and redundant Defense Information Systems Network (DISN) backbone is crucial for data transport security. Strategic Imperative #2: Support Strategic Command, Control, and Communications (C3) Developing, provisioning, and operating C3 solutions that enable secure communications is a critical function for the DISA. Operationalizing the cloud, building an accessible hybrid cloud environment, and strengthening standards for data management are key operational goals. These DISA 357 innovations will allow warfighters to access data at the scope and scale needed for modern combat operations and maintain the agility and adaptability to respond to emerging threats. Strategic Imperative #3: Optimize the Network Optimizing the DoDIN is a responsibility that involves both security and adaptability—innovating while providing the infrastructure necessary to maintain confidence in network resilience. The user experience must be seamless, and technical debt must be minimized. Goals around an unconstrained DoDIN and consolidated Defense Agencies and Field Activities (DAFA) and CCMDs will help steer this priority imperative. Strategic Imperative #4: Operationalize Data Leveraging data to make decisions that help the warfighter gain a strategic advantage over adversaries is critical to our continued competitive advantage. Culture, conduct, and capabilities must be aligned to innovate in the operationalization of data. Modernizing the coordination capabilities of the NLCC and joint warfighting tools will enhance the collaborative process of operationalizing data. The DISA aligns its program resource structure across seven mission areas. These mission areas reflect the DoD's national defense priorities and represent DISA's focus on executing its lines of operations: Transition to Net Centric Environment: Create and strengthen the network environment to facilitate DoD information sharing by making data continuously available in a trusted environment. Cultivate emerging technologies to rapidly integrate them into the military's arsenal to maintain a technological edge over adversaries. Eliminate Bandwidth Constraints: Build and sustain the DoDIN transport infrastructure that eliminates bandwidth constraints and rapidly surges to meet demands, whenever and wherever needed. DoDIN Network Operations and Defense: Operate, protect, defend, and sustain the enterprise infrastructure and information sharing services and enable Command and Control. Supports the CCMDs by providing cybersecurity and network operations to the edge of conflict. Exploit the DoDIN for Improved Decision Making: Build the DoD enterprise-wide capabilities for communities of interest, such as command and control, and combat support that exploit the DoDIN for improved decision-making. Enables collaboration, joint military exercises, intelligence sharing, and strategic planning for strategic deterrence. Deliver Capabilities Effectively/Efficiently: Deliver capabilities, based on established requirements, more effectively, economically, and efficiently than the DISA does today. Special Mission Area: Execute special missions to provide communications support required by the President, including day-to-day management, fielding, operation, and maintenance of communications and information technology. Cyberspace Operations: Defend DoD networks against cyber-attacks, proactively identify threats, and promote Zero Trust implementation throughout the Department. Ensures robust defense mechanisms are in place to protect the homeland from threats, both on the ground and in the air. DISA 358 The DISA continues to use the Cost Allocation Model (CAM) to assign shared services costs to products and services. The CAM identifies the total cost of a program and avoids unintended subsidies to the Defense Working Capital Fund (DWCF), provides visibility into the cost and consumption of shared services, and identifies efficiencies. Mission Area: Transition to Net Centric Environment (FY 2026: $483,201 thousand) 1. DoDIN ES - (FY 2026: $215,424 thousand): The DISA, through the DoDIN with technical architectures and integration engineering, updates to interface standards, and modeling and simulation services to promote performance monitoring, cost effective technical solutions, and interoperability across the enterprise and maintain critical engineering standards across the DoD, Services, and Agencies. The DISA strives to update essential command and control (C2) standards every two years while continually enhancing its technical engineering capabilities. These advancements support national defense priorities to rapidly integrate emerging technologies into the military's arsenal to maintain a technological edge over adversaries. Ongoing efforts supported include: • Promoting centralized technology policy, standards, and leadership across the organization. The DISA conducts technology outreach, such as weekly Technical Exchange Meetings (TEM) with the DoD CIO, federal agencies, and industry to support this. The weekly TEMs aim to identify best practices, material solutions, mature capabilities, and enterprise services. • Performing security engineering and accreditation of products via the assessment capabilities within the Technology Analysis Center (TAC) lab environment. The TAC lab enables analysis of emerging technologies and the associated capabilities via flexible and rapidly reconfigurable environments. This allows for real and/or near real-time assessment, ultimately providing faster delivery of leading-edge technologies to the warfighters and mission partners. • Ensuring engineering and technical support integration for technology solutions as they transition to operations and maintenance requirements. • Providing cutting-edge network monitoring for Non-classified Internet Protocol router networks (NIPRNet) and the Secret Internet Protocol router network (SIPRNet) includes covering network sensors' maintenance and developing algorithms to interpret sensor data. • Delivering a comprehensive SIPRNet Endpoint management solution to enhance the security of the SIPRNet, enabling DoD to monitor all devices connected to the SIPRNet and transfer uniform security settings across devices. Modeling and simulation services provide analyses to inform the DISA’s and DoD’s infrastructure services and applications, ensuring DISA and DoD capabilities are planned, implemented, and assessed to meet the performance objectives cost-efficiently. Modeling and simulation services provide predictive analysis, systems engineering, and End-to-End (E2E) analytical assessments to inform design and investment recommendations, while integration engineering works to ensure integrated capabilities collectively meet warfighter mission requirements. DISA 359 Benefits of these capabilities include when the boundary defenses, also known as “the first line of protection against outside threats”, change due to increased traffic demands or as capabilities such as commercial cloud solutions are integrated to meet warfighter requirements. 2. Net-Centric Enterprise Services (NCES) - (FY 2026: $172,460 thousand): The DISA, through NCES, provides a portfolio of critical enterprise collaboration services to Warfighters, business, and intelligence end-users on the SIPRNet and NIPRNet. Collaborative intelligence sharing aligns with national defense priorities around maintaining an agile and adaptable warfighter support network. This portfolio: • Allows more than two million authorized DoD users to collaborate across the CCMDs, Services, Joint Staff, and Agencies using a suite of web-accessible collaboration capabilities. • Provides a resilient and flexible infrastructure to enable a secure collaborative environment that facilitates information sharing across the DoD. • Contains a robust enterprise messaging service that distinguishes the producer from the consumer, allowing consumers to subscribe to information that supports their missions, and allowing producers to publish perishable and non-perishable data without having to specify recipients. • Provides the user with flexibility to couple services in varying ways and provides access to web and application content, warfighter information, and critical data in a secure environment. • Supports application rationalization efforts by identifying and prioritizing legacy applications for modernization. This facilitates the transition of applications to cloud hosting environments (commercial and DoD on-premises solutions). • Supports SIPR Modernization for Microsoft 365 (M365) Impact Level 6 (IL6) license upgrades. The Defense Enterprise Office Solution (DEOS) provides a DoD-wide enterprise cloud solution for common communication, collaboration, and productivity. The DEOS is mission-effective, secure, cost-effective, efficient, ubiquitously accessible, intuitive, and enables the DoD to operate and fight worldwide. It is a department-wide capability that offers greater functionality and efficiency than legacy collaboration systems. It supports military environments, creates a simpler, defensible perimeter by reducing the DoD’s IT footprint, streamlines information access and data sharing across the DoD, and strengthens the DoD’s Cybersecurity posture. The DEOS integrates email, collaboration services, office automation, and content management in unclassified and classified environments. Enterprise Messaging (EM) enables the DoD to exchange data between applications. It is a machine-to-machine service that connects data publishers with data consumers across the DoD on both NIPR and SIPR using a publish-subscribe method and reduces the need for peer-to- peer integrations. EM is now available in the cloud, and EM Modernization provides a machine-to-machine cloud-based messaging transport solution centered around open and lightweight protocols for easier integration. DISA 360 3. DoD Enterprise Cloud Computing Ecosystem - (FY 2026: $95,317 thousand): The DISA provides industry-leading cloud hosting and computing capabilities to the DoD, the Joint Force, and, ultimately, to the warfighter. These cloud capabilities enable DoD staff and the warfighter to secure mission-critical data accurately and efficiently, in any location. The Agency’s DoD Enterprise Cloud Computing Ecosystem program drives readiness through innovation by providing best-value hybrid cloud offerings. These enhancements in cloud computing capabilities fortify a technological edge over adversaries. The current offerings include the Joint Warfighting Cloud Capability (JWCC) and Cloud Accelerators. The JWCC is the portfolio’s primary offering. It is a multi-vendor, enterprise-wide acquisition vehicle that enables the DoD to acquire commercial cloud services directly from a commercial Cloud Service Provider. The JWCC delivers a first-of-its-kind capability that encompasses the needs of the entire enterprise at every classification level; this includes supporting separate top-secret cloud environments. The JWCC is the first enterprise contract vehicle available DoD-wide, and this scope brings cloud capabilities down to the Warfighter. The JWCC brings the power of the commercial cloud to the DoD, enabling initiatives such as Combined Joint All Domain Command and Control (CJADC2) and Zero Trust (ZT) to increase the lethality of the Department. Once a DoD customer selects a commercial cloud option, the JWCC also provides additional layers of monitoring and cybersecurity. Cloud Accelerators equip mission partners with the tools needed to adopt cloud services as a set of innovative products that make ordering, provisioning, onboarding, securing, and managing the cloud faster, cheaper, and easier while ensuring maximum efficiency in procurement. Current capabilities include: •   DoD Cloud Infrastructure as Code (IaC) uses automation to accelerate cloud adoption through accredited baselines that build out cloud environments, significantly reducing deployment times. •   The Account Tracking and Automation Tool (ATAT) is a cloud provisioning tool that enables the initial creation of accounts for mission owners across multiple cloud vendors at all classification levels and tracks spend against existing task orders. •   DISA Acquisition Package Preparation System (DAPPS) is a web-based interview tool that guides mission owners through the development of acquisition packages to streamline the DoD acquisition process and expedite the JWCC task order award process. •   Joint Operational Edge (JOE), an interconnected and integrated mesh of large form factor edge computing platforms, is installed on- premises at DOD locations and delivers commercial Infrastructure as a Service (IaaS) and Platform as a Service (PaaS) to Mission Partners. DISA 361 Mission Area: Eliminate Bandwidth Constraints (FY 2026: $721,834 thousand) 1. DISN Enterprise Activities (EA) - (FY 2026: $449,763 thousand): The DISN is the DoD's consolidated worldwide telecommunications infrastructure that provides end-to-end information transport for DoD operations to the warfighters and the Combatant Commanders via a robust Command, Control, Communications, Computers, and Intelligence information long-haul transport infrastructure. The DISN, seamlessly spanning the full spectrum from terrestrial to space and strategic to tactical domains, provides the interoperable telecommunications connectivity required to plan, implement, and support all operational missions, anytime. DISN services reach the edge of the communications network; the warfighter can access them worldwide. Continual enhancement of the DISN is needed to provide optimal network resources to the warfighter so that strategic advantages over evolving adversarial threats can be maintained. Major DISN capabilities include the following: Airborne Intelligence, Surveillance & Reconnaissance (AISR): Supports the Combatant Commanders/Services Agencies (CC/S/A) to gather, analyze, and stream AISR sensor data to globally dispersed strategic, operational, and tactical customers. This timely and assured delivery of fused intelligence allows information superiority in support of Counterterrorism, Theater Campaign Plans, and Contingency Operations. The AISR funding sustains the various critical capabilities, which include the video and data dissemination, and provides end-to- end transport of AISR data to globally dispersed strategic, operational, and tactical consumers (DoD and Mission Partners) at the time and place, quantity, and quality they need. Resilient Ground Infrastructure (RGI): The AISR ground entry points (GEP) receive sensor data from unmanned aerial systems (UAS) (e.g., drones) and aircraft and transmit that data to deployed warfighters, increasing their effectiveness and lethality. Should one or more GEPs become unavailable, the remainder of the ground infrastructure must be able to continue to support U.S. Warfighting forces engaged in operational missions. Additionally, the GEPs must provide redundancy across multiple frequency bands and sites. The AISR resilient ground infrastructure improvements resulting from the GOaR recommendations will assure delivery of ISR data from airborne sensors to globally disbursed combatant commands and engaged Warfighting forces, improving their ability to negate adversary maneuver and achieve decisive victory. This funding will increase capacity, resiliency, and geographic diversity of the AISR capabilities. Reliable and resilient communications, access to intelligence data, and battlespace awareness are key to supporting the SECDEF's priorities of maintaining readiness and establishing lethality. Funding provides equipment operations, maintenance, and sustainment with investment purchases. Defense Red Switch Network (DRSN): Provides multi-level secure, rapid, ad-hoc, voice calling and conferencing capability from SECRET up to TS/SCI to the President, Secretary of Defense, Services, CCMDs, subordinate organizations (military and civilian), and coalition allies. DRSN meets the requirements of Nuclear Command Control Communications (NC3) and CJCSI Vol. 6: Emergency Conferences. The DRSN requires sustainment funding. DISA 362 Multi-Level Secure Video and Voice (MLSV2): The DISA has developed a prototype of a new IP-based, multi-level classified voice and video capability that enables communication across multiple classification levels on the same platform. DISA will be sustaining the initial prototype in FY 2026. The MSLV2 supports the nation’s NC3 system. The NC3 system must always provide command and control of U.S. nuclear forces, under all circumstances, including during and following a nuclear or non-nuclear attack by any adversary. Resilient NC3 capabilities are a critical enabler of mission assurance for nuclear operations. The MLSV2 is a key program to modernize DoD secure conferencing capabilities to meet current National and Military leadership mission essential functions for Command and Control and Decision-Making, and current and future technology and security requirements. Enhanced Pentagon Capability/Survivable Emergency Conferencing Network (EPC/SECN): Provides classified capabilities to support senior leaders' communications. The EPC/SECN must meet the stringent requirements of the Chairman of the Joint Chiefs of Staff Instruction, CJCSI 6811.01B, Nuclear Technical Performance Criteria (NTPC), and must be readily available and operate at its optimum performance level at all times. DoD Mobility: Provides both unclassified and classified mobile communications to the DoD through the following service platforms: • DoD Mobility Unclassified Capability (DMUC): Service providing Government-owned mobile device access to Unclassified DoDIN and commercial information services for Senior Leaders, DAFAs, and Combatant Commanders. The DISA is exploring leveraging Microsoft Intune to provide this service more efficiently. • DoD Mobility Classified Capabilities Secret (DMCC-S): This service enables government-owned mobile device access to Classified Secret DoDIN telephony and information services. • DoD Mobility Classified Capabilities Top Secret (DMCC-TS): This service enables mobile device access to Top Secret Collateral DoDIN telephony services. The funding provides the gateway and infrastructural support, and the program management support for the Mobility Program. Interoperability and Internet Protocol (IP) Enabling: Supports the DoD Network Information Center (NIC). The NIC plans, manages, and sustains the delivery of Domain Name System (DNS) capabilities for the global Internet and the classified SECRET and unclassified CUI DISN. The DISA is responsible for integrating voice, video, and/or data services delivered ubiquitously across an interoperable, secure, and highly available IP network infrastructure. IP Enabling provides management and registration of all IP number resources for the DoD, and external internet governance organizations recognize it as the DoD agent for IP number management. In addition, it provides the “Who Is” capability for database queries relating to IP number registrations and .MIL domain information is for the benefit of the DoD and the intelligence community organizations. The DISA continues to enhance IP capabilities by converting to a global converged infrastructure through IP version 6, where fault isolation and dynamic routing of network traffic enable enhanced service delivery and prevent service interruption to the warfighter or end user. DISA 363 DISN Global Core Reconfiguration: Adds resiliency to the DISN Core infrastructure. Detects and resolves CCMD vulnerabilities by procuring assets, systems, and networks, whether physical or virtual, to eliminate vulnerabilities that would have debilitating effects on critical infrastructure. Funding supports capabilities associated with the Global DISN Resiliency (formerly Hypercore) Program. Senior National Leadership Communications - Communications with Other Nations (SNLC-CWON): A set of capabilities and agreements that allow secure voice, video, and data communications between U.S. senior leaders and their foreign counterparts for cooperation, de-escalation, and nuclear reduction. The funding operates and sustains the following sub-capabilities: • The Washington-Moscow Direct Communications Link (DCL) includes terrestrial and commercial satellite links between the U.S. and Russia. DCL provides data, voice, and video communications between senior Russian leaders and U.S. POTUS, SECDEF, Chairman of the Joint Chiefs of Staff (CJCS), and State Department Nuclear Risk Reduction Center. • The Defense Telephone Link (DTL) provides voice and video communications between U.S. Senior Leaders (SECDEF, CJCS, CCMDs, Policy Directors, and Senior Officers) with their counterparts in approximately 40 foreign nations. • The Equivalent Value Exchange (Memorandum of Understanding) governs and maintains long-standing communications interoperability, interconnection, and data and resource exchange efforts between the U.S. DoD and our Five Eyes partners (the U.S, United Kingdom, Canada, Australia, and New Zealand). It also provides continual data exchanges between the U.S. and the Israel Defense Force (IDF) in IT infrastructure, data, and voice. Proliferated Low Earth Orbit (pLEO): A network of satellites that creates a reliable communications network for the warfighter. The pLEO network is a layer of satellites in space that allows ground stations and satellites to connect. The network consists of many redundant and overlapping smaller satellites that connect in a multi-nodal system, eliminating the risk of having a network with a single point of failure. The program securely connects the DoD with DISN Core Infrastructure services. pLEO peering leverages commercial pLEO capabilities to provide diverse routing options for DISN traffic. Diversifying DISN routing decreases risk for the Joint Force as it challenges adversarial targeting of critical communications mediums. This integration of innovative technologies allows the warfighter to remain ahead of constantly evolving threats. The pLEO is crucial for DISA operations because it provides lower latencies in transmissions between users, provides a transmission platform with multiple redundancies in the case of satellite failure or foreign adversary action, and is less expensive to insert in the operating environment. The DISA is contracting for and sustaining five pLEO/Software-Defined Wide Area Network (SD-WAN) enabled deployable DISN nodes. The pLEO DISN SD-WAN nodes provide classified and unclassified voice, video, and data services, allowing the Warfighter to connect to the DISN anywhere in the world. They are portable and can be shipped to emerging global hotspots, enabling the warfighter to connect to the DISN before permanent infrastructure is available reliably. Contracting for and sustaining the initial nodes will allow DISA to scale to meet future requirements rapidly. DISA 364 2. Defense Spectrum Organization (DSO) - (FY 2026: $45,577 thousand): The DISA delivers Electromagnetic Spectrum Operations (EMSO) capabilities through the delivery of software products for use by joint and coalition warfighters, as well as engineering and analytical services. These products and services mitigate adverse effects from harmful EMS interference and enable friendly forces to gain and maintain advantages in contested and congested EMS environments to meet their warfighting needs. Access to the radio frequency portion of the EMS plays a critical role in national security. The DISA delivers a broad range of capabilities and services to enable spectrum access that supports data links and decision making at all levels of the DoD - strategic to tactical. The entire DoD uses these spectrum capabilities; DISA is the sole provider for many of the DoD’s EMSO needs. The DISA develops the spectrum's primary capabilities, including cloud-based spectrum management software and services, under the Electromagnetic Battle Management-Joint (EMBM-J) and the Global Electromagnetic Spectrum Information System (GEMSIS) capability portfolios. The EMBM-J program is the Joint EMS Command and Control (C2) system for the DoD and critical to CJADC2 and DoD’s EMSO warfighting needs. The GEMSIS portfolio delivers the End-to-End Spectrum Supportability (E2ESS) capability, the DoD’s enterprise-friendly force, Blue, data capture, and host nation coordination capability. The Services and CCMDs use the E2ESS application to create a digital record of DoD spectrum-dependent systems (C5ISR) and to coordinate host nation spectrum access for all of DoD. The GEMSIS also delivers the Joint Spectrum Data Repository, the authoritative EMS Blue data repository containing millions of DoD and coalition partner records needed for the planning and execution of DoD EMS Operations. The Spectrum Sharing and Coordination capabilities portfolio also enables Dynamic Spectrum Sharing, which involves coordinating DoD spectrum access with interagency partners. The Spectrum mission is integral to vital activities such as information operations, electronic warfare, and other Joint Staff-directed projects. In support of the mission, the DISA: • Provides Electromagnetic Battle Management (EMBM) joint capability for CCMD and Joint Task Force (JTF) spectrum cells supporting C2. The PEO Spectrum improves EMS Situational Awareness and EMS tools in support of the Joint EMS Operations and the deliberate planning process. • Provides data services and analytics for full electromagnetic situational awareness. This allows users to visualize the electromagnetic environment, configure their own operational picture, make decisions within relevant time scales, and enable command and control for EMSO within the CJADC2 framework. • Improves DoD spectrum data quality to enable application of Artificial Intelligence/Machine Learning (AI/ML). The Spectrum program supports software deliveries that enable access to the EMS and mitigate interference to friendly data links. • Supports the Joint Spectrum Interference Resolution (JSIR) program, which provides capabilities to report electromagnetic spectrum interference and coordinate mitigation procedures through the JSIR-O (JSIR Online) system. This includes engineering services for the DoD enterprise to mitigate interference to critical strategic national defense systems and data links. • Creates architecture products for reference and guides capability development to enable interoperability across the DoD, support the CJADC2 framework, and enable the DoD in the national spectrum sharing initiatives. DISA 365 3. DISN Infrastructure Services - (FY 2026: $24,624 thousand): The DISA, through the DISN, provides key infrastructure services required by the warfighter for day-to-day IT functionality that enhances mission readiness, such as secure voice, video, and data services. The secure voice and video services operate on classified and unclassified networks and incorporate security requirements unique to the military into commercially competitive services. The capabilities provided by DISN are crucial to providing the warfighter with continuous, reliable, and secure voice, video, and data services at the speed of the mission. These resources fund DISA’s payment towards the consumption of these DISN enterprise services. 4. DoD Teleport Program - (FY 2026: $59,203 thousand): The DoD SATCOM ground infrastructure provides key nodes via which deployed U.S. Warfighting forces can connect to the rest of the DoDIN. Connecting to the DoDIN enables the Warfighters to coordinate maneuver and logistics and access the vast amounts of information maintained by the U.S. military and intelligence agencies. Without this information, deployed Warfighters would face greater uncertainty about adversarial forces and be less effective in achieving victory. The DoD Teleport program acquires and modernizes the ground infrastructure segment of DoD satellite communications (DoD SATCOM) to connect deployed U.S. Warfighting forces with the fixed elements of the DoDIN and provide them access to DISN services, including SIPRNet, NIPRNet, Defense Red Switch Network (DRSN), Defense Switched Network (DSN), Video Teleconference (VTC), and classified systems. Teleport allows U.S. Warfighters to leverage the DoDIN to communicate across a theater, regionally, between regions, and globally. The DoD Teleport is an Acquisition Category III combined program that acquires and modernizes SATCOM capabilities, providing a long-term variety of communications interfaces between the DISN terrestrial and tactical SATCOM assets at a single point of presence. The DoD Teleport System provides deployed warfighters with multiband, multimedia, and worldwide reach-back capabilities to DISN services through interoperability between multiple SATCOM systems and deployed warfighter tactical networks. As a result of combining the SATCOM Gateway and STEP under Teleport, there are now Teleport capabilities at 16 Joint SATCOM Teleport Ground Stations located worldwide. The Joint SATCOM Teleports are a vital dissemination interface between deployed warfighters and the terrestrial DoDIN, connecting them with U.S. installations and depots and providing them access to the DISN services and information available via the DoDIN. The Teleport RGI initiative will increase capacity, resiliency, and geographic diversity of SATCOM ground infrastructure managed by DISA to support deployed Warfighting forces. Reliable and resilient communications, access to intelligence data, and battlespace awareness are key to supporting the SECDEF's priorities of maintaining readiness and establishing lethality. O&M funding will provide equipment operations, maintenance, and sustainment with investment purchases. The DISA SATCOM Joint Management Tool (JMT) program (formerly known as SATCOM Ordering, Management & Situational Awareness Tools (SOMSAT)): JMT provides a common operating environment for the DoD’s Enterprise Satellite Communications Management and Control (ESC-MC), and it is the foundation of the U.S. Space Force’s SATCOM vision and SATCOM Force Design that enables the rapid integration of SATCOM network services (both military and commercial/partnered) by automating resource allocation processes and mitigating adversarial spectrum activity. It is one of the most critical elements of the CJADC2 technical modernizations. It brings together multiple legacy offerings to streamline the processes to order and provide satellite resources to the warfighter, ensuring mission-critical SATCOM capabilities DISA 366 are available in an era of great power competition. A recent study revealed that in the USINDOPACOM theater alone, approximately 920 hours per year were spent correcting SATCOM resource allocation requests. The JMT centralizes and automates fragmented, time-intensive processes for requesting, managing, and allocating mission-critical SATCOM bandwidth. The JMT will be in sustainment in FY 2026, and funding will sustain and enhance the JMT to meet DoD satellite resource, cybersecurity, and data management requirements. 5. 4th Estate Network Optimization (4ENO) - (FY2026: $142,667 thousand): The DISA has been designated as the single service provider of common-use IT for the DAFAs and is working to consolidate the commodity IT local area networks and service desks associated with 14 DAFAs. The goal is to migrate disparate, separate organizational networks onto a single DoDNet. After migration, each DAFA will use DoDNet as its primary network in a common IT environment. Migration to DoDNet facilitates cost savings by moving to enterprise IT delivery models. Migration to DoDNet promotes Zero Trust compliance as migrating DAFAs will have Zero Trust capabilities through DISA’s Thunderdome program (in the DISA Cyber OP-5). Beyond FY 2026, the DISA will look to bring additional DAFAs and CCMDs onto DoDNet. By adopting the single-service-provider framework, the DISA will significantly strengthen the cybersecurity of the DAFAs, drive uniform adoption of IT enterprise services, reduce duplicative IT, and simplify network administration to provide an advanced, safeguarded, and consolidated network integrating state-of-the-art Zero Trust capabilities. Mission Area: DoDIN Network Operations and Defense (FY 2026: $214,767 thousand) 1. Field Commands and Field Offices (FC/FO) - (FY 2026: $133,423 thousand): The DISA FC/FO ensures that the DoDIN (spanning voice, video, and data services) aligns to the Joint Cyber Warfighting Architecture (JCWA) and fulfills global warfighter needs in all phases of conflict. The FC/FOs support Combatant CCMD staff and integration of DISA services within the Joint All Domain Operations (JADO) Operational Plans (OPLANS). The FC/FOs help the DoD deter aggression, while being prepared to prevail in conflict when necessary. This includes the prioritization of the pacing threats in regionally challenged areas. Sustaining a resilient Joint Force and defense ecosystem requires ongoing IT services, facility/space accommodations, and programmatic operational support worldwide at eleven CCMD and National Military Command Center (NMCC) HQ locations. Additionally, FC/FO aligns effective and on-site strategic C2 and situational awareness between the CCMD, Military Departments (MILDEPs), DAFAs, and deployed forces and supports National Security by: • Preparing and publishing DISA support plans for all the CCMD Theater Campaign Plans (TCP), global campaign plans, and contingency plans. • Reviewing and recommending DISA service improvements to more than 50 OPLANS annually. • Providing customer service support and requirements advocacy to all stakeholders who subscribe, or plan to subscribe, to DISA’s existing or emerging information products and services. • Enabling effective coordination and information exchange in support of the services, policy, planning, and new capabilities. DISA 367 •   Sustaining CJADC2/DoDIN services by assigning DISA FC/FO employee specialists worldwide to each CCMD HQ facility. •   Developing solutions to specific warfighting capability gap requirements identified in the Integrated Priority Lists (IPLs) for the CJCS. •   Defending the DoDIN by assuring system and network availability, information delivery, and information protection across strategic, operational, and tactical boundaries in support of the DoD, CCMDs, MILDEPs, DAFAs, and the Joint Staff. •   Actively participating in Joint and coalition exercises. •   Conducting assessments of the threat and hazards, vulnerability, and risk to DoD-owned Defense Critical Infrastructure (DCI) and the inter/intra-dependencies needed to execute without fail required DoD missions in accordance with the Department of Defense Directive (DoDD) 3020.40, DoD Policy and Responsibilities for Critical Infrastructure. •   Assessing critical Command, Control, Computer, Communication, Intelligence, Surveillance, and Reconnaissance (C4ISR) components and capabilities during combat operations, even under service delivery constraints. Work is done via the Critical Infrastructure Program (CIP), which identifies, labels, and prioritizes the DoDIN sector and DISA assets. •   Developing Continuity of Operations (COOP) plans and exercises to ensure that essential functions and operations will continue throughout various threats, contingency operations, and humanitarian disasters. Additional missions include: •  United States Indonesian Pacific Combatant Command (USINDOPACOM) coalition partners and North Atlantic Treaty Organization (NATO) Field Offices ensure the U.S./Indo-Pacific/NATO partnership is considered in all planning and design efforts to facilitate C4ISR interoperability. The program is prepared to deter aggression and overcome conflict in the Indo-Pacific. • Provide support to the Indo-Pacific coalition partners and NATO Ministry of Communications and Information Technology (MCIT) for transforming the Information and Communication Technology (ICT) in support of the business stabilization mission, while encouraging strategic economic growth in other areas of operational responsibility. 2. Network (DoDIN) Operations (NetOps) - (FY 2026: $50,009 thousand): The DISA ensures that the DoDIN (spanning voice, video, and data services) capabilities, access points, and boundary protections meet critical DoD mission requirements. The DISA leads technical refresh, configuration control, and sustainment to improve DISA service delivery to the warfighter to achieve end-to-end interoperability and maintain competitive strength over adversaries. The DISA provides continuous DoDIN operational service delivery in 42 countries at 3,800 locations worldwide, including all CCMD, MILDEP, DAFA, and Joint Staff centers across U.S. global military operations. The DISA delivers continuous situational awareness, ensures DoDIN resilience, and conducts intelligence activities to identify and assess network threats. The DISA develops threat assessments, based on intelligence from the Defense Intelligence Enterprise, to inform decision-making for both fielded systems and capabilities and those currently in development. By fulfilling these duties, the DISA mitigates service interruptions, anticipates threats, develops alternate configurations, and provides enhanced mission support for no-fail services. DISA 368 The DISA also supports the United States Cyber Command (USCYBERCOM) mission to provide secure, interoperable, and reliable operations across the DoDIN within the JCWA. The DISA’s primary tasks in this capacity are: • Operating and defending the DoDIN, enabling DoD Enterprise services support to the USCYBERCOM internal and external Cyberspace Operations (CO), DoD Cyber Operations Forces (DoD COF), Defensive Cyber Operations (DCO), and DoDIN Operations (DO). • Enabling and conducting the actions necessary to provide certification, threat identification, intrusion prevention, intrusion detection, and incident response/recovery for the NIPRNet and the SIPRNet. • Providing the C2, situational awareness, and defense of the DoDIN and Enterprise services across all levels of command: strategic, operational, and tactical boundaries in contested battlespace. • Supporting the DoD's full spectrum of war fighting, to include support for intelligence and business missions. The DISA executes its C2 mission to plan, direct, coordinate, integrate, and synchronize DO and DCO globally. More specifically, the DISA: • Manages and executes approximately 200 million managed network assets, over 50,000 Telecommunications Service Orders (TSO) and circuit actions, 40,000 servers hosting 870 user applications, 17,000 circuits, 55 SATCOM gateways, 38 petabytes of storage, 4.5 million DoD identities, 1.6 million to 4.5 million enterprise users, and 1 million to 4.5 million mobility/voice/video/data over IP users. • Reports blockage and/or tracking of an average of 380 million malicious events monthly. Increasing cybersecurity threats have expanded the program’s CO mission in terms of the breadth (e.g., Enterprise Services) and required depth of defenses in the DO/DCO mission space. The DISA supports USCYBERCOM’s mission to direct, synchronize, and coordinate cyberspace planning and operations to defend and advance national interests in collaboration with domestic and international partners. The DISA can meet this requirement by leveraging the existing enterprise infrastructure. 3. Joint Staff Support Center (JSSC) - (FY 2026: $31,335 thousand): The JSSC provides 24/7 C2, Nuclear Command and Control (NC2), and National Military Command and Control (NMC2) operational and communications support. The JSSC supports the President, SECDEF, CJCS, Joint Staff (JS), Combatant Commanders, and other National-level leaders through global maintenance of the Joint C2 and NC2 systems and cybersecurity oversight. In accordance with CJCS Operating Order (OPOR) 6-19 and CJCS Instruction (CJCSI) 3280.01E “National Military Command System,” the JSSC Director provides operational direction for C3 support to create a mission-capable National Military Command Center (NMCC). These efforts enable the NMCC to perform the National Military Command System’s (NMCS) seven mission essential functions (MEF) and twenty-five mission essential tasks (MET). The JSSC oversees a critical decision support system for the NMCC and the National Joint Operations-Intelligence Center in the Pentagon and at alternative location(s). By deterring strategic attacks against the U.S., Allies, and partners through 24/7 support, the JSSC advances and safeguards vital national defense priorities. DISA 369 The JSSC provides 24/7 monitoring of the NMCC and alternate NMCC (NMCC-A) locations. The JSSC provides nuclear support operations for C2, communications, computer, and intelligence systems for worldwide situational monitoring, rapid decision-making, and force direction. Operational services support strategic threat operational warning, crisis management, situational awareness, course of action development, and national senior leadership decision-making. The JSSC provides these capabilities by sustaining the Global Command and Control System- Joint (GCCS-J), the Processing and Display System-Migration (PDS-M), the Nuclear Planning and Execution System (NPES), and other systems. The JSSC sustains these capabilities for the Pentagon and an alternative location to ensure continuity of operations. The JSSC has aligned priorities to provide a secure, reliable, and effective nuclear command, control, and communication (NC3) system by building a resilient and cohesive warfighter support network to overcome evolving threats. The JSSC also provides full-service television production and multimedia support to the SECDEF, the CJCS, JS, and other DoD agencies, per requests from Pentagon organizations. These media types include remote video and audio recordings, electronic graphics, video teleconferencing guidance, and NMCC secure television system operation. In addition, the JSSC provides tactical, operational, strategic, and collaborative planning support for various JS IT initiatives such as the NMCC IT Working Group (NIWG) and the JS IT migration. Personnel also assist the Joint Staff Hampton Roads, JS Pentagon, and other regional mission partners as they transition their IT services to the DISA- based offerings. Mission Area: Exploit the DoDIN for Improved Decision Making (FY 2026: $1,064,272 thousand) 1. Joint Service Provider (JSP) - (FY 2026: $594,476 thousand): The JSP, is the exclusive IT service provider for over 30 facilities and a wide variety of DoD personnel throughout the Pentagon Reservation and National Capital Region (NCR) and provides infrastructure network support, application support, data storage management, defensive cyber operations, cyber security compliance, and customer service support to critical DoD facilities. The JSP serves over 55,000 customers spanning the Office of the Secretary of Defense (OSD), Washington Headquarters Services (WHS), Army, Joint Staff, and additional onboarded customers. The JSP employees operate and defend DoD cyber terrain by building, sustaining, supporting, and protecting mission-critical integrated IT systems to “Enable. Every. Mission." The JSP services include infrastructure network support, application support, data storage management, defensive cyber operations, cybersecurity compliance, and customer service support to critical DoD facilities. The JSP IT program provides end-user computing capabilities needed to fulfill component missions. The JSP IT program includes DoD local area networks, computer servers, network storage subsystems, workstations, and desktop applications for processing information at all classification levels on over 110,000 end-user devices. By maintaining IT infrastructure for all key facilities and personnel, the JSP enables maximum mission effectiveness for all DoD IT users throughout the NCR. The JSP enables cutting-edge IT capabilities that help the warfighter maintain its competitive advantage in the face of emerging threats. JSP also encompasses the Secretary of Defense Communications Office (SECDEFCOMS). The DoD Instruction O-3710.02 requires that the SECDEFCOMS serve as the authoritative source for operational and strategic communication requirements supporting the Secretary and DISA 370 Deputy Secretary of Defense. In accordance with DoD Policy, the SECDEF must have resilient communication and situational awareness capabilities at the Pentagon. SECDEF also requires access to fully equipped alternative operating facilities and mobile communications during transit between facilities. SECDEFCOMS provides the SECDEF with these capabilities, which enable the SECDEF and his immediate office to coordinate national defense in every scenario. 2. Senior Leadership Enterprise (SLE)/Logistics Support Activities (LSA) - (FY 2026: $321,530 thousand): Details are submitted in appropriately classified exhibits. 3. Combined Advanced Applications - (FY 2026: $71,165 thousand): The Compartmented Enterprise Services Office (CESO) provides an accredited Special Access Program (SAP) IT system for users who must work and communicate in an SAP environment and enables executive leaders and mission partners throughout the DoD and Intelligence Community (IC) to communicate with one another in a secure cloud environment. The CESO provides users with email, file storage, wiki, federated search capabilities, and print services, and operates and sustains the Joint Access Database Environment (JADE), which provides an authoritative source for verifying the identity of individuals and programs to networks and other systems. Funding sustains CESO capabilities and makes incremental improvements based on customer feedback and SAP CIO concurrence. 4. Global Command and Control System-Joint (GCCS-J) - (FY 2026: $25,654 thousand): The GCCS-J is the Joint C2 system of record and an essential component for warfighting situational awareness. It provides an integrated near-real-time picture of the battlespace to support joint and multinational operations on U.S. and coalition networks. The GCCS-J displays air, maritime, ground, space, and cyber tracks for decision making. It also provides applications for missile warning, intelligence, targeting, and imagery exploitation. Key strategic, national, theater, and operational decision makers rely on GCCS-J. The GCCS-J supports CJADC2, the modernized approach to military decision-making by promoting information sharing between Services. CJADC2 achieves agile and resilient C2 across the Services through integrated and synchronized capability development. The CJADC2 capabilities provide the ability to connect distributed sensors, intelligence, information, data, and effects from all Services to decision makers at the speed of the mission. The GCCS-J also directly supports building a resilient Joint Force and defense ecosystem for enhanced collaboration and innovative technological integration. The GCCS-J incorporates the core planning and assessment tools required by CCMDs, their subordinates, and the JTF Commanders to support the readiness of the Services' requirements and warfighter capabilities. The GCCS-J provides critical C2 capabilities to the Commander-in-Chief, Secretary of Defense, National Military Command Center, CCMDs, Joint Force Commanders, and Service Component Commanders. GCCS-J users include decision makers at the strategic national, theater, and operational levels and all CCMDs at sites worldwide. DISA 371 The GCCS-J: • Provides a Common Operational Picture (COP) with ground, air, maritime, cyber, and space tracks of U.S., coalition, and enemy forces. • Has many tactical decision aids and other applications for COP management and situational awareness. • It is the system of record for Theater Missile Warning, which provides alerts and displays for real-time missile events. • Displays launch points, missile locations, threat fans, and projected impact points. • Provides intelligence support to C2 operators with national and tactical intelligence data from DIA's Modernized Integrated Database (MIDB), still and motion imagery, and other intelligence sources. The Joint Staff Support Center (JSSC) provides 24/7 support to DoD components around the globe. Support efforts include: • Global Tier II technical support to over 660 sites. • Operational monitoring and reporting of 51 critical sites. • Global Common Operational Picture (G-COP) technical support and management of National Capital Region (NCR) Global COP servers. 5. Joint Planning and Execution Services (JPES) - (FY 2026: $28,440 thousand): The DISA, through the JPES Program Management Office (PMO), provides IT capabilities to support the Department of Defense’s Joint Planning Process (JPP). These capabilities support force planning, deployment planning, allocation of forces, execution, and Global Force Management (GFM) processes for military operations as part of the Joint Command & Control (JC2) mission. The JPES program maintains and sustains three operational systems: Joint Operations Planning and Execution System (JOPES): The JOPES is the critical Joint C2 system that provides automated force planning and execution capabilities necessary for simultaneous and resource-informed planning activities. The JOPES supports thousands of operational users across the globe. Additionally, 18 external systems across the CCMDs, Military Services, and Defense Agencies depend on JOPES to perform force planning, deployment planning, and execution activities. The JOPES will sunset in FY 2026 and be replaced by the JPES below. Joint Capabilities Requirements Manager (JCRM): The JCRM is a web-based application and database that enables the Global Force Management Allocation Plan (GFMAP) for CCMDs to draft, staff, store, and submit force requirements for ongoing and emerging military operations, contingency plans, and military exercises worldwide. JCRM is vital to managing complex global force requirements and tracking the distribution of U.S. military forces among the CCMDs. This system fulfills the JCRM mission. DISA 372 Joint Planning and Execution Services (JPES): The JPES will replace JOPES as the critical JC2 system that provides automated force planning and execution capabilities necessary for simultaneous and resource-informed planning activities. The JPES is a collection of capabilities supporting joint policies, processes, procedures, and reporting structures supported by communications and information technology used by the Joint Planning and Execution Community (JPEC). JPEC uses these capabilities to monitor, plan, and execute mobilization, deployment, employment, sustainment, redeployment, and demobilization activities associated with joint operations and exercises. The JPES is planned to enter sustainment in FY 2026. 6. Other Programs - (FY 2026: $23,007 thousand): These are the infrastructure and support costs for the DISA’s interoperability facility in the NCR. Infrastructure and support costs include facility operations, utilities, business management, and IT support costs. These requirements enable the DISA interoperability facility to operate more efficiently and effectively in pursuit of national defense priorities. Mission Area: Deliver Capabilities Effectively/Efficiently (FY 2026: $210,637 thousand) 1. Shared Services Units/Program Executive Offices - (FY 2026: $137,294 thousand): This activity funds foundational operating capabilities for the DISA, such as financial management, information technology, strategic planning, manpower/personnel security, facilities, logistics, and acquisition products and services to agency programs and business areas world-wide. The DISA continues to deploy modern technical solutions to support improvements in software licensing provisioning (DoD365), contract provisioning, human resources, and financial functions. These solutions strengthen readiness through providing continuous and reliable operating capabilities. Ongoing efforts include: •   Funding the DISA’s commodity IT requirements, including: • Internal network operations, maintenance, and sustainment. • Connectivity to the NIPRNet and SIPRNet via DoDNet. • Global service desk support (remote and on-site problem response, change management, and request fulfillment for end-user IT). • Licensing for productivity and collaboration software (Microsoft 365). • Other services are required to ensure the DISA maintains a securely connected and productive workforce. •   Managing the evolving DISA data architecture, data governance, metadata collection, data platform design, systems design, and interface design. • Enforcing data management disciplines and enhancing data quality to embrace digital transformation and out-maneuver our adversaries in the digital battle space. •   Managing records declassification, IT commodity tracking, policy oversight, and compliance reviews. •   Operating and maintaining the human resources systems that track employee attendance, provide continuity of operations, and facilitate compliance with the personnel security requirements and the Executive Order on Return to In-Person Work. •   Operating and maintaining the financial systems is critical to prudently managing DISA’s resources, promoting auditability, preventing improper payments, and providing DISA leadership with the data necessary to manage the Agency efficiently. DISA 373 •   Performing critical oversight functions to mitigate fraud, waste, and abuse, reduce costs, and strengthen internal controls to support the Warfighter effectively. •   Performing financial management functions, adhering to internal controls and standardized procedures, and aggressively working toward strengthening DISA’s posture for the financial statement audit. A clean audit and resource accountability are essential to achieving the SECDEF’s priority of Rebuilding the Military. •   Managing trainings and certifications to include IT/Cyber, financial management, acquisition, and congressionally mandated certifications and trainings. •   Providing seamless operations by efficiently managing facility real property services, assets, and logistical processes while providing a safe, sustainable, and optimized environment. This includes maintaining secure office space at DISA Headquarters and JSP leased facilities to support the Executive Order on Return to In-Person Work. 2. Management Headquarters - (FY 2026: $38,215 thousand): This funding supports the key oversight organizations, which provide guidance and direction of DISA acquisition, financial, and personnel activities. Command and executive staff enable the DISA to continuously operate and assure a global net-centric enterprise in direct support to the joint warfighter, national-level leaders, and other mission and coalition partners across the full spectrum of operations. Management Headquarters supports the military, civilian, and contractor personnel across twenty-five States, the District of Columbia, and seven countries (and Guam) worldwide. Management Headquarters employees shape and administer financial and human resources policy for the agency and develop the audits and reviews to safeguard the Agency’s resources and processes. They provide the Agency legal counsel so DISA can properly conduct its operations in accordance with its statutory authorities. They are working diligently to identify savings and organize the Agency to comply with the President’s Executive Orders promoting a more efficient approach to Agency operations and preparing the Agency for a clean audit opinion. 3. Revolving Fund (PRMRF) - (FY 2026: $35,128 thousand): Section 2674 of title 10 U.S. Code, established the Pentagon Reservation Maintenance Revolving Fund (PRMRF), which authorizes the Secretary of Defense to establish rates, collect charges, and make payments for space, services, protection, maintenance, construction, repairs, and alterations of facilities provided at the Pentagon Reservation. This activity funds DISA feeds for these services. Mission Area: Special Mission Area (FY 2026: $347,848 thousand) 1. White House Communications Agency (WHCA) - (FY 2026: $325,030 thousand): The WHCA is a joint service military agency under the operational control of the White House Military Office (WHMO) and the administrative control of the agency. All mission operations are in accordance with the National Defense Authorization Act (NDAA) of 2006, Public Law 109-163. The WHCA provides 24/7 worldwide classified and unclassified information services to the POTUS, Vice President of the United States (VPOTUS), WHMO, and others as directed by the President via the White House Director of Technology. These services equip the President and other key leaders with the information to decide on and communicate high-level national security challenges. WHCA primarily operates in the National Capital Region but also supports the Presidential Information Technology Community (PITC) networks at Camp David, second residences, various worldwide travel sites, and DISA 374 other Executive Office of the President (EOP) and WHMO offices, as well as in vehicles and aircraft. It also supports alternate sites for COOP and Continuity of Government (COG), the Signal Support Element (SSE), and other Head of State (HoS) services in specific designated locations. This enables unified communications at all classification levels and allows leaders to communicate during emergencies. Through its four core mission areas – Information Systems Services, Customer Service, Deployable Communications, and Visual Information Services - WHCA ensures that the President can communicate with anyone, anywhere, under any condition. The ability of the President to securely communicate in all situations is crucial to ensuring that the warfighter, under the leadership of the Commander-in-Chief, is equipped to respond to emerging threats in real time. 2. White House Situation Support Staff (WHSSS) - (FY 2026: $21,523 thousand): WHSSS is responsible, under Presidential direction, to provide financial and personnel resources to support and manage critical information technology, audiovisual, and communications functions within the National Security Council (NSC), including those performed by the White House Situation Room (WHSR). The WHSR provides 24/7 global situational awareness, crisis management facilitation, secure conference facilities, emergency actions support, and conducts executive communications directly for the President of the United States as Commander-in-Chief of the Armed Forces, Head of State, and Chief Executive. The WHSR also directly supports the Vice President, National Security Advisor, NSC staff, and select senior White House staff. The funding sustains a wide spectrum of operations, including applications and tools supporting WHSR watch floor operations and NSC decision making; operations and maintenance of telecommunications systems within WHSR’s operating locations including those supporting COOP and COG; forward deploying WHSR’s support globally in support of special mission travel; facility sustainment of WHSR’s locations; and the budgeting, acquisition, logistics and administrative activities required to support and execute these responsibilities. 3. Communications Management Control Activity (CMCA) - (FY 2026: $1,295 thousand): The CMCA provides communications support to the United States Secret Service (USSS) for the Presidential campaigns, dignitary protective duties, and National Special Security Events. It also supports the Joint Staff/J3, Joint Chiefs of Staff Special Events, and Joint Directorate of Military Support (JDOMS) for special events. Public Law 106-544 assigned the USSS responsibility for coordinating, planning, exercising, and implementing security for the National Special Security Events (NSSE). Additionally, the DoD Directive 3025.13 mandates that the DISA support the CMCA. DISA 375$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 333569000, "fy26": 483201000, "name": "1.Transition to Net Centric Environment", "fy25_current": 356681000, "fy25_request": 338030000, "fy25_cong_amt": 18651000, "fy25_cong_pct": 5.52}$$::jsonb, $${"fy24": 500171000, "fy26": 721834000, "name": "2.Eliminate Bandwidth Constraints", "fy25_current": 415076000, "fy25_request": 431876000, "fy25_cong_amt": -16800000, "fy25_cong_pct": -3.89}$$::jsonb, $${"fy24": 194738000, "fy26": 214767000, "name": "3.DODIN Network Operations & Defense", "fy25_current": 211622000, "fy25_request": 224336000, "fy25_cong_amt": -12714000, "fy25_cong_pct": -5.67}$$::jsonb, $${"fy24": 979504000, "fy26": 1064272000, "name": "4.Exploit the DODIN for Improved Decision Making", "fy25_current": 1032353000, "fy25_request": 1073612000, "fy25_cong_amt": -41259000, "fy25_cong_pct": -3.84}$$::jsonb, $${"fy24": 301669000, "fy26": 210637000, "name": "5.Deliver Capabilities Effectively/Efficiently", "fy25_current": 193499000, "fy25_request": 199407000, "fy25_cong_amt": -5908000, "fy25_cong_pct": -2.96}$$::jsonb, $${"fy24": 318256000, "fy26": 347848000, "name": "6.Special Missions", "fy25_current": 338547000, "fy25_request": 346780000, "fy25_cong_amt": -8233000, "fy25_cong_pct": -2.37}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 360, 412, FALSE, $${"json_key": "DISA__umbrella", "fy27_v192_bucket_a_dw": {"session": "2026-05-09_v41", "source_pdf": "O&M/FY27/DW/Vol1_Part1/DISA_OP-5.pdf", "content_hash": "468d71484a6aea4fa5bee0647cb934a7205049dc0a8f0b0fd14d13b958c54705", "source_page_amount": 24, "source_page_description": 2}}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 3873222000, to_jsonb(ARRAY[$${"fy25": 336.759, "fy27": 526.607, "name": "1.Transition to Data-Centric Environment", "fy26_current": 430.785, "fy26_request": 483.201, "fy26_cong_amt": -52.416, "fy26_cong_pct": -10.85}$$::jsonb, $${"fy25": 422.952, "fy27": 967.085, "name": "2.Eliminate Bandwidth Constraints", "fy26_current": 688.906, "fy26_request": 721.834, "fy26_cong_amt": -32.928, "fy26_cong_pct": -4.56}$$::jsonb, $${"fy25": 197.558, "fy27": 220.071, "name": "3.DoWIN Network Operations & Defense", "fy26_current": 216.117, "fy26_request": 214.767, "fy26_cong_amt": 1.35, "fy26_cong_pct": 0.63}$$::jsonb, $${"fy25": 1056.235, "fy27": 1343.275, "name": "4.Exploit the DoWIN for Improved Decision Making", "fy26_current": 1057.337, "fy26_request": 1064.272, "fy26_cong_amt": -6.935, "fy26_cong_pct": -0.65}$$::jsonb, $${"fy25": 278.963, "fy27": 195.525, "name": "5.Deliver Capabilities Effectively/Efficiently", "fy26_current": 214.437, "fy26_request": 210.637, "fy26_cong_amt": 3.8, "fy26_cong_pct": 1.8}$$::jsonb, $${"fy25": 343.169, "fy27": 620.659, "name": "6.Special Missions", "fy26_current": 347.983, "fy26_request": 347.848, "fy26_cong_amt": 0.135, "fy26_cong_pct": 0.04}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/FY2027_o1.txt$$, 12385145000) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dla_umbrella$$, $$DLA$$, $$Defense Logistics Agency$$, $$DLA$$, $$om_dw_ba04$$, NULL, $$dw_dla$$, 2026, 449683000, 412257000, -14719000, -3.57, 397538000, 401513000, $$b) DoD Enterprise Business System (DEBS) Infrastructure: This consolidated support provides key skill sets that can be shared among the DEBS programs reducing overall unique program costs and using standard and repeatable processes to manage programs throughout all phases of the acquisition life cycle. DEBS provide operational guidance and support to the PEO and J62 staff to achieve objectives, plans, priorities, and assignments for executing the PEO’s mission and functions. It also promotes leading acquisition processes and innovative practices in the development, delivery, operation and sustainment of information technology capabilities across the spectrum of operations for the DLA and DOD Enterprises. c) Joint Contingency Contract System (JCCS): The Joint Contingency Contracting System (JCCS) is the only DLA program that provides the warfighter with the necessary contracting systems to ensure warfighters and their support staff can travel safely In-Theatre, manage In- Theatre cash transactions, award and monitor In-Theatre contracts, and vet and manage In-Theatre vendors. The JCCS is the primary source for vendor information in the CENTCOM (21 Countries), and AFRICOM (53 Countries) areas of responsibility. The JCCS provides a capability to register host nation vendors in English and Arabic and includes vendor past performance information. In addition, the JCCS provides a capability for vendors to submit proposals, track historical contract data, and allow oversight of In-Theatre contracts to monitor cost, schedule, performance, and vendor activities. The JCCS provides the combatant command professionals a single source of data for host nation Vendor Management to include: Host Nation Vendor Registration, Vendor Vetting, Invoice and Payment for contracting and financial data to support mission spend analysis, strategic sourcing and staffing requirements. The JCCS produces a myriad of contract and financial reports to support the Warfighter’s overall acquisition forecasting. The JCCS is also a platform for web services delivery of expeditionary and contingency business applications to include Theatre Business Clearance (TBC), Government Furnished Life Support Validation (GFLSV) and the Civilian Army Authorization Management System (CAAMS). Other applications in the JCXS platforms used in contingency environments and in worldwide operations include the 3in1 Next Generation (3in1 NG), Contingency Acquisition Support Module (cASM) and the ACSA-Global Acquisition Tracking Reporting Tool (AGATRS). d) Standard Procurement System (SPS): The SPS is the DoD current enterprise contract writing system. SPS automates the contracting process from procurement request through award and administration to final closeout. It provides contract writing functionality to DoD-wide contracting professionals, who use the SPS product suite to acquire supplies and services at over 500 contracting offices located around the world. SPS is used by nearly 24,000 procurement professionals within the Army and the Navy/Marine Corps, as well as nineteen (19) Defense agencies (CONUS & OCONUS). The Standard Procurement System supports the warfighter by bringing greater efficiency and accountability to the DoD procurement process using a standard automated business system process that supports FAR and DFAR contract rules. SPS also supports DoD audit readiness by providing a standardized system process and data validations needed to create contract actions that meet audit evidentiary matter standards and support applicable audit controls. System also provides Procurement Data Standard (PDS) compliant contract data that meets DoD standards for data interoperability throughout the Procure-to-Pay (P2P) end-to-end procurement process. DLA 438 The SPS Joint Program Management Office (JPMO) manages the acquisition of the SPS software and support, which is distributed to and operated by the DoD Components and maintains the suite of applications by providing version releases approximately once per year. Since the program is in the sustainment phase, version releases are limited to security updates, policy updates, technology updates, and product defect fixes. The SPS JPMO also provides help desk services, deployment support, and integration support to its customers. The SPS Milestone Decision Authority is the DLA Program Executive Officer. The Director of Defense Pricing and Contracting (OUSD-DPC) is the Principal Functional Proponent. The Enterprise Contract Writing Module (ECWM) is a strategic initiative, directed by the USD(A&S), to modernize aging SPS Procurement Desktop-Defense (PD2) contract writing technology. ECWM is a technology refresh of PD2 from a client-server based to cloud-based technology stack hosted in the PIEE Amazon Web Services (AWS) GovCloud, to provide next generation 4th Estate contract writing system. In Q3 FY 2024, the DBSSO Program Office deployed ECWM to the initial 4th Estate Agencies in Wave 1. Subsequent Waves 2- 10 are being planned and worked to field ECWM and conduct data migration to the rest of the 4th Estate Agencies, with the goal to meet PD2 sunset date of Sept 30, 2026. PD2 will continue to be available for the services, for a fee, until they are able to migrate to their perspective service contract writing system. HQ DLA Programs includes programs associated with the DLA logistics mission as well as Departmental programs. DLA provides budget administrator support and is responsible for program oversight and policy guidance for these programs, described in the paragraphs that follow: 1. Audit Readiness 2. Contingency Logistics 3. Continuing Health 4. Data Loss Prevention (DLP) 5. Defense Critical Infrastructure Program (CIP) 6. Defense Finance and Accounting Service (DFAS) 7. Defense Information System Network (DISN) 8. Disability Compensation 9. Homeless Blankets 10. Law Enforcement Support Office (LESO) 11. Logistics and Manufacturing Technology 12. Managerial Support 13. Mapping 14. Military Global Positioning System (GPS) User Equipment (MGUE): 15. Morale, Welfare and Recreation (MWR) 16. Unemployment Compensation 17. Warstopper DLA 439 I. Description of Operations Financed: (Cont.) 1. Audit Readiness: This funding supports the audit activities of the DLA General Fund appropriations. This includes: 1) Audit readiness support; 2) Business Process Controls (BPC) support to include Process Cycle Memorandum Review, BPC identification and testing, Corrective Action Plans (CAP), Request for Change (RFC) and CAP validation and documentation remediation; 3) Service provider support which will include updated Memorandum of Agreements, Memorandum of Understanding, or Service Level Agreements and Defense Information Systems Agency (DISA) support; and 4) Other systems and micro applications, CAPs, RFCs, CAP validation and update System Assertion Work Products. 2. Contingency Logistics: The Contingency Logistics program supports military unique (DoD-Mandated) tasks, such as readiness support, that a commercial distribution company would not experience. Contingency Logistics helps to keep the DLA’s prices competitive with those of the private sector, which do not include overhead for DoD unique costs. For example, a commercial operation would either dispose of inventory demanded only in wartime (War Reserve Materiel) or charge the customer for the costs of retaining this inventory. By funding the cost of retaining this inventory outside customer prices, DLA can reduce the materiel surcharge (Cost Recovery Rate) to achieve more comparable pricing. The baseline includes peacetime contingency planning and Command and Control Center costs, and the Department’s hazardous and ozone depleting substances programs. 3. Continuing Health: The Continuing Health program provides coverage for DLA employees affected by reductions-in-force and Base Realignment and Closure (BRAC) actions. 4. Data Loss Prevention (DLP): The Data Loss Prevention program provides enterprise-wide stewardship for the warfighters’ and government employees’ Personal Identifiable Information (PII) to minimize the risk of loss, theft or being compromised within information systems operated by the DLA. This program complies with statutory and regulatory requirements which direct the implementation of a risk reduction strategy using DLP technologies, which will detect and protect unsecured PII on shared drives, e-mails, websites, and throughout the information lifecycle of records. 5. Defense Critical Infrastructure Program (DCIP): The DCIP supports DoD-wide risk management decisions by enabling responsible authorities to execute a wide variety of mission essential functions in support of national security objectives. The Defense Logistics Infrastructure Sector Lead Agent funding was realigned from ASD (Homeland Defense & Americas Security Affairs) in FY 2009 to DLA. This allows Logistics DCIP program management to take place closer to the execution source. DLA facilitates the identification, assessment, and risk management of DoD-wide logistics critical assets. This information is shared with the Combatant Commands, Services, and other Defense Agencies via a DCIP shared data environment for integrated, DoD-wide DCIP risk management. This enables the prioritization of scarce Component resources for remediation of infrastructure vulnerabilities, mitigation of impact of incidents upon infrastructure, and reconstitution of DoD infrastructure capabilities by allowing resources to be applied to Defense critical infrastructure assets essential to project, support, and sustain military forces and operations. 6. Defense Finance and Accounting Service (DFAS): These funds reimburse DFAS for accounting services provided to the General Fund activities (DoD Programs and HQ DLA Programs). 7. Defense Information System Network (DISN): These funds reimburse DISA for the DISN services. DISA publishes their rates in advance. DLA 440 I. Description of Operations Financed: (Cont.) 8. Disability Compensation: This program provides required funding for disability compensation claims for qualified personnel formerly employed at the DLA Clothing Factory (Troop Support) which closed in 1993. 9. Homeless Blankets: The Stewart B. McKinley Homeless Assistance Act of 1987 enables DLA to provide blankets to qualified US 501(C)3 organizations working with the homeless. Homeless shelters request blankets, which are issued on a first-come, first-served basis up to the amount of funding. 10. Law Enforcement Support Office (LESO): The Secretary of Defense (SECDEF) is authorized in accordance with reference (a) to transfer to Federal and State Law Enforcement Agencies (LEAs), personal property that is excess to the needs of the DoD, including small arms and ammunition, that the Secretary determines is suitable to be used by such agencies in law enforcement activities, with preferences for counter- drug/counter-terrorism, disaster-related emergency preparedness or border security activities, under such terms prescribed by the Secretary. The SECDEF delegated program management and oversight to the DLA in 1995. The DLA LESO administers the program in accordance with 10 USC § 2576a. LESO Program provides information and training on the process and procedures of the excess property program to Federal and State agencies annually in accordance with 10 USC § 280. Since inception, the LESO Program has transferred $7.5 billion in equipment to participating LEAs. In FY 2023, equipment valued at over $159 million has been transferred to program participants, and as of the third quarter of FY 2024 it is at $199 million. Over 6,700 LEAs from 52 States and U.S. Territories participate in this highly visible program that enhances law enforcement capabilities while saving taxpayer dollars. LESO has consultation and coordination of authority with the OSD, Department of Justice (DoJ), and the Office of National Drug Control Policy (ONDCP) in an effort to aide in the National Military Strategy and the National Drug Control Strategy. 11. Logistics and Manufacturing Technology: Program funds DLA Headquarters Research, Development, Technology, and Evaluation (RDT&E) expenses for standard and repeatable program management oversight as required by the Financial Management Regulation (FMR) and transitional sustainment of successful R&D projects for operational use until sponsoring organization’s funding (O&M or DWCF) is available, thereby avoiding the “valley of death” for R&D projects. 12. Managerial Support: Program funds, interest, investigative support, Official Representation Funds, and expenses incurred against inactive programs. 13. Mapping: DLA serves as the DoD Integrated Materiel Manager and Distributor of approximately 220,669,000 map items. DLA provides a unified world-wide tailored distribution system for all geospatial products. Map products are no longer strictly hard copy, but also include a wide variety of classified and unclassified hydrographic, topographic, and aeronautical maps in digital form, as well as charts and various publications required to support the warfighter. DLA 441 I. Description of Operations Financed: (Cont.) 14. Military Global Positioning System (GPS) User Equipment (MGUE): MGUE (Increment I) are GPS cards capable of receiving a modernized GPS signal known as military code (M-code); they will be installed in all military equipment items and critical weapon systems/platforms requiring GPS capability. In 2019, the trusted foundry responsible for the production of the Application-Specific Integrated Circuits (ASIC), critical subcomponents integrated into MGUE, provided end-of-life notification to the DoD. The DLA was tasked via Tri-Service memo to conduct the end-of-life procurement of three ASIC configurations, and to provide oversight for their storage and distribution. The execution will provide a stable supply of circuits to the Military Services or until the next incremental ASIC is fielded, originally anticipated to occur in CY2030. The O&M funding covers contractor support services for ASIC storage, and DLA costs to manage the project as the material is free issue to the Services. 15. Family and Morale, Welfare and Recreation (FMWR): The FMWR provides programs and services that deliver operational and mission support by enhancing the mental, physical, and emotional wellbeing of the Warfighter and Warfighter Sustainers; thereby enabling readiness and resilience for a globally proactive Agency. The FMWR is designed to foster readiness, and enhance the lives of Warfighters, Warfighter Sustainers, Families, Civilians, Retirees, Veterans, and other eligible patrons. This work is vital to DLA in support of the total well-being of over 25,000 personnel to better serve the Warfighter and our Nation. Included are family programs, child and youth programs, recreation and sports programs, business programs, and leisure activities. Funding is based on program operational requirements and DoD funding standards for FMWR activities. 16. Unemployment Compensation: The DLA pays the Unemployment Compensation bill for all Defense Agencies. 17. Warstopper Program: The Warstopper Program implements industrial preparedness measures and preserves critical industrial capabilities to support the Department’s readiness requirements and meets requirements of the Defense Production Act of 1950, Section 103 of Executive Order 13603, and the NDAA 1992-1993 Conference Report requirements directing DLA to maintain industrial readiness for critical “War stopper” items. These industrial readiness measures are applied to vulnerable industrial base items within the DLA supply chains such as chemical protective suits, nerve agent antidote auto-injectors, meals-ready-to eat, aging aircraft spares, specialty fuels, the nuclear enterprise, and some specialty steels. Peacetime demand for these items is inadequate to sustain an industrial base sufficient to meet mobilization requirements. DLA uses a rigorous business case evaluation to obtain a return on investment that maximizes warfighter benefits. The Warstopper Program is the single Agency program for the preservation of essential production capability. It provides the means to invest in improving industry responsiveness, typically without purchasing finished goods inventory. The Warstopper Program has led to cumulative DoD inventory, War Reserve Materiel, costs avoidance of nearly $7 billion through the investment of approximately $1 billion over the program’s lifetime (1993). DLA 442$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 107729000, "fy26": 92866000, "name": "DoD Programs", "fy25_current": 105585000, "fy25_request": 101991000, "fy25_cong_amt": 3594000, "fy25_cong_pct": 3.52}$$::jsonb, $${"fy24": 2175000, "fy26": 2330000, "name": "Business Process Reengineering Center", "fy25_current": 2755000, "fy25_request": 2763000, "fy25_cong_amt": -8000, "fy25_cong_pct": -0.29}$$::jsonb, $${"fy24": 558000, "fy26": 2603000, "name": "(DBSSO)", "fy25_current": 2516000, "fy25_request": 2626000, "fy25_cong_amt": -110000, "fy25_cong_pct": -4.19}$$::jsonb, $${"fy24": 20378000, "fy26": 18269000, "name": "Defense Property Accountability System", "fy25_current": 15968000, "fy25_reque