INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dlsa_umbrella$$, $$DLSA$$, $$Defense Legal Services Agency$$, $$DLSA$$, $$om_dw_ba04$$, NULL, $$dw_dlsa$$, 2026, 196301000, 207918000, -17066000, -8.21, 190852000, 164770000, $$The Defense Legal Services Agency (DLSA) provides legal advice, services, and support to the Defense Agencies, the Department of Defense (DoD) Field Activities, and, as assigned, other organizational entities within the DoD. Among other legal services, the DLSA administers the DoD Standards of Conduct Program; supports and assists the Assistant Secretary of Defense for Legislative Affairs (ASD(LA)) in developing the DoD Legislative Program, to include drafting legislation and comments; negotiating on behalf of the DoD clients with private entities and other Government agencies; ensuring proper use of Government funds and property; providing opinions and counseling on legal compliance issues; and participating in contractual matters. The Defense Office of Hearings and Appeals (DOHA) is the largest component of the DLSA, and is responsible for: • Adjudicating personnel security clearance cases for contractor personnel performing classified work for DOHA-serviced DoD Components and 30 other Federal Agencies and Departments; • Conducting personal appearance hearings, and issuing decisions in security clearance and sensitive national security position cases for DOHA-serviced DoD civilian and military personnel; • Providing legal reviews, approving statements of reasons, conducting hearings, and issuing decisions in cases under DOHA jurisdiction requiring trustworthiness decisions for contractor performance of sensitive duties; and, • Implementing the administrative due-process requirements of Executive Order 10865 on behalf of the DoD, which serves as the executive agent for the entire Federal Government's implementation of the National Industrial Security Program. The Office of Military Commissions (OMC), established by the Secretary of Defense on March 21, 2002, under the DLSA, handles the trials of enemy combatants pursuant to the Military Commissions Act of 2009. There are currently 12 detainees with active charges pending before military commissions, most notably 5 defendants allegedly involved with the September 11th attacks as well as an alleged United States Ship (USS) Cole bomber. The DLSA FY 2026 President’s Budget request includes funding for civilian pay and allowances, contract support, interagency reimbursable agreements (e.g., U.S. Marshals Service), reimbursable costs for the DoD components providing support to detainee efforts (e.g., document declassification and information security), rent, temporary duty travel costs, supplies, furniture, training, information technology support, telecommunications, and security. DLSA 469$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 65072000, "fy26": 71118000, "name": "Compensation and Benefits", "fy25_current": 66776000, "fy25_request": 74576000, "fy25_cong_amt": -7800000, "fy25_cong_pct": -10.46}$$::jsonb, $${"fy24": 2216000, "fy26": 2486000, "name": "Defense Legal Services Agency, HQ (DLSA HQ)", "fy25_current": 2383000, "fy25_request": 2526000, "fy25_cong_amt": -143000, "fy25_cong_pct": -5.66}$$::jsonb, $${"fy24": 9718000, "fy26": 10811000, "name": "Defense Office of Hearings and Appeals (DOHA)", "fy25_current": 11321000, "fy25_request": 12531000, "fy25_cong_amt": -1210000, "fy25_cong_pct": -9.66}$$::jsonb, $${"fy24": 29742000, "fy26": 26556000, "name": "HABEAS Corpus (HC)", "fy25_current": 35691000, "fy25_request": 37947000, "fy25_cong_amt": -2256000, "fy25_cong_pct": -5.95}$$::jsonb, $${"fy24": 89553000, "fy26": 53799000, "name": "Office of Military Commission (OMC)", "fy25_current": 74681000, "fy25_request": 80338000, "fy25_cong_amt": -5657000, "fy25_cong_pct": -7.04}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 472, 485, FALSE, $${"json_key": "DLSA__umbrella"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 147620000, to_jsonb(ARRAY[$${"fy25": 66.662, "fy27": 69.6, "name": "Compensation and Benefits", "fy26_current": 69.063, "fy26_request": 71.118, "fy26_cong_amt": -2.055, "fy26_cong_pct": -2.89}$$::jsonb, $${"fy25": 5.366, "fy27": 2.391, "name": "Defense Legal Services Agency, HQ (DLSA HQ)", "fy26_current": 2.283, "fy26_request": 2.486, "fy26_cong_amt": -0.203, "fy26_cong_pct": -8.17}$$::jsonb, $${"fy25": 9.129, "fy27": 10.408, "name": "Defense Office of Hearings and Appeals (DOHA)", "fy26_current": 9.877, "fy26_request": 10.811, "fy26_cong_amt": -0.934, "fy26_cong_pct": -8.64}$$::jsonb, $${"fy25": 23.308, "fy27": 25.955, "name": "HABEAS Corpus (HC)", "fy26_current": 24.329, "fy26_request": 26.556, "fy26_cong_amt": -2.227, "fy26_cong_pct": -8.39}$$::jsonb, $${"fy25": 0.074, "fy27": 2.144, "name": "Military Justice Review Panel (MJRP)", "fy26_current": 0.0, "fy26_request": 0.0, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 85.637, "fy27": 37.122, "name": "Office of Military Commission (OMC)", "fy26_current": 49.383, "fy26_request": 53.799, "fy26_cong_amt": -4.416, "fy26_cong_pct": -8.21}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part1/DLSA_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dma_umbrella$$, $$DMA$$, $$Defense Media Activity$$, $$DMA$$, $$om_dw_ba04$$, NULL, $$dw_dma$$, 2026, 243974000, 244689000, -3328000, -1.36, 241361000, 226665000, $$The Defense Media Activity (DMA) is a Department of Defense (DoD) mass media organization that creates and distributes DoD content across a variety of media platforms to audiences around the world and provides joint-service training for the public affairs and visual information career fields. As listed in DoD Directive 5105.74, DMA: A. Provides consolidated public-facing website hosting service within a central program to leverage enterprise-level purchasing power, B. Provides DoD Public Affairs and Visual Information common core training and education, C. Provides and operates a digital asset management system to afford DoD and American public access to publicly released imagery depicting current U.S. military activities and operations, D. Provides central receipt, retrieval, and storage of DoD publicly released Visual Information per the National Archives and Records Administration (NARA) records schedule, E. Produces DoD-wide and Component-unique audio-visual productions supporting objectives of DoD leadership to support and improve quality of life and morale, promote situational awareness, provide force protection information, and sustain readiness, F. Provides U.S. radio and television programming and integrated command information to authorized audiences serving outside of the U.S., its territories, or possessions, and G. Administers the Stars and Stripes news service, which respects the editorial independence in accordance with the First Amendment of the U.S. Constitution. OP-5 Exhibit DMA$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 225548000, "fy26": 208766000, "name": "Defense Media Operations", "fy25_current": 223945000, "fy25_request": 227273000, "fy25_cong_amt": -3328000, "fy25_cong_pct": -1.46}$$::jsonb, $${"fy24": 18426000, "fy26": 17899000, "name": "Stars and Stripes", "fy25_current": 17416000, "fy25_request": 17416000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/DMA_OP-5.pdf$$, 1, 17, FALSE, $${"json_key": "DMA__DMA", "fy27_v192_bucket_a_dw_dma_via_dwia": {"session": "2026-05-09_v41", "source_pdf": "O&M/FY27/DW/Vol1_Part1/DWIA_OP-5.pdf", "rename_note": "DMA renamed to DWIA in FY27", "content_hash": "a32a5c25ec65895774e85766f50fe51b4b75464e928711dd214f7f853b7468d3"}}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 207551000, NULL, NULL, NULL, $$O&M/FY27/FY2027_o1.txt$$, 37115000) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dodea_dodde$$, $$DoDDE$$, $$DoD Dependents Education$$, $$DODEA$$, $$om_dw_ba04$$, NULL, $$dw_dodea$$, 2026, 3535269000, 3559288000, -16283000, -0.46, 3543005000, 3600175000, $$The Department of Defense Education Activity (DoDEA) is the Department of Defense’s (DoD) showcase for education excellence and provides a world-class education program that inspires and prepares students in military communities worldwide to be successful and responsible citizens in a dynamic global environment. The DoDEA schools’ diverse curriculum offerings fully support the DoDEA Strategic Plan, Blueprint for Continuous Improvement. The DoDEA is a DoD field activity operating under the direction, authority, and control of the Under Secretary of Defense for Personnel and Readiness (P&R) and Assistant Secretary of Defense for Manpower & Reserve Affairs (M&RA). The DoDEA comprises the DoD Dependents Schools (DoDDS), the DoD Domestic Dependent Elementary and Secondary Schools (DDESS), Management Headquarters, and the Consolidated School Support. The mission of the DoDDS program is to provide a superior educational program that educates, engages, and empowers military-connected students to succeed in a dynamic world. In accomplishing its mission, the DoDEA looks to national education initiatives to continually enhance its programs. The DoDDS educates 45,057 students in 107 schools located in 11 countries (Bahrain, Belgium, Cuba, Germany, Italy, Japan, Korea, Netherlands, Spain, Turkey, and the United Kingdom), and has oversight of the DoDEA Virtual High School (DVHS) to offer online courses to meet academic and career-oriented goals. The DoDDS program also provides funds for 4,211 students enrolled in non-DoD Schools. The DoDEA Non-DoD Schools Program (NDSP) supports the primary and secondary education of eligible dependents of active-duty U.S. military and DoD civilians assigned to remote, overseas areas where DoDEA schools are unavailable. Eligible military and civilian sponsors' dependents must be included on official orders and meet age requirements. To help defray education expenses for eligible dependents, NDSP assists with funding tuition and other costs. The DoDEA funds the cost to educate over 4,800 dependents who attend schools worldwide in Asia, Africa, Europe, and the Americas. NDSP regulations include Title 20 U.S. Code Section 926(b), DoDEA Regulation 1342.13, DoDEA Regulation 1035.1, and the U.S. Department of State Standardized Regulation (DSSR) Section 270. DoDDE 499 Like DoDDS, the DDESS program seeks to provide a world-class education to students in the U.S., Guam, and Puerto Rico military communities. In accomplishing its mission, DoDEA looks to national education initiatives to continually enhance its programs. The DDESS educates 22,001 students in 53 schools in seven states (Alabama, Georgia, Kentucky, New York, North Carolina, South Carolina, and Virginia), the Territory of Guam, and the Commonwealth of Puerto Rico. The DDESS program also funds 629 students enrolled in NDSP, whose active-duty U.S. military and DoD civilians are assigned in Canada, Mexico, and South America, and manages Special Arrangement contracts for 1,285 students with local school districts. The contracts provide funds for payment of tuition and transportation services at locations not served by the DDESS. Special Arrangements contracts are available in Delaware, Massachusetts, New York, and Puerto Rico. A Special Arrangement is an agreement under Title 10 U.S. Code § 2164 (10 U.S.C. 2164) between the Secretary of Defense, or designee, and a public Local Educational Agency (LEA) whereby a school or school system operated by the LEA provides educational services to eligible dependent children of military personnel and federally employed civilian personnel. Special Arrangements support partial or total federal funding for educational services to the LEAs. Special Arrangement contracts with LEAs that provide full educational services, including transportation for military dependents, exist at Hanscom Air Force Base (MA), Dover Air Force Base (DE), and West Point (NY). In 2004, DoD established two additional Special Arrangement contracts to provide educational services to dependents residing in the commuting areas of Ceiba and Ponce, Puerto Rico. The DoD established these two Special Arrangement contracts due to the closure of DoD installations in Puerto Rico and the requirement to transport children to English-speaking schools. The Management Headquarters group oversees, directs, and controls Agency activities, establishes educational standards, develops Agency- wide policy and guidance, monitors programs and outcomes, provides technical assistance, and garners resources for DoDEA. They provide academic leadership, support, and direction to area directors, district superintendents, and school administrators; develop the Pre-kindergarten (Pre-K) through Grade 12 curriculum; conduct educational program evaluations; coordinate curriculum materials adoptions; implement consistent, rigorous academic programs that reflect national trends; coordinate systemic professional development and accountability profiles; and provide counsel to the Under Secretary of Defense (P&R) on matters relating to educational programs for Pre-K-12 dependents of Service members. The Consolidated School Support (CSS) program streamlines financial management, logistics, procurement, human resources, education, information technology, internal review, manpower management, and safety and security at DoDEA. These functions directly support specific day- to-day operations, including resource management personnel who are responsible for area office and district budgets and accounting records, procurement personnel who manage and procure contracts for the area offices, districts, and schools; human resources personnel who process personnel actions for area offices, districts, and school personnel; engineers who coordinate school facility projects; and, instructional support specialists who coordinate and conduct assessments, staff development, and curriculum reviews in support of the educational programs for grades Pre-K-12. The Educational Partnership Program (EPP) responds to congressional direction in Section 574(d) of Public Law 109-364, as amended (codified at 20 U.S.C. 7703b note), to ease the transition of military dependent students to LEAs. Approximately 80% of military children (~ 1.2 million children) in the U.S. attend public schools. DoDDE 500 DoDEA Schools: To ensure sustained, high levels of student achievement, the DoDEA Blueprint for Continuous Improvement contains goals and benchmarks that drive resources and organizational improvements. The Blueprint is the catalyst for changing the teaching and learning process, raising the standard of learning to ensure excellence, creating greater local autonomy in devising methods and strategies to meet standards, creating a common language for communication among all stakeholders, and creating greater accountability for reaching expected outcomes. The DoDEA Blueprint unifies the strategic direction for both DoDDS and DDESS, yet provides the flexibility to address each program and community’s unique issues and challenges. The plan provides a road map for keeping the DoDEA at the forefront in advancing the DoD’s agenda for education and, as a leader in the nation, improving student performance and achievement. The DoDEA schools are primarily overseas, and the DoDEA performs its mission in many unique and demanding circumstances due to geography, U.S. national interests, and the current military environment, despite heightened security and the perpetual threat of terrorism. This budget request supports the DoDEA’s plan to: •   Strengthen the high school (9-12) program to include advanced studies; support and enrichment in academic courses; enhance college and career counseling; provide professional/technical preparation; increase distance learning for student learning; and professional staff development. •   Provide specialized equipment and furnishings for children with moderate to severe disabilities to comply with the Individuals with Disabilities Education Act (IDEA); maintain staffing and provide professional development and materials for special education staff. •   Infuse technology into the curriculum and enhance distance learning system capabilities. •   Maintain and develop a virtual school curriculum and an enhanced instructional delivery system. The 21st Century Military Child Initiative will provide synchronous and asynchronous learning opportunities aligned with DoDEA’s curriculum to address the educational needs of military dependent students in transition via a fully accredited Virtual School program. The initiative will also create a systemic approach of blended learning via a reusable, object-based digital resources system to support face-to-face instruction and professional development within DoDEA. •   Maintain quality programs with increased academic rigor through data analysis of student performance. •   Focus on continuous professional staff growth and development so our teachers can provide quality instruction and optimize student achievement. •   Provide students with uniform curricula and standards that mitigate the stress of frequent moves, unit deployments, redeployments, and extensions. DoDDE 501 •   Implement ambitious strategic goals and performance metrics for optimum student achievement. Family Assistance (FA): The FA program provides programs, resources and outreach to Active Duty and Reserve Component personnel, their families, and survivors that are more effectively resourced and executed at the Department level as identified in Title 10 U.S. Code Chapter 88 – Military Family Programs and Military Child Care (10 U.S.C. 1781-1800). These programs include but are not limited to the 1-800 Military OneSource call center and website; the Military and Family Life Counseling Program; Spouse Education and Career Opportunities including spouse licensure portability, My Career Advancement Account (MyCAA) tuition assistance, and the Military Spouse Career Accelerator Program (MSCAP); Child Development Program (CDP) initiatives including community based fee assistance, Child Care In Your Home pilot, childcare public-private partnerships, and oversight; youth development and support services; and centralized morale, welfare and recreation programs. Programs provide outreach both on and off installations, as well as to geographically dispersed populations. The Military OneSource website serves as the Department’s entry point for comprehensive, vetted information, online resources, tools, and applications that assist Service members and their families in reaching their goals, overcoming challenges, and thriving in military life. Specific examples include relocation, deployments, childcare, Exceptional Family Member (EFMP & Me), emergency family assistance, and dedicated resources for commanders to address and support economic security. Military OneSource serves as the single DoD point of contact for the collection of personnel accounting information from the DoD Components (DoDI 3001.02 "Personnel Accountability in Conjunction with Natural or Manmade Disasters") and has become the Department’s standard for providing 24/7 assistance to military members and their family members around the world. Family Advocacy Program (FAP): The Military Community Advocacy (MCA) Directorate allocates and distributes the centrally managed FAP funding to the Military Services to operate installation-level Family Advocacy Programs and to support Coordinated Community Response (CCR) efforts involving other community entities that address domestic abuse, child abuse and neglect, and child-initiated serious harmful behaviors between children and youth. The FAP delivers evidence-based and/or informed prevention and clinical intervention programs that address adult- initiated child abuse and neglect and domestic abuse and child-initiated serious harm between children and youth. The program takes a multi- tiered approach, starting with prevention efforts and extending to response when there is adult-initiated abuse. FAP includes a distinct prevention arm that aims to reach all Service members, family members, and intimate partners. Also included are New Parent Support Program is an extension of FAP prevention that provides for home visitation for parents who want to improve healthy parenting skills as well as for those who screen at-risk for child abuse and neglect. Domestic abuse victim advocates (DAVA) provide confidential safety planning and risk assessments, information about available military and civilian resources, and victim support, and clinical staff provide clinical intervention services that support the evaluation and treatment of domestic abuse, child abuse, and neglect within the Department of Defense. The MCA program also addresses serious harm to children, which includes problematic sexual behavior and serious harmful behaviors between children and youth, related to misconduct on military installations. This includes engagement with civilian subject matter experts and the requirement to maintain a database that tracks incidents of problematic sexual behavior between children and youth at the installation level. DoDDE 502 The budget supports Office of the Secretary of Defense FAP and Service-level data collection, analysis, and reporting as required by law and per DoD and Service policies. This includes the development of a Congressionally mandated central database with information on each domestic abuse incident reported to a commander, a law enforcement authority of the Armed Forces, legal, or the Family Advocacy Program. Additional support includes: training for service providers, commanders, chaplains, and others who work with military personnel and families; research efforts; monitoring of Service-level implementation of the research-based Incident Severity Scales and the Intimate Partner Physical Incident Risk Assessment Tool; the development of comprehensive screening and assessment instruments for problematic sexual behavior between children and youth; and the implementation of the National Child Traumatic Stress Network (NCTSN) learning collaborative platform to train clinical staff and members of the coordinated community response on trauma-informed care and evidenced-based programs. The FAP funds support DoD- level Fatality Review efforts, including the Annual DoD Fatality Review Summit, and the DoD policy-required annual certification, accreditation, and inspection process per Section 546 of Public Law 108-136, the National Defense Authorization Act for Fiscal Year 2004 which directed Military Departments to conduct multidisciplinary, impartial reviews of all deaths suspected to be the result of abuse. The FAP budget also supports the additional responsibilities, staffing needs, inflation, and requirements from National Defense Authorization Act and U.S. Government Accountability Office requirements. Financial Readiness: As part of the 2025 DoD Comprehensive review, the Office of Financial Readiness merged with the Office of Military Compensation Policy to form the Office of Military Compensation and Financial Readiness (MC&FR). The financial readiness component was established to address the needs of Servicemembers and their families, to make informed financial decisions, and to meet professional and personal goals throughout the military lifecycle. Funding supports Title 10 U.S. Code § 992 (10 U.S.C. 992) requirements for the Secretary of Defense to carry out a program to provide comprehensive financial literacy training and counseling to Armed Forces Members. Public Law 114-92, the National Defense Authorization Act for Fiscal Year 2016, greatly expanded the required education of Service members on various financial matters and services under 10 U.S.C. 992. The office provides policies and programs, including centralized counseling support, education strategies, communication efforts, innovative learning modalities, and a collaborative financial readiness network to sustain Service members' and families' overall financial well-being. The office also serves as the Department’s focal point to carry out the Secretary of Defense’s responsibility for prescribing rules to carry out Title 10 U.S.C. § 987, commonly referred to as the Military Lending Act (MLA). Voluntary Education: The DoD values programs that support our Service members' professional and personal development and successful transition to the civilian workforce. Voluntary, off-duty education and training programs adhere to Title 10 U.S. Code § 2005, 2006a, and 2007 statutory requirements that articulate directives and restrict the military Services’ financial assistance to help Service members attain academic and skill-based credentials. The Officer & Enlisted Personnel Management office (OEPM) manages policy and oversight of these programs in accordance with applicable statutes, appropriations, and Executive Orders. DoDDE 503$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 2365332000, "fy26": 2314198000, "name": "1. DoDEA", "fy25_current": 2291133000, "fy25_request": 2288734000, "fy25_cong_amt": 2399000, "fy25_cong_pct": 0.1}$$::jsonb, $${"fy24": 19862000, "fy26": 20878000, "name": "1. Management Headquarters", "fy25_current": 21942000, "fy25_request": 20538000, "fy25_cong_amt": -776000, "fy25_cong_pct": -3.78}$$::jsonb, $${"fy24": 361915000, "fy26": 242660000, "name": "2. Consolidated School Support", "fy25_current": 294936000, "fy25_request": 251506000, "fy25_cong_amt": 75051000, "fy25_cong_pct": 29.84}$$::jsonb, $${"fy24": 54430000, "fy26": 2301000, "name": "3. Educational Partnership Program", "fy25_current": 2277000, "fy25_request": 27244000, "fy25_cong_amt": -744000, "fy25_cong_pct": -2.73}$$::jsonb, $${"fy24": 1246809000, "fy26": 1319786000, "name": "4. DoDDS", "fy25_current": 1262306000, "fy25_request": 1283939000, "fy25_cong_amt": -61800000, "fy25_cong_pct": -4.81}$$::jsonb, $${"fy24": 682316000, "fy26": 728573000, "name": "5. DDESS", "fy25_current": 709672000, "fy25_request": 705507000, "fy25_cong_amt": -9332000, "fy25_cong_pct": -1.32}$$::jsonb, $${"fy24": 1169937000, "fy26": 1285977000, "name": "2. Family Assistance/Family Advocacy Programs", "fy25_current": 1251872000, "fy25_request": 1270554000, "fy25_cong_amt": -18682000, "fy25_cong_pct": -1.47}$$::jsonb, $${"fy24": 858712000, "fy26": 934628000, "name": "1. Family Assistance", "fy25_current": 909444000, "fy25_request": 934180000, "fy25_cong_amt": -13736000, "fy25_cong_pct": -1.47}$$::jsonb, $${"fy24": 261105000, "fy26": 287330000, "name": "2. Family Advocacy Program", "fy25_current": 280711000, "fy25_request": 273736000, "fy25_cong_amt": -4025000, "fy25_cong_pct": -1.47}$$::jsonb, $${"fy24": 44334000, "fy26": 57931000, "name": "3. Financial Education", "fy25_current": 55848000, "fy25_request": 56681000, "fy25_cong_amt": -833000, "fy25_cong_pct": -1.47}$$::jsonb, $${"fy24": 5786000, "fy26": 6088000, "name": "4. Voluntary Education", "fy25_current": 5869000, "fy25_request": 5957000, "fy25_cong_amt": -88000, "fy25_cong_pct": -1.48}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 502, 530, FALSE, $${"json_key": "DODEA__umbrella", "fy27_v192_bucket_a_dw": {"session": "2026-05-09_v41", "source_pdf": "O&M/FY27/DW/Vol1_Part1/DoWDE_OP-5.pdf", "content_hash": "06376d4d6f6f59c45549f8a13a4195a2d8071b93d5261da616d1b1e5f665f73f", "source_page_amount": 6, "source_page_description": 2}}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 3493232000, NULL, NULL, NULL, $$O&M/FY27/FY2027_o1.txt$$, 1650716000) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_mc_reserve_4emm$$, $$4EMM$$, $$Cancelled Account Adjustment$$, NULL, NULL, NULL, $$mc$$, 2026, 0, 0, 0, NULL, 0, 0, NULL, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY26/Army/Reserve Army Operation and Maintenance.pdf$$, NULL, NULL, FALSE, $${"fy26_v192_subprogram_synth": {"session": "2026-05-09_v41", "source_pdf": "O&M/FY26/Army/Reserve Army Operation and Maintenance.pdf", "synth_type": "subprogram_synth", "content_hash": "1888af3577e876f823a5fa6edf444b96899801a6afff60dc7049de58f2ee3d56"}}$$::jsonb, $$2026-05-08T00:07:59.691542+00:00$$, FALSE, 18000, NULL, NULL, NULL, 0, 0, NULL, NULL, NULL, $$O&M/FY27/Navy/OMMCR_Book.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dtra_umbrella$$, $$DTRA$$, $$Defense Threat Reduction Agency$$, $$DTRA$$, $$om_dw_ba04$$, NULL, $$dw_dtra$$, 2026, 938404000, 858476000, -17300000, -2.02, 841176000, 708214000, $$The U.S. faces a highly competitive security environment characterized by diverse and dynamic weapons of mass destruction (WMD) threats across multiple domains. Consistent with national strategy and the Interim National Defense Strategic Guidance (INDSG), focused on Peace Through Strength, the Defense Threat Reduction Agency (DTRA) is focusing its efforts to counter threats from our strategic nation-state competitors with a focus on the INDOPACIFIC region. China and Russia are expanding and modernizing their nuclear forces, diversifying advanced conventional WMD delivery systems, and actively developing chemical, biological, radiological, and nuclear (CBRN) capabilities that directly threaten the homeland and American security. At the same time, Iran and North Korea are pursuing advanced warfighting capabilities to undermine regional security and global stability in ways that pose considerable risk to U.S. strategy and priorities. Additionally, the potential for natural or accidental release of biological pathogens or hazardous chemicals contributes to an evolving, destabilizing, and dynamic CBRN threat environment. “China remains intent on modernizing, diversifying, and expanding its nuclear posture. China’s nuclear weapons and advanced delivery systems pose a direct threat to the Homeland and are capable of delivering catastrophic damage to the U.S. and threatening U.S. military forces here and abroad. China most likely possesses capabilities relevant to chemical and biological warfare (CBW) that pose a threat to U.S., allied, and partner forces as well as civilian populations.” [Annual Threat Assessment, 2025, ODNI] The DTRA budget invests in delivering the technologies, methodologies, and capabilities required to counter WMD threats and mitigate risk while enabling DoD, the United States Government (USG), and international partners to deter strategic attacks against the U.S. and its Allies; prevent, reduce, and counter WMD and emerging CBRN threats; and prevail against WMD- armed adversaries in crisis and conflict. In FY 2024, DTRA received an unmodified audit opinion (the highest level of opinion possible), leading the way within the Department and proving that DTRA is accountable for the taxpayer funds entrusted to us. The DTRA will continue to ensure we receive that same opinion every year. DTRA 587 The DTRA strategic priorities align with the priorities of the 2025 INDSG and other strategic guidance documents directing DoD to meet national security goals through deterrence and supporting warfighter lethality and resilience. The DTRA aligns operations, activities, and investments primarily focused on China’s WMD threats, but also addresses other adversaries and high-risk regional destabilizers. In its dual roles as a Defense and Combat Support Agency, DTRA is committed to achieving concrete outcomes and strategic effects through its five core functions: •   Ensuring a reliable, resilient strategic deterrent through nuclear surety, mission assurance, and crisis response activities; •   Developing and delivering technical capabilities to the warfighter across the WMD threat spectrum; •   Preventing, reducing and eliminating CBRN threats through targeted and focused risk reduction, arms control, and partner capacity building and warfighter support; •   Providing strategic and operational support through subject matter expertise, technical reach back, tailored analysis, and exercise support; and •   Supporting the Joint Force with plans, concepts, exercises and materiel solutions to address CBRN operational and strategic risks. As a Combat Support Agency, DTRA remains focused on identifying, developing, and delivering solutions and capabilities required to counter WMD and emerging CBRN threats specifically posed by China, but also applicable to those from Russia, North Korea, and Iran. The DTRA supports whole-of-government efforts to prevent the acquisition, proliferation, and use of WMD and associated materials and to confound the decision calculus of WMD-armed adversaries. Given the CBRN-related challenges posed by WMD-armed actors, DTRA will continue to enhance its crisis response readiness and its ability to posture for crisis and conflict. The DTRA enduring partnerships at the international level, within the DoD, and across the USG, are among the Agency’s greatest strengths. The DTRA will carefully focus these relationships to better align with whole-of-government activities targeting WMD challenges in accordance with Department priorities. This includes emphasis on collaboration and integration with allies and partners in ways that create enduring advantages for DoD and the USG. By focusing on addressing these challenges in integrated and cross-cutting ways, DTRA can leverage its highly skilled workforce of subject matter experts to provide the full spectrum of support to counter WMD threats. DTRA’s Operation & Maintenance (O&M) Non-Cyber programs support the nuclear enterprise, develop common situational awareness to inform global integrated operations, targeted and focused building partnership capacity efforts to enhance homeland defense, while maintaining and implementing capability for future Arms Control. DTRA programs strengthen our nuclear deterrent through force-on-force exercises and wargaming; tracking nuclear weapons to maintain positive control and support emergency verifications; providing visibility on mission risk across the DoD enterprise; conducting mission assurance assessments that provide risk mitigation strategies for Defense Critical Assets and Infrastructure; and testing strategies to defend critical missions against emulated adversarial disruption. Additionally, O&M funding enables DTRA to support Combatant Command (CCMD) responses to WMD and emerging CBRN threats through planning and exercise support; monitoring and verification activities; CBRN material security and elimination, creation of decision support tools to increase awareness of consequence of action DTRA 588 and implications of WMD attack; and allied and partner capacity/capability for interoperability, crisis/conflict division of labor, and awareness of current and future WMD threats. Narrative Explanation of Changes: The FY 2026 O&M budget request reflects an overall decrease of $133.0 million when compared to the FY 2025 current estimate. This net decrease includes a price adjustment of +$13.6 million; program increases of +$56.7 million; program decreases of -$203.3 million. The DTRA continually strives to achieve the right balance of civilian Full-Time Equivalents and service support contracts. In the face of rapidly growing and evolving requirements to counter and deter WMD and emerging threats, DTRA will continue to strike the right parity across our mission portfolio to ensure support for the highest priorities within the overall resource constraints. DTRA 589 $ in thousands FY 2024            FY 2025           FY 2026 Actuals            Enacted           Estimate A. NONPROLIERFATION ACTIVITIES                                                               53,482             58,328            52,611 As an essential element of nonproliferation efforts, arms control activities enhance confidence in agreement compliance through effective inspection, monitoring, and verification. In addition, arms control activities contribute to a more stable and calculable balance of world power. The U.S. seeks to reduce the threat from WMD in several ways, particularly through efforts to control, safeguard, and eliminate existing weapons and to verify and monitor compliance with agreements intended to prevent the proliferation of nuclear weapons. As the focal point for U.S. implementation, DTRA executes current arms control treaties and agreements and prepares for new initiatives. The DTRA is increasingly involved in shaping the international security environment through on-site activities in post-conflict stabilization operations because of its arms control experience. The DTRA inspectors provide the Secretary of Defense with first-hand evidence that international commitments are fulfilled through the verifiable reduction of the world’s stockpiles of nuclear, chemical, and conventional weapons which includes the training and equipping of law enforcement and border guard personnel in the former Soviet Union, Eastern Europe, Baltics, Balkans, South Asia, Southeast Asia, and Africa. The DTRA arms control mission directly enhances U.S. security interests. The three primary objectives of DTRA’s arms control activities are to: conduct USG inspections of foreign facilities, territories, or events; coordinate and conduct the escort of inspection teams for inspections or continuous monitoring activities in the U.S. and at U.S. facilities overseas; and acquire and field technology capabilities required to implement, comply with, and allow full exercise of U.S. rights and prerogatives under existing and projected arms control agreements. Implementation of existing arms control agreements is an important nonproliferation element. The DTRA trains, equips, organizes, deploys, and exercises operational control over inspection, monitoring, and escort teams, ensuring the USG can exercise its full treaty rights for on-site inspection and protect U.S. treaty rights with respect to inspected sites or activities. The DTRA also installs, operates, maintains, and sustains U.S. nuclear detonation verification and monitoring radionuclide and waveform stations as part of the U.S. contribution to the Comprehensive Nuclear-Test-Ban Treaty Organization’s International Monitoring System. The DTRA provides technical advice to USG elements concerned with developing, implementing, or evaluating compliance with arms control agreements. The DTRA continues its efforts to carry out the inspection, escort, and monitoring provisions of the Plutonium Production Reactor Agreement, the Vienna Document 2011, the Dayton Peace Agreement, the Chemical Weapons Convention, and Comprehensive Nuclear-Test-Ban Treaty (when ratified). The DTRA executes other missions requiring its unique skills, organization, and experience, including support for the Biological Weapons Convention; confidence and security building measures; the International Atomic Energy Agency Integrated Safeguards; and the Technical Equipment Inspection program. DTRA 590 The DTRA budget for nonproliferation arms control activities provides support for the full range of treaty implementation requirements and reflects the latest revision to treaty entry-into-force dates and projections for FY 2026 inspection and compliance requirements. TREATY/AGREEMENT                                                          ENTRY-INTO-FORCE Comprehensive Nuclear-Test-Ban Treaty                                     TBD Vienna Document 2011                                                      1 Dec 2011 International Atomic Energy Agency Integrated Safeguards                  6 Jan 2009 Plutonium Production Reactor Agreement                                    23 Sep 1997 Chemical Weapons Convention                                               29 Apr 1997 Dayton Peace Agreement                                                    14 Dec 1995 Conventional Armed Forces in Europe Treaty (SUSPENDED) (7 Dec             17 Jul 1992 2023*) Biological Weapons Convention                                             26 Mar 1975 The DoD Implementation Guidance concerning the U.S. Full And Indefinite Suspension Of Its Obligations Under The Treaty On Conventional Forces in Europe, signed on 26 July 2024, tasks DoD Components with residual responsibilities in accordance with DoD Directive 2060.01 Implementation Of, And Compliance With, Arms Control Agreements (for specific details see classified memo). Inspections Operations Missions This includes activities required to implement and support DoD-directed treaty and agreement activities essential to reestablishing deterrence and focused on supporting both current and future verifiable and enforceable arms control arrangements. Supported agreements and treaties include the Chemical Weapons Convention Treaty, the Plutonium Production Reactor Agreement, the Biological Weapons Convention, the Comprehensive Nuclear-Test-Ban Treaty, and the International Atomic Energy Agency Integrated Safeguards. The program funds mission costs for on-site implementation and essential support to include training, exercises, staff assisted visits, planning and negotiations, interagency coordination, and workforce development to support future arms control regimes and risk reduction measures. The program also supports annual exercises with the Korea Arms Control Verification Agency in the U.S., Republic of Korea, and Germany. These efforts include expanding engagement with allies and partners to strengthen cooperation in the area of arms control and nonproliferation including the AUKUS (Australia, the United Kingdom, and the U.S.) partnership. Funding for the Chemical Weapons Convention Missions was consolidated into the Inspection Operation Missions programs in FY 2026. DTRA 591 Conventional Weapons Missions The DTRA conducts Conventional Weapons Missions under the auspices of international agreements, treaties, and interagency agreements. The Vienna Document 2011 and the Dayton Peace Agreement program activities include compliance and verification missions, such as active inspections, and passive escort, liaison, and observation activities. Under the Dayton Peace Agreement, DTRA provides observers during active inspections between the four parties under the auspices of the Organization for Security and Cooperation in Europe. The DTRA supports the Defense Security Cooperation Agency (DSCA) in countering the illicit diversion of U.S.-origin defense articles previously transferred to Ukraine for the support of End-Use Monitoring activities. The current security environment increased the importance of the Vienna Document 2011, as it remains one of the key international arms control agreements aimed at strengthening deterrence by promoting confidence and security building measures. The Conventional Weapons Missions program has expanded to include previously underused provisions of the Vienna Document 2011, such as Chapter X (Regional Measures) and Chapter IV (Military Contacts), each of which seek to strengthen relations with key non-NATO partners and to enhance deterrence by demonstrating the U.S. military will remain the strongest and most lethal force in the world. In addition, since Russia’s withdrawal from the Conventional Armed Forces in Europe Treaty in 2023 amounted to a fundamental change in circumstances, the U.S. responded by indefinitely suspending participation in the treaty. During the period of the treaty’s suspension, the Office of the Under Secretary of Defense for Acquisition & Sustainment (OUSD(A&S)) has directed DTRA to preserve arms control capability and expertise for on-site inspection activities. Inspections Training and Support (Previously named Treaty Support) This program serves as the USG source for providing training for inspectors and escorts, for students from USG agencies, and for arms control experts at U.S. facilities subject to inspection. The program also serves as the centralized language support node for the overall on-site inspection mission by funding military linguists, interviewing and selection processes, and scheduling of language professionals for assignment to DTRA. The program also provides in-house and contracted language training, and linguistic support, and is responsible for the recruitment of professional military linguists, their training at the Defense Language Institute, and their day-to-day mission support of arms control operations from three different locations. In-house Russian language instructors provide daily treaty-specific, technical, and global language training to over 100 professional military linguists and Foreign Area Officers. The instructors also play a central role in ensuring language professionals can carry out their vital mission. In addition, Inspections Training and Support conducts external language immersion courses for languages other than Russian to ensure DTRA has the proper unique language professionals to support its expanding regional focus. The DTRA also offers treaty courses for future U.S. inspectors and escorts and other Federal Government offices supporting ongoing arms control missions. The Agency provides courses for the following agreements: the Plutonium Production Reactor Agreement, International Atomic Energy Agency Integrated Safeguards, and the Chemical Weapons Convention. Inspections Training and Support also contracts for additional training needed for both the personal safety and knowledge of arms control inspectors, to include the Radiological Worker II and Graphite Moderated Reactor Seminar Course. The program ensures U.S. arms control inspection and escort teams are trained and certified prior to worldwide deployment. DTRA 592 The Technical Equipment Inspection (TEI) program was consolidated into the Inspections and Training Support programs beginning in FY 2026. The TEI program is designed to ensure that all equipment used during arms control activities meets the agreed treaty specifications and parameters and will not present a safety hazard during inspections at DoD facilities and also TEI inspects equipment brought into the U.S. during Chemical Weapons Convention (CWC) treaty activities, as well as during inspections under the International Atomic Energy Agency Integrated Safeguards Agreement. Arms Control Enterprise System (ACES) The ACES is a mission critical information system that facilitates compliance with legally binding arms control agreements and provides asset accountability, notification processing, and data management support for the following conventional and strategic agreements: Vienna Document 2011, Global Exchange of Military Information, United Nations Transparency in Armaments and the Wassenaar Arrangement. The ACES generates the finished product for annual treaty data exchange reports for the Vienna Document 2011, and the Global Exchange of Military Information, and supports Inspection Operations activities. The ACES provides detailed asset reports and uses complex algorithms for maintaining accurate asset inventories for treaties/agreements for similar equipment but with different equipment categorizations. The ACES also provides passport/visa management for arms control inspectors and escorts, treaty inspector list management, treaty training administration, and inspection mission planning which further aids in meeting USG treaty obligations. Asymmetric Threats This program leads the Agency’s next generation arms control implementation, synchronizes the building partner capacity efforts, and provides integration of expertise that cover initiatives, cross-cutting programs, and implementation of new/emerging technologies into building partner capacity and arms control efforts. This program brings together Geographic CCMDs, international agencies, USG agencies, as well as NATO and other strategic partners and allies to deconflict and coordinate the various engagements being accomplished around the globe and across the various building partner capacity and security cooperation programs funded by the USG. The program envisions long-term arms control, with a focus on three to fifteen years into the future, and works to identify risk reduction opportunities, confidence, and security building measures, and develops innovative technical certification capabilities and operational concepts as well as partnerships both within the USG and with close international partners and allies. Nuclear Assessments The Nuclear Arms Control Technology operations mission provides for the management and operation of 32 U.S. waveform and radionuclide stations and the U.S. Radionuclide Analysis Laboratory, representing the majority of the U.S. International Monitoring System stations in support of U.S. and DoD objectives. $ in thousands DTRA 593 FY 2024               FY 2025                FY 2026 Actuals               Enacted               Estimate B. WMD COMBAT SUPPORT AND OPERATIONS                                                            613,463               497,423                377,331 These programs provide combat and warfighter support to the Chairman, Joint Chiefs of Staff, the CCMDs, and military Services as they engage the threat and challenges posed to the U.S., its forces, and allies by any WMD to include chemical, biological, radiological, nuclear, and high-yield explosive weapons. DTRA supports the essential WMD response capabilities, functions, activities, and tasks necessary to sustain all elements of operating forces within their areas of responsibility at all levels of warfare: strategic, operational, and tactical. The DTRA also supports DoD with programs that provide oversight for DoD nuclear matters, providing expert and responsive DoD nuclear mission support to OSD, Joint Staff, CCMDs, and the Military Services. The DTRA successfully collaborates with the National Nuclear Security Administration and other interagency partners and programs, supporting the viability and credibility of the U.S. Strategic Deterrent, the forward deployed deterrent, and their transformation into the 21st century. Additionally, DTRA’s operational programs are closely tied with its Research, Development, Test, and Evaluation programs that provide technical support to DoD components and other organizations in areas related to WMD and designated advanced weapons. The demand for combat and warfighter support to the CCMDs continues to increase because of the threat of WMD attacks against the U.S., its partners and interests, and U.S. counterterrorism operations. These programs integrate the requirements of the national strategies, INDSG, the Joint Strategic Capabilities Plan, Guidance for the Employment of the Force, and the Unified Command Plan. Moreover, DTRA places emphasis on meeting emerging threats, to include leveraging strategic and operational planning principles to assist in the development and execution of countering adversary WMD efforts. The DTRA is continuing to enhance combat support missions to be dual-purposed, synergistic, and closely aligned with joint operational efforts, providing a foundation for transformational initiatives within the WMD arena. Building Partner Capacity (BPC) The BPC program supports the overall Counter WMD (CWMD) mission by engaging with foreign partners, both military and civilian, globally to build new or improve existing capabilities and/or capacities that enable partners to burden share and to counter, prevent and disrupt proliferation attempts and networks, enhance proliferation security, and respond to the consequences associated with the intentional or accidental use of WMD and related dual use/precursor materials in support of U.S. objectives. The BPC program supports the International Counterproliferation Program (primarily focused on building partner capacity through engagement in coordination with our DoD/Federal Bureau of Investigation (FBI)/Department of Homeland Security and partner Law Enforcement Organizations), and the CWMD Security Cooperation Engagement Program. The BPC program includes funding for multilateral proliferation security engagements, CBRN/CWMD gap assessments, logistic support requirements, equipment, and congressionally mandated security cooperation engagements approved under the Section 333(a) of the National Defense Authorization Act for FY 2017 Security Cooperation specific to CWMD. Additionally, this program leverages the U.S. Interagency partners, the National Guard and Service partners to improve partner training, equipment, doctrine and interoperability. Engagements are prioritized according to the CWMD priorities outlined in the INDSG, DoD Security Cooperation Guidance, and CCMD Theater Campaign Plans, DTRA 594 known proliferation threats and vulnerabilities, and capability gaps of international partners. The DTRA does not receive Title 10 Section 333 authority through its own direct appropriations. Mission Assurance The DTRA serves as the Mission Assurance Center of Excellence by performing assessments that identify vulnerabilities in critical systems, networks, and architecture that could be exploited well below the level of armed conflict by state or non-state threat networks or could be impacted by natural or accidental hazardous events. This analysis is accomplished through the utilization of the Defense Critical Infrastructure Vulnerability Analysis process, which includes: •   Survivability Assessments: provide a balanced look at the mission survivability of key DoD facilities and provide specific recommendations with supporting rationale to leadership. These assessments identify vulnerabilities within the U.S. and allied critical mission systems. The assessment team provides continuing support to infrastructure leadership to enable them to carry out a long- term investment strategy for risk management. •   Mission Assurance Assessments: identify vulnerabilities affecting defense critical assets, task critical assets, and critical infrastructure that support defense critical missions. The assessment team works with the installation and mission personnel to identify risks that may lead to mission loss or degradation and provides recommendations for risk reduction based on DoD Mission Assurance Assessment Benchmarks. •   Red Team Assessments: replicate adversarial capabilities to assess vulnerabilities for both DoD and non-DoD government agencies. The purpose is to identify exploitable conditions that could cause serious or grave damage to the interest of the U.S., allies, and partners. All assessments provide recommendations to mitigate identified risks to critical infrastructure. This analysis is narrowed to specific key missions identified by DoD leadership (most commonly, Defense Critical Missions). The Mission Assurance program identifies mission impacts, trends, and lessons learned through strategic analysis. This information is provided to DoD senior leaders, who will then decide the best courses of action for vulnerability remediation, mitigation, or acceptance. In partnership with the Critical Infrastructure Defense Analysis Center (CIDAC), DTRA's Mission Assurance program will also provide support to oversee the implementation of strategic planning and guidance and program management for CIDAC activities. Those activities include mission analysis; commercial infrastructure network interdependency analysis; mission assurance assessments; information enterprise design, implementation, and support; and defense industrial base supply chain network and related analysis. The DTRA will provide broad leadership, best practices, and support to DoD Components around specific focus areas to drive solution-oriented efficiencies, collaboration, and results that benefit the entire DoD mission assurance enterprise. DTRA 595 Nimble Elder The Nimble Elder program provides the CCMDs with Technical Support Groups (TSG) who are either forward deployed or able to rapidly deploy across the globe to provide the CCMDs and other USG agencies with the capability to CWMD threats by utilizing low visibility CBRN search. The DTRA TSGs provide equipment, training, scientific on-site subject matter expertise, and direct operational assistance to CCMD’ designated search forces. The TSGs bring a 24/7 Reachback capability through the DTRA Joint Operations Center with a linkage to multiple USG laboratories (providing additional subject matter expertise). Additionally, the program provides tailored CWMD exercise support (subject matter experts, academics, and training) to CCMDs, Theater Special Operations Commands, and other designated commands to increase U.S. capability to respond to CWMD threats. The supported exercises and training occur both in the U.S. and outside the continental U.S. and emphasize WMD crisis response. No other DoD agency or command provides this depth of support to exercises or training across the spectrum of an organization acquiring and attempting to employ CBRN weapons. Stockpile Logistics The Stockpile Logistics program provides support to the OSD, Joint Staff, CCMDs, military Services, National Nuclear Security Administration, and NATO for day-to-day activities necessary to maintain an effective nuclear deterrent. The program provides nuclear weapons expertise in all areas of nuclear weapons and sustainment including maintenance, safety, technical procedures, discrepancy resolution, nuclear weapons-related materials, logistics, transportation authorizations, policy, and technical matters. The program develops and maintains the Defense Stockpile Management System, a suite of software services for nuclear weapons information, which includes the Defense Integration and Management of Nuclear Data Services (DIAMONDS) system and the Enterprise-wide Nuclear Common Operations and Reporting Environment (ENCORE) system. The DIAMONDS system is the sole DoD-level nuclear weapons reporting system and system of record for all nuclear weapons sustainment records with the prime function is to account for, track, and inventory the U.S. nuclear weapon, component, and assembly stockpiles. This critical system contains accurate, near real-time nuclear weapon stockpile data and provides the capability to perform worldwide nuclear stockpile emergency verifications, an emergency inventory capability. The DTRA, in partnership with the National Nuclear Security Administration, also develops, sustains, and modernizes the ENCORE system which is a collaborative Secret-Restricted Data/Critical Nuclear Weapons Design Information system which facilitates exchanging nuclear weapons data between the two agencies’ information systems. The DIAMONDS system supports the DTRA Director’s role as the Executive Agent for three main functions: manage the U.S. nuclear stockpile and provide nuclear weapon data to the President, Congress, and Joint Staff; manage the Unsatisfactory Reporting System to resolve nuclear weapons related discrepancies; and manage the Joint Nuclear Weapons Publication System for the preparation and distribution of electronic technical publications. Nuclear Surety The Nuclear Surety program provides expertise related to nuclear policy, safety, security, planning, studies, weapon systems, and provides support to U.S. nuclear weapon modernization programs through coordinated activities within DoD in partnership with the National Nuclear Security Administration. The program serves as the focal point for nuclear deterrence, policy and planning, forces, and modernization; provides senior leader focus in multiple nuclear enterprise-related forums (e.g., Nuclear Weapons Council, Council on Oversight of the National Leadership Command, Control, and Communications System, and associated subordinate committees); and provides military Services oversight and Congressional/Executive Branch studies and reports. The Nuclear Surety program provides maintenance and improvements to nuclear surety DTRA 596 through nuclear safety and security efforts, force-on-force physical security policy evaluations, threat-based delay and denial assessments and tests, use control, Physical Security Modeling, and Simulation Center of Excellence, physical security performance testing, and independent nuclear safety and security risk analyses. Surety subject matter experts provide varying levels of assessments on the health, security, and safety of the U.S. nuclear deterrent. In addition, the Nuclear Surety program sustains a networked community of nuclear experts from across the nuclear enterprise, including the laboratories, military, industry, academic, and policy communities through its Project on Nuclear Issues and provides nuclear awareness through DTRA Strategic Forums. Nuclear Exercises The Nuclear Exercise program provides national-level nuclear exercise planning and execution support to the CCMDs and appropriate federal, state, local, and international agencies. The largest exercise is the Nuclear Weapon Accident Incident Exercise series, which is coordinated through the Joint Chiefs of Staff worldwide exercise schedule. The program provides nuclear weapons technical training to DoD nuclear weapon incident response forces; supports the incident response community and DoD Component nuclear or radiological incident response forces; and coordinates with the CCMDs on curriculum content to ensure exercises remain consistent with current theater nuclear response contingency plans. Defense Nuclear Weapons School (DNWS) The DNWS program provides specialized training in U.S. nuclear weapons, incident and accident response, explosive ordnance disposal (EOD) threat awareness/assessment, and counter-proliferation with emphasis on operational support. The DNWS develops and orchestrates the delivery of essential WMD training and knowledge management efforts for DoD. It executes courses to familiarize the U.S. nuclear enterprise on the national nuclear weapons stockpile, nuclear surety inspections, and the nuclear weapons program. Additionally, DNWS provides training to the global nuclear community in nuclear weapons accident and incident response procedures and to customers in CBRN modeling and simulation and the EOD arena. DNWS provides training in the only DoD live radioactive field training sites and also maintains an extensive nuclear weapons instructional museum (both classified and unclassified exhibits) to enhance the comprehensive training. The DNWS trains students from all levels of DoD, federal and state agencies. Defense Nuclear Surety Inspection Oversight (DNSIO) The DNSIO program provides the Chairman of the Joint Chiefs of Staff with an independent assessment of Air Force and Navy Nuclear Surety Inspection teams' compliance with DoD and Joint Staff Nuclear certification and inspection requirements. The DNSIO assessment aids in maintaining the highest standards of integrity and objectivity within the Nuclear Weapons Enterprise and supports public confidence that the Nation's nuclear assets are, and will remain, safe, secure, and reliable. The DNSIO team augments the Joint Staff Nuclear Procedures Inspection, serving as Personnel Reliability Assurance Program (PRAP) subject matter experts/inspectors during staff assessment visits, providing assurance of PRAP oversight at nuclear-capable CCMDs. The program also teaches nuclear weapons technical inspectors courses to build skills and baseline knowledge necessary for future inspections personnel to effectively conduct nuclear inspections. DTRA 597 Joint Operations Center (Operational Information Management System (OIMS)) The OIMS enables the Joint Operations Center to maintain 24/7 global situational awareness and analytical tools (e.g., Mission Data Reporting System, etc.) to view DTRA operational functions in alignment with the INDSG. This capability enables decision making to support DTRA Crisis Response Framework and associated Crisis Response Playbook efforts, support to all DTRA travelers around the globe, as well as tracking of all requests the Agency receives (technical analysis, capabilities and forces, etc.). Cross-Cutting Research and Development The Cross-Cutting Research and Development Support mission provides operational resources for the sustainment of critical functions for combating WMD, including Technology-driven WMD Threat Forecasting, International Programs, and Technical Reachback Support. Technology-driven WMD Threat Forecasting supports organizational capabilities to anticipate emerging/disruptive technology-driven WMD threats through a defined, repeatable process involving federated discovery, distributed analysis and synthesis, and unified output to inform the Science and Technology portfolio. The Technical Reachback Support role provides a cadre of specialized chemical, biological, radiological, nuclear, and high yield explosives (CBRNE) subject matter experts providing 24/7/365 technical and decision support capabilities for deliberate, adaptive, and crisis planning and operations. Support includes CBRNE collateral effects analyses for target nomination, post-CBRNE event analyses, and deployable teams. Technical Reachback products/capabilities include: •   Monitoring and participating in CWMD exercises and real-world missions, focusing on capturing and incorporating lessons learned; •   Providing CCMDs, DoD, other USG elements, and first responders decision support capability for CBRNE planning, operations, and post-event analysis, including near real-time operational analysis and access to specialized WMD subject matter expertise; •   Fielding a National CWMD Technical Reachback Enterprise; and •   Utilizing high performance computers to continue providing DoD customers with decision support for CBRNE scenarios. Nuclear Survivability The Nuclear Survivability program supports the Nuclear Test Personnel Review (NTPR), confirming the participation of Atomic Veterans in nuclear testing and radiological events and providing radiation dose assessments. The NTPR provides DoD support for the Department of Veterans Affairs and the Department of Justice radiogenic disease compensation programs, and the Department of Health and Human Services epidemiological health studies. This program also facilitates the award of the Atomic Veterans Service Certificate and the Atomic Veterans Commemorative Service Medal. DTRA 598 Nuclear Integration and Applications This program delivers integrated applications, data analysis, and artificial intelligence (AI)-enhanced capabilities in a cloud-ready, cross-cutting platform to support the full spectrum of nuclear operations, wargaming, and assessments. The program provides timely electronic access to the Nuclear Testing Archives to support validation of the effectiveness of the Nuclear Deterrent and survivability of U.S. military assets without a return to nuclear testing. This program encompasses the Defense Threat Reduction Information Analysis Center (DTRIAC) that manages a vast collection of unclassified and classified knowledge databases. It promotes the use of existing scientific and technical information to meet DoD research, development, test, evaluation, training, logistics, maintenance, and operational requirements. The collection, located on Kirtland Air Force Base, Albuquerque, NM, has more than 3 million records. It is the largest collection in the Information Analysis Center community. These records include more than 400 thousand catalogued text file titles, 20 thousand films (more than 10 million feet), 2 million still photos, and other types of records dating from 1944 to present. These records are irreplaceable. Mission Information Technology The Mission Information Technology (IT) program provides infrastructure in support of Agency mission capabilities. The program: • Provides and sustains a reliable, resilient IT infrastructure in support of the Agency and its strategic partners’ mission capabilities on three classification domains (Unclassified, Secret, and Top Secret-Sensitive Compartmented Information (TS-SCI); • Increases access to reliable and robust secret computing across the DTRA workforce and enable broader access to classified resources, communication, and capabilities; • Provides remediation of computer and network vulnerabilities across all information technology domains; • Manages implementation of DoD-mandated Comply-to-Connect and Zero Trust technologies; • Provides for the global operation, management, and support of the Agency’s Mission IT computing hardware, software, services, and other capabilities on which Agency mission capabilities depend; and • Ensures access to Mission IT systems and services for DTRA’s strategic partners, which include the Services, CCMDs, Federal Agencies, allies and coalition partners. Plans and Exercises This program provides regional and global planning/exercise support to maximize strategic alignment of DTRA Combat Support Agency and Defense Agency capabilities against current operating environment needs in planning, exercises, doctrine, strategy, and opportunity analysis for the Agency, CCMD, and other DoD Components, in coordination with interagency and international partners, while enhancing mission readiness through collective staff training. The program: • Develops and supports joint CWMD mission strategy, plans, policy and doctrine; • Provides CCMDs with adaptive planning support to counter and deter WMD threats; • Manages the Agency’s requirement process to identify, analyze, adjudicate, and document requirements; • Conducts Opportunity Analysis in support of CCMD strategic issues and objectives; DTRA 599 •   Identifies, develops and sequences cross-government and partner operations, activities, and investments; •   Enables the Agency’s Campaigning approach to synchronize operations, activities, and investments against our most pressing challenges; •   Identifies Risk Mitigation Approaches and performs gap analysis to inform a strategic alignment of the Agency’s programs and activities; •   Deploys fully integrated planning teams in support of contingency operations and exercises; •   Provides CWMD training and education to both U.S. and Partner organizations; and •   Develops, manages and executes DTRA’s Joint Training Program. Catapult Catapult is a DoD Program of Record that supports the U.S. Joint Force through rapid development, fielding, and maintenance of its private cloud- based data analytics platform. Catapult is a hybrid tactical combat support and data analytics system that processes over 1,220 data feeds and is leveraged by a set of tools and services to provide national-level capabilities for data and information discovery, access, aggregation, correlation, visualization, analysis, sharing, and distribution for users from the strategic level to the tactical edge. Catapult leverages cutting-edge technologies, including machine learning and AI, to enhance data ingestion, processing, and analysis. The platform focuses on continuous innovation and modernization, improving data accessibility, quality, and visualization, and driving strategic insights for national security. Catapult supports DTRA’s mission through advanced analytical capabilities, dynamic decision support, and a scalable, secure data ecosystem. Catapult supports the detection and identification of emerging threats, threat networks and actors, command and control, operations and engagement for neutralizing, attacking, and defeating both current and emerging threats. The Catapult data lake supports a suite of tools designed to visualize key elements of data in a variety of ways (tabular, geospatial, network diagrams). Enable Global Integrated Operations The program supports Joint Staff validated requests and CCMD requirements for DTRA support to global operations focused on proliferation pathways, great power competition, and defense of DoD strategic sites. This program provides capability to monitor and participate in real-world CWMD missions; CBRNE decision support capability for CBRNE planning, operations, and post-event analysis; operational support to Hard Target Defeat units specifically tasked to defeat asymmetric WMD threats to the homeland and deployed U.S. and coalition forces; data applications that identify adversary activity to build, buy, or employ WMD; asymmetric techniques to disrupt WMD proliferation and WMD delivery systems; and analysis and operational research to protect critical CWMD technologies and supply chains. These activities work by, with, and through a robust constellation of allies and partners - undergirded through deliberate information sharing and subject matter exchanges with Other Government Agencies and Five Eyes partners to tailor methodologies and their applications to understand competitor vulnerabilities amid the changing character of war and enable integrated, global CCMD operations across contested domains. The DTRA provides proactive options to protect DTRA investments, Joint Forces, and enduring DTRA partnerships through advising and assisting CCMD and Joint Force planning to identify CWMD vulnerabilities that provide long-term solutions to CWMD threats. DTRA 600 $ in thousands FY 2024               FY 2025                FY 2026 Actuals               Enacted               Estimate 271,459               285,425                278,272 C. CORE MISSION SUSTAINMENT These programs enable Agency execution against national priorities and represent a wide range of functions that provide the necessary resources to support the Agency’s core mission essential functions (spanning four direct appropriations within a $1.7 billion portfolio). These functions provide the foundation for all DTRA programs to enable the DoD, the USG, and international partners to counter and deter WMD and emerging threats. Functions include: Facilities, Engineering, and Logistics • Provides the Agency's space and utilities in the Government-owned McNamara Complex, Reston, Alexandria, and other Virginia locations; • Provides for installation support and services at all DTRA locations (DTRA facilities at Travis, Eglin, and Kirtland Air Force Bases; White Sands Missile Range; Fort Belvoir (other than the McNamara Complex); Reston; Alexandria; Kaiserslautern, Germany; Yokota, Japan; and other various smaller detachments; • Provides needed repairs and improvements for the aging infrastructure, primarily in Germany and Kirtland Air Force Base (facilities constructed in the early 1900s and 1960s respectively), which consistently require restoral, maintenance, and repair to remain functional by minimal standards. The majority of facility improvement funding is dedicated to structural repairs, utilities, HVAC and electrical/plumbing systems, and some quality of life or capital improvements; and • Provides for leasing and maintenance of motor vehicles, large load commercial shipping and receiving, commercial transportation (buses, vans, etc.), local travel transportation cards (Smartcards), and mandated mass transit subsidies benefit. Financial Management • Provides financial management of the Agency's $1.7 billion direct resource portfolio, including: support for DTRA’s standalone audit, contributing to the overall DoD-wide consolidated financial statement audit, audit remediation and sustainment, programming, budget formulation, budget execution, civilian payroll/Full-Time Equivalents, Official Representation Fund program, finance and accounting, Risk Management Internal Control Program, financial reporting, financial services, financial system support, account analysis and reconciliation, program/project specific financial support services, decision-making support; and • Includes must-pay bills for Defense Finance and Accounting Services support and Prompt Payment Act requirements. DTRA 601 Human Resources • Provides a results-oriented human resource management program that acquires, develops, and sustains an agile workforce; • Provides workforce management and strategic planning through targeted outreach and recruitment efforts; tailored use of hiring programs with available recruitment and retention initiatives; Service Level Agreement with Defense Logistics Agency for transactional support; Learning Management System; establishment and maintenance of long-term relationships with academic and Military Services’ transition communities to expand the applicant pool; • Provide centralized Military Reservist support; management of Joint Active Military forces; and • Provides leadership and professional development opportunities to enhance leadership skills and technical competencies supporting the Agency’s mission, vision, and values. Information Technology (IT) Support • Maintains and sustains a reliable and cost-effective IT infrastructure that conforms to all DoD IT requirements and mandates across the spectrum of connectivity and communication capabilities necessary to meet DTRA requirements; • Provides systems engineering and development necessary to produce the next generation of reliable, maintainable, and secure IT systems and capabilities, including migration to meet mandates of the Data Center Optimization Initiative and the objectives of the DoD Joint Information Environment; • Provides Agency-wide support for data-driven decision-making by making data available and discoverable at speed and scale consistent with the DTRA mission; • Operations and maintains End User Computing (Desktop, Laptops, Printers, Thin Clients, Senders, etc.); and • Supports DevSecOps-enabled Continuous Integration/Continuous Deployment (CI/CD) pipeline to support delivery of mission capabilities from Unclassified, to Secret to TS-SCI environments. Environmental, Safety, and Occupational Health • Develops policies, processes, and procedures to sustain a safe and healthful work environment; • Provides support to sustain regulatory compliance with environmental, safety, and occupational health regulations; • Manages high visibility programs such as Mishap Investigation, Notification, and Recordkeeping, Hearing Conservation, and Medical Surveillance; • Mitigates the severity of activities and operations on personnel and the environment through: o Performing Safety and Environmental inspections, risk assessments, and job hazard analyses; o Performing environmental compliance reviews of project proposals and new equipment purchases to determine National Environment Policy Act applicability; o Reviewing Environmental Assessments/Environmental Impact Statements generated by DTRA or its contractors; • Manages the Agency radiological licenses and sources for critical CWMD exercises and operations; • Manages Agency-wide external and internal radiation monitoring programs for radiation workers and treaty compliance; DTRA 602 •   Conducts occupational health travel screening for DTRA personnel in support of deployments, contingency operations, and advisory missions; and •   Supports mission readiness through immunizations/examinations; consults on the Agency Federal Employees’ Compensation Act interests; and reviews all Reasonable Accommodations with complex medical concerns. Legal Advice and Support • Ensures compliance with relevant legal authorities and minimal disruption due to non-compliance issues; • Provides legal advice on all operational programs and exercises, including: all administrative law topics; internal investigations; training in the law of war and military personnel actions/laws; and the applicability of Status of Forces Agreements; • Provides fiscal law advice for the Cooperative Threat Reduction Program, the nuclear enterprise, research and development activities, treaty programs, and all other DTRA programs; • Reviews all Freedom of Information Act and Privacy Act request responses and serves as the Senior Component Official for Privacy; and • Administers the DTRA ethics program, provides mandatory ethics training for the Agency, and serves as the Designated Agency Official for Ethics. Security (Information, Personnel, Physical) • Conducts security and counterintelligence for all DTRA sites and geographically separated units to defend critical CWMD and emerging threat missions, people, facilities, critical technologies, and information; • Prevents/minimizes unauthorized access to DoD classified and controlled unclassified information and safeguards them against espionage, sabotage, terrorism, and criminal activity; • Prevents unauthorized access to facilities, control systems, and critical information by validating security clearance eligibility and need-to-know on all individuals, considering background, qualifications, and operational restrictions, prior to granting an individual access to sensitive/protected information and controlled spaces; and • Prevents unauthorized access to personnel, equipment, facilities, and information by integrating physical protective, security, and antiterrorism measures and procedures, which include: electronic security systems, surveillance systems, access control systems and procedures, random entry/exit inspections, random anti-terrorism measures, and Force Protection Condition measures. Other Essential Services • Provides for the essential management, planning, and operational support to the entirety of DTRA; • Enhances mission accomplishment and readiness by establishing policies, guidelines, and standards in accordance with The Equal Employment Opportunity Commission and DoD guidance; • Facilitates Agency communication with Congress to gain support for DTRA's mission, programs, authorities, and funding in the NDAA and Defense Appropriations Bill. Ensures Congress is well informed on DTRA's role and activities in the CWMD space; DTRA 603 •   Identifies organizational risks and internal control deficiencies, which informs DTRA’s Director of matters impacting mission execution through assists, audits, inspections and investigations; •   Enables decision advantage and domain superiority during competition, crisis, and conflict through value-driven data and AI- enabled solutions; •   Facilitates DTRA's transition to a data-centric and AI-enabled enterprise by providing strategic guidance, oversight, and governance of DTRA data and AI initiatives, aligned with DoD guidance and direction; •   Implements proven communications strategies, leverages opportunities with the most appropriate digital communications tools and manages the Agency’s reputation by promoting a positive DTRA brand; •   Supports various contracting functions from establishment to closeout of DTRA contracts, grants, and other agreements and provides the acquisition workforce with training and tools to enhance performance and execute Agency initiatives; and •   Provides classified instructional products and items for senior-level mission assessments not available elsewhere, in-house and combat camera related photography/videography, video-teleconferencing support, visual graphics and design services, and conference center support (to include maintenance of associated equipment). DTRA 604$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 53482000, "fy26": 52611000, "name": "1. Nonproliferation Activities", "fy25_current": 58328000, "fy25_request": 65628000, "fy25_cong_amt": -7300000, "fy25_cong_pct": -11.12}$$::jsonb, $${"fy24": 613463000, "fy26": 377331000, "name": "Operations", "fy25_current": 497423000, "fy25_request": 507423000, "fy25_cong_amt": -10000000, "fy25_cong_pct": -1.97}$$::jsonb, $${"fy24": 271459000, "fy26": 278272000, "name": "3. Core Mission Sustainment", "fy25_current": 285425000, "fy25_request": 285425000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 590, 646, FALSE, $${"json_key": "DTRA__umbrella"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 637514000, to_jsonb(ARRAY[$${"fy25": 56.465, "fy27": 51.112, "name": "1. Nonproliferation Activities", "fy26_current": 52.611, "fy26_request": 52.611, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 524.161, "fy27": 342.554, "name": "Operations", "fy26_current": 353.49, "fy26_request": 377.331, "fy26_cong_amt": -23.841, "fy26_cong_pct": -6.32}$$::jsonb, $${"fy25": 258.705, "fy27": 243.848, "name": "3. Core Mission Sustainment", "fy26_current": 278.272, "fy26_request": 278.272, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part1/DTRA_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_dtsa_umbrella$$, $$DTSA$$, $$Defense Technology Security Administration$$, $$DTSA$$, $$om_dw_ba04$$, NULL, $$dw_dtsa$$, 2026, 41857000, 42380000, -471000, -1.11, 41909000, 40052000, $$Mission, Responsibilities, and Core Functions The Defense Technology Security Administration (DTSA) – a Field Activity under the authority, direction, and control of the Under Secretary of Defense for Policy (USD(P)) – develops and implements Department of Defense (DoD) technology security policies on international transfers of defense-related goods, services, and technologies. 1 DTSA’s mission directly links to the priorities of the 2025 Interim National Defense Strategic Guidance and the Secretary of Defense’s priorities to re-establish deterrence, increase burden sharing, and restore the warrior ethos. The DTSA protects the U.S. military’s critical technological advantages by ensuring the responsible transfer of information and technology that – in the wrong hands – could prove potentially detrimental to U.S. national security interests. The DTSA pays particular attention to transfers that could result in the proliferation of weapons of mass destruction and their means of delivery, as well as conventional weapons and dual-use technology that could erode the U.S. warfighter’s technological advantage. The DTSA assesses the risk of diversion of U.S. ­ produced, defense-related goods to countries and entities of concern, including terrorists, and helps develop mitigation measures, where possible, to reduce the risks of diversion or misuse. The DTSA works with multilateral export control and nonproliferation regime members to identify and control critical technologies and to establish common licensing practices to prevent exports to military end-user and end-uses in countries of national security concern. The DTSA plays an essential role in campaigning and working with international partners through bilateral technology security cooperative efforts to improve technology security practices and procedures that enable broader and deeper security cooperation. Further, DTSA executes foreign disclosure reviews of classified information in support of ally and partner interoperability with U.S. forces, and thereby assists in the enhancement of their military capabilities to address national security matters of mutual concern. The DTSA also plays a critical role in implementing Australia, United Kingdom, U.S. (AUKUS)-impacted regulations and process changes for technology release approval. Finally, in executing the foregoing responsibilities, DTSA strives to balance the safeguarding of critical defense information and technologies with fostering the health of the U.S. defense industrial base through four core functions: (1) conducting national security reviews of defense technology transfers; (2) working closely with allies and partners on cooperative endeavors that have a 1 Visit http://www.dtsa.mil/ for more information. DTSA 661 technology security dimension; (3) developing and implementing DoD policies related to defense technology exports, technology release processes, and foreign disclosure of classified information; and (4) performing important management functions for other U.S. Government (USG) agencies, as well as the DoD. History Established in the mid-1980s as a field activity under the Office of the Under Secretary of Defense for Policy (OUSD(P)), DTSA focused efforts on countering the Soviet Union’s attempts to acquire technology that would improve its military capabilities. DoD officials considered such transfers – especially of dual-use technologies – a major threat to U.S. national security. With the fall of the Soviet Union, DTSA’s role evolved. While retaining its mission to protect the U.S. military’s technological edge in the most critical and sensitive areas, DTSA has increasingly been involved in reviewing the transfer of critical technologies to allies and partners. National Security Review of Defense Information and Technology Transfers There is widespread recognition that U.S. adversaries go to extraordinary lengths to steal or otherwise obtain U.S. and western technology. The DTSA advocates for effective technology security policy and export controls as important elements in preserving U.S. technological advantages. The policies of past and present Administrations, as well as congressional oversight requirements, have intended to prevent the transfer of technologies that contribute to the military capabilities of our adversaries. In partnership with other USG agencies and industry, DTSA assesses defense technologies and develops measures to prevent the diversion or proliferation of information and technology that could prove detrimental to U.S. national security. DTSA accomplishes this function in several ways. It assesses the technology transfer risks associated with Direct Commercial Sales and Foreign Military Sales and assists in managing those risks. DTSA plays a key role in risk management by advising the development of technology control plans, drafting U.S. export regulatory controls, adjudicating export classification of equipment and technology, assessing harm to U.S. national security on potential violations of export laws and regulations, and supporting end-user checks. As the DoD lead for export control, DTSA makes recommendations on export licenses for Direct Commercial Sales (equipment, technology, data, and services). The DTSA leads or plays a central role in several USG bodies that identify and manage risks tied to technology exports. DTSA plays a leading role in the oversight of technology exports for foreign space launches of satellites and spacecraft with U.S. content. In this regard, it applies special export controls and physically monitors launch vehicle preparation activities to ensure that illegal technology transfers do not occur. As a key DoD stakeholder for the Committee on Foreign Investment in the United States (CFIUS), DTSA plays a leading role, on behalf of OUSD(P), in reviewing defense-critical technology that could be transferred when U.S. companies are sold to foreign owners and to assess if existing export controls are adequate for technology protection. DTSA also plays an essential role in developing International Agreements on information and technology sharing. Further, it manages DoD’s patent secrecy review program to prevent public release of sensitive or classified technologies through patents. DTSA assists other agencies in assessing whether foreign purchasers of critical technology are complying with license requirements and supports DTSA 662 USG enforcement efforts when license requirements are violated. Finally, DTSA reviews documents describing sensitive U.S. technology to make sure they are suitable for public release. International Engagements and Information and Technology Security Cooperation To strengthen our network of allies and partners, DTSA collaborates with international partners to protect critical defense-related information and technology, re-establish deterrence, allow for increased burden sharing, and enhance military interoperability. DTSA performs this function in a variety of ways. DTSA’s leadership conducts regular bilateral engagements with allies and partners around the world to address export controls and other elements of technology security to strengthen deterrence and gain advantages over adversaries. Often these engagements are directly tied to cooperative technology security programs, for which DTSA plays a principal role in representing the USG's national security interests. DTSA’s leadership also supports a variety of interagency and intra-departmental bilateral engagements as the USG's technology security subject matter experts. Representatives from DTSA represent the Department and are important and regular contributors, as part of official U.S. government delegations, to multilateral export control and non-proliferation regimes (e.g., Wassenaar Agreement (WA), Missile Technology Control Regime (MTCR), Nuclear Suppliers Group (NSG), and Australia Group (AG)). Additionally, DTSA plays a central role in the development and maintenance of key treaties and arrangements with a trade or technology security dimension, such as the Defense Trade Cooperation Treaties with the United Kingdom and Australia (UK/AU), the Arms Trade Treaty, the North Atlantic Treaty Organization (NATO), and AUKUS strategic partnership. Elements of DTSA work routinely with foreign partners to design and maintain viable industrial security programs. Teams from DTSA regularly conduct National Disclosure Policy Committee (NDPC) security surveys in foreign countries to assess the protection of U.S. sensitive and classified information. DTSA also liaises with the combatant commands to facilitate deeper understanding of technology export matters as these commands work with partners and allies in their respective areas of responsibility. DoD Export, Technology Release, and Foreign Disclosure Policy Determinations The DTSA shapes international and domestic policies and regulations that protect defense information and technology while facilitating security cooperation with allies and partners in many ways. DTSA experts regularly contribute to U.S. export control laws, regulations, and policies; commodity jurisdictions determinations; commodity classifications; and the USG Entities List. On behalf of DoD, DTSA allows technology release waivers when it assesses the potential risk to U.S. national security is acceptable or adequate protective measures can be put in place to reduce risk to an acceptable level. To get ahead of materiel and technology requirements in a fast-paced operational environment, DTSA – in cooperation with the Department of State (DoS) and other DoD components – develops "anticipatory" technology-release policies. DTSA also plays a unique role in supporting key governmental bodies responsible for oversight of information and technology security. DTSA leads the development and implementation of National and DoD policies on, and authorities for, the disclosure of classified military information and material. It also provides guidance to DoD components DTSA 663 in a variety of ways (e.g., export control-related directives and requirements, the Defense Federal Acquisition Regulation Supplement, trade security controls, and demilitarization requirements). Technology Security Management Functions The DTSA supports the USG and DoD by performing several management functions that support technology security-related systems. DTSA oversees the international visits program (DoD Directive 5230.20) that sets policy guidance for foreign personnel visits and assignments to USG organizations. DTSA operates and maintains four information technology systems that support the USG and DoD: USXPORTS interagency export licensing system; DoD Patent Application Review System (DPARS); Foreign Visits System (FVS); and the National Disclosure Policy System (NDPS). DTSA 664 Export Controls Directorate (ECD): FY 2024                  FY 2025                   FY 2026 Actual                  Estimate                  Estimate 16,987                   17,106                    16,706 The Export Controls Directorate (ECD) is the entry and exit point for all DoD actions related to the U.S. national security review of DoS licensing related to direct commercial sales of defense articles, technical data and defense services, Department of Commerce (DoC) export licensing of dual- use items, and Department of Energy (DoE) export licensing of nuclear energy-related technology and National Regulatory Commission (NRC) nuclear-controlled materials. The ECD provides DTSA’s principal source of technical and regulatory insight, advice, and analysis on international transfers of defense-related items and other technology-related matters of national security interest. The ECD reviews over 53,000 munitions and dual-use export license applications and regulatory actions per year. ECD participated, staffed, and consolidated DoD positions in more than 68 Military End User and Entity List actions issued by the DoC through the End User Review Committee. Since February 2022, ECD processed a total of 1,374 Ukraine licenses and in 2024, processed 727 Ukraine licenses. Some of these licenses were with high visibility requiring extensive research and manpower affecting normal tasks. Since October 2023, ECD has expedited 2,221 Israeli licenses. The ECD processes approximately 17,000 munitions Direct Commercial Sales export license applications received annually from DoS. In accomplishing this significant responsibility, the directorate develops and adjudicates the DoD’s final national security decision on munitions-related export license applications referred to the Department by the DOS. The directorate prepares and releases DoD decisions on recommendations the Military Departments, the Joint Staff, and Defense Agencies provide to ECD under urgent mandated review timelines. Third party transfers from other nations of U.S. technologies were also reviewed, ensuring U.S. security interests for technology were addressed. The annual caseload of approximately 36,000 dual-use and Commerce-controlled munitions time-sensitive export license applications received from the DoC continues to grow in complexity, primarily because of increased concern for China and policies created to address technology assisting their growth in areas of national security concern. In this regard, ECD develops and adjudicates the Department’s final national security position on DoC-regulated dual-use and munitions export license applications for submission to the DoC based on recommendations provided by the Military Departments, Joint Staff, and Defense Agencies. In 2024, ECD defended 739 disputed technology transfer requests escalated to the DoC-led dispute resolution process and defended 70 escalated cases at the Assistant Secretary level. ECD also worked around 1,836 commodity classification requests staffed to DTSA by the DoC. DTSA 665 The ECD supports the DTSA mission by providing the technical foundation to virtually every action or activity undertaken. As one of its core functions, ECD identifies technologies that are critical to the U.S.’ military advantage and national security, including identifying and proposing regulations and policies to control critical and emerging technologies for the department to the interagency in line with the national strategy. This is particularly true with respect to DoD efforts to modernize, streamline, and synchronize the USG’s export control systems and regulations, as well as international export control regimes, such as the MTCR, NSG, WA, and AG. In the process of reviewing technology transfers to other countries, ECD is often called upon to recommend solutions to complex technical problems affecting national security. This task requires ECD to document and convey clear and accurate positions on international transfers that protect the U.S. warfighting edge and mitigate technology security risks. The ECD technical staff consists of senior engineers, scientists, subject matter experts, and licensing analysts who contribute to maintaining and promoting the U.S. military’s advantages on the battlefield. In addition, the knowledge and expertise residing in ECD influences and helps shape DoD’s technology security policies. To effectively accomplish the DTSA mission in a timely manner, ECD scientists and engineers must be experts on both domestic and foreign defense-related technology and capabilities. They must also be highly proficient at applying their technical knowledge in a manner consistent with the USG’s policy and regulatory framework, as well as a variety of multilateral forums concerned with technology security. The foregoing requires ECD’s engineers and scientists to integrate contributions from DoD, and other USG stakeholders, in developing viable technical solutions for managing technology transfer risks. Finally, they must convey their analysis and recommendations on complex technical subjects in understandable terms to a broad audience. The ECD is the technical lead for DTSA regarding all national security reviews of transactions filed with CFIUS, which involve the purchase of U.S. companies (that provide products, services, or technologies with U.S. national security or defense applications) by a foreign entity. The basis for many decisions regarding these sales hinges on the technical nature and importance of the commodity in question, which the ECD scientists and engineers provide. ECD coordinates with the International Engagement Directorate as the DTSA CFIUS lead, ensuring other relevant policies are considered and staffing is completed within the deliberation process. The ECD also protects U.S. space-related technological advantages and prevents the diversion or proliferation of this critical technology. ECD promotes the U.S. space industry’s competitiveness in the international marketplace by providing responsive services that support the U.S. space industry’s export license requests. ECD performs post-licensing oversight of both DoS and DoC exported spacecraft, satellites, or related items if they are to be launched using a foreign space launch vehicle. The ECD maintains a technically qualified and readily available staff of engineers who can respond quickly to the industry’s demands for space monitoring services and deploys its space monitors when the DoS’s Directorate of Defense Trade Controls imposes special export controls (SEC) on space-related export authorizations. SECs are imposed when a satellite (or related items) is exported for launch in a foreign country that is neither a member of NATO nor a major non-NATO ally of the United States (or by the nationals of such a country). In cases where SECs are mandated, the applicant must reimburse the USG for all monitoring costs. In the event of a launch failure (e.g., crash), a separate mandatory license is required for the conduct of investigations and analysis. Export licenses for evaluating launch failures in such cases also require reimbursement from the industry. DTSA 666 Although SECs are not required for the launch of U.S.-origin satellites, spacecraft, and components from or by nationals of a country that is a member of NATO or a major non-NATO ally, such export controls may nonetheless be applied. SECs include physical monitoring and the development of Technology Transfer Control Plans. ECD reviews and approves these industry plans to ensure the launch campaign is carried out within DoS or DoC authorizations or limitations and prevents the unauthorized transfer of U.S. space technology. The ECD is DoD’s lead in the DoS commodity jurisdiction (CJ) process, which determines the proper regulatory jurisdiction for controlled technology and defense services. Further, ECD leads DoD’s commodity classification reviews regarding munitions articles controlled under the Export Administration Regulations (EAR) to determine the appropriate export control classification number (ECCN) for an item or technology that determines licensing policy. The ECD also spearheads DoD efforts in developing and drafting U.S. regulatory export control language regarding proposed changes to the International Traffic in Arms Regulations (ITAR) and EAR. Finally, it heads the DoD’s efforts in assessing the potential harm to U.S. national security resulting from export violations. The ECD plays an important role in adjudicating or otherwise resolving important USG or DoD export control and technology transfer issues. Frequently, the U.S. industry is still determining whether the DoS, or the DoC, has regulatory jurisdiction over a defense article that may be subject to the ITAR or the EAR. As a result, the directorate annually develops and adjudicates the Department’s final determination on an average of 256 Commodity Jurisdiction requests received from DoS. In addition, ECD annually develops and adjudicates the Department’s final “harm to national security” decisions on an average of 61 notifications of possible export violations received from DoS. The ECD leads the DoD process for review of changes to the ITAR and EAR. In this capacity it proposes and provides the DoD’s decisions on changes to rules and regulations of the ITAR and EAR, to include export control parameters, licensing policies and licensing exemptions (e.g., exports not requiring an individual U.S. Government license authorization), based on recommendations provided by the Military Departments, Joint Staff, and Defense Agencies. The Department, interagency, and the U.S. high-tech business industry frequently seeks guidance from ECD staff for its regulatory and direct commercial sales licensing expertise and experience. For example, ECD serves as the Department’s export licensing experts on a variety of technology security teams that address major DoD defense and cooperative programs. These programs require the expertise – and often considerable time - of DTSA’s subject matter experts. ECD also provides the DoD with expertise on export licensing in interagency and international forums to concerning individual licensing actions, commodity jurisdictional determinations, and violations of the Arms Export Control Act. In the interagency and international arena, ECD represents the DoD in USG forums that deliberate dual-use and military-related license decisions that fall within the scope of the MTCR, NSG, WA, and AG. In support of U.S. policies to stem the proliferation of controlled goods and technology to foreign countries and entities of concern, and on behalf of the DoD, ECD reviews open-source and intelligence reporting and recommends foreign entities for inclusion on DoC’s Entity List. The Entity List places a significantly higher burden on high-risk foreign parties seeking access to controlled U.S. technologies and goods. ECD is the DoD’s focal point for developing and disseminating final decisions to approve parties for addition on the USG’s Validated End-User Program, which confers favorable license-free treatment to trusted foreign companies. ECD also serves the DoD by DTSA 667 maintaining a comprehensive repository of export information to include licensing trends, industry technology roadmaps, technical specifications, historical data, and supply chain information. This information is useful for developing export control policy, establishing technology security thresholds, and supporting Federal law enforcement agencies in pursuing violations of export control laws and interdicting illicit reports. DTSA 668 International Engagement Directorate (IED): FY 2024                   FY 2025                  FY 2026 Actual                   Estimate                 Estimate 8,932                      9,006                    8,806 Composed primarily of foreign affairs, foreign disclosure, and security specialists (civil servants, military officers, and contractor personnel), the IED works with other DoD Components, the National Security Council, several USG departments and agencies, international partners, multilateral organizations, academia, and industry on information and technology security policy and implementation matters. IED, as the focal point for DoD policy on disclosure of classified military information and technology security, provides strategic analysis of the risks related to technology transfer and provides mitigation strategies where possible to influence the U.S. interagency and foreign partners on technology security and foreign disclosure issues. IED leads DTSA’s engagement in the Department and the interagency for the implementation of the Interim National Defense Strategic Guidance to ensure the technological advantage of the U.S. warfighter and to engage allies and partners concerning information and technology security to strengthen deterrence and gain advantages over adversaries. As directed or delegated by treaty, law, regulation, DoD Directive, or DoD Instruction, all of which are equally binding in terms of implementation, IED leads the DoD’s efforts in a wide variety of technology security, foreign disclosure, and export control matters. Internationally, IED provides policy and subject-matter expertise in a number of multilateral and export control forums. IED represents the Department and oversees DoD input into the MTCR, NSG, AG (Export Controls for Chemical and Biological Agents), and WA (Export Controls for Conventional Arms and Dual-Use Goods and Technologies). IED leads the Department’s efforts in activities related to Section 123 of the Atomic Energy Act, which addresses U.S. civil nuclear cooperation agreements with other nations. IED also spearheads OUSD(P)’s work in the development and implementation of the UK/AU and AUKUS strategic partnership. IED is responsible for all DTSA’s bilateral engagements. IED’s serves as the principal DoD coordinators concerning technology security matters for DoD contact with foreign governments, international organizations, other Federal and intergovernmental agencies, interagency working groups, industry, and other DoD Components. IED is also responsible for all DTSA coordination with OUSD(P) offices and components. IED has primary responsibility, in coordination with ECD, for DTSA’s formal bilateral dialogues, for DTSA’s input into OUSD(P)’s bilateral engagement, and for coordinating with OUSD(A&S), OUSD(I&S), and OUSD(R&E) on bilateral issues. IED is DTSA’s primary point of contact for OUSD(A&S) Declaration of Principles working groups and for input on technology security issues in meetings of the National Armaments Directors, as well as the Director, DSCA. The IED partners with ECD, and other stakeholders in the Department, to identify critical and emerging technologies that require protection via export controls and foreign direct investment reviews, consistent with the authorities provided under the Export Control Reform Act of 2018 in the John S. McCain National Defense Authorization Act for Fiscal Year 2019 and DoC’s Emerging Technology Steering Committee. DTSA is focused DTSA 669 on strengthening technology protections and is a key player in the USG effort to identify and address current technology protection gaps, particularly with respect to China and Russia. The IED manages the Department’s national security reviews of patent applications for sensitive, and classified defense-related technology and provides the Department’s recommendations on secrecy orders to the U.S. Patent and Trademark Office. IED also manages classified foreign patent applications covered under the “NATO Agreement for the Mutual Safeguarding of Secrecy of Inventions Relating to Defense and for which Applications for Patents Have Been Made” and related bilateral agreements. The IED plays an important role for the Department in contributing to USG decisions on sanctioning violators of U.S. export regulations and helping to determine which business entities (U.S. and foreign companies and individuals) should be restricted from purchasing sensitive or classified defense technology. IED plays a central role in U.S. export denial consultations with foreign partners. IED plays a coordinating role in country- specific sanctions regimes, including but not limited to the Iran, North Korea, Syria Non-Proliferation Act, country-specific UN sanctions regimes, and other single-country USG actions. In addition, IED is the OUSD(P) lead for all national security reviews of transactions filed with CFIUS, which involve the purchase of U.S. companies (that provide products, services, or technologies with U.S. national security or defense applications) by a foreign entity. IED also plays an essential part in the Department’s and USG’s outreach to foreign partners on the establishment of national foreign investment review processes. The IED is responsible for the China and Russia strategic competition portfolios related to technology security, the U.S. Critical and Emerging Technologies List, and coordination of this and other related efforts with other DoD offices. Because China and Russia go to extraordinary lengths to steal or otherwise obtain U.S. and western technology, effective technology security policy and export controls to delay and counter our strategic competitors are essential elements in preserving U.S. technological advantages. The IED plans and executes all DTSA’s bilateral international engagements including the Cooperative Technology Security Dialogues (CTSD) to increase technology security cooperation to work with partners to better develop their domestic technology security practices and procedures, protect U.S. origin defense technology and classified military information (CMI), and enhance military interoperability. CTSD is associated with the DoD Institutional Capacity Building program initiatives in which IED experts coordinate with other countries’ defense and security establishments regarding technology security practices, procedures, and policies, and is a mechanism to work with foreign partners to protect sensitive indigenous and U.S.- origin military technologies. CTSD helps build USG confidence in partner nations’ technology protection and export control capabilities; provides crucial information on technology security practices, procedures, and policies; and bolsters partners' institutional capacity. CTSD is a key enabler of greater security cooperation to strengthen our network of allies and partners. DTSA 670 The IED’s workload and accomplishments for a typical year are considerable. IED plans, coordinates, and executes more than 300 bilateral international engagements of varying types, some requiring overseas travel for the DTSA Director. In addition to bilateral international engagements, IED plans, coordinates, and executes over 280 engagements involving multilateral export control and non-proliferation regimes for which DTSA is responsible on behalf of the DoD. IED also conducts over 500 engagements with the foreign policy and national security interagency including engagements requiring the DTSA Director’s participation, over 1,600 reviews of Foreign Liaison Officer and Defense/Military Personnel Exchange Memoranda of Agreement, and over 4,000 patent security reviews. This is in addition to day-to-day licensing and information and technology transfer operations reviews. The National Disclosure Policy Committee (NDPC) Executive Secretariat resides in IED. IED’s Assistant Director is dual hatted as the Executive Director of the NDPC. The Executive Secretariat formulates, coordinates, and publishes the National Disclosure Policy (NDP-1), which set policy on levels of U.S. classified military information that foreign partners are authorized to receive based on their ability and intention to protect sensitive information. The NDPC sets disclosure levels for a foreign partner across seven broad categories of information and authorizes more specific, narrow exemptions to allow further disclosure to a foreign partner for specific information. The Executive Secretariat for the USG’s NDPC runs day- to-day operations and provides administrative support to the 16-member interagency body. Through the NDPC, IED also carries out the responsibilities of the Secretary of Defense for U.S. national policy governing the disclosure of classified military information and materiel to foreign governments and international organizations. It provides DoD’s liaison with foreign government national and designated security authorities for this and other purposes. In support of government and commercial international activities, IED develops security policies and associated arrangements. IED also develops and negotiates on behalf of the USG international security agreements with foreign governments and international organizations. IED’s Assistant Director also serves as the Delegated Disclosure Authority for USD(P) and DoD Fourth Estate. In this role, IED Foreign Disclosure Officers review all foreign military sale congressional notifications; various intelligence arrangements; and cooperative research, development, test, and evaluation initiatives to ensure that the requisite disclosure authority is in place to support the execution of these efforts. The IED Assistant Director serves as the Designated Security Authority for International Programs. As such, IED works with foreign governments and international organizations to assess their capability and intent to protect classified information and to develop mutual protective security policy and practices to strengthen deterrence and gain advantages over adversaries. To this end, IED develops, negotiates, and concludes general, special, and industrial security agreements with foreign partners. These legally binding agreements codify a foreign governments or an international organization’s capability and intent to protect shared classified information. In addition, IED conducts on-site security surveys of a foreign government and international organization’s security laws, regulations, policies, and practices to ensure foreign governments and international organizations have the ability to protect shared classified information substantially equivalent to U.S. security standards. It provides liaison between the DoD and security officials of allied and other friendly nations on matters of mutual concern and represents the DoD’s security interests in international organizations, meetings, and conferences. Examples of this responsibility include co-chairing the U.S.-Canada Security and Technology Sharing Subcommittee and representing the U.S at the Multinational Industrial Security Working Group (MISWG). DTSA 671 The IED also provides international industrial security policy oversight and guidance to the Under Secretary of Defense for Intelligence and Security and the Defense Counterintelligence and Security Agency (DCSA) as the Cognizant Security Office for the National Industrial Security Program. IED is also the principal U.S. delegate to the MISWG, which develops common measures for the protection of classified information with regard to non-NATO Multinational Defense Programs and international industrial security matters. Leveraging NATO to advance U.S. security interests, such as safeguarding ATOMAL information, is also a significant part of the IED’s portfolio. The IED Assistant Director represents the Secretary of Defense in his capacity as the United States Security Authority for NATO Affairs (USSAN) and is the executive agent for the development and USG-wide implementation of policies and procedures for the protection of NATO classified information through USSAN Instruction. IED represents the U.S at NATO Security Committee and NATO Archives Committee meetings, at NATO’s security-related working groups, and leads the formation of the U.S. position on NATO security matters. IED implements NATO security regulations and develops the U.S. position on NATO Security Agreements with Partnership for Peace and other aspirant countries and for NATO member nation COSMIC TOP SECRET and ATOMAL sub-registries. IED also exercises policy oversight over the Central United States Registry, which provides security compliance and accountability oversight for NATO classified materials provided to the U.S. and for NATO communications and information systems employed by U.S. departments and agencies to control NATO classified documents worldwide. The IED provides foreign disclosure and international programs security policy guidance and oversight to the military Services, Defense Acquisition University, DCSA Center for Development of Security Excellence, and Defense Security Cooperation University on training courses pertaining to foreign disclosure policy and international security procedures. The IED manages DTSA’s active participation in the DoD Security Cooperation Workforce process. In particular, IED ensures that all eligible DTSA personnel fulfill the necessary DoD security cooperation subject matter requirements and certifications. For the DoD, IED drafts, coordinates, and promulgates policies and procedures governing the conduct of activities (e.g., foreign visitors, personnel exchanges, cooperative programs, intelligence engagements, coalition operations and planning) that involve the sharing of classified military information and materiel with foreign governments and international organizations through the issuance of DoD Directive 5230.11. IED also advises and provides policy advice and guidance to the DoD Components on the security aspects of security assistance, armaments cooperation, and other international activities. For the DoD, IED is responsible for oversight of the International Visits Program, which sets policies and procedures for visits and assignments of foreign nationals to DoD Components. IED drafts, coordinates, and promulgates policies and procedures governing the conduct of activities that involve visits and the assignment of foreign nationals to DoD Components through the issuance of DoD Directive 5230.20 and implemented through the FVS. IED is also responsible for receiving, reviewing, coordinating, and approving proposed MOA text for negotiations and conclusion of the Defense Personnel Exchange Program, Military Personnel Exchange Program, Administrative Personnel and Exchange Program, and Foreign DTSA 672 Liaison Officer agreements with foreign governments. IED also develops and negotiates special security provisions for international acquisition programs (e.g., cooperative research and development, security assistance, and reciprocal procurement). IED provides technology release and foreign disclosure (TR/FD) process oversight, coordination, and synchronization of the DoD’s high-priority requests for releasing classified or sensitive defense-related technology. IED ensures transparent, timely, and well-informed guidance and decisions on information or technology transfers using established TR/FD processes. The IED is responsible for the development and coordination of work responding to congressional legislation, as well as White House Executive Orders on expediting TR/FD activities. IED is also responsible for reforming OSD-level TR/FD processes, consistent with existing authorities and in response to congressional inquiries to improve the TR/FD approval process. In supporting senior leaders’ guidance, IED screens, performs triage, and tracks TR/FD actions that merit the attention of the DoD’s senior leaders. Based upon senior leader guidance, IED develops, coordinates, and promulgates strategic export policy decision documents for foreign military sales, direct commercial sales, and Under Secretary of Defense for Acquisition and Sustainment cooperative programs with applicable DoD Components, Executive Branch agencies, nations, and U.S. companies. IED provides guidance and direction to DoD’s Technology Security and Foreign Disclosure processes to support the protection of critical U.S. technologies; provide proactive, collaborative, and strategic policy development; ensure unity of effort on DoD arms transfer objectives; and ensure that release considerations are balanced with building allied and partner-nation capability objectives. The intent is to anticipate needs so the Department can quickly react to emergent requirements when they arise. IED also enables the expedited review of technology transfers by providing guidance to the DoD on staffing release requests through applicable processes in the most efficient and effective way. IED conducts outreach efforts to engage the DoD TR/FD community to make aware of senior leader guidance and interests. IED supports several Senior Integration Groups that have time-sensitive technology release and disclosure review requirements for urgently needed technology in support of ongoing operations. DTSA 673 Mission Support Office (MSO): FY 2024                 FY 2025                 FY 2026 Actual                 Estimate                Estimate 12,376                  12,176                  11,219 The MSO is responsible for human capital, finance, contracts, information technology, cybersecurity, facilities and logistics, and general administrative support services to the Director, DTSA, and the other directorate line organizations of DTSA. Proper execution of these services ensures DTSA fulfills its technology and information security mission and meets its strategic goals. The MSO staff consists of experts in financial management, human resources, contract administration, Information Technology (IT), and business operations. MSO provides the necessary professional, technical, and administrative guidance, and actions to plan, align, use, and protect all of DTSA’s resources. MSO has wide-ranging responsibilities. MSO leads the development, integration, and sustainment of NDPS, DPARS, FVS, and the interagency single information technology program for licensing, USXPORTS. The MSO implements the DTSA Human Capital Strategy and is responsible for the hiring and retention of a specialized and highly technical workforce. MSO implements DTSA's workforce, training and development, and incentive awards programs. MSO also directs the implementation of military personnel assignments and actions, training and development, and incentive awards programs, coordinating and expediting priority requests with military personnel through the Washington Headquarters Services. The MSO manages DTSA’s annual budget cycle to include planning, programming, budgeting, and execution of all Operation and Maintenance (O&M) funds. MSO manages DTSA’s participation in all exercises relating to the President's Budget and the Program Objective Memorandum and identifies manpower requirements. MSO also provides oversight of DTSA's acquisition and support contracts administration and manages DTSA’s space and facilities requirements. Administratively, MSO provides guidance to the broader organization by publishing, monitoring, and updating DTSA's administrative instructions, standard operating procedures, and policy memorandums related to the MSO programs through continuous process improvement. Application Management Systems (AMS) is a group of automated systems and applications that support U.S. technology security objectives. DTSA operates and maintains five primary AMS system mission applications. Catastrophic failures of the aging AMS applications this year and associated impact of processing transactions supporting allies and partners have demonstrated the need to replace these 1990s systems while keeping them operational in the short-term. DTSA 674 1. USXPORTS (classified) and USXlite (unclassified) provide case management and adjudication of munitions and dual-use license applications submitted by U.S. exporters. They are adjudicated by the DoD, DoE, Department of Treasury, and Department of Homeland Security, and ultimately approved or disapproved by the DoS, DoC, or DoE. The Export Licensing Information System Advisor (ELISA) is a USXPORTS adjunct application that allows U.S. exporters to obtain the status of their dual-use and munitions license applications. The DoD, DoS, and DoE are fully on-line and using USXPORTS. The DoC is partially on-line, and the National Security Staff directed the DoC to continue its transition to USXPORTS. DTSA continues to upgrade USXPORTS through enhancements that support the export licensing adjudication processes, to include flexibility to process license applications in a telework environment. 2. Spacelink supports DTSA’s statutory Space Monitoring mission as a web-based, collaborative tool used by the DoD and U.S. industry to share and review documentation associated with foreign space launches of U.S. technology (i.e., satellites and/or their components). 3. FVS consists of three IT applications used to request, adjudicate, and confirm visits by foreign nationals to DoD and DoD contractor facilities within the continental United States. 4. NDPS records the National Disclosure Policy Committee’s decisions on exceptions to national disclosure policy. 5. DPARS is a web-based case management tool used by Military Departments to review and adjudicate technology-based U.S. patent applications. The DoD provides secrecy order recommendations to the U.S. Patent and Trademark Office for U.S. patent application that have a military application. DHS began leveraging this system in FY 2022. Classified AMS systems are scheduled for cloud migration in late early/mid FY 2025. USG personnel oversee contractor support for Security Policy Automation Network applications in the areas of software/hardware upgrades, operations and maintenance, life cycle documentation, and Federal archiving of electronic records. USG personnel also oversee infrastructure support for DTSA’s networks/cloud environments, servers, databases, cybersecurity, and Risk Management Framework certification and accreditation. DTSA 675 Research Analysis and Intelligence Dissemination (RAID): FY 2024                  FY 2025                  FY 2026 Actual                  Estimate                 Estimate 996                      1,011                     861 The Research Analysis and Intelligence Dissemination (RAID) directorate is responsible for proactively analyzing and assessing strategic-level technology security issues and advance policies which mitigate diversion or proliferation risks to preserve U.S. military technological advantages. RAID anticipates technological ‘game changers’ and avoids blind spots that ultimately ensures national survival. The RAID staff consists of experts in intelligence, foreign affairs, and security who contribute to maintaining, promoting, and protecting U.S. military and technological advantage by leveraging their analytic expertise to impede strategic competitors’ efforts to erode U.S. technological edge, disrupt alliances, and distort international trade. Additionally, these experts monitor, and conduct network analysis of entities and governmental agencies’ attempts to acquire sensitive U.S. technologies and proliferation, diversion of those technologies through front companies or other means. The RAID safeguards DTSA’s equities through the identification of technologies with future military or intelligence applications or national security implications. It also conducts regional and transnational strategic intelligence analysis and identifies proliferation, diversion, and networks concerns. The RAID intelligence function directly supports DTSA’s overall mission, vision, and strategic goals. The RAID is the internal intelligence analytic focal point that contributes to each DTSA directorate’s mission success by informing them of technology transfer trends and global threats and by uniquely tailoring analyses to satisfy specific internal intelligence requirements related to state and non- state actors, companies, and personalities. RAID is regionally and technologically agnostic, providing the analytic flexibility and agility to cover diverse regions and technologies as DTSA’s mission requires. The RAID provides support to ECD and IED through recurring reviews of approximately 46,000 munitions and dual-use license applications per year. RAID analyzes over 500 USXPORTS munitions and dual-use cases each week for any derogatory information related to the end-users, consignees, intermediary parties, or individuals involved. RAID seeks to uncover broader illicit technology transfer trends in diverse regions and those involving various state and non-state entities. The number of cases requiring review of intelligence reporting continues to expand in tandem with America’s adversaries’ interest in obtaining controlled U.S. technology, articles, and services. DTSA 676 The RAID analyses directly shape the regulatory and policy environment, ensuring technology security, information security, and foreign disclosure requirements are met. RAID is responsible for ensuring potential technology transfers risks are highlighted, considered, and addressed. RAID also helps influence policy through daily highlighting and distribution of relevant and current intelligence, garnered from various intelligence sources, and tailored to the diverse requirements of individual members from DTSA’s regionally (IED) and technology (ECD)-focused directorates. The RAID, in support of U.S. policies to impede the proliferation of controlled goods and technology for foreign countries and entities of concern (state and non-state), plays a significant role on behalf of the Department. RAID reviews open source, raw, and finished intelligence reporting and recommends foreign entities for inclusion on the DoC Entity List. The Entity List places a higher responsibility on high- and critical-risk foreign parties seeking to procure USG’s controlled technologies and goods. The RAID supports engagements with U.S. allies and partners to increase interoperability and build partner capacity to protect critical technology and information. RAID provides valuable intelligence on the status and capability of our allies’ and partners’ capabilities. This enables DTSA’s components to appropriately address any concerns or issues with countries and/or help guide conversations with foreign delegations. The RAID supports the denial or approval of USXPORTS cases through the interagency Operating Committee (OC) and Advisory Committee on Export Policy (ACEP) processes. RAID disseminates relevant classified intelligence to committee members for reference in articulating their positions on various cases. RAID also researches specific derogatory intelligence supporting DoD OC and ACEP positions, bolstering DoD’s arguments for denials where appropriate. The RAID raises intelligence awareness through reporting provided in the Daily Read Book as well as pre-travel intelligence briefings, directly provided by RAID subject matter experts or through coordination with the intelligence community. The RAID is responsible for updating the USXPORTS Repository as new derogatory intelligence reporting is discovered, maintaining the most up- to-date reporting available to inform DTSA and interagency partner’s licensing decisions. Currently, RAID updates the Repository on an ad-hoc basis, balancing in-depth analyses with the necessity of returning positions in a timely manner. Administratively, RAID provides guidance to the broader organization through the management of DTSA’s information, communication, controlled unclassified information, and personnel security programs. DTSA 677 Executive Operations: FY 2024                   FY 2025                   FY 2026 Actual                   Estimate                  Estimate 2,566                     2,610                     2,460 Consistent with U.S. policy, national security objectives, and Federal laws and regulations, the DTSA Director is responsible for protecting U.S. advantages in military technology. The DTSA Director and Deputy Director accomplish this responsibility through direct support to the Interim National Defense Strategic Guidance. To protect the technological superiority of our warfighters, DTSA works with DoD Components and industry in identifying critical technologies that are key to current and future warfighting capabilities. The DTSA oversees the development and implementation of the DoD technology security policies for international transfers of these defense-related goods, services, classified information, and technology. The DTSA strengthens alliances by working with international partners in coordination with the DoS, DoC, and others to control and prevent the transfer of critical technologies to strategic competitors and/or adversaries such as China, Russia, Iran, and North Korea. The DTSA supervises the control, and mitigates the risk, of information and technology transfers to key partners and allies to ensure that they are not detrimental to U.S. security. The DTSA identifies and mitigates transfers that would result in the proliferation of weapons of mass destruction and their means of delivery. One of the fundamental pillars of the Interim National Defense Strategic Guidance is to harness innovative technologies from our industries to build and maintain a more lethal, resilient, and rapidly innovative force. The DTSA implements policies and processes that promote the health of the U.S. defense industrial base. The DTSA also has active and robust programs for legislative liaison and public affairs, for which the Executive Office is responsible. DTSA 678$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 41857000, "fy26": 40052000, "name": "Defense Technology Security Agency", "fy25_current": 41909000, "fy25_request": 42380000, "fy25_cong_amt": -471000, "fy25_cong_pct": -1.11}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 664, 694, FALSE, $${"json_key": "DTSA__umbrella"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 47101000, to_jsonb(ARRAY[$${"fy25": 43.839, "fy27": 47.101, "name": "Defense Technology Security Administration", "fy26_current": 38.284, "fy26_request": 40.052, "fy26_cong_amt": -1.768, "fy26_cong_pct": -4.41}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part1/DTSA_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
