INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_mda_umbrella$$, $$MDA$$, $$Missile Defense Agency$$, $$MDA$$, $$om_dw_ba04$$, NULL, $$dw_mda$$, 2026, 569336000, 605766000, -7260000, -1.2, 598506000, 720365000, $$Provides the following Ballistic Missile Defense (BMD) unique sustainment support: A. Aegis BMD. Provides BMD unique sustainment support for deployed Aegis BMD ships, Standard Missile-3 (SM-3), BMD Aegis Weapon System (AWS), Operational Readiness, and Aegis Ashore sites. The SM-3 missile sustainment includes recertification, repair, and second destination transportation of missiles; installation of software and hardware updates; modeling and simulation; and logistics efforts. The BMD AWS sustainment support includes: 1. Technical and engineering services for in-service BMD ships and sites Missile Defense System test infrastructure maintenance to ensure in-service BMD AWS baselines maintain directed operational availability. 2. BMD Engineering Agent technical support and operational analysis for BMD units for casualty correction, technical issues, improvements, maintenance, certification, and delivery of BMD AWS computer program updates to the Fleet. 3. Aegis software maintenance corrections in the common source library. 4. Readiness analysis, ship installs, system-level test, maintenance builds, and post-cert Threat Adaptation Development updates for BMD 4.x and BMD 5.x. 5. Test site infrastructure and maintenance. 6. Integrated logistics support of BMD unique parts including technical documentation review and updates, diminishing manufacturing sources, and obsolete materiel surveillance, identification, and resolution. 7. Aegis BMD mission planner re-host to fleet warfighters. 8. Depot-level maintenance (DLM) for Aegis BMD missile defense unique equipment. MDA 692 Aegis Ashore sustainment support includes facilitating data management efforts, such as, oversight for collection, storage, and distribution of technical data and documentation required for sustainment of the Aegis Ashore sites. B. Ground-Based Midcourse Defense (GMD). Sustainment support for operational Ground-Based Interceptors and GMD Weapon System based at Fort Greely, AK (FGA) and Vandenberg Space Force Base (VSFB), CA, as well as supporting systems and nodes at Schriever Space Force Base (SSFB), CO, Fort Drum, NY (FDN) and Eareckson AS (EAS), AK. Sustainment support also includes repairs and improvements on aging support facilities at FGA, VSFB, SSFB, FDN and EAS critical to the GMD mission. Funding also ensures GMD assets are properly maintained, and crews are trained to meet Combatant Commanders’ needs. Specific activities include: 1. Weapon system sustainment support, equipment maintenance, operations support, and sustaining engineering. 2. Mission support, network operations and defense, and integrated logistics support. 3. GMD unique base operations support, facility maintenance and repairs, facility restoration and modernization, and communication support at FGA, VSFB, FDN, and EAS as outlined in respective support agreements and/or MDA contracts. The respective Military Services are responsible for common use areas and common use items. 4. Utilities for facilities that GMD occupies at VSFB, FDN, and EAS and in the FGA cantonment area as outlined in the associated support agreements. The FGA cantonment area does not include the FGA Missile Defense Complex. 5. Configuration management and control for the fielded weapon system. 6. Facility Sustainment Restoration and Modernization (FSRM) at GMD sites to support aging infrastructure and to ensure power reliability and redundancy. 7. Contractor supported offsite maintenance activities for GMD Weapon System subsystems. 8. Real-property support contractor services for operations, maintenance, and facility repair activities at FGA. 9. GMD Communication Network hardware support, maintenance, and Simultaneous Test and Operation support in the field to include the Upgraded Early Warning Radar (UEWR) locations at Beale Air Force Base, CA; Cape Cod Air Force Station, MA; Clear Air Force Station, AK; EAS, AK; Royal Air Force, Fylingdales, UK; Pituffik Space Force Base (previously known as Thule Air Force Base), Pituffik, Greenland; and the Sea-Based X-Band Radar. C. Missile Defense Systems Radars. Funding provides sustainment support for thirteen (13) Army Navy/Transportable Radar Surveillance and Control-2 (AN/TPY-2) Forward Based Mode (FBM) and Terminal High Altitude Area Defense (THAAD) (THAAD) configured Terminal Mode (TM) radars. Sustainment support also includes MDA Missile Defense mission unique sustainment for the five (5) UEWRs, Long Range Discrimination Radar (LRDR), and COBRA DANE radar that are in the US Space Force’s Global Command, Control, Communication, Intelligence (C3I) & Early MDA 693 Warning program. The Space Force is the responsible organization for the UEWR, LRDR and COBRA DANE force structure, radar operators and maintainers, and operation and maintenance costs. Specific activities include: 1. Supply support, repair, maintenance, modernization, transportation, and storage. 2. Special tools, test equipment, and parts. 3. Recurring and delta training, technical interface, and training device maintenance. 4. Engineering support and interactive electronic technical manual (IETM) updates. 5. Software revision certification and software user guide updates. 6. DLM for MDA Ground Sensors missile defense unique equipment. 7. Gallium Nitride (GaN) Transmit/Receive Integrated Microwave Module (T/RIMM) to replace obsolete Gallium Arsenide T/RIMM, incorporate server updates, and enhance radar capabilities. D. THAAD. The MDA is responsible for the sustainment of the THAAD missile defense unique and development items, while the US Army is responsible for the operations and sustainment of the common items. The MDA funding provides sustainment for all fielded THAAD Batteries, ensures THAAD assets are properly maintained and that crews are trained to meet Combatant Commanders needs including: 1. Field and sustainment level supply, maintenance, modernization, hazardous materials/waste disposal, and DLM for THAAD missile defense unique equipment. 2. Spares, Interceptor spares, repair parts, and maintenance capability at the location of each THAAD battery. 3. Engineering support for the THAAD missile defense unique equipment. 4. Deployment software support for fielded software to include: deficiency report reviews, error correction, incremental capability improvements, and hardware/system interface compatibility maintenance. 5. Missile transportation and handling from the missile storage location to the site of the THAAD launchers. 6. IETM updates, software users' guide updates, and software revision certification. 7. Maintenance and upkeep for all THAAD training devices. 8. Supply maintenance and transportation support for all new equipment training, and sustainment training relating to design changes and equipment upgrades. MDA 694$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 569336000, "fy26": 720365000, "name": "4. Administrative and Servicewide Activities", "fy25_current": 598506000, "fy25_request": 605766000, "fy25_cong_amt": -7260000, "fy25_cong_pct": -1.2}$$::jsonb, $${"fy24": 79460000, "fy26": 152247000, "name": "Aegis Ballistic Missile Defense Program", "fy25_current": 74208000, "fy25_request": 75016000, "fy25_cong_amt": -808000, "fy25_cong_pct": -1.08}$$::jsonb, $${"fy24": 174086000, "fy26": 166305000, "name": "Ground-Based Midcourse Defense Program", "fy25_current": 182298000, "fy25_request": 184280000, "fy25_cong_amt": -1982000, "fy25_cong_pct": -1.08}$$::jsonb, $${"fy24": 226852000, "fy26": 284785000, "name": "Missile Defense System Radars Program", "fy25_current": 251198000, "fy25_request": 254680000, "fy25_cong_amt": -3482000, "fy25_cong_pct": -1.37}$$::jsonb, $${"fy24": 88938000, "fy26": 117028000, "name": "Terminal High Altitude Area Defense Program", "fy25_current": 90802000, "fy25_request": 91790000, "fy25_cong_amt": -988000, "fy25_cong_pct": -1.08}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 695, 712, FALSE, $${"json_key": "MDA__umbrella"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 487235000, to_jsonb(ARRAY[$${"fy25": 671.366, "fy27": 487.235, "name": "4. Administrative and Servicewide Activities", "fy26_current": 697.729, "fy26_request": 720.365, "fy26_cong_amt": -22.636, "fy26_cong_pct": -3.14}$$::jsonb, $${"fy25": 109.373, "fy27": 100.052, "name": "Aegis Ballistic Missile Defense", "fy26_current": 147.477, "fy26_request": 152.247, "fy26_cong_amt": -4.77, "fy26_cong_pct": -3.13}$$::jsonb, $${"fy25": 181.419, "fy27": 204.261, "name": "Ground-Based Midcourse Defense", "fy26_current": 161.089, "fy26_request": 166.305, "fy26_cong_amt": -5.216, "fy26_cong_pct": -3.14}$$::jsonb, $${"fy25": 270.149, "fy27": 182.922, "name": "Missile Defense System Radars", "fy26_current": 275.787, "fy26_request": 284.785, "fy26_cong_amt": -8.998, "fy26_cong_pct": -3.16}$$::jsonb, $${"fy25": 110.425, "fy27": 0.0, "name": "Terminal High Altitude Area Defense", "fy26_current": 113.376, "fy26_request": 117.028, "fy26_cong_amt": -3.652, "fy26_cong_pct": -3.12}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part1/MDA_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
