INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_osd_miso$$, $$OSD - MISO$$, $$Office of the Secretary of Defense - Military Information Support Operations$$, $$OSD$$, $$om_dw_ba01$$, NULL, $$dw_osd$$, 2026, 252091000, 253176000, -3034000, -1.2, 250142000, 209442000, $$Military Information Support Operations (MISO) funds the operational employment of MISO to change the behavior of foreign target audiences to meet Department of Defense (DoD) objectives. These funds are distributed to, and executed by, the Combatant Commands (CCMD). The interconnectedness of global communication systems and the ability of our adversaries to use information trans-regionally requires the DoD to compete in the information domain at a strategic level. The FY 2026 discretionary request of $209,442 thousand reflects the Department’s approach to MISO budgeting by utilizing a central fund within the Office of the Secretary of Defense (OSD). The Office of the Assistant Secretary of Defense for Special Operations and Low Intensity Conflict (ASD(SO/LIC)) is responsible for MISO program management and budget formulation. A single MISO account increases transparency and enhances ASD(SO/LIC) oversight of MISO programming; FY 2026 represents the fourth year of the Department’s utilization of a consolidated MISO budget to fund MISO operations and the third year the Department used a MISO Resource Request (MRR) process managed by ASD(SO/LIC) to prioritize and allocate resources amongst CCMDs. In FY 2023, the Department transferred funds previously programmed and funded by the Military Departments and US Special Operations Command (USSOCOM) to capitalize the central MISO account. The USSOCOM executes directly from the centralized MISO account for the Joint MISO Web Operations Center (JMWC). Similarly, MISO conducted by USSOCOM Theater Special Operations Commands are executed from the centralized MISO account by the appropriate Geographic Combatant Command. The USSOCOM continues to receive the MISO money used for manning, training, and equipping their active duty PSYOP force through their USSOCOM budget request. OSD - MISO 826 In FY 2024, the MISO program was granted approval to collapse the structure from three program project codes (Execution, Assessment, Support) to one program project code (Execution). This consolidation allows for better management and oversight of the program, better execution definitions, and easier congressional reporting. The revised description is as follows: Execution: Funds the operational employment of MISO to change the behavior of foreign target audiences and covers MISO planning, execution, assessment, and support. This includes the planning, analysis, production, translation, distribution, and dissemination costs associated with providing information to foreign audiences, through a variety of communication mechanisms (audio, visual, and audio-visual,) designed to affect the foreign audiences' perceptions, reasoning, beliefs, motivations, decisions, and ultimately behavior. These funds are distributed to all Combatant Commands for requirements associated with MISO and utilized in accordance with DoD policies for MISO fund expenditures. Also includes necessary travel expenses of civilian full-time equivalents (FTE) and contractor FTEs (CFTE) conducting MISO. OSD - MISO 827$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 252091000, "fy26": 209442000, "name": "01. OSD - MISO", "fy25_current": 250142000, "fy25_request": 253176000, "fy25_cong_amt": -3034000, "fy25_cong_pct": -1.2}$$::jsonb, $${"fy24": 252091000, "fy26": 209442000, "name": "MISO - Execution, Assessment and Support", "fy25_current": 250142000, "fy25_request": 253176000, "fy25_cong_amt": -3034000, "fy25_cong_pct": -1.2}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 829, 842, FALSE, $${"json_key": "OSD__Military_Information"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 325609000, NULL, NULL, NULL, $$O&M/FY27/DW/Vol1_Part1/PSYOP_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_osd_umbrella$$, $$OSD$$, $$Office of the Secretary of Defense$$, $$OSD$$, $$om_dw_ba04$$, NULL, $$dw_osd$$, 2026, 2692989000, 2980715000, -139690000, -4.69, 2841025000, 2093717000, $$The Office of the Secretary of Defense (OSD) is responsible for policy development, planning, resource management, and program evaluation. The OSD includes the offices of top civilian defense decision-makers concerning personnel, weapons acquisition, research, intelligence, and fiscal policy, as well as offices the Secretary of Defense (SECDEF) establishes to assist in carrying out assigned responsibilities. The OSD includes the immediate offices of the SECDEF and Deputy Secretary of Defense (DEPSECDEF), the Under Secretaries of Defense, the Principal Staff Assistants (PSA), the Executive Support Offices, and other core programs, which are listed below: OSD Offices/Principal Staff Assistants: • Immediate Office of the Secretary and Deputy Secretary of Defense • Assistant Secretary of Defense for Legislative Affairs (ASD(LA)) • Assistant Secretary of Defense for Special Operations Low-Intensity Conflict (ASD(SO/LIC)) & Secretariat for Special Operations (SSO) • Assistant to the Secretary of Defense for Privacy, Civil Liberties, and Transparency (ATSD(PCLT)) • Assistant to the Secretary of Defense for Public Affairs (ATSD(PA)) • Chief Digital and Artificial Intelligence Officer (CDAO) • Defense Innovation Unit (DIU) • Performance Improvement Officer & Director of Administration and Management (PIO/DA&M) • Director, Cost Assessment and Program Evaluation (D,CAPE) • Director, Operational Test and Evaluation (D,OT&E) • DoD Chief Information Officer (DoD CIO) • Office of General Counsel (OGC) • Office of the Director of Net Assessment (ODNA) • Office of the Under Secretary of Defense for Acquisition and Sustainment (OUSD(A&S)) • Office of the Under Secretary of Defense (Comptroller) (OUSD(C)) • Office of the Under Secretary for Intelligence and Security (OUSD(I&S)) • Office of the Under Secretary for Personnel and Readiness (OUSD(P&R)) • Office of the Under Secretary of Defense for Policy (OUSD(P)) • Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)) OSD 730 •   Strategic Capabilities Office (SCO) •   Test Resource Management Center (TRMC) Other Funded Programs and Organizations: • Civilian Pay Centrally Funded Account • Capital Security Cost Sharing (CSCS) • Grants • Training Civilian Pay: The OSD Core Operating Program provides the necessary resources to support the effective implementation of the Interim National Defense Strategic Guidance (INDSG). Funding includes all civilian personnel compensation and benefits required for OSD's operations and the centrally funded support services as depicted in the subsequent tables: OSD 731 FY 2024-2026 PSA Labor and FTE Profile ($ in Thousands) OSD PSA                                              FY 2024 Actuals             FY 2025 Enacted        FY 2026 Request Change $           FTE             $        FTE           $        FTE Immediate Office of the Secretary and Deputy Secretary of Defense                                 10,895                48     9,449           40     9,157           40       - Assistant Secretary of Defense for Legislative Affairs (ASD(LA))                                   6,287                32     6,868           33     7,293           36            3 Assistant Secretary of D