25_current": 16844000, "fy25_request": 19861000, "fy25_cong_amt": -3017000, "fy25_cong_pct": -15.19}$$::jsonb, $${"fy24": 181547000, "fy26": 38291000, "name": "Other A&S Programs", "fy25_current": 342826000, "fy25_request": 357660000, "fy25_cong_amt": -14834000, "fy25_cong_pct": -4.15}$$::jsonb, $${"fy24": 55742000, "fy26": 21793000, "name": "Procurement Technical Assistant Program", "fy25_current": 22738000, "fy25_request": 22738000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 210791000, "fy26": 158352000, "name": "Readiness Environmental Protection Initiative", "fy25_current": 155561000, "fy25_request": 177348000, "fy25_cong_amt": -21787000, "fy25_cong_pct": -12.28}$$::jsonb, $${"fy24": 132085000, "fy26": 138652000, "name": "Comptroller", "fy25_current": 131992000, "fy25_request": 140637000, "fy25_cong_amt": -8645000, "fy25_cong_pct": -6.15}$$::jsonb, $${"fy24": 21417000, "fy26": 24984000, "name": "DoD Consolidated Audit", "fy25_current": 23870000, "fy25_request": 23870000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 110668000, "fy26": 113668000, "name": "Other Comptroller Programs", "fy25_current": 108122000, "fy25_request": 116767000, "fy25_cong_amt": -8645000, "fy25_cong_pct": -7.4}$$::jsonb, $${"fy24": 143932000, "fy26": 111191000, "name": "and Security", "fy25_current": 123096000, "fy25_request": 129023000, "fy25_cong_amt": -5927000, "fy25_cong_pct": -4.59}$$::jsonb, $${"fy24": 641000, "fy26": 857000, "name": "Defense Military Deception Program Office", "fy25_current": 610000, "fy25_request": 832000, "fy25_cong_amt": -222000, "fy25_cong_pct": -26.68}$$::jsonb, $${"fy24": 143291000, "fy26": 110334000, "name": "Intelligence Mission and Classified Programs", "fy25_current": 122486000, "fy25_request": 128191000, "fy25_cong_amt": -5705000, "fy25_cong_pct": -4.45}$$::jsonb, $${"fy24": 159233000, "fy26": 106586000, "name": "Personnel and Readiness", "fy25_current": 137835000, "fy25_request": 147877000, "fy25_cong_amt": -10042000, "fy25_cong_pct": -6.79}$$::jsonb, $${"fy24": 16442000, "fy26": 13352000, "name": "Defense Readiness Reporting System", "fy25_current": 13717000, "fy25_request": 13717000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 142791000, "fy26": 93234000, "name": "Other P&R Programs", "fy25_current": 124118000, "fy25_request": 134160000, "fy25_cong_amt": -10042000, "fy25_cong_pct": -7.49}$$::jsonb, $${"fy24": 118176000, "fy26": 186539000, "name": "Policy", "fy25_current": 143285000, "fy25_request": 142858000, "fy25_cong_amt": 427000, "fy25_cong_pct": 0.3}$$::jsonb, $${"fy24": 118176000, "fy26": 186539000, "name": "Operations", "fy25_current": 143285000, "fy25_request": 142858000, "fy25_cong_amt": 427000, "fy25_cong_pct": 0.3}$$::jsonb, $${"fy24": 96844000, "fy26": 15114000, "name": "Research and Engineering", "fy25_current": 82118000, "fy25_request": 85354000, "fy25_cong_amt": -3236000, "fy25_cong_pct": -3.79}$$::jsonb, $${"fy24": 0, "fy26": 3943000, "name": "Cyber Resiliency", "fy25_current": 3692000, "fy25_request": 3850000, "fy25_cong_amt": -158000, "fy25_cong_pct": -4.1}$$::jsonb, $${"fy24": 747000, "fy26": 3122000, "name": "Defense Innovation Board", "fy25_current": 2880000, "fy25_request": 2997000, "fy25_cong_amt": -117000, "fy25_cong_pct": -3.9}$$::jsonb, $${"fy24": 44423000, "fy26": 0, "name": "Other R&E Programs", "fy25_current": 61503000, "fy25_request": 63885000, "fy25_cong_amt": -2382000, "fy25_cong_pct": -3.73}$$::jsonb, $${"fy24": 51674000, "fy26": 8049000, "name": "War-Gaming", "fy25_current": 14043000, "fy25_request": 14622000, "fy25_cong_amt": -579000, "fy25_cong_pct": -3.96}$$::jsonb, $${"fy24": 3231000, "fy26": 3039000, "name": "20. Director, Test Resource Management Center", "fy25_current": 3079000, "fy25_request": 3121000, "fy25_cong_amt": -42000, "fy25_cong_pct": -1.35}$$::jsonb, $${"fy24": 3231000, "fy26": 3039000, "name": "Operations", "fy25_current": 3079000, "fy25_request": 3121000, "fy25_cong_amt": -42000, "fy25_cong_pct": -1.35}$$::jsonb, $${"fy24": 388197000, "fy26": 318565000, "name": "21. Other Defense Programs and Initiatives", "fy25_current": 420071000, "fy25_request": 359190000, "fy25_cong_amt": 60881000, "fy25_cong_pct": 16.95}$$::jsonb, $${"fy24": 277229000, "fy26": 296939000, "name": "Capital Security Cost Sharing", "fy25_current": 314432000, "fy25_request": 314432000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 22471000, "fy26": 7361000, "name": "Cross Agency Priority Goals", "fy25_current": 7216000, "fy25_request": 7216000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 12171000, "fy26": 14265000, "name": "Office of the Secretary of Defense", "fy25_current": 9754000, "fy25_request": 9754000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 76326000, "fy26": 0, "name": "Other Programs", "fy25_current": 88669000, "fy25_request": 27788000, "fy25_cong_amt": 60881000, "fy25_cong_pct": 219.09}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 733, 809, FALSE, $${"json_key": "OSD__umbrella", "fy27_v192_bucket_a_dw": {"session": "2026-05-09_v41", "source_pdf": "O&M/FY27/DW/Vol1_Part1/OSW_OP-5.pdf", "content_hash": "23c6ce21f797309cc4d685f24b10411f6b9dd8f1cdc45ab80078d0b076070e8c", "source_page_amount": 18, "source_page_description": 2}}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 3832831000, NULL, NULL, NULL, $$O&M/FY27/FY2027_o1.txt$$, 1067469000) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_ohdaca_umbrella$$, $$OHDACA$$, $$Overseas Humanitarian, Disaster, and Civic Aid (OHDACA)$$, $$OHDCA$$, $$om_ohdca$$, NULL, $$dw_ohdaca$$, 2026, 210168000, 115335000, 0, 0.0, 115335000, 100793000, $$The Overseas Humanitarian, Disaster, and Civic Aid (OHDACA) appropriation supports the Secretary of Defense (SECDEF) and the Combatant Commanders (CCDRs) in the pursuit of national and theater strategies to build partner nation resilience, capacity and capability; expand and strengthen alliances and partnerships; advance DoD access, influence, and visibility; and increase burden-sharing with allies and partners. OHDACA-funded Security Cooperation programs include Humanitarian Assistance (HA) and Humanitarian Mine Assistance (HMA). These programs are critically needed to support Department of Defense (DoD) goals and further U.S. National Security and Defense objectives. The OHDACA appropriation is also used to fund DoD support to USG Foreign Disaster Relief (FDR) activities. Humanitarian Assistance (HA) Program: The HA program funds activities which relieve or reduce endemic conditions such as human suffering, disease, hunger, and privation, particularly in regions where humanitarian needs may pose significant challenges to stability or potentially pose a threat to the United States or its national security interests. Developed jointly with partner nation ministerial-level authorities, the DoD HA program builds capacity in the areas of disaster risk reduction; mitigation and preparedness; basic education support; public health support, including pandemics and infectious diseases; and basic infrastructure support (e.g., water, sanitation, and shelter) in support of U.S. security priorities. OHDACA-funded HA activities include individual HA projects, the donation of non-lethal DoD excess property for humanitarian purposes, and the transportation of private humanitarian donations to achieve national security priorities. DoD HA activities bolster a partner nation’s capacity to reduce the risk of, prepare for, mitigate the consequences of, and respond to humanitarian disasters, including pandemic emergencies, thereby reducing reliance on foreign disaster relief or costly U.S. intervention. They also build partner nation resilience against the influence of malign strategic competitors and transnational threats to security and stability and make our partners more capable of defense burden-sharing. OHDACA 69 Overseas Humanitarian, Disaster, and Civic Aid The Combatant Commands (CCMDs) leverage OHDACA-funded security cooperation HA as a highly effective military-to-civilian program that complements other security cooperation tools by enhancing U.S. military access in selected countries, building relationships with critical partners, and furthering security priorities in strategic areas. DoD’s global reach is demonstrated by high-impact, low-cost DoD HA engagements, allowing the CCMDs to respond at the speed of relevancy to partner nation needs and become the defense partner of choice. Humanitarian Mine Action (HMA) Program: The OHDACA-funded HMA program pursues DoD’s security cooperation objectives and engagement in critical countries. The DoD HMA Program assists partner nation civilian populations plagued by landmines, explosive remnants of war (ERW), and the hazardous effects of unexploded ordnance (UXO) to develop indigenous capacity for humanitarian demining, explosive ordnance disposal (including underwater), and safe management of stockpiled conventional munitions. The program trains partner nation demining cadres to identify suspected contaminated areas, conduct surveys and assessments, destroy landmines and ERW, and return cleared areas to civilian use. It also provides humanitarian demining supplies and equipment to partner nations for training on clearance of contaminated areas to allow the repatriation of internally displaced persons and/or refugees. U.S. forces provide training and support in the disposal, demilitarization, physical security, and stockpile management of potentially dangerous stockpiles of explosive ordnance, small arms, and light weapons, including man-portable air defense systems. In addition to providing geographic CCMDs with access to geographical areas otherwise not readily available, this security cooperation program contributes to DoD, unit, and individual U.S. force readiness by providing unique deployment opportunities to hone critical wartime, civil-military, language, and cultural skills while preparing allies and partners to assume increased burden-sharing roles to address the threats of ERW/UXO. Directly supporting the HMA Program, the Humanitarian Demining Training Center (HDTC) in Virginia, is the DoD center for the training of deploying U.S. military personnel for humanitarian mine action missions. The HDTC incorporates new demining technologies and techniques into training plans and provides current data on country-specific ERW (including UXO, mines, booby traps, and small arms ammunition) in support of training. The HDTC training includes the preparation and delivery of instruction in landmine and battle area clearance, explosive ordnance disposal (EOD), stockpiled conventional munitions assistance, underwater ERW clearance, and casualty care. The CCMDs leverage OHDACA-funded HMA as a military-to-civilian program that complements other security cooperation tools by enhancing U.S. military access in selected countries, building relationships with critical partners, and furthering security priorities in strategic areas. Foreign Disaster Relief (FDR): The DoD is postured to support the U.S. government’s response to disaster relief activities outside the United States and its territories, typically in response to a formal request from the Department of State (DoS). DoD provides unique military capabilities to save lives and alleviate the immediate suffering of foreign disaster victims. DoD FDR supports these activities when directed by the President or approved by the Secretary of Defense. Typical DoD FDR activities include logistics, transportation (such as rotary- and fixed-wing airlift), air traffic control, imagery and engineering assessments, and search and rescue. DoD assets provide important direct and indirect contributions – speed, specialization, efficiency, and effectiveness – especially in the early phase of relief response. OHDACA 70 Overseas Humanitarian, Disaster, and Civic Aid$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 210168000, "fy26": 100793000, "name": "1. Operational Forces", "fy25_current": 115335000, "fy25_request": 115335000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 25829000, "fy26": 9994000, "name": "Foreign Disaster Relief", "fy25_current": 20000000, "fy25_request": 20000000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 163251000, "fy26": 79599000, "name": "Humanitarian Assistance", "fy25_current": 80335000, "fy25_request": 80335000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 21088000, "fy26": 11200000, "name": "Humanitarian Mine Action Program", "fy25_current": 15000000, "fy25_request": 15000000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part_2.pdf$$, 71, 84, FALSE, $${"json_key": "OHDACA__umbrella"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 78187000, to_jsonb(ARRAY[$${"fy25": 119.038, "fy27": 78.187, "name": "1. Operational Forces", "fy26_current": 100.793, "fy26_request": 100.793, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 6.712, "fy27": 10.0, "name": "Foreign Disaster Relief", "fy26_current": 9.994, "fy26_request": 9.994, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 92.949, "fy27": 57.656, "name": "Humanitarian Assistance", "fy26_current": 79.599, "fy26_request": 79.599, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 19.377, "fy27": 10.531, "name": "Humanitarian Mine Action Program", "fy26_current": 11.2, "fy26_request": 11.2, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part2/OHDACA_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_oig_cyber$$, $$OIG - Cyber$$, $$Office of Inspector General Cyber$$, $$OIG$$, $$om_oig$$, NULL, $$dw_oig$$, 2026, 1948000, 1988000, 0, 0.0, 1988000, 2030000, $$The Department of Defense (DoD) Office of Inspector General (OIG) operates its own independent networks, on the Department of Defense Information Network, to ensure the confidentiality of its data. The DoD OIG Cyber Security Division uses multiple cyber security tools to protect and monitor these networks and to analyze, detect, and respond to unauthorized activity. The DoD OIG Cyber Security Division ensures the DoD OIG systems and applications comply with all DoD policies and protect networks from attacks aimed at stealing or damaging DoD OIG data or disrupting DoD OIG operations. The DoD OIG Cyber Security Division provides Computer Network Defense, Information Assurance, Endpoint Security Solutions, and User Activity Monitoring services for the DoD OIG Secret Internet Protocol Routing (SIPR) Protocol Routing Network System. OIG - Cyber 110 Office of Inspector General - Cyber$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 1948000, "fy26": 2030000, "name": "DoD OIG Cyber", "fy25_current": 1988000, "fy25_request": 1988000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part_2.pdf$$, 113, 123, FALSE, $${"json_key": "OIG__OIG_-_Cyber"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 2073000, to_jsonb(ARRAY[$${"fy25": 1.988, "fy27": 2.073, "name": "DoW OIG Cyber", "fy26_current": 2.03, "fy26_request": 2.03, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part2/OIG_Cyber_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_oig_umbrella$$, $$OIG$$, $$Office of Inspector General$$, $$OIG$$, $$om_oig$$, NULL, $$dw_oig$$, 2026, 534717000, 545343000, -7562000, -1.39, 537781000, 500569000, $$The Department of Defense (DoD) Office of Inspector General (OIG) promotes the economy, efficiency, and effectiveness of DoD programs and operations, and the integrity of its workforce, through impactful audits, evaluations, investigations, and reviews. The DoD OIG audits, investigates, and evaluates the programs and operations of the DoD, operates the DoD Hotline, Contractor Disclosure, and Whistleblower Protection programs, and produces quarterly reports on overseas contingency operations for which the DoD IG has been designated the Lead Inspector General (IG). The DoD OIG executes its mission and responsibilities through the activities of five oversight and investigative components, the Office of General Counsel, and various mission support functions. The aggregate FY 2026 budget request for DoD OIG operations is $500.6 million: $494.9 million Operations and Maintenance (BA 01), $4.63 million Research, Development Test and Evaluation (BA 02), and $1.07 million Procurement (BA 03). The details of funding for the DoD OIG Cyber budget are provided in a separate exhibit. The breakout of the funding details for the DoD OIG Cyber budget are provided in a separate exhibit. The DoD OIG programs are as follows: 1. Audit: Audit conducts independent audits of DoD operations, systems, program, and functions. 2. Defense Criminal Investigative Service (DCIS): DCIS conducts criminal investigations related to DoD programs and operations, focusing on procurement fraud, public corruption, product substitution, financial crimes, health care fraud, illegal technology transfer, cyber-crimes, and computer network intrusions. 3. Administrative Investigations (AI): AI investigates, and oversees DoD Components’ investigations of, allegations of senior DoD officials misconduct of whistleblower reprisal and restriction from communication with an IG or member of Congress. AI performs the DoD Whistleblower Protection Coordinator function, which is responsible for educating DoD employees on whistleblower statutory prohibitions and protections. AI also manages the DoD Hotline for confidential reporting of fraud, waste, abuse, and danger to public health and safety related to DoD programs, operations, and employees. OIG 83 Office of Inspector General 4. Evaluations (EVAL): EVAL conducts independent evaluations of DoD operations and activities. 5. Overseas Contingency Operations (OCO): OCO coordinates comprehensive joint oversight and reporting on designated overseas contingency operations by the DoD OIG and other Federal OIGs, in fulfillment of the DoD IG’s Lead Inspector General and Special Inspector General responsibilities. 6. Mission Support Team (MST): MST provides essential support services to the DoD OIG enterprise, both at DoD OIG headquarters and at over 50 field offices worldwide. These services include strategic planning, human capital management, financial management, acquisition support, logistics services, information management and information technology support, security management, enterprise risk management, data analytics support, and correspondence management. MST also operates the Defense Case Activity Tracking System–Enterprise (D- CATSe) Program Management Office (PMO) to establish and sustain a single DoD-wide system for the management of administrative investigation information, and the Criminal Investigative Management System (CRIMS) PMO that supports the criminal investigation case management system used by DCIS. OIG 84 Office of Inspector General$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 108030000, "fy26": 99461000, "name": "1. Audit", "fy25_current": 113772000, "fy25_request": 115032000, "fy25_cong_amt": -1260000, "fy25_cong_pct": -1.1}$$::jsonb, $${"fy24": 116913000, "fy26": 98017000, "name": "Investigations", "fy25_current": 116669000, "fy25_request": 117929000, "fy25_cong_amt": -1260000, "fy25_cong_pct": -1.07}$$::jsonb, $${"fy24": 35092000, "fy26": 34098000, "name": "3. Administrative Investigations", "fy25_current": 37081000, "fy25_request": 38341000, "fy25_cong_amt": -1260000, "fy25_cong_pct": -3.29}$$::jsonb, $${"fy24": 50992000, "fy26": 41623000, "name": "4. Evaluations", "fy25_current": 51812000, "fy25_request": 53072000, "fy25_cong_amt": -1260000, "fy25_cong_pct": -2.37}$$::jsonb, $${"fy24": 195990000, "fy26": 198557000, "name": "5. Mission Support", "fy25_current": 191507000, "fy25_request": 192769000, "fy25_cong_amt": -1262000, "fy25_cong_pct": -0.65}$$::jsonb, $${"fy24": 23202000, "fy26": 23109000, "name": "6. Overseas Contingency Operations", "fy25_current": 23704000, "fy25_request": 24964000, "fy25_cong_amt": -1260000, "fy25_cong_pct": -5.05}$$::jsonb, $${"fy24": 3400000, "fy26": 4625000, "name": "7. RDT&E", "fy25_current": 1900000, "fy25_request": 1900000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 1098000, "fy26": 1079000, "name": "8. Procurement", "fy25_current": 1336000, "fy25_request": 1336000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part_2.pdf$$, 85, 112, FALSE, $${"json_key": "OIG__umbrella"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 504531000, to_jsonb(ARRAY[$${"fy25": 119.05, "fy27": 113.478, "name": "1. Audit", "fy26_current": 113.478, "fy26_request": 99.461, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 51.812, "fy27": 50.41, "name": "2. Evaluations", "fy26_current": 50.41, "fy26_request": 41.623, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 116.669, "fy27": 110.963, "name": "investigations", "fy26_current": 110.963, "fy26_request": 98.017, "fy26_cong_amt": 7.5, "fy26_cong_pct": 7.65}$$::jsonb, $${"fy25": 37.081, "fy27": 41.72, "name": "4. Administrative Investigations", "fy26_current": 41.72, "fy26_request": 34.098, "fy26_cong_amt": 7.5, "fy26_cong_pct": 22.0}$$::jsonb, $${"fy25": 23.704, "fy27": 5.473, "name": "5. Overseas Contingency Operations", "fy26_current": 5.473, "fy26_request": 23.109, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 192.654, "fy27": 179.588, "name": "6. Mission Support", "fy26_current": 201.412, "fy26_request": 198.557, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 1.9, "fy27": 1.506, "name": "7. RDT&E", "fy26_current": 1.506, "fy26_request": 4.625, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 1.336, "fy27": 1.393, "name": "8. Procurement", "fy26_current": 1.393, "fy26_request": 1.079, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part2/OIG_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_oldcc_umbrella$$, $$OLDCC$$, $$Office of Local Defense Community Cooperation$$, $$OLDCC$$, $$om_dw_ba04$$, NULL, $$dw_oldcc$$, 2026, 496798000, 117081000, 38187000, 32.62, 155268000, 159534000, $$The Office of Local Defense Community Cooperation (OLDCC), statutorily authorized under Title10 USC §198, is a unique Department of Defense (DoD) field activity that furthers the Secretary’s priorities by supporting efforts to enhance the readiness and lethality of military installations, ranges, and test facilities. These efforts in turn help support the States, defense communities, warfighters, and their families. In accordance with Title 10 USC §2391 and numerous National Defense Authorization and DoD Appropriation Acts, the OLDCC provides assistance to States, counties, municipalities, regions, and other communities to foster cooperation with military installations to enhance the military mission, achieve facility and infrastructure savings and reduced operating costs, address encroachment and compatible land use issues, support military families, and increase military, civilian, and industrial readiness and resiliency. The OLDCC often engages at the juxtaposition of State and local civilian efforts in response to local mission activity and/or need, embodying the Secretary of Defense’s priorities to restore the warrior ethos, rebuild our military, and reestablish deterrence. The DoD facilities and the industrial base rely upon the States and communities that host them, a circumstance where the readiness and resilience of installations and the industrial base are intrinsically related to their neighboring civilian jurisdictions, including public infrastructure and services. The OLDCC continuum of technical and financial assistance enables these State and community partners to organize, plan, and carry out efforts that benefit both them and DoD installations, the organic industrial base, and the defense industrial base. On behalf of the Secretary of Defense, the OLDCC also directs and executes the Defense Economic Adjustment Program, coordinating the involvement of other Federal Agencies through the Economic Adjustment Committee (EAC) per Executive Order 12788 signed on January 15, 1992 , as amended by Executive Order 13378 on May 12, 2005. The OLDCC Director is the Executive Director for the EAC, and provides guidance and assistance in leveraging other Federal agency expertise and resources to enable the DoD, its Components, and affected States and communities to: 1) assess economic and socioeconomic hardships caused by DoD program changes; 2) identify and evaluate alternative responses for local economic recovery; 3) identify resource requirements; and 4) assist in the preparation and implementation of adjustment strategies or action plans. The Departments of Labor and Commerce are each co-vice chairs of the EAC. For example, DoD Indo-Pacific basing actions are complemented by the OLDCC-led EAC efforts along with the Territory of Guam’s Office of the Governor and its legislature, resulting in the execution of approximately $233 million in outside-the-fence infrastructure investments. OLDCC 710 The OLDCC is currently managing over 206 active awards, totaling more than $1.4 billion. The OLDCC’s project management and grant oversight responsibilities require a wide range of capabilities and expertise to perform critical functions from pre-award risk assessments to post-award compliance, as mandated by Title 2 of the Code of Federal Regulations, Part 200 (2 CFR 200), the “Uniform Administrative Requirements, Cost Principles, and Audit Requirements for Federal Awards,” and DoD-specific responsibilities under 2 CFR Parts 1104-1125. Depending on the award, audit responsiveness and Federal Interest oversight responsibilities and OLDCC involvement may extend for several years after the close- out of a grant award. Programs of Assistance: The OLDCC Programs of Assistance are continually scrutinized to ensure they effectively enable communities to be responsive to DoD needs as they support the military and civilian households (over 70% of the military households reside off installation) that sustain the local mission. These programs presently include Installation Readiness (which encompasses OLDCC Compatible Use activities); Mission Growth - including support for our Indo-Pacific basing actions; Defense Community Infrastructure; Community Noise Mitigation that was authorized in FY 2022 and is executed as a new competitive grant program; Public Schools on Military Installations; and Mission Realignment (including Base Closures and Realignments). These programs help states and communities respond to a continuum of need, including DoD mission changes; mitigating threats to the installation-level operating environment; job loss and economic disruption; and demand for increased public services and infrastructure with a focus on civilian Defense Critical Infrastructure risk management. Installation Readiness: These efforts are the only DoD source of technical and financial assistance for States and communities to work with nearby installations (including testing and training ranges, special use airspace, military operations areas, and/or military training routes) to plan, enhance infrastructure, and implement measures that contribute to maintaining or enhancing a military installation’s readiness and lethality while also supporting the warfighter mission. Installation Readiness activities are geared to support the organizing, planning, and implementation actions necessary to avoid, prepare for, minimize the effect of, adapt to, and recover from extreme weather events, or from anticipated or unanticipated changes in environmental conditions, that do, or have the potential to, adversely affect the lethality of a military installation, assessing potential impacts to critical infrastructure, and designing risk management enhancements / mitigations in order to maintain, improve, or rapidly reestablish installation mission assurance and mission-essential functions. Under this assistance, State or local governmental entities analyze external threats and vulnerabilities to the readiness and lethality of the installation, develop mitigation strategies, and identify resources necessary to ensure the continuity of DoD and installation mission capabilities. This program enables a collaborative response that leverages Federal, State, local, and private resources to optimize the capacities and funds that each can bring to the effort. These program activities establish or reinforce an ongoing collaboration between civilian (public and private) and military equities that thrives beyond the term of any project. Installation Readiness projects may include a comprehensive review of threats and vulnerabilities; targeted studies or plans concerning, but not limited to, transportation, land use/encroachment, utility services, housing, stormwater management, and other critical infrastructure. Since FY 2023, applicants have been encouraged to undertake tabletop exercises with their local installations and other key partners, including State National Guard, to facilitate threat- based scenarios to identify critical infrastructure vulnerabilities and prioritize improvements. The OLDCC is currently supporting 123 active efforts OLDCC 711 serving the readiness needs of the Department through the development of plans to identify and then carry out efforts to prevent encroachment and mitigate threats. The Military Departments may nominate installations and ranges for this program, or State and local governments may directly request assistance. Efforts under this program benefit the Department as well as DoD civilian partners, such as: •   McMullen County, Texas is working with Naval Air Station Kingsville and other state and local entities through a $948,000 effort to plan and design 12 miles of road improvements along an unimproved, rural road, which is the single access road to the McMullen Range and the ROTHR-TX site. This effort supports the Secretary of Defense’s priority of reestablishing deterrence through enhancing capabilities at the only United States-based radar system in USSOUTHCOM’s surveillance architecture, enhances detection and surveillance capabilities along the southern border, and strengthens mission readiness and lethality at Naval Air Station Kingsville. •   The City of Portsmouth, Virginia is working with Norfolk Naval Shipyard and Naval Medical Center Portsmouth through a $527,000 effort to prepare comprehensive flood mitigation and stormwater management strategies for five key corridors critical to Naval facilities and subject to severe flooding. Portsmouth will also conduct a tabletop exercise with city and regional U.S. Navy personnel to identify potentially hazardous scenarios, with a focus on flooding, and coordinate responses to maximize access to Norfolk Naval Shipyard and Naval Medical Center Portsmouth. •   The City of Lakewood, Washington and surrounding jurisdictions through a $1.7 million effort obtained $16.1 million for a Phase 1 buyout of properties in the Clear Zones near Joint Base Lewis McCord; developed a Land Exchange Plan for other properties in the Clear Zones; created a Military Influence Area Overlay; and conducted a Lighting Study to preclude further light encroachment. •   The State of Connecticut through a $649,000 effort, invested more than $2.3 million in land purchases and infrastructure projects to prevent or mitigate civilian encroachment of missions at Naval Submarine Base New London. Their effort included the purchase and demolition of a marina across the Thames River from the base that impaired the Navy’s ability to dredge a turning basin wide enough to accommodate a new class of submarines. Efforts are presently underway to strategically locate future housing to reduce traffic congestion and improve workforce retention for the Navy and General Dynamics Electric Boat (EB), as EB ramps up to build additional systems. The OLDCC FY 2026 President’s Budget requests $5,000 thousand for the programs of assistance in Installation Readiness. This program enables a collaborative response that leverages Federal, State, local, and private resources to optimize the capacities and funds that each can bring to the effort. Defense Diversification: These programs assist DoD civilian partners to respond to DoD dependencies and prepare for and respond to changes in DoD spending. Assistance is available to assess DoD-dependent geographic areas including supply chain tiers and workforce skills; posture State and local programs of assistance for rapid responses to possible dislocations; retain and/or expand impacted worker skill sets; and leverage local ecosystems to expand business opportunities for impacted defense manufacturing firms to transition from legacy systems. It is the only source of OLDCC 712 technical and financial resources for State and local government efforts to respond to changes in DoD spending. These efforts can be undertaken in close coordination with other Federal capabilities, including the U.S. Department of Labor’s Employment and Training Administration, and the U.S. Department of Commerce’s Economic Development Administration. Efforts under this program benefit the Department as well as DoD civilian partners such as: •   Community leaders in Madison County, Kentucky and Pueblo, Colorado developed economic diversification plans and workforce retention strategies with the goal of retaining a majority of the workforce connected to the chemical demilitarization missions that completed at the end of 2023 in these rural locations. •   Grand Forks, North Dakota pivoted from the reassignment of an air refueling mission (with 355 federal civilian jobs) to hosting Grand Sky, a business park and airport focused on Unmanned Aerial Systems (UAS) that directly supports the current mission of Grand Forks Air Force Base through a $1 million+ effort. No property was available for community redevelopment after the realignment of a portion of the local mission, thus assistance supported foundational planning (including a UAS Roadmap, a regional broadband study, a Life Sciences Roadmap, and a Regional Industrial Land Study) that led to the identification of 217 acres of property at the installation for an Enhanced Use Lease for the community to develop Grand Sky. Working in partnership with Grand Forks County and the Air Force, Grand Sky has grown over the past ten years from an under-utilized (former alert ramp) to a multi-tenanted airpark with daily UAS operations. The North Dakota Legislature invested $33 million over 12 years in the road, airfield, and utility infrastructure necessary to make the park economically viable, and the private sector has already invested $159 million. Grand Sky has had a significant economic impact on the greater Grand Forks region with approximately 269 jobs created. Defense Community Infrastructure: These programs assist State and local partners through a competitive program to address deficiencies in community infrastructure, supportive of a military installation, to enhance military value, support the training of Reserve Officer Training Corps cadets, installation resilience, and/or military family quality of life. These infrastructure projects enhance our local installations, benefitting our Service members, their families, and missions. Awards fund community infrastructure projects, which are statutorily defined as transportation projects, community support facilities (e.g., schools, hospitals, police, fire, and emergency response), and utility infrastructure projects (e.g., water, wastewater, telecommunications, electric, gas, etc.) that are located off a military installation or on land leased from the DoD, supporting a military installation, and are owned by a State or local government or a not-for-profit, member-owned utility. Under the program, 16 grants were made in FY 2020, 12 in FY 2021, 19 in FY 2022, 17 in FY 2023, and 14 in FY 2024. In total, $395.7 million in Federal funds are supporting $666 million in total enhancements to benefit installations. OLDCC 713 Efforts under this program benefit the Department as well as DoD civilian government partners such as: •   A $12.7 million investment replaces the McCombs Wells water collector line which provides 100 percent of Texas’s McGregor Range water supply, ensuring a critical water supply for training exercises, improving readiness and fire suppression, and preparing warfighters to defend our homeland as well as the availability of the range for missile defense system testing, such as for a Golden Dome system, supporting an installation population of 66,293. •   A $10.3 million investment is constructing roadway improvements to alleviate traffic congestion that inhibits both public safety and anti- terrorism force protection capability at the main gate of Fort Hood, Texas, supporting an installation population of 73,359. The project will facilitate more rapid force deployment and mobilization of materials by diverting operational and commercial traffic away from the main gate, thereby improving mission readiness and support for Southern border operations. The OLDCC FY 2026 President’s Budget requests $100,000 thousand for this program, which will provide resources and enable the Department to leverage state and local investments in critical infrastructure projects. Community Noise Mitigation: • Authorized and funded under the Consolidated Appropriations Act, 2022 (Pub. L. 117-103), Section 8120, the Community Noise Mitigation Program is a one-time $75 million three year period of availability competitive program to fund grants to state and local governments for projects to reduce the impact of fixed wing military aviation noise on “covered” facilities. Of the $75 million in funding available, $56,250,000 is allocated for funding at or near active-duty military installations and $18,750,000 allocated for funding at or near guard or reserve installations, of which $5 million shall be for funding to communities for which a nearby military installation has transitioned to a new type or model of aircraft after January 1, 2019. The OLDCC issued the first Notice of Funding Opportunity for the program on July 24, 2024, which resulted in 10 grants awarded for $13,084,552. A Notice of Funding Opportunity for a second competition to obligate the remaining funds was issued on May 27, 2025. Recipients will be selected through a competition before the end of FY 2025 and will have up to 5 years from the date of obligation to complete their project that will require ongoing oversight. The OLDCC FY 2026 President’s Budget requests $32,000 thousand for the programs of assistance in Mission Growth, Defense Community Infrastructure; Community Noise Mitigation that was authorized in FY 2022 and is executed as a new competitive grant program; Public Schools on Military Installations; and Mission Realignment (including Base Closures and Realignments.) Public Schools on Military Installations: These programs enable Local Education Agencies to remedy condition and capacity deficiencies at public schools on military installations as prioritized by the Secretary of Defense. Participation in this program is by invitation only based on 1) a Deputy Secretary of Defense prioritization ranking of all 160+ public schools on a military installation through a Priority Listing, and 2) the availability of appropriations to fund a project in the order of that prioritization. Grants are provided to construct, renovate, repair, or expand elementary and secondary public schools. Since FY 2011, the program has received $3.25 billion in appropriations to execute this program. The top 71 schools prioritized by the Secretary are currently being addressed. OLDCC 714 Efforts under this program benefit the Department as well as our civilian government partners such as: •   A $179 million investment ($142 million Federal, $37 million non-Federal) for Muroc Joint Unified School District, Lancaster, California, replaced a severely deteriorated elementary school (Forbes Elementary School) and high school (Desert Junior-Senior High School ) at Edwards Air Force Base, CA, benefiting over 1,600 students annually and vastly improving the military family quality of life and airmen retention rates at Edwards Air Force Base, contributing to the readiness and lethality of Edwards missions. •   A $112 million investment ($91.2 million Federal, $20.8 million non-Federal) for Geary County Unified School District 475, Manhattan, Kansas, replaced four severely deteriorated schools (Fort Riley Middle School, Fort Riley Elementary School, Jefferson Elementary School, and Morris Hill Elementary School) at Fort Riley, Kansas, benefitting over 1,600 students annually and vastly improving the military family quality of life and retention rates at Fort Riley, contributing to the readiness and lethality of Riley missions. A $175 million investment ($139 million Federal, $35 million non-Federal) for Sierra Sands Unified School District, Ridgecrest, California, replaced two schools (Murray Middle School, Richmond Elementary School) and renovated a third school (Burroughs High School) at Naval Air Weapons Station, China Lake, California, benefitting over 2,500 students annually and vastly improving the military family quality of life and airmen retention rates at Naval Air Weapons Station China Lake, contributing to the readiness and lethality of China Lake missions. OLDCC 715$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 372492000, "fy26": 37119000, "name": "Grants (Core Programs of Assistance)", "fy25_current": 41268000, "fy25_request": 43081000, "fy25_cong_amt": -1813000, "fy25_cong_pct": -4.21}$$::jsonb, $${"fy24": 100000000, "fy26": 100000000, "name": "Defense Community Infrastructure Program (DCIP)", "fy25_current": 90000000, "fy25_request": 50000000, "fy25_cong_amt": 40000000, "fy25_cong_pct": 80.0}$$::jsonb, $${"fy24": 0, "fy26": 0, "name": "(DMCSP)", "fy25_current": 0, "fy25_request": 0, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 0, "fy26": 0, "name": "8108", "fy25_current": 0, "fy25_request": 0, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 0, "fy26": 0, "name": "Noise Mitigation Community Partnership", "fy25_current": 0, "fy25_request": 0, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 24306000, "fy26": 22415000, "name": "Operational Support Activities", "fy25_current": 24000000, "fy25_request": 24000000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 713, 732, FALSE, $${"json_key": "OLDCC__umbrella"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 142597000, to_jsonb(ARRAY[$${"fy25": 352.342, "fy27": 21.097, "name": "Grants (Programs of Assistance)", "fy26_current": 30.14, "fy26_request": 35.928, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 90.0, "fy27": 100.0, "name": "Defense Community Infrastructure Program", "fy26_current": 130.0, "fy26_request": 100.0, "fy26_cong_amt": 23.606, "fy26_cong_pct": 23.61}$$::jsonb, $${"fy25": 26.0, "fy27": 21.5, "name": "Operational Support Activities", "fy26_current": 23.0, "fy26_request": 23.606, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part1/OLDCC_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_osd_cyber$$, $$OSD - Cyber$$, $$Office of the Secretary of Defense Cyber$$, $$OSD$$, $$om_dw_ba04$$, NULL, $$dw_osd$$, 2026, 90990000, 99583000, 1954000, 1.96, 101537000, 98034000, $$The Office of the Secretary of Defense (OSD) is the principal staff of the Secretary of Defense (SECDEF) in the exercise of policy development, planning, resource/fiscal management, and program evaluation responsibilities. The OSD Principal Staff Assistants (PSA) supporting cyber activities are listed below: Principal Staff Assistants: • DoD Chief Information Officer (DoD CIO) • Office of the Under Secretary of Defense for Policy (OUSD(P)) • Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)) OSD - Cyber 807 A. Core Operating Program CivPay: This provides the necessary resources to support effective implementation of the Interim National Defense Strategic Guidance (INDSG) by building a ready and capable civilian workforce. Funding includes all civilian personnel compensation and benefits required for OSD operations and centrally funded oversight, policy, and control cyber services. FY 2024-2026 PSA Labor and FTE Profile ($ in Thousands) OSD PSA                                       FY 2024 Actuals     FY 2025 Enacted      FY 2026 Request Change $        FTE          $        FTE         $        FTE DoD CIO 9,796         38        9,345       37       6,421       45         8 OUSD(P) 2,358         10        6,226       25       1,264        9        (16) OUSD(R&E) 1,327          5        1,313        5        830         5             - Total 13,481        53       16,884       67       8,515       59         (8) OSD - Cyber 808 $ in Thousands FY 2024          FY 2025          FY 2026 Actuals          Enacted          Request B. DoD Chief Information Officer (CIO):                                                          67,285            73,925           80,799 The DoD CIO is the PSA and advisor to the SECDEF and the Deputy Secretary of Defense (DEPSECDEF) for information technology (IT), including national security systems and information resources management (IRM) matters. The DoD CIO is responsible for all matters relating to the DoD information enterprise, including network operations, information systems, and cybersecurity. The DoD CIO develops Department- wide strategy and policy on the operation and protection of all DoD IT and information systems, including development and promulgation of enterprise-wide architecture requirements and technical standards, and enforcement, operation, and maintenance of systems, interoperability, collaboration, and interface between DoD and non-DoD systems in direct support of both the National Security Strategy (NSS) and INDSG. The DoD CIO activities support the modernization and development of advanced IT and cybersecurity capabilities to enhance readiness and lethality; focus attention on modernization of key information capabilities; develop the cyber workforce; and ensure DoD maintains an advantage over adversaries in an environment with an assumed breach and access granted based on trust (Zero Trust Architecture). The activities related to Cybersecurity include: 1) Information Systems Security Program (ISSP) 2) Cybersecurity Initiatives 3) Cybersecurity Risk Management Oversight 4) Defense Industrial Base, Cyber Security/Information Assurance 5) Cyber scholarship and workforce development OSD - Cyber 809 $ in Thousands FY 2024         FY 2025           FY 2026 Actuals         Enacted           Request C. Under Secretary of Defense (Policy) (Office of Principal Cyber Advisor):                           5,129            7,367             5,226 The OUSD(P) is the PSA and advisor to the SECDEF and DEPSECDEF on capabilities, force, and contingency plans necessary to implement the NDS, defense policy, and the integration and oversight of DoD policy and plans to achieve national security objectives. As specified in Section 392a of Title 10, United States Code, the Assistant Secretary of Defense for Cyber Policy, serving as the Principal Cyber Advisor (PCA) to the SECDEF, acts as the principal advisor to the SECDEF on military cyber forces and activities, and is responsible for the overall integration of Cyber Operations Forces activities relating to cyberspace operations, including associated policy and operational considerations, resources, personnel, technology development and transition, and acquisition. Funding supports the Office of the Principal Cyber Advisor (OPCA) to oversee the development of USCYBERCOM and the Cyberspace Operations Forces (COF); establishes cyberspace operations policy and strategy; ensures the integration of activities in support of cyber, information, and electromagnetic spectrum operations; and drives implementation of the DoD Cyber Strategy and Cyber Posture Review. The OPCA also synchronizes and directs issues related to COF posture and readiness, and advises senior leadership on relevant policy, programmatic, and process gaps inhibiting operational effectiveness across the DoD. Funds ensure fiscal, budgetary, and programmatic oversight of the Department’s annual Cyberspace Operations budget, in compliance with PCA budget certification authority as directed in Section 329a of Title 10; and support increased oversight and advocacy for USCYBERCOM responsibilities in Section 167B of Title 10 for organizing, equipping, and training the COF, in addition to development and acquisition efforts pursuant to joint cyberspace operational capabilities. OSD - Cyber 810 $ in Thousands FY 2024          FY 2025          FY 2026 Actuals          Enacted          Request D. Under Secretary of Defense (Research and Engineering):                                           5,096            3,361            3,494 The OUSD(R&E) is the PSA and advisor to the SECDEF and DEPSECDEF for all matters relating to research and engineering, and other related matters. The OUSD(R&E) serves as the Department’s Chief Technical Officer and is responsible for unifying defense research, development, and prototyping activities across the enterprise. The OUSD(R&E) establishes policies on, and oversees, all defense research and engineering, technology development, technology transition, prototyping, experimentation, and development testing activities and programs. The OUSD(R&E) responsibilities also include: establishing a Department-wide, mission-focused roadmap for each of the Critical Technology Areas (CTA); developing and implementing a National Defense Science and Technology (S&T) Strategy; leading the establishment and implementation of Department-wide protection methodologies that mitigate the risk of loss of critical technologies to determined adversaries; initiating critical prototypes within the OUSD(R&E) identified capability thrust priorities; developing policy and guidance for DoD Mission and Enterprise Architectures; establishing Open Architecture Standards, piloting alternate rapid acquisition approaches. The funding supports the OUSD(R&E) Damage Assessment Management Office (DAMO) oversight and coordination mission. The OUSD(R&E) DAMO develops and provides policy oversight of cyber incident damage assessments conducted by the military department DAMO organizations as mandated by Defense Federal Acquisition Regulations Supplement (DFARS) clause 252.204-7012 (Safeguarding Covered Defense Information and Cyber Incident Reporting). The purpose of the assessments is to analyze the impact of compromised information on US military capability underpinned by technology. In addition, OUSD(R&E) conducts cyber incident damage assessments for Components lacking organic DAMO capability. OSD - Cyber 811$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 90990000, "fy26": 98034000, "name": "01.Cyberspace Activities", "fy25_current": 101537000, "fy25_request": 99583000, "fy25_cong_amt": 1954000, "fy25_cong_pct": 1.96}$$::jsonb, $${"fy24": 13481000, "fy26": 8515000, "name": "Compensation and Benefits", "fy25_current": 16884000, "fy25_request": 16884000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 67284000, "fy26": 80799000, "name": "Department of Defense Chief Information Officer", "fy25_current": 73925000, "fy25_request": 71236000, "fy25_cong_amt": 2689000, "fy25_cong_pct": 3.77}$$::jsonb, $${"fy24": 5129000, "fy26": 5226000, "name": "Office of the Under Secretary of Defense for Policy", "fy25_current": 7367000, "fy25_request": 7996000, "fy25_cong_amt": -629000, "fy25_cong_pct": -7.87}$$::jsonb, $${"fy24": 5096000, "fy26": 3494000, "name": "Research and Engineering", "fy25_current": 3361000, "fy25_request": 3467000, "fy25_cong_amt": -106000, "fy25_cong_pct": -3.06}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 810, 828, FALSE, $${"json_key": "OSD__Cyber"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 81163000, NULL, NULL, NULL, $$O&M/FY27/DW/Vol1_Part1/OSW_Cyber_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_pscp_2$$, $$2$$, $$Private Sector Care$$, $$PSCP$$, $$om_pscp$$, $$BA-01: Operation and Maintenance$$, $$mcsc$$, 2026, 0, 0, 0, NULL, 0, 0, NULL, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/FY2027_o1.txt$$, NULL, NULL, FALSE, $${"fy27_v187_ingested_at": "2026-05-09 21:50:06.756046+00", "fy27_v187_source_file": "Budget J-Books/FY27/MHS/MHS_PB27_J-Book-Vol1-COMP_PSCP.pdf"}$$::jsonb, $$2026-05-08T02:56:44.031152+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 22175472000, NULL, NULL, NULL, $$Budget J-Books/FY27/MHS/MHS_PB27_J-Book-Vol1-COMP_PSCP.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_sisc_umbrella$$, $$SISC$$, $$Support for International Sporting Competitions$$, $$SISC$$, $$om_dw_ba04$$, NULL, $$dw_sisc$$, 2026, 957000, 0, 0, 0.0, 0, 0, $$The Support for International Sporting Competitions, Defense (SISC) account is funded with a no-year appropriation that provides continuing Department of Defense (DoD) support to national and international sporting events that are either certified by the Attorney General or supports specific organizations, such as: the Special Olympics, Paralympics, and the United States Olympic and Paralympic Committees (USOPC) through the Paralympic Military Program. The Department is not requesting any appropriated funds in FY 2026 due to the available balances in the account from the DoD Appropriations Acts for FY 2015 and FY 2023. In FY 2025, the Department is supporting 19 Paralympic sporting events sanctioned by the USOPC through the Paralympic Military Program with an estimated cost of $1 million. In FY 2026, the Department intends to support approximately 24 sporting events with an estimated cost of $2.7 million. The International Sporting Competitions planning cycles do not fully align with the DoD budget cycle, which can result in year of execution requests for support. These funds support safety, security and logistical requirements for certain sporting competitions. Under the provisions of 10 U.S.C. Section 2564, the Department has the authority to assist Federal, state and/or local agencies in support of civilian sporting events if the Attorney General certifies that such assistance is necessary to meet essential security and safety needs. The Department can also provide support to the Special Olympics, the Paralympics, a sporting event sanctioned by the U.S. Olympic and Paralympic Committee, through the Paralympic Military Program, and/or any national or international Paralympic sporting event that meet requirements outlined in 10 U.S.C. Section 2564, as amended by Public Law (P.L.) 110-181 Section 372. Support for these events are eligible for DoD support and exempt from Attorney General certification. SISC 122 Support for International Sporting Competitions$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 957000, "fy26": 0, "name": "Support to International Sporting Competitions", "fy25_current": 0, "fy25_request": 0, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part_2.pdf$$, 124, 136, FALSE, $${"json_key": "SISC__umbrella"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 0, to_jsonb(ARRAY[$${"fy25": 0.147, "fy27": 0.0, "name": "Support to International Sporting Competitions", "fy26_current": 0.0, "fy26_request": 0.0, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/DW/Vol1_Part2/SISC_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_socom_cdact$$, $$CDAct$$, $$Combat Development Activities$$, $$SOCOM$$, $$om_dw_ba01$$, NULL, $$dw_socom$$, 2026, 2275874000, 2082777000, -105303000, -5.06, 1977474000, 2136165000, $$Combat Development Activities - Includes Joint and Component manpower authorizations, SOF-peculiar equipment, necessary facilities, and the associated costs specifically identified and attributable to the development of combat doctrine, organizational concepts, materiel requirements, and other developmental activities related to SOF. Also includes activities to support experimentation, tests, and project evaluations necessary to develop and/or validate new doctrine and organizations for special operations. The FY 2026 request for 1PL6 – Combat Development Activities includes $2,136,165 thousand of discretionary and $184,777 thousand of mandatory (reconciliation) for a total of $2,320,942 thousand. The mandatory funds enhance USSOCOM mission readiness. Further information for this reconciliation request is provided in Section 20010 (Readiness) of the Reconciliation Exhibit. CDAct 854$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 2275874000, "fy26": 2136165000, "name": "Combat Development Activities (CDA)", "fy25_current": 1977474000, "fy25_request": 2082777000, "fy25_cong_amt": -105303000, "fy25_cong_pct": -5.06}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 857, 872, FALSE, $${"json_key": "SOCOM__CDAct"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 2589383000, NULL, NULL, NULL, $$O&M/FY27/DW/Vol1_Part1/SOCOM_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_socom_cyberact$$, $$CyberAct$$, $$Cyberspace Activities$$, $$SOCOM$$, $$om_dw_ba01$$, NULL, $$dw_socom$$, 2026, 49689000, 51263000, -614000, -1.2, 50649000, 77241000, $$Cyberspace Activities - Includes cyber resources associated with computer network defense and information assurance, service contracts specifically intended to secure, defend, and preserve data, networks, net-centric capabilities, and other designated systems by ensuring security controls and measures are in place, and taking internal defense actions on the SOF Information Environment (SIE). This includes access to system controls, monitoring, administration, and integration of cybersecurity into all aspects of engineering and acquisition of cyberspace capabilities. In addition, these activities include implementation, evaluation, and disposal of information technology and services, as well as information resources management, and the management, storage, transmission, and display of data and information. The FY 2026 request for 1PLS - Cyberspace Activities includes $77,241 thousand of discretionary and $0 thousand of mandatory (reconciliation) for a total of $77,241 thousand. CyberAct 870$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 49689000, "fy26": 77241000, "name": "Cyberspace Activities", "fy25_current": 50649000, "fy25_request": 51263000, "fy25_cong_amt": -614000, "fy25_cong_pct": -1.2}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 873, 886, FALSE, $${"json_key": "SOCOM__CyberAct"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 78512000, NULL, NULL, NULL, $$O&M/FY27/DW/Vol1_Part1/SOCOM_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_socom_int$$, $$Int$$, $$Intelligence$$, $$SOCOM$$, $$om_dw_ba01$$, NULL, $$dw_classified$$, 2026, 1420388000, 1266217000, -15634000, -1.23, 1250583000, 1187600000, $$Intelligence - Includes all USSOCOM HQs and/or component funding to sustain USSOCOM equipment, systems, logistics, and maintenance required to perform/sustain USSOCOM's MIP. These programs support the Secretary of Defense's intelligence, counterintelligence, and related intelligence responsibilities. The USSOCOM MIP programs, projects, and activities provide capabilities to meet SOF operational and tactical requirements more effectively. These include ISR systems and sustainment; PED capabilities; tactical intelligence collection and analysis devices/systems/databases; and classified programs and activities. The FY 2026 request for 1PLU – Intelligence includes $1,187,600 thousand of discretionary and $0 thousand of mandatory (reconciliation) for a total of $1,187,600 thousand. Int 884$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 1420388000, "fy26": 1187600000, "name": "Intelligence", "fy25_current": 1250583000, "fy25_request": 1266217000, "fy25_cong_amt": -15634000, "fy25_cong_pct": -1.23}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 887, 909, FALSE, $${"json_key": "SOCOM__Int"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 1130849000, NULL, NULL, NULL, $$O&M/FY27/DW/Vol1_Part1/SOCOM_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_socom_maint$$, $$Maint$$, $$Maintenance$$, $$SOCOM$$, $$om_dw_ba01$$, NULL, $$dw_socom$$, 2026, 1250964000, 1197289000, 27203000, 2.27, 1224492000, 1273409000, $$Maintenance - Includes maintenance (to include installation of modification and conversion kits), CLS, and FSRs of weapons support systems and commodity groups associated with SOF activities. This also includes USSOCOM funds for reimbursement of Service industrial funds for depot maintenance of SOF-peculiar aircrafts, maritime craft, and equipment. Includes reimbursement for maintenance activities at industrial funded naval shipyards and costs associated with non-industrial funded maintenance activities at Navy repair facilities. The FY 2026 request for 1PL7 - Maintenance includes $1,273,409 thousand of discretionary and $55,210 thousand of mandatory (reconciliation) for a total of $1,328,619 thousand. The mandatory funds enhance USSOCOM mission readiness. Further information for this reconciliation request is provided in Section 20010 (Readiness) of the Reconciliation Exhibit. Maint 907$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 1250964000, "fy26": 1273409000, "name": "Maintenance", "fy25_current": 1224492000, "fy25_request": 1197289000, "fy25_cong_amt": 27203000, "fy25_cong_pct": 2.27}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 910, 934, FALSE, $${"json_key": "SOCOM__Maint"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 1388865000, NULL, NULL, NULL, $$O&M/FY27/DW/Vol1_Part1/SOCOM_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_socom_mngmthq$$, $$MngmtHQ$$, $$Management/Operational Hqtrs$$, $$SOCOM$$, $$om_dw_ba01$$, NULL, $$dw_socom$$, 2026, 195061000, 203622000, -13736000, -6.75, 189886000, 181122000, $$Management/Operational Headquarters - Includes manpower authorizations, SOF-peculiar and support equipment, necessary facilities and associated costs specifically identified and attributable to the USASOC, AFSOC, NSWC, and MARSOC Component Command HQs, as well as the USSOCOM HQs and its management support activities. Also includes costs associated with the expenditure of funds in support of officially sanctioned activities used to maintain the standing and prestige of the United States by extending official courtesies to guests who promote the goals of the Commander, USSOCOM and the DoD. The FY 2026 request for 1PLM – Management/Operational Headquarters includes $181,122 thousand of discretionary and $0 thousand of mandatory (reconciliation) for a total of $181,122 thousand. MngmtHQ 932$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 195061000, "fy26": 181122000, "name": "Management/Operational Headquarters", "fy25_current": 189886000, "fy25_request": 203622000, "fy25_cong_amt": -13736000, "fy25_cong_pct": -6.75}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 935, 950, FALSE, $${"json_key": "SOCOM__MngmtHQ"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 180691000, NULL, NULL, NULL, $$O&M/FY27/DW/Vol1_Part1/SOCOM_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_socom_operational-support$$, $$Operational Support$$, $$Operational Support$$, $$SOCOM$$, $$om_dw_ba01$$, NULL, $$dw_dote$$, 2026, 1496239000, 1453809000, -18142000, -1.25, 1435667000, 1579137000, $$Operational Support – Funds SOF-peculiar support resources for communications, MILCON collateral equipment, FSRM projects, unit sustainment support, and acquisition program management. Funding provides civilian manpower authorizations, general contractor support, equipment sustainment, travel, and associated management costs. Communication capabilities support SOF IT enterprise-wide services, SOF worldwide command and control systems, deployable communications, airtime, circuits, and bandwidth. Facility projects include SOF enterprise- wide FSRM activities, and communication infrastructure. Acquisition program management includes sustainment, fielding, engineering, logistical, and operational test and evaluation support for SOF acquisition programs. The FY 2026 request for 1PLV – Operational Support includes $1,579,137 thousand of discretionary and $175,803 thousand of mandatory (reconciliation) for a total of $1,754,940. The mandatory funds enhance USSOCOM mission readiness. Further information for this reconciliation request is provided in Section 20010 (Readiness) of the Reconciliation Exhibit. Operational Support 948$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 1496239000, "fy26": 1579137000, "name": "Operational Support", "fy25_current": 1435667000, "fy25_request": 1453809000, "fy25_cong_amt": -18142000, "fy25_cong_pct": -1.25}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 951, 979, FALSE, $${"json_key": "SOCOM__Operational_Support", "fy27_v192_bucket_a_dw": {"session": "2026-05-09_v41", "source_pdf": "O&M/FY27/DW/Vol1_Part1/SOCOM_OP-5.pdf", "content_hash": "5c32f3a832e5fe05f3f08cc86970ca50ea41c19baebe09e019093b53154511e9", "source_page_amount": 104, "source_page_description": 103}}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 1796851000, NULL, NULL, NULL, $$O&M/FY27/FY2027_o1.txt$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_socom_prodev$$, $$ProDev$$, $$Professional Development Education$$, $$SOCOM$$, $$om_dw_ba03$$, NULL, $$dw_socom$$, 2026, 33816000, 31806000, -354000, -1.11, 31452000, 28697000, $$$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 33816000, "fy26": 28697000, "name": "Professional Development Education", "fy25_current": 31452000, "fy25_request": 31806000, "fy25_cong_amt": -354000, "fy25_cong_pct": -1.11}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 1015, 1028, FALSE, $${"json_key": "SOCOM__ProDev"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 30040000, NULL, NULL, NULL, $$O&M/FY27/DW/Vol1_Part1/SOCOM_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_socom_theater-forces$$, $$Theater Forces$$, $$Theater Forces$$, $$SOCOM$$, $$om_dw_ba01$$, NULL, $$socom_jsoc$$, 2026, 3402253000, 3410271000, -53222000, -1.56, 3357049000, 3409285000, $$Theater Forces - Provides for the USAJFKSWCS, the U.S. Army Special Warfare Center Medical Training Facility, the NSWCEN, the MSOS, the SOAWC, and the SOF Language Office. The schools provide recruitment and training in both basic and advanced SOF skills and operations and educate American and Allied personnel in geopolitical and military aspects of joint special operations. Funding also provides SOF language training to produce language proficient personnel. Supports Naval Special Warfare Groups; Special Boat Teams; SEAL Delivery Vehicle Teams; and other maritime operations. Includes Active and Reserve Navy manpower authorizations, SOF-peculiar and support equipment, necessary facilities, and associated costs specifically identified to combatant and support craft assigned to the NSWC. Includes manpower authorizations, SOF-peculiar and support equipment, necessary SOF-peculiar facilities and other operational costs specifically associated with: SOF Active Army Rangers; Active and National Guard Army special forces activities; Active Army MISO units; Active and Reserve Army civil affairs units; Naval Special Warfare groups, units, teams, and detachments; Marine Corps special operations units and teams; Active and Reserve SOF units and detachments; 24th SOW; Air Force 720th and 724th STGs; STSs; combat control squadrons; and SOF pararescue forces. Also included is support for the TSOCs. H/CA activities are carried out in conjunction with authorized military operations, subject to approval by the Secretary of State and Secretary of Defense. These activities promote security and foreign policy interests of the U.S. and the host nation and allow SOF to demonstrate commitment to priority partners supporting contingencies; H/CA activities are a function of Title 10, U.S. Code, section 401. Provides for the conduct of, or participation in, strategic mobility, Commander-In-Chief directed, and Joint Chiefs of Staff exercises participation by SOF and force related training through JCET events sponsored by the Commander, USSOCOM in support of regional Theater Commanders and the military Services. Includes USSOCOM HQs and/or Component manpower authorizations, SOF-peculiar and support equipment, necessary facilities, and the associated costs specifically identified and measurable to the conduct of SOF-related training. Theater Forces 977 Supports 5 active SOWs to include the 1st SOW, Hurlburt Field, FL; 492nd SOW Hurlburt Field, FL; 352nd SOW, RAF Mildenhall, UK; 27th SOW, Cannon AFB, NM; 58th SOW, Kirtland AFB, NM; and the 353rd SOG, Kadena AB Japan and their associated squadrons. Costs are also included for: 919th Special Operations Reserve Wing located at Duke Field, FL; 193rd Special Operations Air National Guard Wing, Harrisburg, PA; 137th Air National Guard Wing, Oklahoma City, OK; USASOAC; 160th SOAR, Ft Campbell, KY, Hunter Army Airfield, GA, and Ft Lewis, WA. Funding supports flying hours, SOF-peculiar and support equipment, initial qualification, and recurring training of aircrews in SOF aircraft operations and tactics. Costs specifically identified and attributable to SOF active tactical aviation operational units, organizations and special operation wings and squadrons are also included. The FY 2026 request for 1PLR – Theater Forces includes $3,409,285 thousand of discretionary and $58,955 thousand of mandatory (reconciliation) for a total of $3,468,240 thousand. The mandatory funds enhance USSOCOM mission readiness. Further information for this reconciliation request is provided in Section 20010 (Readiness) of the Reconciliation Exhibit. Theater Forces 978$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 3402253000, "fy26": 3409285000, "name": "Theater Forces", "fy25_current": 3357049000, "fy25_request": 3410271000, "fy25_cong_amt": -53222000, "fy25_cong_pct": -1.56}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 980, 1014, FALSE, $${"json_key": "SOCOM__Theater_Forces", "fy27_v192_bucket_a_dw": {"session": "2026-05-09_v41", "source_pdf": "O&M/FY27/DW/Vol1_Part1/SOCOM_OP-5.pdf", "content_hash": "d776ddf4918c3b3148da437466e892c6431d34d9c278ae66e622df08b1ca6628", "source_page_amount": 137, "source_page_description": 135}}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 3695859000, NULL, NULL, NULL, $$O&M/FY27/FY2027_o1.txt$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_socom_umbrella$$, $$SOCOM$$, $$United States Special Operations Command$$, $$SOCOM$$, $$om_dw_ba01$$, $$BA-01: Operating Forces - The units and/or functions associated with these Sub-Activity$$, $$dw_socom$$, 2026, 10124284000, 9697054000, -179802000, -1.85, 9517252000, 9872656000, $$The United States Special Operations Command (USSOCOM) develops and employs the world's finest Special Operations Forces (SOF) to conduct global special operations and activities as part of the Joint Force, in concert with the U.S. Government Interagency, Allies, and Partners, to support persistent, networked, and distributed combatant command operations and campaigns against state and non-state actors all to protect and advance U.S. policies and objectives. In support of this mission, the USSOCOM serves as the Coordinating Authority for Countering Violent Extremist Organizations (C-VEO), Countering Weapons of Mass Destruction (CWMD), and internet-based Military Information Support Operations (MISO). The budget request reflects the Secretary of Defense focus on restoring the warrior ethos, rebuilding military capabilities, and enhancing national deterrence while simultaneously balancing readiness to create a strategic, asymmetric advantage for the nation by strengthening our force and their families, bolstering integrated deterrence capabilities, and ensuring our enduring advantage through innovation and modernization. •    Budget Activity 01 (BA-01)/Operating Forces - The units and/or functions associated with these Sub-Activity Groups (SAG) are: • 1PL6 - Combat Development Activities - Includes Joint and Component manpower authorizations, SOF-peculiar equipment, necessary facilities, and the associated costs specifically identified and attributable to the development of combat doctrine, organizational concepts, materiel requirements, and other developmental activities related to SOF. Also includes activities to support experimentation, tests, and project evaluations necessary to develop and/or validate new doctrine and organizations for special operations. SOCOM 840 • 1PLS - Cyberspace Activities - Includes cyber resources associated with computer network defense and information assurance, service contracts specifically intended to secure, defend, and preserve data, networks, net-centric capabilities, and other designated systems by ensuring security controls and measures are in place, and taking internal defense actions on the SOF Information Environment (SIE). This includes access to system controls, monitoring, administration, and integration of cybersecurity into all aspects of engineering and acquisition of cyberspace capabilities. In addition, these activities include implementation, evaluation, and disposal of information technology and services, as well as information resources management, and the management, storage, transmission, and display of data and information. • 1PLU - Intelligence - Includes all USSOCOM Headquarters (HQs) and/or Component funding to sustain USSOCOM equipment, systems, logistics, and maintenance required to perform/sustain USSOCOM Military Intelligence Programs (MIP). These programs support the Secretary of Defense's intelligence, counterintelligence, and related intelligence responsibilities. The USSOCOM MIP programs, projects, and activities provide capabilities to meet SOF warfighter operational and tactical requirements more effectively. These include intelligence, surveillance, and reconnaissance (ISR) systems and sustainment; processing, exploitation, and dissemination (PED) capabilities; tactical intelligence collection and analysis devices/systems/databases; and classified programs and activities. • 1PL7 - Maintenance - Includes maintenance (to include installation of modification and conversion kits), contractor logistics support (CLS), and field service representatives (FSR) of weapons support systems and commodity groups associated with SOF activities. This also includes USSOCOM funds for reimbursement of Service industrial funds for depot maintenance of SOF-unique aircraft, maritime craft, and equipment. Includes reimbursement for maintenance activities at industrial funded naval shipyards and costs associated with non-industrial funded maintenance activities at Navy repair facilities. • 1PLM - Management/Operational Headquarters - Includes manpower authorizations, SOF-peculiar and support equipment, necessary facilities and associated costs specifically identified and attributable to the U.S. Army Special Operations Command (USASOC), Air Force Special Operations Command (AFSOC), Naval Special Warfare Command (NSWC), and Marine Forces Special Operations Command (MARSOC) Component Command HQs, as well as the USSOCOM HQs and its management support activities. • 1PLV - Operational Support - Includes SOF-peculiar support resources for communications, military construction (MILCON) collateral equipment, facility restoration and modernization projects, unit sustainment support, and acquisition program management. Funding provides civilian manpower authorizations, general contractor support, equipment sustainment, travel, and associated management costs. Communication capabilities support SOF Information Technology (IT) enterprise-wide services, SOF worldwide command and control systems, deployable communications, airtime, circuits, and bandwidth. Facility projects include SOF enterprise-wide Facility Sustainment, Restoration and Modernization (FSRM) activities and communications infrastructure. Acquisition program management includes sustainment, fielding, engineering, logistical, and operational test and evaluation support for SOF acquisition programs. SOCOM 841 • 1PLR - Theater Forces - Provides for the U.S. Army John F. Kennedy Special Warfare Center and School (USAJFKSWCS), the U.S. Army Special Warfare Center Medical Training Facility, the Naval Special Warfare Center (NSWCEN), the Marine Special Operations School (MSOS), the U.S. Air Force Special Operations Air Warfare Center (SOAWC), and the SOF Language Office. The schools provide recruitment and training in both basic and advanced special operations skills and operations and educate American and Allied personnel in geopolitical and military aspects of joint special operations. Funding also provides SOF language training which produces language proficient personnel. Supports Naval Special Warfare Groups, Special Boat Teams, Sea, Air, and Land (SEAL) Delivery Vehicle Teams, and other maritime operations. Includes Active and Reserve Navy manpower authorizations, SO-Peculiar and support equipment, necessary facilities, and associated costs specifically identified to combatant and support craft assigned to Naval Special Warfare Command (NSWC). Includes manpower authorizations, SOF-peculiar and support equipment, necessary SOF-unique facilities and other operational costs specifically associated with: SOF Active Army Rangers; Active and National Guard Army Special Forces activities; Active Army MISO units; Active and Reserve Army civil affairs units; Naval Special Warfare groups, units, teams, and detachments; Marine Corps forces special operations units and teams; Active and Reserve SOF units and detachments, 24th Special Operations Wing (SOW), Air Force 720th and 724th Special Tactics Group (STG), Special Tactics Squadrons (STS), Combat Control Squadrons, and SOF pararescue forces. Also included in this SAG is support for the Theater Special Operations Commands (TSOC). Humanitarian/Civic Assistance (H/CA) activities are carried out in conjunction with authorized military operations, which are subject to approval by the Secretary of State and Secretary of Defense. These activities promote security and foreign policy interests of the U.S. and the host nation and allows SOF to demonstrate commitment to priority partners supporting contingencies. The H/CA activities are a function of Title 10, United States Code, Section 401. Provides for the conduct of, or participation in, strategic mobility, Commander-In-Chief-directed, and Joint Chiefs of Staff exercises participation by SOF and force related training through Joint Combined Exchange Training (JCET) events sponsored by the Commander, USSOCOM in support of regional Theater Commanders and the military Services. Includes USSOCOM HQs and/or Component manpower authorizations, SOF-peculiar and support equipment, necessary facilities, and the associated costs specifically identified and attributable to the conduct of SOF-related training. SOCOM 842 Costs specifically identified and attributable to SOF active tactical aviation operational units, organizations, and SOWs and squadrons are also included in this SAG. Supports 5 active SOWs to include the 1st SOW, Hurlburt Field, FL; 492nd SOW Hurlburt Field, FL; 352nd SOW, RAF Mildenhall, UK; 27th SOW, Cannon AFB, NM; 58th SOW, Kirtland AFB, NM, and 1 Special Operations Group (SOG), the 353rd SOG, Kadena AB, Japan and their associated squadrons. Costs are also included for: the 919th Special Operations Reserve Wing located at Duke Field, FL; the 193rd Special Operations Air National Guard Wing, Harrisburg, PA; 137th Air National Guard Wing, Oklahoma City, OK; U.S. Army Special Operations Aviation Command (USASOAC); 160th Special Operations Aviation Regiment (SOAR) at Ft Campbell, KY, Hunter Army Airfield, GA, and Ft Lewis, WA. Funding supports flying hours, SOF-peculiar and support equipment, initial qualification, and recurring training of aircrews in SOF aircraft operations and tactics. •   Budget Activity 03 (BA-03)/Training and Recruiting - The units and/or functions associated with this SAG are: A. 3EV8 - Professional Development Education - Includes the Joint Special Operations University (JSOU) at MacDill Air Force Base, FL, the U.S. Air Force Special Operations School (USAFSOS) at Hurlburt Field, FL, and the Naval Special Warfare Leadership Education and Development (NLEAD) Command at San Diego, CA. The JSOU is an institution of higher learning consisting of teaching and research facilities focused on producing Joint Special Operations strategic and operational analysis and education. As a Joint Special Operations Center of Excellence, JSOU is dedicated to building and maintaining a consortium of Joint special operations specialized learning activities focused on professional development of SOF leaders as well as non-SOF decision makers at the intermediate and senior levels. The USAFSOS offers education in irregular warfare, regional studies and cultural awareness, SOF professional development to educate Air Commandos, the special operations community, services, and other U.S. Government agencies. The NLEAD Command provides SOF education and leadership growth for platoon leaders, lead petty officers, career counselors, and command leaders. SOCOM 843$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 10090468000, "fy26": 9843959000, "name": "1. BA01: Operating Forces", "fy25_current": 9485800000, "fy25_request": 9665248000, "fy25_cong_amt": -179448000, "fy25_cong_pct": -1.86}$$::jsonb, $${"fy24": 2275874000, "fy26": 2136165000, "name": "Combat Development Activities (CDA)", "fy25_current": 1977474000, "fy25_request": 2082777000, "fy25_cong_amt": -105303000, "fy25_cong_pct": -5.06}$$::jsonb, $${"fy24": 49689000, "fy26": 77241000, "name": "Cyberspace Activities", "fy25_current": 50649000, "fy25_request": 51263000, "fy25_cong