INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_tjs_cyber$$, $$TJS - Cyber$$, $$The Joint Staff Cyber$$, $$TJS$$, $$om_dw_ba01$$, NULL, $$dw_js$$, 2026, 8195000, 9100000, -109000, -1.2, 8991000, 9086000, $$The Joint Staff Cyber program provides cybersecurity program support and capabilities to the Joint Staff Chief Information Office and the Joint Staff environments. It also provides oversight and management of the evaluation and mitigation process for identified cybersecurity vulnerabilities. Activities include implementation of the Risk Management Framework for the assessment, authorization, and continuous monitoring of Joint Staff mission networks and major applications; developing component/business unit-level cybersecurity processes and procedures; compliance oversight and reporting (DoD CIO Scorecard and Federal Information Security Modernization Act); cybersecurity workforce management tracking and reporting; system administration of the Joint instances of the Enterprise Mission Assurance Support Service (eMASS) for Joint Staff (internal) and Combatant Command use. Cyber and C2 Operational Development Division (C3OD2) is a capability provider within the DoD Enterprise Cyber Range Environment (DECRE), which also includes the National Cyber Range (NCR) and Joint Mission Environment Test Capability’s (JMETC) Multiple Independent Layers of Security (MILS) Network (JMN) Regional Service Delivery Points (RSDP). C3OD2 provides assessment planning and execution expertise to support cyber project objectives that may include testing, training, or exercise support. C3OD2 provides a variety of commonly deployed joint C2 systems, including Global Command and Control System-Joint (GCCS-J), Joint Advanced Deep Operations Coordination System (JADOCS), and Joint Range Extension (JRE), and others as required by project. C30D2 provides the environment required to drive C2 system operation, and the system operators required to generate a realistic exchange of system data or to assess the cyber impacts on system functionality. C3OD2’s cyber projects include a range of activities from assessment of cyber impacts on individual C2 systems, to mission rehearsal for real world scenarios, training of cyber mission teams, to providing system and facility support to large cyber exercises such as those sponsored by USCYBERCOM. 1. Core Management Headquarters ($9,086 thousand): Provides general support of the Joint Staff in the following key area: 1.1 Joint Staff CIO Directorate: Assists the CJCS in providing military advice while advancing cyber defense, Joint and Coalition interoperability, and C2 systems capabilities required by the Joint Force to preserve the nation’s security. The Joint Staff CIO also provides management and oversight of processes that support and enable Joint Staff mission networks. TJS - Cyber 2$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 8195000, "fy26": 9086000, "name": "Cyber Activities", "fy25_current": 8991000, "fy25_request": 9100000, "fy25_cong_amt": -109000, "fy25_cong_pct": -1.2}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/TJS_OP-5.pdf$$, 54, 64, FALSE, $${"json_key": "TJS__TJS - Cyber"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 9103000, NULL, NULL, NULL, $$O&M/FY27/DW/Vol1_Part1/TJS_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_tjs_jiatf$$, $$JIATF$$, $$Joint Chiefs of Staff - JIATF$$, $$TJS$$, $$om_dw_ba04$$, NULL, $$dw_js$$, 2026, 0, 0, 0, NULL, 0, 11500000, NULL, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/FY2027_o1.txt$$, NULL, NULL, FALSE, $${"line": "0100D 430 8PL3", "source": "o1_fy27", "json_key": "TJS__JIATF", "fy27_v192_bucket_a_dw": {"session": "2026-05-09_v41", "source_pdf": "O&M/FY27/DW/Vol1_Part1/TJS_OP-5.pdf", "content_hash": "0eff94565691ed377bf46cae93b88c099319777d171176a2d1601f74f651d420", "source_page_amount": 83, "source_page_description": 83}, "fy26_v192_transitional_synth": {"session": "2026-05-09_v41", "source_pdf": "O&M/FY27/DW/Vol1_Part1/TJS_OP-5.pdf", "synth_type": "transitional_synth", "content_hash": "aa9fcb2d436ce8808538ea3e7a7881c88f5ffc2ba6450bffde9c27be841ac405"}}$$::jsonb, $$2026-05-08T14:27:45.454489+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 431652000, NULL, NULL, NULL, $$O&M/FY27/FY2027_o1.txt$$, 0) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_tjs_jteep$$, $$JTEEP$$, $$Joint Training Exercise Evaluation Program$$, $$TJS$$, $$om_dw_ba01$$, NULL, $$dw$$, 2026, 682598000, 696446000, -26938000, -3.87, 669508000, 1026502000, $$The FY 2026 budget requests $1,026.502 thousand to support the exercise and engagement requirements of the eleven Combatant Commands (CCMD), increase joint context in Service exercises, train individuals in key joint skills, and provide joint training enablers to the CCMDs and Services. In addition, FY 2026 supports an annual Large Scale Global Exercise/ ELITE CONSTELLATION (LSGE/EC) that will stress global integration of the force across multiple levels of command and control in the conduct of Joint All Domain Operations. The increased funding enhances joint exercises within INDOPACOM and select CCMDs to execute ELITE CONSTELLATION (EC), a campaign of exercise and training events that collectively prepare the Joint Force for a transregional, multi-functional and multi-domain conflict against a near-peer adversary. ELITE CONSTELLATION is a multi-year campaign that provides a framework for the Joint Force to conduct globally integrated, multi-domain operations to strengthen warfighting readiness and lethality, enabling the Joint Force to adapt to the changing character of war and deter or defeat global threats. ELITE CONSTELLATION operationalizes the Joint Warfighting Concept (JWC) through integrated events across the DoD and with mission partners; priorities are to: • Increase globally integrated readiness and lethality. • Refine and implement the JWC through the EC campaign. • Adapt Joint Force readiness to the changing global operating environment across all domains. • Enable Joint Force to address global threats while defending the homeland. • Exercise options for rapid decision making in global conflict. • Identify solutions for rapid mobilization and deployment of forces. • Expand integration and interoperability among the interagency and Allies & Partners The Secretary of Defense priorities drive the alignment of JTEEP resources to enable and prepare the military to Defend the Homeland, Revive Warrior Ethos and Reestablish Deterrence – in support of Peace through Strength. The Secretary provided guidance to make this exercise a priority event in the Department to prepare the force to execute global campaign plans against peer adversaries and achieve Interim National Defense Strategic Guidance objectives. These JTEEP- funded events improve the readiness of the force to conduct joint operations, highlight U.S. capabilities, deter potential adversaries, build partner capacity, and operationalize the Secretary of Defense-approved JWC. In addition, the Secretary of Defense has directed JTEEP to support consolidating some of the eleven CCMD exercises to prepare the force. The CCMD exercise and engagement events are key DoD levers for strategic competition in preparation for warfighting and day-to-day competition. This funding JTEEP 2 enables over 105 major exercises annually that prepare U.S. forces to execute operational plans, train the combatant command staffs in demanding and realistic environments, provide presence and regional expertise for U.S. allies and partners, and build relationships and trust. Joint Training Exercise Evaluation Program (JTEEP) Program Summary ($1,026,502 thousand): Funds exercise and training capabilities supporting CCMD exercise programs, theater security cooperation, and Global Campaign Plan objectives; joint context in Service training venues; joint training enablers; and development of a more adaptive joint force. The JTEEP enables joint force readiness, future force development and design, strategic messaging and posture (deterrence and assurance), inter-agency integration, multi-national interoperability and strengthening relationships with our allies and partners. The JTEEP funding is the key resource used for the joint training requirements of the DoD, including exercises for eleven CCMDs and training that prepares the Services to operate as part of a joint force. These training events and exercises are key to improving mission-essential task-based readiness levels and supporting the threat-based global campaign plans. The priority use of these funds is for the readiness of U.S. forces and the CCMD staffs to execute missions assigned to them by national command authorities. Aside from Title 22 Security Assistance programs, JTEEP provides most Combatant Commanders’ funds for military-to-military engagement. Because of their international political impact, Combatant Commanders’ exercises are tools of national power, and the exercises directly advance the Interim National Defense Strategic Guidance. In addition to their primary purpose of training U.S. forces, the Combatant Commanders’ exercises have corollary effects that assist in strengthening alliances, shaping the geopolitical environment, as well as providing a realistic environment for the validation of joint concepts and capabilities to enable rapid innovation of joint force development and design. For Service joint training, the JTEEP program supports the participation of multiple Service units/capabilities in Service training venues; for example, Air Force participation in the Army’s pre-deployment exercises at the National Training Center. The JTEEP also provides training enablers for realistic and robust combat training with interagency participation in Service events, realistic opposing forces, feedback and lessons learned, and development of a more adaptive joint force. The JTEEP non-MHA funding is further subdivided into eleven major sub-programs as follows: 1 Joint Exercise Transportation Program (JETP): Funds transportation of personnel and equipment to worldwide joint exercises. This tactical, operational, and strategic lift capability enables Combatant Commanders to train battle staffs and participating forces in joint and combined operations, evaluate contingency and operations plans, and execute theater engagement. The program also provides an opportunity to stress strategic transportation systems as well as command and control and intelligence, surveillance, reconnaissance systems to evaluate their readiness across the range of military operations. JTEEP 3 2 Service Incremental Funding (SIF): These are funds provided for Service participation in CCMD Exercise and engagement events. Through a collaborative planning process, CCMDs identify forces required for an exercise. SIF is then provided to pay for the additional costs that the Services would otherwise absorb. This allows CCMDs to achieve Theater Campaign Plan objectives without detrimental impact on Service training budgets. The SIF is essential to the realistic conduct of field training exercises, which include forces in all domains, rather than exercises merely for the headquarters. 3 Joint Staff Support to Combatant Command Exercises: Each year, Combatant Commanders conduct exercises and engagement events. Linked multi-CCMD events informed by the Joint Staff, OSD, and interagency participation advances globally integrated operations to address the Nation’s priority strategic challenges as an ELITE CONSTELLATION (EC) component. To maximize the effectiveness of these events, the Joint Staff prioritizes support to the CCMDs in accordance with the Interim National Defense Strategic Guidance. Joint Staff leads the design, planning and execution of EC and provides functional and technical support to each CCMD and associated components during the planning and execution of their CCMD Training and Exercises. The support is essential to battle staff coordination, decision processes, and rehearsal of key UCP mission areas. The JS J7 enabling support includes scenario development; observer/trainers; exercise management; and subject matter expertise in Interagency, Information Operations, Cyber Operations, Intelligence, Communications Synchronization, Sustainment and other warfighting functional areas. The program is an enterprise model that eliminates the need for redundant capabilities across each CCMD and optimizes best practice and insight across the Joint Staff. The Joint Staff provides this support to subordinate unified commands and to select Executive Branch organizations during the biennial National Level Exercise. 4 Combatant Command Training and Exercises: The CCMDs are resourced to conduct annual training, exercises, transformation, and engagement events to maximize readiness for assigned missions. This includes small-scale events through major command and national-level or globally integrated exercises. The program supports developing, evaluating, and integrating a single, high-quality training environment. In addition to serving as the operating budget for CCMDs, this program ensures the readiness of CCMD and component staff to execute key operational plans supporting the Interim National Defense Strategic Guidance. Increased funding for INDOPACOM enhances joint exercises that enable joint force readiness, deterrence (via strategic messaging and posture), future force development and design, inter-agency integration, multinational interoperability, and strengthening relationships with our allies and partners. Increased United States Southern Command (USSOUTHCOM) funding will enhance its ability to plan and execute field training exercises in Panama and the Southern Cone of South America. These exercises are crucial for several reasons: •   Multinational Training Opportunities: They provide a platform for the US and its partner nations to train, improving interoperability and coordination among their military forces. •   Demonstrating Commitment: These exercises serve as a visible demonstration of the U.S. and its partners’ commitment to maintaining security and stability in the region. This is particularly important for ensuring free and unfettered access to key sea lanes of communication, which are vital for global trade and economic stability. •   Strengthening Partnerships: By engaging in joint exercises, the US can strengthen its relationships with partner nations in the region, fostering greater trust and cooperation. JTEEP 4 •   Enhancing Regional Security: These exercises help to enhance the region’s overall security by preparing forces to respond to various potential threats, from natural disasters to security challenges. Overall, the increased funding will enable USSOUTHCOM to play a more active and effective role in promoting regional stability and security through these critical training exercises. 5 Joint National Training Capability (JNTC): JNTC provides the technical standards, architecture, and development processes required to integrate/link joint training programs across the enterprise. Funding supports the technical integration and interoperability of Joint and Service models and simulations with an integrating architecture of Joint, Live, Virtual, Constructive (JLVC) training capabilities. At scale, the capabilities enable distributed training and exercise for training audiences at the Combatant Command, Joint Task Force, Component Command headquarters, and Service joint tactical levels. The funding also supports the modernization of the Joint Training Environment (JTE) through a Modular Open Systems Architecture (MOSA) approach, including a cloud-enabled, web-accessible Joint Training Platform (JTP) and Joint Training Tool (JTT) that support all phases of an exercise (planning, execution, and AAR). JTP and JTT represent a digital transformation that increases warfighter access to digital and AI- enabled training enablers within the Joint Training Synthetic Environment (JTSE). This funding will also support the transition to and operation of advanced JLVC capabilities, such as a fully informed simulation environment and non-kinetic effects tools, delivered through JLVC modernization. Through the centralized maintenance and operation of joint exercise control, simulations, C4, and 40 persistent networked training sites, JNTC enables a Joint, Interagency, Intergovernmental, and Coalition context for the benefit of the entire training enterprise. This DoD enterprise-level capability realizes cost efficiency for the Department by reducing redundant systems, integrating CCMD/S/CSA networks and systems, and maximizing integrated training across the Services and Combatant Commands. This capability directly supports the ELITE CONSTELLATION campaign and the JTEEP program’s published goals and objectives (Goal 5) to improve the joint training infrastructure and management, enhancing the joint training environment. Through a network of subject matter experts, JNTC provides a vital link between joint training activities and ongoing operations. This linkage is crucial for institutionalizing lessons learned and lessons anticipated at the speed of need with the changing character of war. JNTC also funds improvements to infrastructure that increase training realism, including enhancements to threat replication, opposition forces, and range infrastructure. These efforts are essential for training the Joint Warfighting Concept (JWC) and the associated concept-related capabilities that must be exercised at the Service and joint levels. Additionally, this service joint training is foundational to effectively executing extensive global exercises like ELITE CONSTELLATION. In support of JTEEP, JNTC conducts technology modernization efforts to mitigate joint training gaps, including leveraging new cloud environment CJADC2 tools, Artificial Intelligence (Generative AI), and other technologies to deliver the directed training enhancements. Overall, JNTC increases training effectiveness while mitigating gaps and seams between Service-centric training programs. 6 Joint Training Coordination Program (JTCP): Enables the Services and U.S. Special Operations Command to participate in the exercises of the other Services. Through such participation, U.S. forces develop the skills and cross-Service familiarity necessary to operate in a joint environment. The JTCP facilitates the integration of special operations and conventional forces and provides cross-Service participation in pre- deployment exercises at Army’s Combat Training Centers, USAF’s Green and Red Flag at Nellis Air Force Base, the Marine Air Ground Task JTEEP 5 Force Training Command at Twenty-Nine Palms, and the Navy’s Fleet Training Program at multiple locations, improving pre-deployment training for warfighters who will be on the front lines. 7 Joint Knowledge Online (JKO): Adaptable 24/7 distributed learning training platform on both classified and unclassified networks, scalable to meet current and emerging individual and staff training needs of CCMD, Combat Support Agency (CSA), Service, multinational, coalition, and Interagency organizations. The JKO advances cost-effective training enablers to support frequent, small-facilitated events with training tools that support responsive, just-in-time staff training opportunities and enable perpetual refresher training. The JKO training content, videos, courses, virtual classroom, and scenario simulations address fundamental training requirements of the Joint Staff, Joint Task Forces, CCMDs, CSAs, and supporting organizations across the DoD. 8 Joint Training Information Management System (JTIMS) sunset: JTIMS capability has transitioned into the cloud-based, web-enabled Joint Training Tool (JTT) within the JNTC at the end of FY 2025, leveraging the JTT’s modern architecture and modular, data-centric approach to development. JTIMS functionality modernized in the JTT supports CJCS Title 10 responsibilities/requirements, CCMDs, Services, CSAs, National Guard, and OSD joint training responsibilities by providing a set of integrated information management capabilities necessary to identify, collect, analyze, develop, store, and disseminate the data required to implement the four phases of the Joint Training System. The JTT integrates with readiness, force sourcing, planning, training, and assessment systems, including Defense Readiness Reporting Systems – Strategic, Joint Capabilities Requirements Manager, Universal Joint Task List Development Tool, and Joint Lessons Learned Information System. 9 Joint Interoperability & Data Link Training Center (JID-TC): Provides tactical data link (TDL) training and operational support for Joint and Coalition forces through courses offered online, in-residence, and via mobile training teams. As the DoD's sole source of qualified Joint Interface Control Officers (JICO), as well as maintaining coordination of the training of Joint Data Network Operations Officers (JDNO), the Training Center ensures the timeliness and accuracy of information used by operational commanders at all levels to make warfighting decisions. This directly reduces the risk of fratricide and improves operational effects. In 1999, the Office of the Secretary of Defense outlined the requirements for a single joint officer (the JICO) and a cell of tactical data link experts to plan, execute, and manage the multi-TDL architecture for the Joint Task Force or CCMD. In 2001, OSD and the Joint Requirements Oversight Council determined that no single service can mitigate interoperability gaps alone and directed the JID-TC to be the sole DoD provider of joint interoperability training and JICO production. Additionally, the JID-TC was tasked through CJCSI 3151.01D with coordinating the training for the Joint Data Network Operations Officers. 10 Joint Targeting School: Provides formal operational-level joint targeting instruction to personnel assigned targeting, fires, and planning duties at CCMDs, the Joint Staff, Services, inter-agencies, and partner countries. Joint Target School (JTS) delivers instruction to over 1,500 students through six courses for mid-career intelligence, operational officers, and Non-Commissioned Officers. Specifically, JTS provides instruction in Joint Targeting Staff, Combat Assessment, Weaponeering Applications, Joint Staff Familiarization, Joint Staff Familiarization for Partners, and Collateral Damage Estimation (CDE). The JTS is the DoD program manager for CDE accreditation of CDE schools as prescribed in the Chairman of the Joint Chiefs of Staff Instruction (CJCSI) 3115.01D series, "No-Strike and the Collateral Damage Estimation." JTEEP 6 11 Joint Deployment Training Center: Provides functional training to all CCMDs, Services, and other DoD Agencies for approved Global Command and Control Systems-Joint applications, including Joint Operation Planning and Execution System (JOPES), Common Operational Picture, and Integrated Imagery and Intelligence. Through the Joint Deployment Training Center (JDTC), the Joint Staff provides training on various Global Force Management (GFM) related tools, including JOPES, Joint Capabilities Requirements Manager, Preferred Force Generation, Logbook, and GFM Toolset. The JDTC also assists in mission analysis and readiness reporting by providing Subject Matter Experts to facilitate analysis, help build situational awareness, and address Joint Task Force Headquarters related sourcing requirement, future force development and design, strategic messaging and posture (deterrence and assurance), inter-agency integration, multinational interoperability and strengthening of relationships with our allies and partners. JTEEP funding is the key resource used for the joint training requirements of the Department of Defense, to include exercises for eleven Combatant Commands as well as training that prepares the Services to operate as part of a joint force. These training events and exercises are key to improving mission-essential task-based readiness levels and supporting the threat-based global campaign plans. The priority use of these funds is for the readiness of U.S. forces and the Combatant Command Staffs to execute missions assigned to them by national command authorities. Aside from Title 22 Security Assistance programs, JTEEP provides most Combatant Commanders’ funds for military-to-military engagement. Because of their international political impact, Combatant Commanders’ exercises are tools of national power, and the exercises directly advance the Interim National Defense Strategic Guidance. In addition to their primary purpose of training U.S. forces, the Combatant Commanders’ exercises have corollary effects that assist in strengthening alliances, shaping the geopolitical environment, as well as providing a realistic environment for the validation of joint concepts and capabilities to enable rapid innovation of joint force development and design. For Service joint training, the JTEEP program supports the participation of multiple Service units/capabilities in Service training venues; for example, Air Force participation in the Army’s pre-deployment exercises at the National Training Center. JTEEP also provides training enablers for realistic and robust combat training with interagency participation in Service events, realistic opposing forces, feedback and lessons learned, and development of a more adaptive joint force. JTEEP non-MHA funding is further subdivided into eleven major sub-programs as follows: 1.1 Joint Exercise Transportation Program (JETP): Funds transportation of personnel and equipment to worldwide joint exercises. This tactical, operational, and strategic lift capability enables Combatant Commanders to train battle staffs and participating forces in joint and combined operations, evaluate contingency and operations plans, and execute theater engagement. The program also provides an opportunity to stress strategic transportation systems, as well as command and control and intelligence, surveillance, reconnaissance systems, to evaluate their readiness across the range of military operations. 1.2 Service Incremental Funding (SIF): These are funds provided for Service participation in Combatant Commander Exercise and engagement events. Through a collaborative planning process, CCMDs identify forces required for an exercise. SIF is then provided to pay for the additional costs that the Services would otherwise absorb. This allows CCMDs to achieve Theater Campaign Plan objectives without detrimental impact on JTEEP 7 Service training budgets. SIF is essential to the realistic conduct of field training exercises, which include forces in all domains, rather than exercises merely for the headquarters. 1.3 Joint Staff Support to Combatant Command Exercises: Each year, Combatant Commanders conduct exercises and engagement events. Linked multi-combatant Command events informed by the Joint Staff, OSD, and interagency participation advance globally integrated operations to address the Nation’s priority strategic challenges as a component of ELITE CONSTELLATION (EC). To maximize the effectiveness of these events, the Joint Staff prioritizes support to the combatant commands in accordance with the Interim National Defense Strategic Guidance. Joint Staff leads the design, planning, and execution of EC and provides functional and technical support to each CCMD and associated components during the planning and execution of their CCMD Training and Exercises. The support is essential to battle staff coordination, decision processes, and rehearsal of key UCP mission areas. JS J7 enabling support includes scenario development; observer/trainers; exercise management; and subject matter expertise in Interagency, Information Operations, Cyber Operations, Intelligence, Communications Synchronization, Sustainment, and other warfighting functional areas. The program is an enterprise model that eliminates the need for redundant capabilities across each CCMD and optimizes best practices & insight across the Joint Staff. The Joint Staff provides this support to subordinate unified commands and to select Executive Branch organizations during the biennial National Level Exercise. 1.4 Combatant Command Training and Exercises: Combatant Commands are resourced to conduct annual training, exercises, transformation, and engagement events to maximize readiness for assigned missions. This includes small-scale events through major command and national- level or globally integrated exercises. The program supports developing, evaluating, and integrating a single, high-quality training environment. In addition to serving as the operating budget for CCMDs, this program ensures the readiness of CCMD and component staff to execute key operational plans supporting U.S. national strategy. Increased funding for INDOPACOM enhances joint exercises that enable joint force readiness, deterrence (via strategic messaging and posture), future force development and design, inter-agency integration, multinational interoperability, and strengthening relationships with our allies and partners. Increased funding for USSOUTHCOM (United States Southern Command) will enhance its ability to plan and execute field training exercises in Panama and the Southern Cone of South America. These exercises are crucial for several reasons: Multinational Training Opportunities: They provide a platform for the US and its partner nations to train together, improving interoperability and coordination among their military forces. Demonstrating Commitment: These exercises serve as a visible demonstration of the US and its partners’ commitment to maintaining security and stability in the region. This is particularly important for ensuring free and unfettered access to key sea lanes of communication, which are vital for global trade and economic stability. Strengthening Partnerships: By engaging in joint exercises, the US can strengthen its relationships with partner nations in the region, fostering greater trust and cooperation. Enhancing Regional Security: These exercises help to enhance the region’s overall security by preparing forces to respond to various potential threats, from natural disasters to security challenges. Overall, the increased funding will enable USSOUTHCOM to play a more active and effective role in promoting regional stability and security through these important training exercises. JTEEP 8 1.5 Joint National Training Capability (JNTC): JNTC provides the technical standards, architecture, and development processes required to integrate/link joint training programs across the enterprise. Funding supports the technical integration and interoperability of Joint and Service models and simulations with an integrating architecture of Joint, Live, Virtual, Constructive (JLVC) training capabilities. The capabilities enable distributed training and exercise, at scale, for a training audience at the Combatant Command, Joint Task Force, Component Command headquarters, and Service joint tactical levels. The funding also supports the modernization of the Joint Training Environment (JTE) through a Modular Open Systems Architecture (MOSA) approach, including a cloud-enabled, web-accessible Joint Training Platform (JTP) and Joint Training Tool (JTT) that support all phases of an exercise (planning, execution, and AAR). JTP and JTT represent a digital transformation that increases warfighter access to digital and AI- enabled training enablers within the Joint Training Synthetic Environment (JTSE). This funding will also support the transition to and operation of advanced JLVC capabilities, such as a fully informed simulation environment and non-kinetic effects tools, delivered through JLVC modernization. Through the centralized maintenance and operation of joint exercise control, simulations, C4, and 40 persistent networked training sites, JNTC enables a Joint, Interagency, Intergovernmental, and Coalition context for the benefit of the entire training enterprise. This DoD enterprise-level capability realizes cost efficiency for the Department by reducing redundant systems, integrating CCMD/S/CSA networks and systems, and maximizing integrated training across the Services and Combatant Commands. This capability directly supports the ELITE CONSTELLATION campaign and the JTEEP program’s published goals and objectives (Goal 5) to improve the joint training infrastructure and management, enhancing the joint training environment. Through a network of subject matter experts, JNTC provides a vital link between joint training activities and ongoing operations. This linkage is crucial for institutionalizing lessons learned and lessons anticipated at the speed of need with the changing character of war. JNTC also funds improvements to infrastructure that increase training realism, including enhancements to threat replication, opposition forces, and range infrastructure. These efforts are essential for training the Joint Warfighting Concept (JWC) and the associated concept-related capabilities that must be exercised at the Service and joint levels. Additionally, this service joint training is foundational to effectively executing large global exercises like ELITE CONSTELLATION Additionally, in support of JTEEP, JNTC conducts technology modernization efforts to mitigate joint training gaps, to include leveraging new cloud environment CJADC2 tools, Artificial Intelligence (Generative AI), and other to deliver the directed training enhancements. Overall, JNTC increases training effectiveness while mitigating gaps and seams between Service-centric training programs. 1.6 Joint Training Coordination Program (JTCP): Enables the Services and U.S. Special Operations Command to participate in the exercises of the other Services. Through such participation, U.S. forces develop the skills and cross-Service familiarity necessary to operate in a joint environment. JTCP facilitates the integration of special operations and conventional forces and provides cross-Service participation in pre- deployment exercises at Army’s Combat Training Centers, USAF’s Green and Red Flag at Nellis Air Force Base, the Marine Air Ground Task Force Training Command at Twenty-Nine Palms, and the Navy’s Fleet Training Program at multiple locations, improving pre-deployment training for warfighters who will be on the front lines. JTEEP 9 1.7 Joint Knowledge Online (JKO): Adaptable 24/7 distributed learning training platform on both classified and unclassified networks, scalable to meet current and emerging individual and staff training needs of Combatant Command (CCMD), Combat Support Agency (CSA), Service, multinational, coalition, and Interagency organizations. JKO advances cost-effective training enablers to support frequent, small-facilitated events with training tools that support responsive, just-in-time staff training opportunities and enable perpetual refresher training. JKO training content, videos, courses, virtual classroom, and scenario simulations address fundamental training requirements of the Joint Staff, Joint Task Forces, CCMDs, CSAs, and supporting organizations across the DoD. 1.8 Joint Training Information Management System (JTIMS) sunset: JTIMS capability has transitioned into the cloud-based, web-enabled Joint Training Tool (JTT) within the JNTC at the end of FY 2025, leveraging the JTT’s modern architecture and modular, data-centric approach to development. JTIMS functionality modernized in the JTT supports CJCS Title 10 responsibilities/requirements, Combatant Commands, Services, Combat Support Agencies, National Guard and OSD joint training responsibilities by providing a set of integrated information management capabilities necessary to identify, collect, analyze, develop, store, and disseminate the data required to implement the four phases of the Joint Training System. JTT integrates with readiness, force sourcing, planning, training, and assessment systems, including Defense Readiness Reporting Systems – Strategic, Joint Capabilities Requirements Manager, Universal Joint Task List Development Tool, and Joint Lessons Learned Information System. 1.9 Joint Interoperability & Data Link Training Center (JID-TC): Provides tactical data link (TDL) training and operational support for Joint and Coalition forces through courses offered online, in-residence, and via mobile training teams. As the Department of Defense’s sole source of qualified Joint Interface Control Officers (JICOs), as well as maintaining coordination of the training of Joint Data Network Operations Officers (JDNOs), the Training Center ensures the timeliness and accuracy of information used by operational commanders at all levels to make warfighting decisions. This directly reduces the risk of fratricide and improves operational effects. In 1999, the Office of the Secretary of Defense outlined the requirements for a single joint officer (the JICO) and a cell of tactical data link experts to plan, execute, and manage the multi-TDL architecture for the Joint Task Force or Combatant Command. In 2001, OSD and the Joint Requirements Oversight Council determined that no single service can mitigate interoperability gaps alone and directed the JID-TC to be the sole DoD provider of joint interoperability training and JICO production. Additionally, the JID-TC was tasked through CJCSI 3151.01D with coordinating the training for the Joint Data Network Operations Officers. 1.10 Joint Targeting School: Provides formal operational-level joint targeting instruction to personnel assigned targeting, fires, and planning duties at Combatant Commands (CCMDs), the Joint Staff, Services, inter-agencies, and partner countries. Joint Target School (JTS) delivers instruction to over 1,500 students through six courses intended for mid-career intelligence, operational officers, and Non-Commissioned Officers. Specifically, JTS provides instruction in Joint Targeting Staff, Combat Assessment, Weaponeering Applications, Joint Staff Familiarization, Joint Staff Familiarization for Partners, and Collateral Damage Estimation (CDE). JTS is the DOD program manager for CDE accreditation of CDE schools as prescribed in the Chairman of the Joint Chiefs of Staff Instruction (CJCSI) 3115.01D series, "No-Strike and the Collateral Damage Estimation." JTEEP 10 1.11 Joint Deployment Training Center: Provides functional training to all Combatant Commands, Services, and other Department of Defense Agencies for approved Global Command and Control Systems-Joint applications, including Joint Operation Planning and Execution System (JOPES), Common Operational Picture, and Integrated Imagery and Intelligence. Through the Joint Deployment Training Center (JDTC), the Joint Staff provides training on various Global Force Management (GFM) related tools, including JOPES, Joint Capabilities Requirements Manager, Preferred Force Generation, Logbook, and GFM Toolset. The JDTC also assists in mission analysis and readiness reporting by providing subject matter experts to facilitate analysis, build situational awareness, and address Joint Task Force Headquarters-related sourcing requirements. JTEEP 11$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 682598000, "fy26": 1026502000, "name": "Joint Training Exercise Evaluation Program (JTEEP)", "fy25_current": 669508000, "fy25_request": 696446000, "fy25_cong_amt": -26938000, "fy25_cong_pct": -3.87}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/TJS_OP-5.pdf$$, 33, 53, FALSE, $${"json_key": "TJS__JTEEP"}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 1393798000, NULL, NULL, NULL, $$O&M/FY27/DW/Vol1_Part1/TJS_OP-5.pdf$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_tjs_ops$$, $$TJS - OPS$$, $$The Joint Staff - Operations$$, $$TJS$$, $$om_dw_ba01$$, NULL, $$dw_js$$, 2026, 454777000, 461772000, -16829000, -3.64, 444943000, 407267000, $$The Joint Staff, FY 2026: $414,097 thousand: There are 12 major programs areas that make up this Joint Staff (JS) budget. The details are provided below by each major program area. 1. Joint Staff Operations Suffolk – Management Headquarters Activities (MHA) - $1,643 thousand: This funding supports JS operations at the DoD Complex located in Suffolk, VA, considered MHA in nature. This includes the JS J7 Joint Warfighting Development, Joint Training and Office of Support Services, Directorate of Management and J6 Deputy Directorate South. Elements of this program include facility maintenance, security, information technology and communication services, administrative, and logistical support. 2. Joint Staff Analytical Support (JSAS) Program - $37,292 thousand: This program delivers advanced analytical support capabilities to the Chairman of the Joint Chiefs of Staff (CJCS) and Combatant Commands (CCMD). It provides the tools, infrastructure, and expertise necessary to conduct comprehensive analyses and present actionable insights, enabling the CJCS to fulfill statutory responsibilities effectively. Core outputs of the JSAS Program include extensive force structure evaluations, development of joint force courses of action, synthesis of lessons learned, and decision-support studies. These efforts facilitate informed decision-making and the implementation of timely, cost-efficient initiatives to enhance operational effectiveness of the Joint Force. Summary-level descriptions of the seven JSAS sub-categories include: 2.1 Joint Collaborative Analysis (JCA): The JCA provides essential analytical capabilities to support the CJCS in decision-making related to force structure assessments and Global Force Management (GFM). The JCA encompasses readiness, availability, and employment data analysis; development of joint courses of action; and joint and coalition analyses that directly support the missions of the CCMDs and JS. These capabilities enable the delivery of globally integrated, prioritized, and risk-informed recommendations, ensuring the most effective and efficient use of forces to achieve the objectives of the National Military Strategy, all while leveraging cost-effective solutions tailored to meet the Chairman's requirements. 2.2 Functional Capabilities Boards (FCB): The FCBs provide analytic support for the Joint Requirements Oversight Council (JROC) and support the JROC by integrating stakeholder views (OSD, CCMDs, Services, Defense Agencies, JS, and other federal agencies) in concept development, capabilities planning, and force development and design to ensure the U.S. military can execute assigned missions. The FCBs provide assessments and recommendations that enhance capabilities integration, examine concept required capabilities, examine joint priorities among existing and future programs, assess program alternatives (including unclassified, collateral, compartmented, and special access programs), minimize duplication of effort throughout the Services, and provide oversight in the management Doctrine, Organization, Training, Materiel, TJS - OPS 2 Leadership and Education, Personnel, Facilities and Policy (DOTMLPF-P) of materiel and non-materiel changes that support the Interim National Defense Strategic Guidance and military strategies to achieve optimum effectiveness and efficiency of the Armed Forces. 2.3 Joint Logistics: This provides strategic guidance with a global perspective to the joint logistics enterprise to advocate for CCMD requirements while accounting for Service responsibilities enabling timely, effective, and efficient initiatives to improve logistics processes, practices, capabilities, and advanced technologies for the Joint Force. This group provides the best possible focused logistics advice to the CJCS through developed detailed readiness assessments, concept development and analyses, multi-national and interagency partnerships, joint doctrine and education development, and a comprehensive understanding of resources, supply, maintenance, distribution, operational contract support and services, preferred munitions and engineering and cross-servicing arrangements. 2.4 Joint Planning and Execution: This establishes an analytic baseline for developing scenarios, contingency operations, force requirements, and necessary equipment required for effective operational planning and execution. Additionally, Joint Planning and Execution serves as the cornerstone for strategic analysis supporting the Planning, Programming, Budgeting, and Execution (PPBE) process. 2.5 Management of Joint Training Programs: This provides policy guidance and technical support for joint training programs throughout the Joint Force to facilitate improvements in comprehensive joint readiness. Through a four-phased, plans-based methodology, ensures joint training programs align with assigned missions consistent with command priories, required capabilities, and available resources. Joint training programs include a range of individual and collective training activities across academic, simulated and realistic field training settings executed to assess the organization’s capability to perform its mission(s) and address any gaps in required proficiency. 2.6 Chairman’s Exercise Program (CEP): This improves the capability and readiness of U.S. forces as well as Interagency and Interorganizational partners to ensure a whole of government approach to the conflict continuum through the conduct of regularly scheduled strategic, national level, and globally integrated exercises and senior leader events. These exercises and events examine plans, policies, and procedures under a variety of real-world and simulated crises addressing the Nation’s priority strategic challenges through multi-agency collaboration and alignment. 2.7 Chairman’s Joint Lessons Learned Program (JLLP): Fulfills the CJCS Title 10 requirement to provide policy, processes, and infrastructure for a lessons learned program for the Armed Forces in support of Joint Force Development and Design. Provides policy to build integrated and interoperable processes for a lessons learned Community of Practice (CoP) across the JS, CCMDs, Services, Combat Support Agencies, and Chairman’s Controlled Activities plus Multinational and Interagency partners. The JLLP provides analytical capability to conduct collection, analysis and assessment of lessons learned for CJCS designated operations, exercises, training, wargames, rehearsals, and experiments. The primary focus of the JLLP is on Joint Strategic Level issues to promote Global Integration and the assessment of ELITE CONSTELLATION and Joint Warfighting Concept (JWC) implementation. This provides issue resolution processes required to institutionalize improvements in DOTMLPF-P across the Joint Force and provides the Joint Lessons Learned Information System (JLLIS) as the common knowledge management infrastructure for the JLLP CoP. TJS - OPS 3 2.8 The Allies and Partners Force Development Division (APFDD): The APFDD develops collaborative Force Development capabilities between the Joint Force, Allies and Partners through coordinated engagements to prevail in competition and conflict. The APFDD directly contributes to our allies and partners development of future capabilities and forces that are interoperable with the U.S. Understanding the U.S. development plan for future forces ensures that Allies and partners develop their own forces with complimentary capabilities. This ensures that in the future the JS will be able to rely on key allies and partners for a coordinated approach to threats throughout the world. The APFDD is divided into two branches: 1) the Engagement Branch supports senior O-6/O-5 liaison officers from 23 separate nations and develops relationships between force development senior leaders through Key Leader Exchanges both in the U.S. and abroad; and 2) the Multi-national Capability Development Campaign leads the efforts of 25 nations/inter-governmental organizations to deliver non-materiel capability development interoperability. Funding supports U.S. led projects and other engagements with multinational and coalition partners. 3. Combatant Commander Initiative Fund (CCIF) - $2,981 thousand: This enables the CJCS to act quickly to support the CCMDs when they lack flexibility or resources to solve emergent challenges and unforeseen contingency requirements critical to joint war fighting readiness and national security interests. Initiatives are evaluated on their individual merits, with the strongest candidates for approval supporting CCMD activities and functions, enhancing interoperability, and yielding high benefits at low cost. Initiatives support authorized activities such as force training, joint exercises, contingencies, command and control, military education and training of foreign personnel, defense personnel expenses for bilateral or regional cooperation programs, urgent and unanticipated humanitarian relief and reconstruction assistance, force protection, and joint war fighting capabilities. 4. Joint Force Development Design (JFDD) - $25,785 thousand: This is an enterprise approach to enhance DoD decision making for current and future readiness by aligning force development and design to mitigate future joint force deficiencies. This synergized and synchronized way forward accelerates the development, implementation, and integration of new threat-based JWCs and concepts of operation through experimentation, wargaming, doctrine, professional military education, and information architecture integration and development to gain and maintain the competitive advantages necessary to deter and defeat adversaries. The FY 2026 request focuses on support to ELITE CONSTELLATION (EC) program improvements of capabilities established with the Joint Force Development and Design effort and provide the ability to address ELITE CONSTELLATION requirements in exercises; Universal Joint Task List (UJTL) analytical support gaps directly related to EC; inclusion of EC elated revisions into joint doctrine publications; facilitates integration coordination of whole of government interagency participation in EC events; address Application Programming Interface and single sign on capabilities, encryption of data and cataloguing to ensure content is captured, integrated, and cross-walked into tools supporting EC; and further identify relevant capabilities to advance JWC implementation. 5. Core Management Headquarters -$221,916 thousand: Provides general support of the Joint Staff in following key areas: 5.1 Office of the Joint Staff Comptroller: Operates an auditable accounting system for JS time and attendance, budget formulation for congressional justification books, recording financial transactions, accounting, financial reporting, acquisition package development, audit sustainment, and management of official representation funds. TJS - OPS 4 5.2 Command, Control, Communications and Computers/Cyber Directorate, Joint Staff Chief Information Officer (J-6): The J-6 provides expertise in support of the CJCS’s core responsibilities and in advancing C4/Cyber across all domains to enable a globally integrated Combined/Joint Force. The J-6 Directorate is the lead JS advocate for the integration, modernization, and innovation of C4/Cyber capabilities for the Combined/Joint Force. The J-6 provides CJCS military advice in advancing cyber defense, Joint/Coalition interoperability, and C2 systems capabilities required by the Joint Force. The J-6 also provides JS Chief Information Officer (CIO) management and oversight roles, responsibilities and processes that support and enable Joint Staff mission networks. 5.3 Joint Staff Security Office (JSSO): The JSSO provides enterprise-wide program management and operational oversight of multiple security programs in support of the CJCS and the JS. Also provides armed security forces for the protection of the National Military Command Center. 5.4 Office of the Secretary, Joint Staff (SJS): The SJS provides the Nation’s top military leadership with effective and timely action processing and information management operations that enable the corporate decision-making process for the CJCS and other JS leaders. The Joint Secretariat manages the JS action process, provides enterprise-wide business tools training to incoming members of the JS using the Enterprise Task Management Software platform as the decision-making tool, ensures statutorily compliant records management on the JS and for the CCMDs, manages the JS Freedom of Information Act and declassification review processes as directed by law, directs JS knowledge management resources, NIPR/SIPR portal administration, and National Miliary Command Center Support, and provides administrative services to the Top-4, all in support of the CJCS’s role as the Principal Military Advisor to the President, Secretary of Defense, and National Security Council. 5.5 Joint Staff Force Development Directorate (J-7): The J-7 leads the development of the Joint Force through joint training, leader development, capability and concept development supporting successful execution of the National Military Strategy. The J-7 is a learning organization focused on leading Joint Force Development, whose cohesive teams leverage partners and communicates relentlessly to enable a global Joint Force optimized for a dynamic and ever-changing security environment. The J-7 accomplishes its mission through the Deputy Director, Joint Training (DDJT), Joint Warfighting Development (DDJWD) and Deputy Director for Joint Force Integration (DDJFI). The DDJT provides distributed training platforms for the entire DoD through the development, delivery, and enabling of a continuum of individual, staff, and collective joint training to enhance the operational effectiveness of the current and future Joint Force. It is responsible for the planning and execution of ELITE CONSTELLATION campaign and ensures the execution and provisioning for joint training capabilities resident at the Suffolk compound that provides 24/7 online training and education support to the Joint Force. The DDJWD provides Joint Education and Doctrine, Allies and Partners Force Development, Futures and Concepts, and Joint Experimentation, Wargaming and Knowledge and Data actions, activities, and capabilities, services, and support to execute the J-7 JFDD mission. 5.5.1 Joint Wargaming and Experimentation Division (JWED) (DDJFI): This funding supports the Title 10 and CJCS requirements to plan, design and execute the Globally Integrated Wargame (GIWG) series and to develop a campaign approach to joint experimentation. This approach includes an annual Joint Experimentation Forum (JEF), promulgating experimentation guidance, and operations and maintenance for the Joint Experimentation Network (JExNet). Funding provides travel, training and supports analysis subject matter expertise that work across the JWED organization to support analytic efforts necessary for Joint Force Development and Design to evaluate the JWC and its Key Operational Problems and Concept Required Capabilities. TJS - OPS 5 5.5.2 Futures and Concepts Division (FCD), DDJWD: This funding supports the Title 10 and CJCS requirements to include threat-informed joint concepts that drive capability development. Specifically, joint futures and concepts are the CJCS's responsibility to express a vision for the future joint force; addressing operational problems on a 20-year horizon; identifying Joint Force development and Design implications; and identifying capabilities required to mitigate and solve future joint warfighting gaps. 5.5.3 Joint Doctrine and Education Division (JEDD), DDJWD: This fulfills Title 10 and CJCS requirements to provide policy guidance for joint professional military education (JPME), ensure policy compliance, improve effectiveness and support the conduct of assessments of JPME program outcomes to determine if Combatant Commanders and the CJCS are receiving the officers with the right skills to conduct global campaigns, combatant command campaigns, and execute joint warfighting in armed conflict. This fulfills requirements to manage the CJCS joint doctrine process, maintain and operate the CJCS electronic publishing effort, DoD terminology program, manage the information technology family of systems (JDEIS) for all of DoD; oversee the CJCS doctrine development system by revising current joint doctrine and developing new joint doctrine; act as the Chairman's assessment agent for joint doctrine; manage the UJTL used by Combatant Commanders to determine and report mission readiness. 5.5.4 Office of Irregular Warfare & Competition, DDJFI: The Office of Irregular Warfare & Competition assesses, conceptualizes, develops, and contributes to the employment of the Joint Force in irregular wars and strategic competition to implement the JWC, the Joint Concept for Competing and to integrate these into force development and design. Funding provides travel, training, and analytic support required to execute these tasks assigned to CJCS. These requirements include the annual Joint Irregular Warfare Assessment, quarterly Irregular Warfare/ Executive Steering Committee and monthly working groups as required by DoDD 3000.07; and integrating the roles and responsibilities of the Joint Force in competition into force development in accordance with CJCSI 3030.01. Additionally, OIWC serves as the CJCS's principal staff advisor regarding irregular warfare and the Joint Force in competition in all joint strategic planning, assessment, development, requirement, and other related processes. 5.6 Joint Staff Support Service Office (JSSSO): This provides maintenance support for facilities and new construction and renovation of existing spaces and also executes rent costs, facilities, and utilities located in the Pentagon and Hampton Roads, VA. 5.7 Information Technology Customer Relations Division (IT CRD): This coordinates across the JS and oversees, funds, and facilitates the provisioning, operation, and life cycle maintenance of Information Technology (IT) capabilities and services for the JS. 6. Pentagon Reservation Maintenance Revolving Fund (PRMRF) - $59,024 thousand: This funds the JS share of the maintenance, sustainment, protection, repair, and renovation of the Pentagon Reservation. The PRMRF budget request includes TJS rent, force protection provided by the Pentagon Force Protection Agency, and real property operations to include standard maintenance, repair, and utilities. Annual funding requirements also include the costs of real property operations and security of Raven Rock Mountain Complex. The Washington Headquarters Service (WHS) is the executive agent for Raven Rock Mountain Complex, and tenants share financing of operations via the PRMRF Defense Working Capital Fund. The JS share of construction and maintenance of the Unified Command Center, which includes the National TJS - OPS 6 Military Command Center, Resource Situational Awareness Center, and National Joint Operations and Intelligence Center, is also included in the PRMRF line. 7. Facilities Sustainment, Restoration & Modernization - $1,147 thousand: This funds facility and life cycle maintenance support functions including maintenance and repair projects and minor construction accomplished by the Pentagon's in-house and contracted workforce. The program executes work orders for facility related repairs/upgrades and plans and executes minor construction and renovation projects supporting the annual improvement program and various JS directorates. 8. Facility Operations - $11,965 thousand: This funds facility leases and utilities that are not considered MHA costs in nature but support the remainder of the JS not associated with the JTEEP program. 9. Direct Support to JTEEP Facility Operations - $2,567 thousand: Funding to support JS operations at the DoD Complex located in Suffolk, VA. Elements of support include facility leases and utilities. The Joint warfighting operational readiness support hub is a premier facility that supports the planning, execution, and evaluation of joint exercises, wargames, and integration activities. The facility provides technical control for joint enterprise networks and simulations, as well as joint integration and interoperability labs. With its highly adaptable and secure spaces, including SCIFs, the facility enables the joint forces to conduct global warfighter training as scale in a realistic environment, enhancing warfighter readiness and joint force development and interoperability. 10. Analysis Working Group Support - $3,677 thousand: This provides support to execute prioritized studies and reform the analytical enterprise through enhanced modeling and simulation and infrastructure improvements. The AWG supports modeling and simulation tools and methods, computational capacity, portfolio expansion and workforce challenges. Initial lines of effort focus on analytic infrastructure reform, knowledge management reform, improved integration for campaign analysis, and rapid capability Concept of Operations (CONOPS) development. Resources fund allies and partner data sets to support rapid CONOPS development; development of CONOPS Red Teams; and maintenance and development of specialized modeling and simulation toolsets. 11. Pentagon Reservation (PRMRF) RRMC ($41,266 thousand): This fully funds JS support costs for Rocky Mountain Complex (RRMC) operations. 12. Office of the Chief Digital and Artificial Intelligence (AI) Officer (OCDAO) - $4,834 thousand: The OCDAO was established effective August 20, 2024 to lead and synchronize JS digital modernization working in collaboration with each of the JS Directorates, the Office of the Secretary of Defense (OSD), the Services, and the CCMDs. The JS OCDAO integrates data, analytics, and AI into JS core functions and empowers the JS with access to data products and digital platforms to enhance decision-making, operational efficiency, and warfighting decision advantage. TJS - OPS 7$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 4607000, "fy26": 0, "name": "Analytical Support to Force Planning", "fy25_current": 0, "fy25_request": 0, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 1559000, "fy26": 1643000, "name": "Joint Staff Operations - Suffolk JTEEP Spt", "fy25_current": 1501000, "fy25_request": 1788000, "fy25_cong_amt": -287000, "fy25_cong_pct": -16.05}$$::jsonb, $${"fy24": 27569000, "fy26": 37292000, "name": "Joint Staff Analytical Support (JSAS)", "fy25_current": 31350000, "fy25_request": 32496000, "fy25_cong_amt": -1146000, "fy25_cong_pct": -3.53}$$::jsonb, $${"fy24": 0, "fy26": 2981000, "name": "Combatant Commanders Initiatives Fund (CCIF)", "fy25_current": 2981000, "fy25_request": 2981000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 541000, "fy26": 0, "name": "Non-conventional Assisted Recovery (NAR)", "fy25_current": 0, "fy25_request": 1957000, "fy25_cong_amt": -1957000, "fy25_cong_pct": -100.0}$$::jsonb, $${"fy24": 31593000, "fy26": 25785000, "name": "Joint Force Development & Design (JFDD)", "fy25_current": 27272000, "fy25_request": 33841000, "fy25_cong_amt": -6569000, "fy25_cong_pct": -19.41}$$::jsonb, $${"fy24": 240554000, "fy26": 221916000, "name": "Management HQ OCJCS", "fy25_current": 223884000, "fy25_request": 230719000, "fy25_cong_amt": -6835000, "fy25_cong_pct": -2.96}$$::jsonb, $${"fy24": 102320000, "fy26": 59024000, "name": "Pentagon Reservation (PRMRF)", "fy25_current": 63313000, "fy25_request": 63313000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 216000, "fy26": 737000, "name": "Facilities Restoration & Modernization", "fy25_current": 200000, "fy25_request": 371000, "fy25_cong_amt": -171000, "fy25_cong_pct": -46.09}$$::jsonb, $${"fy24": 4535000, "fy26": 410000, "name": "Facilities Sustainment", "fy25_current": 1302000, "fy25_request": 402000, "fy25_cong_amt": 900000, "fy25_cong_pct": 223.88}$$::jsonb, $${"fy24": 11319000, "fy26": 11965000, "name": "Facility Ops", "fy25_current": 11195000, "fy25_request": 11959000, "fy25_cong_amt": 823000, "fy25_cong_pct": 6.88}$$::jsonb, $${"fy24": 2732000, "fy26": 2567000, "name": "JTEEP Facility Operations Direct Support", "fy25_current": 2516000, "fy25_request": 2516000, "fy25_cong_amt": -1587000, "fy25_cong_pct": -63.08}$$::jsonb, $${"fy24": 24666000, "fy26": 0, "name": "JTEEP Staffing Direct Support", "fy25_current": 26720000, "fy25_request": 26720000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 2566000, "fy26": 3677000, "name": "Support for Analysis Working Group", "fy25_current": 3824000, "fy25_request": 3824000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 0, "fy26": 41266000, "name": "Pentagon Reservation (PRMRF) RRMC", "fy25_current": 43797000, "fy25_request": 43797000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 0, "fy26": 4834000, "name": "Chief Data Office - Dashboard", "fy25_current": 5088000, "fy25_request": 5088000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/TJS_OP-5.pdf$$, 12, 32, FALSE, $${"json_key": "TJS__TJS - OPS", "fy27_v192_bucket_a_dw": {"session": "2026-05-09_v41", "source_pdf": "O&M/FY27/DW/Vol1_Part1/TJS_OP-5.pdf", "content_hash": "d42a351bae3f22e91f080cfa524c80ab0686bb488a7e82b4080f9952c3c0929f", "source_page_amount": 22, "source_page_description": 15}}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, 461533000, NULL, NULL, NULL, NULL, 534218000, NULL, NULL, NULL, $$O&M/FY27/FY2027_o1.txt$$, 11530000) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_tjs_training$$, $$TJS-Training$$, $$The Joint Staff - Training$$, $$TJS$$, $$om_dw_ba03$$, NULL, $$dw_js$$, 2026, 116867000, 132101000, -3479000, -2.63, 128622000, 119223000, $$The National Defense University (NDU) $124,869 thousand: The NDU is the premier center for joint professional military education with a main campus on Fort McNair in Washington, D.C. The Joint Forces Staff College is located in Norfolk, VA. The NDU’s third and smaller campus supporting the Joint Special Operations Master of Arts (JSOMA) program is at Fort Bragg, NC. The Middle States Commission on Higher Education accredits the NDU. The NDU conducts world class Joint Professional Military Education (JPME), seminars, symposia and professional development and conferencing for DoD and Congressional representatives. The NDU is composed of the following colleges, institutions, and budget activities located at Ft. McNair, Washington, DC, and Norfolk, VA: • CAPSTONE / PINNACLE / KEYSTONE • College of International Security Affairs (CISA) • Dwight D. Eisenhower School of National Security and Resource Strategy • College of Information Cyberspace (CIC) (formerly Information Resources Management College) • Institute for National Strategic Studies (INSS) • Joint Forces Staff College (JFSC) • National War College (NWC) • NDU Operations • NDU – Headquarters Activities 1. CAPSTONE / PINNACLE / KEYSTONE, $3,418 thousand: CAPSTONE: This is a congressionally-mandated course required for all newly promoted active duty one star generals and admirals. By DoD policy, attendance is required within the first two years of confirmation to the one-star rank. CAPSTONE, offered four times a year, is a five-week course consisting of seminars, case studies, informal discussions, visits to key U.S. military commands within the continental U.S. and overseas field studies to areas with high U.S. interests. Overseas field studies involve interactions with the Combatant Commanders, American Ambassadors, embassy staffs, and senior political and military leaders of foreign governments. PINNACLE: Prepares selected three-star commanders to lead joint and combined forces, building upon CAPSTONE and the Joint Flag Officer Warfighting Course. TJS-Training 2 KEYSTONE: Prepares Command Senior Enlisted Leaders (CSELs to serve in a general or flag officer level joint or Service headquarters.) 2. College of International Security Affairs (CISA), $3,385 thousand: The CISA builds expert practitioners of Irregular Warfare across its campuses at Fort McNair and Fort Bragg (CISA-JSOMA) and educates conventional and special operations joint warfighters, civilian national security leaders, and America’s partners and allies in the theory and application of irregular warfare in order to promote U.S. national security interests. Students earn an NDU MA Degree in Strategic Security Studies, with McNair graduates earning JPME II credit and JSOMA students earning Advanced Operations Course (AOC) credit. The CISA two-week Reserve Component National Security Course (RCNSC) is executed three times each year for U.S. military officers (O4-O6) and non-commissioned officers (E8-E9) of the U.S. Reserve Components, interagency civilians, and partner nation officers. Upon completion of RCNSC, U.S. reserve officers earn two Joint credits toward Joint Qualification. The CISA four-month Homeland Defense Fellowship certificate program has been composed of International, Joint, and Interagency students where Fellows analyze emerging security threats in their respective homelands and share best practices to organize appropriate and effective strategic integrated responses and protect critical infrastructure. The majority of CISA international students are funded through the DoD’s Regional Defense Fellowship Program. 3. Dwight D. Eisenhower School of National Security and Resource Strategy, $6,909 thousand: This Senior-level course of study in national security strategy to prepare selected military officers, federal officials, and international officers for high-level policy, command, and staff responsibilities to lead the strategic institutions and activities associated with the integrated development and resource execution of national security and national defense strategies. The academic program includes courses in national security studies, economics, defense strategy and resourcing, acquisition, the global industrial base, and strategic leadership. The curriculum includes a one-of-a-kind study of industry that requires the development of a strategic perspective on the U.S. and global industrial base and its role in supporting the resource requirements of national security. 4. College of Information Cyberspace (CIC), $6,918 thousand: This curriculum prepares U.S. military and civilian leaders, international officers, and cyber workforce experts to lead, advise, and advance national and global security in the cyber domain and information environment; prepares graduates in a dynamic forum in which senior defense professionals and the broader military and federal civilian communities gain knowledge, skills, and competencies for development of national security and national cybersecurity strategies; and awards graduate level certificates and a Master of Science in Strategic Information and Cyberspace. 5. Institute for National Strategic Studies (INSS), $4,910 thousand: The INSS produces cutting-edge research and analysis for joint warfighters and other national security leaders and integrates scholarship to advance NDU’s educational mission. The INSS consists of the Center for Strategy and Military Power, Center for the Study of Chinese Military Affairs, the Center for the Study of Weapons of Mass Destruction, the Center for Disruptive Technology and Future Warfare (CDTFW), and NDU Press. The INSS provides timely, objective analyses and recommendations to senior DOD decision makers and joint warfighters on international security and defense issues TJS-Training 3 6. Joint Forces Staff College (JFSC), $7,375 thousand: This intermediate and senior-level joint college educates national security leaders to plan and execute operational-level joint, multinational, and interagency operations. The JFSC was established to meet the requirements of the Goldwater-Nichols Act of 1986 that led to the establishment of the Joint Forces Staff College (JFSC) and other institutions focused on joint military education. The Officer Professional Military Education Policy establishes three Joint Professional Military Education programs: Joint Advanced Warfighting School (JAWS), Joint and Combined Warfighting School (JCWS), and the Joint and Combined Warfighting School-Hybrid (JCWS-H) to meet that congressional mandate. The JCWS awards JPME Phase II and JAWS awards a Master of Science in Joint Warfighting. 7. National War College (NWC), $5,348 thousand: This senior-level course of study in national security strategy prepares selected military officers, federal officials, and international officers for high-level policy, command, and staff responsibilities. The college emphasizes the joint (multi-service), interagency, and international perspectives and awards the Master of Science in National Security Strategy. 8. NDU Operations, $80,379 thousand: This supports the Information Technology, Facilities and Engineering, Operations Management, Human Resources, Resources and Financial Management, Library, Security, Strategic Communications, Academic Affairs, Wargaming and Simulation, Institutional Research and Registrar, and Health and Fitness Directorates which provide general support to the Joint Staff and NDU components enabling the University to optimize its joint professional education, research, and outreach missions. 9. NDU Headquarters Activities, $6,227 thousand: This supports the seamless execution of university management functions primarily performed by the NDU President and Chief Support Officer (CSO) to include activities in support of international partners, interagency, industry, and other stakeholder engagements, as well as strategic initiatives to assess and implement modern academic and business processes and practices. TJS-Training 4$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 111288000, "fy26": 118642000, "name": "3. Training", "fy25_current": 122395000, "fy25_request": 125134000, "fy25_cong_amt": -2739000, "fy25_cong_pct": -2.19}$$::jsonb, $${"fy24": 3082000, "fy26": 3418000, "name": "Capstone", "fy25_current": 3786000, "fy25_request": 3786000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 6923000, "fy26": 6918000, "name": "Information Resources Management College", "fy25_current": 7286000, "fy25_request": 7286000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 5604000, "fy26": 3385000, "name": "College of International Security Affairs (CISA)", "fy25_current": 3753000, "fy25_request": 3753000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 7876000, "fy26": 6909000, "name": "Eisenhower School", "fy25_current": 7278000, "fy25_request": 7278000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 4182000, "fy26": 4910000, "name": "Institute for National Strategic Studies", "fy25_current": 5094000, "fy25_request": 5094000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 6983000, "fy26": 7375000, "name": "Joint Forces Staff College", "fy25_current": 7743000, "fy25_request": 7743000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 5518000, "fy26": 5348000, "name": "National War College", "fy25_current": 5716000, "fy25_request": 5716000, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 71120000, "fy26": 80379000, "name": "NDU Operations", "fy25_current": 81739000, "fy25_request": 84478000, "fy25_cong_amt": -2739000, "fy25_cong_pct": -3.24}$$::jsonb, $${"fy24": 5579000, "fy26": 6227000, "name": "National Defense University - MHA", "fy25_current": 6227000, "fy25_request": 6967000, "fy25_cong_amt": -740000, "fy25_cong_pct": -10.62}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/TJS_OP-5.pdf$$, 65, 85, FALSE, $${"json_key": "TJS__TJS-Training", "fy27_v192_bucket_a_dw": {"session": "2026-05-09_v41", "source_pdf": "O&M/FY27/DW/Vol1_Part1/TJS_OP-5.pdf", "content_hash": "e6d6aeaf474ecabcc9fca3a4ab8bb2496199230c5a860ea2b049ff5fc5038b1d", "source_page_amount": 57, "source_page_description": 55}}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, 128399000, NULL, NULL, NULL, NULL, 173748000, NULL, NULL, NULL, $$O&M/FY27/FY2027_o1.txt$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_tjs_umbrella$$, $$TJS$$, $$The Joint Staff$$, $$TJS$$, $$om_dw_ba01$$, $$BA-01: Operating Forces$$, $$dw_osd$$, 2026, 1262437000, 1299419000, -47355000, -3.64, 1252064000, 1574554000, $$Budget Activity 01 (BA-01)/Operating Forces$$, to_jsonb(ARRAY[$${"program": "The Joint Staff (TJS) Operations", "narrative": "Twelve major program areas make up the Joint Staff Direct Operation and Maintenance funding for FY 2026: The major programs are (1) Joint Staff Operations Suffolk, MHA; (2) Joint Staff Analytical Support (JSAS); (3) Combatant Commander Initiative Fund (CCIF); (4) Joint Force Development and Design (JFDD); (5) Management Headquarters; (6) Pentagon Reservation Maintenance Revolving Fund (PRMRF); (7) Facilities Sustainment, Restoration & Modernization; (8) Facility Operations; (9) Direct Support to Joint Training Exercise Evaluation Program (JTEEP) Facility Operations; (10) Analysis Working Group Support; (11) Pentagon Reservation (PRMRF) RRMC, (12) Office of the Chief Digital and Artificial Intelligence Officer (OCDAO). Analytical Support to Force planning transferred to OSD in the FY25PB. Non-Conventional Assisted Recovery (NAR) program transferred to SOCOM. And Direct Support to Joint Training Exercise Evaluation Program (JTEEP) Joint Staff Activities Program transferred into the JTEEP Budget Line item 8PL1.", "fy26_dollars": 414097000}$$::jsonb, $${"program": "TJS Cyber", "narrative": "The Joint Staff Cyber program provides cybersecurity program support and capabilities to the Joint Staff Chief Information Office and the Joint Staff environments. It also provides oversight and management of the evaluation and mitigation process for identified cybersecurity vulnerabilities. Activities include implementation of the Risk Management Framework for the assessment, authorization, and continuous monitoring of Joint Staff mission networks and major applications; developing component/business unit-level cybersecurity processes and procedures; compliance oversight and reporting (DoD CIO Scorecard and Federal Information Security Modernization Act); cybersecurity workforce management tracking and reporting; system administration of the Joint instances of the Enterprise Mission Assurance Support Service (eMASS) for Joint Staff (internal) and Combatant Command use. Joint C5AD (JS-C5AD) is a capability provider within the DoD Enterprise Cyber Range Environment (DECRE), which also includes the National Cyber Range (NCR) and Joint Mission Environment Test Capability’s (JMETC) Multiple Independent Layers of Security (MILS) Network (JMN) Regional Service Delivery Points (RSDP). C5AD provides assessment planning and execution expertise to support cyber project objectives that may include testing, training, or exercise support. C5AD provides a variety of commonly deployed joint C2 systems, including Global Command and Control System-Joint (GCCS-J), Joint Advanced Deep Operations Coordination System (JADOCS), and Joint Range Extension (JRE), and others as required by project. C5AD provides the environment required to drive C2 system operation, and the system operators required to generate a realistic exchange of system data or to assess the cyber impacts on system functionality. C5AD’s cyber projects include a range of activities from assessment of cyber impacts on individual C2 systems,", "fy26_dollars": 9086000}$$::jsonb, $${"program": "TJS Training/National Defense University (NDU)", "narrative": "NDU is the premier center for joint professional military education. The University’s main campus is on Fort McNair in Washington, D.C. The Joint Forces Staff College is located in Norfolk, VA. The Middle States Commission on Higher Education accredits the National Defense University. NDU conducts world class Joint Professional Military Education (JPME), seminars, symposia and professional development and conferencing for DOD and Congressional representatives. NDU is composed of the following colleges, institutions, and activities located at Ft. McNair, Washington, DC, and Norfolk, VA: o CAPSTONE / PINNACLE / KEYSTONE o College of International Security Affairs (CISA) o Dwight D. Eisenhower School of National Security and Resource Strategy o College of Information Cyberspace (CIC) (formerly Information Resources Management College (iCollege)) o Institute for National Strategic Studies (INSS) o Joint Forces Staff College (JFSC) o National War College (NWC) o NDU Operations o NDU – Headquarters Activities", "fy26_dollars": 124869000}$$::jsonb]), to_jsonb(ARRAY[$${"fy24": 1145570000, "fy26": 1449685000, "name": "BA-01. Operating Forces", "fy25_current": 1123442000, "fy25_request": 1167318000, "fy25_cong_amt": -43876000, "fy25_cong_pct": -3.76}$$::jsonb, $${"fy24": 454777000, "fy26": 414097000, "name": "The Joint Staff - Operations", "fy25_current": 444943000, "fy25_request": 461772000, "fy25_cong_amt": -16829000, "fy25_cong_pct": -3.64}$$::jsonb, $${"fy24": 682598000, "fy26": 1026502000, "name": "Joint Training Exercise Evaluation Program", "fy25_current": 669508000, "fy25_request": 696446000, "fy25_cong_amt": -26938000, "fy25_cong_pct": -3.87}$$::jsonb, $${"fy24": 8195000, "fy26": 9086000, "name": "Cyber", "fy25_current": 8991000, "fy25_request": 9100000, "fy25_cong_amt": -109000, "fy25_cong_pct": -1.2}$$::jsonb, $${"fy24": 116867000, "fy26": 124869000, "name": "BA-03. Training", "fy25_current": 128622000, "fy25_request": 132101000, "fy25_cong_amt": -3479000, "fy25_cong_pct": -2.63}$$::jsonb, $${"fy24": 116867000, "fy26": 124869000, "name": "National Defense University", "fy25_current": 128622000, "fy25_request": 132101000, "fy25_cong_amt": -3479000, "fy25_cong_pct": -2.63}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/TJS_OP-5.pdf$$, 1, 11, FALSE, $${"json_key": "TJS__TJS", "fy27_v192_bucket_a_dw": {"session": "2026-05-09_v41", "source_pdf": "O&M/FY27/DW/Vol1_Part1/TJS_OP-5.pdf", "content_hash": "e70b325b277cdff3f44dda2459e481f239ebf7a02356d1a32a86fab79a967073", "source_page_amount": 7, "source_page_description": 5}}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 1928016000, NULL, NULL, NULL, $$O&M/FY27/FY2027_o1.txt$$, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_om_sags (id, sag_short_code, sag_title, defense_wide_org, appropriation_id, budget_activity, owning_org_id, fiscal_year, fy24_enacted, fy25_request, fy25_cong_amt, fy25_cong_pct, fy25_current, fy26_estimate, description, sub_narratives, subactivities, personnel, source_pdf, source_page_start, source_page_end, is_synthetic, raw_source, created_at, is_priority, fy25_actual, fy26_request, fy26_cong_amt, fy26_cong_pct, fy26_current, fy27_estimate, fy27_subactivities, fy27_sub_narratives, fy27_personnel, fy27_source_pdf, fy27_mandatory_amount) VALUES ($$om_whs_umbrella$$, $$WHS$$, $$Washington Headquarters Services$$, $$WHS$$, $$om_dw_ba04$$, NULL, $$dw_whs$$, 2026, 415061000, 496512000, -24776000, -4.99, 471736000, 411182000, $$The Washington Headquarters Services (WHS) FY 2026 President’s Budget request of $411,182 thousand is $60,554 thousand below the FY 2025 enacted amount and is comprised of $10,813 thousand in pricing decreases and $49,741 thousand in programmatic decreases. The FY 2026 request empowers the WHS to continue to support key administration initiatives and priorities in defense of the Nation. The WHS directly supports the Department of Defense (DoD), the Secretary of Defense (SECDEF), the Office of the Secretary of Defense (OSD), the Deputy Secretary of Defense (DEPSECDEF), the Defense Legal Services Agency (DLSA), the United States Court of Appeals for the Armed Forces (USCAAF), the Defense Agencies and DoD Field Activities (DAFA), including Pentagon Force Protection Agency (PFPA), the Defense Security Cooperation Activity (DSCA), the Defense Prisoner of War (POW)/Missing in Action (MIA) Accounting Agency (DPAA), National Guard Bureau, Defense Technology Security Administration (DTSA), and Defense Test Resource Management Center (DTRMC) and other select Federal Agencies such as the Department of State (DoS), the National Archives and Records Administration (NARA), and the White House. The WHS provides more than 80 essential services, absorbing and consolidating administrative requirements that allow DoD staff to focus on matters involving policy analysis and program oversight more efficiently. The WHS demonstrates expertise and innovation and provides solutions to tackle complex issues though operational prioritization. The WHS continues to transform into an organization of the future by focusing and upgrading core functions. The WHS continues to cultivate the future by investing in the Interim National Defense Strategic Guidance (INDSG) objectives of “America First and Achieve Peace Through Strength,” through the following resource drivers: 1) Defend the Homeland – The WHS invests in cyber security by implementing risk management processes and vulnerability mitigations, conducting monitoring, testing, and incident response and reporting requirements, and managing cyber performance. 2) Resource Management – The WHS streamlines administrative and support functions in support of the Department by efficiently allocating and maximizing resources, consistently innovating solutions, and providing a skilled workforce. 3) Supporting the Warfighter – The WHS provides essential support services within the Pentagon Reservation (Pentagon, Mark Center, and Raven Rock Mountain Complex) and the National Capital Region (NCR) providing reliable and responsive service to customers. WHS 1116 The WHS services are organized into three main functional areas: People, Business, and Facilities. Each is supported by various operational areas throughout the organization. The WHS enables centralized operational support functions to maximize efficiency, emphasizing our commitment to providing leading edge services to our mission partners in support of the defense to the Nation in the following functions: WASHINGTON HEADQUARTERS SERVICES IMMEDIATE OFFICE: The WHS Immediate Office (WHS IO) serves as the Agency integrator and establishes the framework for synchronizing emergent, cross- functional requirements among WHS Directorates to secure mission accomplishment and achieve strategic goals on behalf of the WHS Director and the Performance Improvement Officer and Director of Administration and Management (PIO/DA&M). The WHS IO provides program management, administrative, and operational services to sustain and meet new administration and regulatory requirements and supports Presidential and DoD transitions. ACQUISITION DIRECTORATE: The Acquisition Directorate (AD) plans, coordinates, and manages a wide range of supplies and services procurement programs, valued at over $3.846 billion annually. The AD is the single enterprise contracting office supporting acquisition services to all OSD components, WHS, the PFPA, the DSCA, the DPAA, and more. Contracts for knowledge-based services, research and development, and facility support account for more than 80 percent of AD’s total obligations, providing a consistent capability to connect people and process information. EXECUTIVE SERVICES DIRECTORATE: The Executive Services Directorate (ESD) provides comprehensive knowledge management, information security, and visual information services to the OSD and DAFAs. The ESD also executes legally mandated programs and supports the Pentagon Reservation by providing a wide variety of customer services. The ESD provides executive services to the SECDEF, DEPSECDEF, OSD components, the Joint Staff and the DAFAs, and other agencies and organizations. Mandated programs include the Freedom of Information Act, the Privacy Act of 1974, the Federal Records Act, the Paperwork Reduction Act, Executive Order 13526, and programs relating to classification and declassification reviews. The ESD services include managing the DoD issuances program, managing correspondence for the SECDEF and DEPSECDEF through the Correspondence and Task Management System, and designing visual information products. The ESD further supports its customers by operating the Pentagon Motor Pool. FINANCIAL MANAGEMENT DIRECTORATE: The Financial Management Directorate (FMD) provides Planning, Programming, Budgeting, Execution and accounting services, to include an established and designated U.S. Department of the Treasury direct treasury payment office, for the WHS, the OSD, and assigned DAFAs, and other programs and task forces. The FMD ensures financial transparency and consistency in identifying, analyzing, and developing funding solutions. Additionally, the FMD manages key functions to include developing the Program Objective Memorandum, formulating the President's Budget; funds distribution and certification; direct treasury disbursement; financial reporting; civilian pay management; audit support; and manpower management. The FMD provides central funds management for the two revolving funds that provide for the operation and security of the Pentagon Reservation and the centralized management of DoD leases within the NCR. The FMD’s Robotic Process Automation team WHS 1117 leverages automation solutions to reduce manual work, enhance accuracy and timeliness, and allow employees to shift from low-value to high- value work. The FMD manages, utilizing key programming and budget services, approximately $18.9 billion on behalf of its customers. The FMD Disbursing Office disbursed over $4.6 billion in FY 2025, an increase from $3.7 billion in FY 2024. This significant growth reflects FMD’s improvement of financial management and disbursement processes, and payment of more higher value contracts. FACILITIES SERVICES DIRECTORATE: The Facilities Services Directorate (FSD) ensures the 24/7/365 readiness of facilities, enabling DoD and national leadership to execute mission responsibilities and provide the DoD workforce at supported locations with a safe, secure, healthy, resilient, energy efficient and operationally effective working environment. The FSD provides comprehensive lifecycle facility management supporting over 60,000 employees in approximately 15 million square feet of facilities across the NCR to include the Pentagon Reservation and 65 leased facilities. The FSD manages the DoD Headquarters Military Construction program, including all aspects of the planning, programming, and design process, and the Capital Improvement Program for the Pentagon Reservation. The FSD customer base includes the OSD, the Joint Chiefs of Staff, the DAFAs, the Military Departments (MILDEPS) in the NCR, the National Guard Bureau, designated boards and commissions, and cross-functional teams. The FSD delivers infrastructure aligned with the NDS by providing structural integrity, resilient, and timely modernization of DoD facilities. Facility management services include design and construction; space allocation; maintenance, repair, alterations, and operations; DoD Sensitive Compartmented Information Facility (SCIF) management including building, design, and inspection; landscaping; property and real-estate management; permits and compliance with fire; and occupational health and safety. The FSD is responsible for Pentagon Reservation master planning and execution with goals to ensure readiness; improve security, safety, and quality of life for employees and visitors; and enhance facility resiliency and sustainability. The FSD is the lead on space reduction initiatives to maximize efficiencies and reduce the leased space portfolio cost to the DoD through consolidation and return of leased facilities. HISTORY AND LIBRARY DIRECTORATE: The History and Library Directorate (HLD) provides a wide range of history and library services to OSD, DoD components, other federal entities, and the public. The OSD Historical Office and the Pentagon Library have distinct but synergetic missions. The Historical Office was founded in the 1940s and is one of the longest, continually operating offices in OSD that provides historical research and analysis services to the SECDEF and OSD leadership, chronicles the history of the SECDEF to inform the American public, and reviews speeches, DoD-related resolutions, and Pentagon corridor exhibits for historical accuracy. WHS 1118 The Pentagon Library connects Pentagon Reservation tenants with information resources and subject matter expertise to meet a broad spectrum of needs in support of the DoD mission and provides customized research and reference services, acquires licensed electronic content for the OSD and DoD components, provides training for customers, maintains collections of DoD-specific materials in a variety of formats, and collaborates with other federal and military libraries. HUMAN RESOURCES DIRECTORATE: The Human Resources Directorate (HRD) provides comprehensive human resources and personnel security services to the OSD, DAFAs, and select government organizations. The HRD also provides a full suite of services for the primary beneficiary base of more than 6,100 civilian employees and nearly 3,000 uniformed military members. The HRD provides the processing, management and due process of security clearances for nearly 13,000 people across the DoD; members of the Legislative Branch, the Executive Branch (e.g., the National Security Council); state, local and academic institutions; and other governmental bodies. The HRD centrally manages its civilian compensation and benefits program. The HRD delivers a full range of advisory and transactional services for employee benefits (e.g., health and life insurance, retirement and injury compensation). The HRD manages the Employee Assistance Program, telework and wellness programs, and giving campaigns (e.g., Combined Federal Campaign). The HRD provides Workforce Shaping program management, including Voluntary Early Retirement Eligibility/Voluntary Separation Incentive Payment, Furlough, and Reduction in Force. The HRD assists WHS-serviced DoD components recruit personnel and serves as a senior technical adviser on a range of HR issues critical to the achievement of human capital goals, including special employment. The HRD provides HR policy guidance and voices HR concerns for all the DAFAs as a voting member of the DoD Civilian Personnel Policy Council. These representative and liaison duties provide a venue through which the PIO/DA&M communicates and translates the SECDEF’s agenda into policy. The Senior Executive Management Office manages all political appointments for the DoD and manages the executive resources, staffing, and performance management for the Senior Executive Service, Scientific and Professional, Senior Level, and Intelligence Executive positions within the DoD Components. The Military Personnel Division provides military personnel support services to the OSD, the WHS, the MILDEPs, the White House, and select DAFAs. SECURITY ENTERPRISE SERVICES DIRECTORATE: The Security Enterprise Services Directorate (SESD) provides comprehensive security, mission assurance, and onboarding support to the OSD, WHS, other supported DoD and non-DoD activities, and elements of the legislative and judicial branches of government across the country and at Naval Station Guantanamo Bay (GTMO). The core mission is executed through six primary divisions: the Onboarding Management Team Division (OMT), Office of Special Security Division (OSS), Integrated Security Operations Division (ISO), the Personnel Vetting Operations Division (PVO), Sensitive Compartmented Information (SCI) Management Division, and the Security Appeals, Policy, and Performance Oversight Division (SAPPO). WHS 1119 The OMT streamlines the onboarding process for new personnel through its Security Branch and Customer Relations Management Branch by achieving Day One facilities and systems accesses and provisioning of equipment. The OSS provides specialized security support to the Office of Military Commissions in the NCR and GTMO, ensuring these critical missions maintain appropriate security protocols. As a key component of the consolidated security enterprise, OSS delivers tailored security solutions for these high-priority operations. The ISO manages comprehensive security operations and dedicated Security Office Support Services for the Pentagon Reservation, leased spaces throughout the NCR, and customer locations across the country. The ISO ensures the physical and information security of WHS- supported missions, facilities, and personnel. The PVO, formerly under the Human Resources Directorate, manages personnel vetting in support of WHS customers to ensure proper security clearance processing and management and serves a vital role in ensuring a trusted workforce across all WHS-supported customers, including all three branches of the federal government. Integration of the PVO into SESD centralizes all personnel security functions under one directorate, creating a more efficient and responsive security clearance process. The SCI Management, led by the WHS Special Security Officer, provides comprehensive SCI support to WHS-serviced customers, including personnel management, indoctrinations and training, and lifecycle management of SCIFs. The SCI Management also supports Special Access Programs, and Alternative Compensatory Control Measures. The SAPPO provides personnel security policy oversight and is the final adjudicative authority for security clearances for the DAFA. SAPPO also provides internal guidance for SESD operations through performance oversight as a direct report to the Director, SESD, by providing policy guidance, performance oversight, and managing clearance appeals. The SESD implementation follows a phased approach to minimize service disruption while ensuring appropriate resources are acquired. Working in conjunction with the Security Enterprise Transformation and Modernization Program Office, SESD is conducting ongoing enterprise assessments of security program capabilities across WHS Directorates to reduce operational overlap and eliminate redundancy. The SESD is scheduled to achieve FOC by December 31, 2028, completing the consolidation of security functions and realignment of personnel, facilities, resources, and other assets to create a more effective and efficient security enterprise for WHS and its customers. WHS 1120$$, to_jsonb(ARRAY[]::text[]), to_jsonb(ARRAY[$${"fy24": 110107000, "fy26": 114881000, "name": "Compensation and Benefits", "fy25_current": 105796000, "fy25_request": 120825000, "fy25_cong_amt": -15029000, "fy25_cong_pct": -12.44}$$::jsonb, $${"fy24": 960000, "fy26": 3042000, "name": "Acquisition Management", "fy25_current": 3908000, "fy25_request": 3924000, "fy25_cong_amt": -16000, "fy25_cong_pct": -0.41}$$::jsonb, $${"fy24": 16781000, "fy26": 11028000, "name": "Executive Services Management", "fy25_current": 17356000, "fy25_request": 17389000, "fy25_cong_amt": -33000, "fy25_cong_pct": -0.19}$$::jsonb, $${"fy24": 250537000, "fy26": 222480000, "name": "Facilities/Installation Management", "fy25_current": 300034000, "fy25_request": 305403000, "fy25_cong_amt": -5369000, "fy25_cong_pct": -1.76}$$::jsonb, $${"fy24": 9225000, "fy26": 10676000, "name": "Financial Management", "fy25_current": 11992000, "fy25_request": 12033000, "fy25_cong_amt": -41000, "fy25_cong_pct": -0.34}$$::jsonb, $${"fy24": 12476000, "fy26": 5052000, "name": "Human Resources", "fy25_current": 9861000, "fy25_request": 13065000, "fy25_cong_amt": -1554000, "fy25_cong_pct": -11.89}$$::jsonb, $${"fy24": 0, "fy26": 2453000, "name": "Security Enterprise Management", "fy25_current": 0, "fy25_request": 0, "fy25_cong_amt": 0, "fy25_cong_pct": 0.0}$$::jsonb, $${"fy24": 14975000, "fy26": 41570000, "name": "WHS Operations", "fy25_current": 22789000, "fy25_request": 23873000, "fy25_cong_amt": -2734000, "fy25_cong_pct": -11.45}$$::jsonb]), $${}$$::jsonb, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 1119, 1142, FALSE, $${"json_key": "WHS__umbrella", "fy27_v192_bucket_a_dw": {"session": "2026-05-09_v41", "source_pdf": "O&M/FY27/DW/Vol1_Part1/WHS_OP-5.pdf", "content_hash": "48b701fe895546064898c182ad814b4515ca3a97b975cf979e8c02b563160a0f", "source_page_amount": 6, "source_page_description": 2}}$$::jsonb, $$2026-04-28T19:22:27.197799+00:00$$, FALSE, NULL, NULL, NULL, NULL, NULL, 536546000, to_jsonb(ARRAY[$${"fy25": 118.655, "fy27": 136.587, "name": "Compensation and Benefits", "fy26_current": 114.881, "fy26_request": 114.881, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 6.527, "fy27": 2.237, "name": "Acquisition Management", "fy26_current": 3.042, "fy26_request": 3.042, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 34.778, "fy27": 13.951, "name": "Executive Services Management", "fy26_current": 11.028, "fy26_request": 11.028, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 267.653, "fy27": 264.805, "name": "Facilities/Installation Management", "fy26_current": 222.48, "fy26_request": 222.48, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 22.476, "fy27": 13.076, "name": "Financial Management", "fy26_current": 10.676, "fy26_request": 10.676, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 1.653, "fy27": 4.283, "name": "Human Resources", "fy26_current": 5.052, "fy26_request": 5.052, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 0.0, "fy27": 2.064, "name": "Security Enterprise Management", "fy26_current": 2.453, "fy26_request": 2.453, "fy26_cong_amt": 0.0, "fy26_cong_pct": 0.0}$$::jsonb, $${"fy25": 22.085, "fy27": 99.543, "name": "WHS Operations", "fy26_current": 40.494, "fy26_request": 41.57, "fy26_cong_amt": -1.076, "fy26_cong_pct": -2.59}$$::jsonb]), to_jsonb(ARRAY[]::text[]), $${}$$::jsonb, $$O&M/FY27/FY2027_o1.txt$$, 513000000) ON CONFLICT DO NOTHING;
